import { PublicCard } from '../../../types';

export const medicalCards: PublicCard[] = [
  { id: 'dc-medical-0001', deck_id: 'deck-medical', sort_order: 1, front: "-itis", back: "Suffix meaning inflammation. Examples: appendicitis (inflammation of the appendix), hepatitis (inflammation of the liver), arthritis (inflammation of joints)." , front_translations: {"es":"-ite","de":"-itis","fr":"-ite","tr":"-it","nl":"-itis","ru":"-ит","zh":"-炎","pt_BR":"-ite","pt_PT":"-ite"}, back_translations: {"es":"Sufijo que significa inflamación. Ejemplos: apendicite (inflamación del apéndice), hepatite (inflamación del hígado), artrite (inflamación de las articulaciones).","de":"Suffix mit der Bedeutung Entzündung. Beispiele: Appendizitis (Entzündung des Blinddarms), Hepatitis (Entzündung der Leber), Arthritis (Gelenkentzündung).","fr":"Suffixe signifiant inflammation. Exemples : appendicite (inflammation de l'appendice), hépatite (inflammation du foie), arthrite (inflammation des articulations).","tr":"Enflamasyon anlamına gelen sonek. Örnekler: apandisit (apandiksin iltihabı), hepatit (karaciğerin iltihabı), artrit (eklem iltihabı).","nl":"Achtervoegsel met de betekenis ontsteking. Voorbeelden: appendicitis (ontsteking van de blindedarm), hepatitis (ontsteking van de lever), artritis (ontsteking van de gewrichten).","ru":"Суффикс, означающий воспаление. Примеры: аппендицит (воспаление аппендикса), гепатит (воспаление печени), артрит (воспаление суставов).","zh":"表示炎症的后缀。示例：阑尾炎（阑尾的炎症）、肝炎（肝脏的炎症）、关节炎（关节的炎症）。","pt_BR":"Sufixo que significa inflamação. Exemplos: apendicite (inflamação do apêndice), hepatite (inflamação do fígado), artrite (inflamação das articulações).","pt_PT":"Sufixo que significa inflamação. Exemplos: apendicite (inflamação do apêndice), hepatite (inflamação do fígado), artrite (inflamação das articulações)."}},
  { id: 'dc-medical-0002', deck_id: 'deck-medical', sort_order: 2, front: "-ectomy", back: "Suffix meaning surgical removal. Examples: appendectomy (removal of the appendix), cholecystectomy (removal of the gallbladder), mastectomy (removal of the breast)." , front_translations: {"es":"-ectomia","de":"-ektomie","fr":"-ectomie","tr":"-ektomi","nl":"-ectomie","ru":"-эктомия","zh":"-切除术","pt_BR":"-ectomia","pt_PT":"-ectomia"}, back_translations: {"es":"Sufijo que significa remoción cirúrgica. Ejemplos: apendicectomia (remoción del apéndice), colecistectomia (remoción de la vesícula biliar), mastectomia (remoción de la mama).","de":"Suffix mit der Bedeutung chirurgische Entfernung. Beispiele: Appendektomie (Entfernung des Blinddarms), Cholezystektomie (Entfernung der Gallenblase), Mastektomie (Entfernung der Brust).","fr":"Suffixe signifiant ablation chirurgicale. Exemples : appendicectomie (ablation de l'appendice), cholécystectomie (ablation de la vésicule biliaire), mastectomie (ablation du sein).","tr":"Cerrahi çıkarma anlamına gelen sonek. Örnekler: apendektomi (apandiksin çıkarılması), kolesistektomi (safra kesesinin çıkarılması), mastektomi (meme dokusunun çıkarılması).","nl":"Achtervoegsel met de betekenis chirurgische verwijdering. Voorbeelden: appendectomie (verwijdering van de blindedarm), cholecystectomie (verwijdering van de galblaas), mastectomie (verwijdering van de borst).","ru":"Суффикс, означающий хирургическое удаление. Примеры: аппендэктомия (удаление аппендикса), холецистэктомия (удаление желчного пузыря), мастэктомия (удаление молочной железы).","zh":"表示手术切除的后缀。示例：阑尾切除术（切除阑尾）、胆囊切除术（切除胆囊）、乳房切除术（切除乳房）。","pt_BR":"Sufixo que significa remoção cirúrgica. Exemplos: apendicectomia (remoção do apêndice), colecistectomia (remoção da vesícula biliar), mastectomia (remoção da mama).","pt_PT":"Sufixo que significa remoção cirúrgica. Exemplos: apendicectomia (remoção do apêndice), colecistectomia (remoção da vesícula biliar), mastectomia (remoção da mama)."}},
  { id: 'dc-medical-0003', deck_id: 'deck-medical', sort_order: 3, front: "-oscopy / -scopy", back: "Suffix meaning visual examination using an instrument. Examples: colonoscopy (colon), bronchoscopy (airways), laparoscopy (abdominal cavity), arthroscopy (joint)." , front_translations: {"es":"-oscopia / -scopia","de":"-oskopie / -skopie","fr":"-oscopie / -scopie","tr":"-oskopi / -skopi","nl":"-oscopie / -scopie","ru":"-оскопия / -скопия","zh":"-镜检查","pt_BR":"-oscopia / -scopia","pt_PT":"-oscopia / -scopia"}, back_translations: {"es":"Sufijo que significa examen visual con un instrumento. Ejemplos: colonoscopia (cólon), broncoscopia (vias aéreas), laparoscopia (cavidad abdominal), artroscopia (articulación).","de":"Suffix mit der Bedeutung visuelle Untersuchung mit einem Instrument. Beispiele: Koloskopie (Dickdarm), Bronchoskopie (Atemwege), Laparoskopie (Bauchhöhle), Arthroskopie (Gelenk).","fr":"Suffixe signifiant examen visuel à l'aide d'un instrument. Exemples : coloscopie (côlon), bronchoscopie (voies respiratoires), laparoscopie (cavité abdominale), arthroscopie (articulation).","tr":"Bir alet kullanarak görsel inceleme anlamına gelen sonek. Örnekler: kolonoskopi (kalın bağırsak), bronkoskopi (hava yolları), laparoskopi (karın boşluğu), artroskopi (eklem).","nl":"Achtervoegsel met de betekenis visueel onderzoek met een instrument. Voorbeelden: coloscopie (dikke darm), bronchoscopie (luchtwegen), laparoscopie (buikholte), artroscopie (gewricht).","ru":"Суффикс, означающий визуальное исследование с помощью инструмента. Примеры: колоноскопия (толстая кишка), бронхоскопия (дыхательные пути), лапароскопия (брюшная полость), артроскопия (сустав).","zh":"表示使用器械进行视觉检查的后缀。示例：结肠镜检查（结肠）、支气管镜检查（气道）、腹腔镜检查（腹腔）、关节镜检查（关节）。","pt_BR":"Sufixo que significa exame visual com um instrumento. Exemplos: colonoscopia (cólon), broncoscopia (vias aéreas), laparoscopia (cavidade abdominal), artroscopia (articulação).","pt_PT":"Sufixo que significa exame visual com um instrumento. Exemplos: colonoscopia (cólon), broncoscopia (vias aéreas), laparoscopia (cavidade abdominal), artroscopia (articulação)."}},
  { id: 'dc-medical-0004', deck_id: 'deck-medical', sort_order: 4, front: "-plasty", back: "Suffix meaning surgical repair or reconstruction. Examples: rhinoplasty (nose), arthroplasty (joint replacement), angioplasty (widening a narrowed blood vessel)." , front_translations: {"es":"-plastia","de":"-plastik","fr":"-plastie","tr":"-plasti","nl":"-plastiek","ru":"-пластика","zh":"-成形术","pt_BR":"-plastia","pt_PT":"-plastia"}, back_translations: {"es":"Sufijo que significa reparo o reconstrución cirúrgica. Ejemplos: rinoplastia (nariz), artroplastia (substituición articular), angioplastia (alargamento de un vaso sanguíneo estreitado).","de":"Suffix mit der Bedeutung chirurgische Reparatur oder Rekonstruktion. Beispiele: Rhinoplastik (Nase), Arthroplastik (Gelenkersatz), Angioplastie (Erweiterung eines verengten Blutgefäßes).","fr":"Suffixe signifiant réparation ou reconstruction chirurgicale. Exemples : rhinoplastie (nez), arthroplastie (remplacement articulaire), angioplastie (élargissement d'un vaisseau sanguin rétréci).","tr":"Cerrahi onarım veya yeniden yapılandırma anlamına gelen sonek. Örnekler: rinoplasti (burun), artroplasti (eklem replasmanı), anjiyoplasti (daralmış bir kan damarının genişletilmesi).","nl":"Achtervoegsel met de betekenis chirurgisch herstel of reconstructie. Voorbeelden: rhinoplastiek (neus), artroplastiek (gewrichtsvervanging), angioplastiek (verwijding van een vernauwd bloedvat).","ru":"Суффикс, означающий хирургическое восстановление или реконструкцию. Примеры: ринопластика (нос), артропластика (протезирование сустава), ангиопластика (расширение суженного кровеносного сосуда).","zh":"表示手术修复或重建的后缀。示例：鼻成形术（鼻子）、关节成形术（关节置换）、血管成形术（扩张狭窄的血管）。","pt_BR":"Sufixo que significa reparo ou reconstrução cirúrgica. Exemplos: rinoplastia (nariz), artroplastia (substituição articular), angioplastia (alargamento de um vaso sanguíneo estreitado).","pt_PT":"Sufixo que significa reparação ou reconstrução cirúrgica. Exemplos: rinoplastia (nariz), artroplastia (substituição articular), angioplastia (alargamento de um vaso sanguíneo estreitado)."}},
  { id: 'dc-medical-0005', deck_id: 'deck-medical', sort_order: 5, front: "-ology", back: "Suffix meaning the study of. Examples: cardiology (heart), neurology (nervous system), dermatology (skin), oncology (cancer), pathology (disease mechanisms)." , front_translations: {"es":"-logia","de":"-logie","fr":"-logie","tr":"-loji","nl":"-logie","ru":"-логия","zh":"-学","pt_BR":"-logia","pt_PT":"-logia"}, back_translations: {"es":"Sufijo que significa el estudio de. Ejemplos: cardiologia (corazón), neurologia (sistema nervioso), dermatologia (piel), oncologia (cancer), patologia (mecanismos de enfermedades).","de":"Suffix mit der Bedeutung die Lehre von. Beispiele: Kardiologie (Herz), Neurologie (Nervensystem), Dermatologie (Haut), Onkologie (Krebs), Pathologie (Krankheitsmechanismen).","fr":"Suffixe signifiant l'étude de. Exemples : cardiologie (cœur), neurologie (système nerveux), dermatologie (peau), oncologie (cancer), pathologie (mécanismes des maladies).","tr":"İnceleme anlamına gelen sonek. Örnekler: kardiyoloji (kalp), nöroloji (sinir sistemi), dermatoloji (cilt), onkoloji (kanser), patoloji (hastalık mekanizmaları).","nl":"Achtervoegsel met de betekenis de studie van. Voorbeelden: cardiologie (hart), neurologie (zenuwstelsel), dermatologie (huid), oncologie (kanker), pathologie (ziektemechanismen).","ru":"Суффикс, означающий изучение. Примеры: кардиология (сердце), неврология (нервная система), дерматология (кожа), онкология (рак), патология (механизмы заболеваний).","zh":"表示研究学科的后缀。示例：心脏病学（心脏）、神经学（神经系统）、皮肤科学（皮肤）、肿瘤学（癌症）、病理学（疾病机制）。","pt_BR":"Sufixo que significa o estudo de. Exemplos: cardiologia (coração), neurologia (sistema nervoso), dermatologia (pele), oncologia (câncer), patologia (mecanismos de doenças).","pt_PT":"Sufixo que significa o estudo de. Exemplos: cardiologia (coração), neurologia (sistema nervoso), dermatologia (pele), oncologia (cancro), patologia (mecanismos de doenças)."}},
  { id: 'dc-medical-0006', deck_id: 'deck-medical', sort_order: 6, front: "-algia", back: "Suffix meaning pain. Examples: neuralgia (nerve pain), myalgia (muscle pain), arthralgia (joint pain without inflammation), fibromyalgia (widespread musculoskeletal pain)." , front_translations: {"es":"-algia","de":"-algie","fr":"-algie","tr":"-alji","nl":"-algie","ru":"-алгия","zh":"-痛","pt_BR":"-algia","pt_PT":"-algia"}, back_translations: {"es":"Sufijo que significa dor. Ejemplos: neuralgia (dor nervosa), mialgia (dor muscular), artralgia (dor articular sin inflamación), fibromialgia (dor musculoesquelética difusa).","de":"Suffix mit der Bedeutung Schmerz. Beispiele: Neuralgie (Nervenschmerz), Myalgie (Muskelschmerz), Arthralgie (Gelenkschmerz ohne Entzündung), Fibromyalgie (weit verbreiteter Muskel-Skelett-Schmerz).","fr":"Suffixe signifiant douleur. Exemples : névralgie (douleur nerveuse), myalgie (douleur musculaire), arthralgie (douleur articulaire sans inflammation), fibromyalgie (douleur musculosquelettique diffuse).","tr":"Ağrı anlamına gelen sonek. Örnekler: nevralji (sinir ağrısı), miyalji (kas ağrısı), artralji (iltihabsız eklem ağrısı), fibromiyalji (yaygın kas-iskelet ağrısı).","nl":"Achtervoegsel met de betekenis pijn. Voorbeelden: neuralgie (zenuwpijn), myalgie (spierpijn), artralgie (gewrichtspijn zonder ontsteking), fibromyalgie (wijdverspreide spier-skeletpijn).","ru":"Суффикс, означающий боль. Примеры: невралгия (боль в нерве), миалгия (мышечная боль), артралгия (боль в суставе без воспаления), фибромиалгия (распространённая мышечно-скелетная боль).","zh":"表示疼痛的后缀。示例：神经痛（神经疼痛）、肌痛（肌肉疼痛）、关节痛（无炎症的关节疼痛）、纤维肌痛（广泛性肌肉骨骼疼痛）。","pt_BR":"Sufixo que significa dor. Exemplos: neuralgia (dor nervosa), mialgia (dor muscular), artralgia (dor articular sem inflamação), fibromialgia (dor musculoesquelética difusa).","pt_PT":"Sufixo que significa dor. Exemplos: nevralgia (dor nervosa), mialgia (dor muscular), artralgia (dor articular sem inflamação), fibromialgia (dor musculoesquelética difusa)."}},
  { id: 'dc-medical-0007', deck_id: 'deck-medical', sort_order: 7, front: "-pathy", back: "Suffix meaning disease or disorder. Examples: neuropathy (nerve disease), cardiomyopathy (heart muscle disease), retinopathy (retinal disease, often from diabetes)." , front_translations: {"es":"-patia","de":"-pathie","fr":"-pathie","tr":"-pati","nl":"-pathie","ru":"-патия","zh":"-病","pt_BR":"-patia","pt_PT":"-patia"}, back_translations: {"es":"Sufijo que significa enfermedad o distúrbio. Ejemplos: neuropatia (enfermedad nervosa), cardiomiopatia (enfermedad del músculo cardíaco), retinopatia (enfermedad de la retina, frecuentemente por diabetes).","de":"Suffix mit der Bedeutung Erkrankung oder Störung. Beispiele: Neuropathie (Nervenerkrankung), Kardiomyopathie (Herzmuskelerkrankung), Retinopathie (Netzhauterkrankung, oft durch Diabetes).","fr":"Suffixe signifiant maladie ou trouble. Exemples : neuropathie (maladie des nerfs), cardiomyopathie (maladie du muscle cardiaque), rétinopathie (maladie de la rétine, souvent due au diabète).","tr":"Hastalık veya bozukluk anlamına gelen sonek. Örnekler: nöropati (sinir hastalığı), kardiyomiyopati (kalp kası hastalığı), retinopati (diyabetten sıklıkla kaynaklanan retina hastalığı).","nl":"Achtervoegsel met de betekenis ziekte of aandoening. Voorbeelden: neuropathie (zenuwziekte), cardiomyopathie (hartspierziekte), retinopathie (netvliesziekte, vaak door diabetes).","ru":"Суффикс, означающий болезнь или расстройство. Примеры: нейропатия (болезнь нервов), кардиомиопатия (болезнь сердечной мышцы), ретинопатия (болезнь сетчатки, часто вследствие диабета).","zh":"表示疾病或障碍的后缀。示例：神经病变（神经疾病）、心肌病（心肌疾病）、视网膜病变（视网膜疾病，常由糖尿病引起）。","pt_BR":"Sufixo que significa doença ou distúrbio. Exemplos: neuropatia (doença nervosa), cardiomiopatia (doença do músculo cardíaco), retinopatia (doença da retina, frequentemente por diabetes).","pt_PT":"Sufixo que significa doença ou perturbação. Exemplos: neuropatia (doença nervosa), cardiomiopatia (doença do músculo cardíaco), retinopatia (doença da retina, frequentemente por diabetes)."}},
  { id: 'dc-medical-0008', deck_id: 'deck-medical', sort_order: 8, front: "-emia", back: "Suffix meaning a condition of the blood. Examples: anemia (low red blood cells), leukemia (blood cancer), hypoglycemia (low blood sugar), bacteremia (bacteria in blood)." , front_translations: {"es":"-emia","de":"-ämie","fr":"-émie","tr":"-emi","nl":"-emie","ru":"-емия","zh":"-血症","pt_BR":"-emia","pt_PT":"-emia"}, back_translations: {"es":"Sufijo que indica una condición del sangre. Ejemplos: anemia (poucos glóbulos vermelhos), leucemia (cancer en el sangre), hipoglicemia (bajo nivel de açúcar en el sangre), bacteremia (bacterias en el sangre).","de":"Suffix mit der Bedeutung Zustand des Blutes. Beispiele: Anämie (zu wenig rote Blutkörperchen), Leukämie (Blutkrebs), Hypoglykämie (niedriger Blutzucker), Bakteriämie (Bakterien im Blut).","fr":"Suffixe signifiant un état du sang. Exemples : anémie (faible nombre de globules rouges), leucémie (cancer du sang), hypoglycémie (faible taux de sucre dans le sang), bactériémie (bactéries dans le sang).","tr":"Kanın bir durumunu ifade eden sonek. Örnekler: anemi (düşük kırmızı kan hücresi), lösemi (kan kanseri), hipoglisemi (düşük kan şekeri), bakteremi (kanda bakteri varlığı).","nl":"Achtervoegsel dat een bloedtoestand aanduidt. Voorbeelden: anemie (te weinig rode bloedcellen), leukemie (bloedkanker), hypoglykemie (laag bloedsuiker), bacteriëmie (bacteriën in het bloed).","ru":"Суффикс, означающий состояние крови. Примеры: анемия (низкое количество эритроцитов), лейкемия (рак крови), гипогликемия (низкий сахар крови), бактериемия (бактерии в крови).","zh":"表示血液状态的后缀。示例：贫血（红细胞减少）、白血病（血液癌症）、低血糖（血糖低）、菌血症（血液中有细菌）。","pt_BR":"Sufixo que indica uma condição do sangue. Exemplos: anemia (poucos glóbulos vermelhos), leucemia (câncer no sangue), hipoglicemia (baixo nível de açúcar no sangue), bacteremia (bactérias no sangue).","pt_PT":"Sufixo que indica uma condição do sangue. Exemplos: anemia (poucos glóbulos vermelhos), leucemia (cancro no sangue), hipoglicemia (baixo nível de açúcar no sangue), bacteriemia (bactérias no sangue)."}},
  { id: 'dc-medical-0009', deck_id: 'deck-medical', sort_order: 9, front: "-ostomy", back: "Suffix meaning surgical creation of an opening. Examples: colostomy (opening in the colon to the skin), tracheostomy (opening in the trachea), ileostomy (opening of the ileum)." , front_translations: {"es":"-ostomia","de":"-ostomie","fr":"-ostomie","tr":"-ostomi","nl":"-ostomie","ru":"-остомия","zh":"-造口术","pt_BR":"-ostomia","pt_PT":"-ostomia"}, back_translations: {"es":"Sufijo que significa criación cirúrgica de una abertura. Ejemplos: colostomia (abertura del cólon para a piel), traqueostomia (abertura en la traqueia), ileostomia (abertura del íleo).","de":"Suffix mit der Bedeutung chirurgische Anlage einer Öffnung. Beispiele: Kolostomie (Öffnung im Dickdarm zur Haut), Tracheostomie (Öffnung in der Luftröhre), Ileostomie (Öffnung des Ileums).","fr":"Suffixe signifiant création chirurgicale d'une ouverture. Exemples : colostomie (ouverture du côlon vers la peau), trachéostomie (ouverture de la trachée), iléostomie (ouverture de l'iléon).","tr":"Cerrahi olarak açıklık oluşturma anlamına gelen sonek. Örnekler: kolostomi (kalın bağırsaktan deriye açılan stoma), trakeostomi (soluk borusunda açıklık), ileostomi (ince bağırsak açıklığı).","nl":"Achtervoegsel met de betekenis chirurgisch aanleggen van een opening. Voorbeelden: colostomie (opening van de dikke darm naar de huid), tracheostomie (opening in de luchtpijp), ileostomie (opening van het ileum).","ru":"Суффикс, означающий хирургическое создание отверстия. Примеры: колостомия (отверстие в толстой кишке на коже), трахеостомия (отверстие в трахее), илеостомия (отверстие подвздошной кишки).","zh":"表示手术造口的后缀。示例：结肠造口术（结肠开口至皮肤）、气管造口术（气管开口）、回肠造口术（回肠开口）。","pt_BR":"Sufixo que significa criação cirúrgica de uma abertura. Exemplos: colostomia (abertura do cólon para a pele), traqueostomia (abertura na traqueia), ileostomia (abertura do íleo).","pt_PT":"Sufixo que significa criação cirúrgica de uma abertura. Exemplos: colostomia (abertura do cólon para a pele), traqueostomia (abertura na traqueia), ileostomia (abertura do íleo)."}},
  { id: 'dc-medical-0010', deck_id: 'deck-medical', sort_order: 10, front: "-otomy / -tomy", back: "Suffix meaning a surgical incision (cutting into). Examples: laparotomy (incision into the abdomen), craniotomy (incision into the skull), tracheotomy (incision into the trachea)." , front_translations: {"es":"-otomia / -tomia","de":"-otomie / -tomie","fr":"-otomie / -tomie","tr":"-otomi / -tomi","nl":"-otomie / -tomie","ru":"-отомия / -томия","zh":"-切开术","pt_BR":"-otomia / -tomia","pt_PT":"-otomia / -tomia"}, back_translations: {"es":"Sufijo que significa incisão cirúrgica (cortar dentro). Ejemplos: laparotomia (incisão en el abdome), craniotomia (incisão en el cráneo), traqueotomia (incisão en la traqueia).","de":"Suffix mit der Bedeutung chirurgischer Schnitt (Einschneiden). Beispiele: Laparotomie (Einschnitt in den Bauch), Kraniotomie (Einschnitt in den Schädel), Tracheotomie (Einschnitt in die Luftröhre).","fr":"Suffixe signifiant une incision chirurgicale (découper). Exemples : laparotomie (incision dans l'abdomen), crâniotomie (incision dans le crâne), trachéotomie (incision dans la trachée).","tr":"Cerrahi kesi (içine kesme) anlamına gelen sonek. Örnekler: laparotomi (karın boşluğuna kesi), kraniyotomi (kafatasına kesi), trakeotomi (soluk borusuna kesi).","nl":"Achtervoegsel met de betekenis chirurgische incisie (insnijden). Voorbeelden: laparotomie (incisie in de buik), craniotomie (incisie in de schedel), tracheotomie (incisie in de luchtpijp).","ru":"Суффикс, означающий хирургический разрез (рассечение). Примеры: лапаротомия (разрез живота), краниотомия (разрез черепа), трахеотомия (разрез трахеи).","zh":"表示手术切开（切入）的后缀。示例：剖腹术（腹部切开）、颅骨切开术（颅骨切开）、气管切开术（气管切开）。","pt_BR":"Sufixo que significa incisão cirúrgica (cortar dentro). Exemplos: laparotomia (incisão no abdome), craniotomia (incisão no crânio), traqueotomia (incisão na traqueia).","pt_PT":"Sufixo que significa incisão cirúrgica (cortar dentro). Exemplos: laparotomia (incisão no abdómen), craniotomia (incisão no crânio), traqueotomia (incisão na traqueia)."}},
  { id: 'dc-medical-0011', deck_id: 'deck-medical', sort_order: 11, front: "-stenosis", back: "Suffix meaning narrowing or constriction. Examples: aortic stenosis (narrowing of the aortic valve), coronary artery stenosis, spinal stenosis (narrowing of spinal canal)." , front_translations: {"es":"-estenose","de":"-stenose","fr":"-sténose","tr":"-stenoz","nl":"-stenose","ru":"-стеноз","zh":"-狭窄","pt_BR":"-estenose","pt_PT":"-estenose"}, back_translations: {"es":"Sufijo que significa estreitamento o constrición. Ejemplos: estenose aórtica (estreitamento de la válvula aórtica), estenose de la arteria coronária, estenose espinhal (estreitamento del canal espinhal).","de":"Suffix mit der Bedeutung Verengung oder Einengung. Beispiele: Aortenstenose (Verengung der Aortenklappe), Koronararterienstenosse, Spinalstenose (Verengung des Wirbelkanals).","fr":"Suffixe signifiant rétrécissement ou constriction. Exemples : sténose aortique (rétrécissement de la valve aortique), sténose coronarienne, sténose rachidienne (rétrécissement du canal rachidien).","tr":"Daralma veya kasılma anlamına gelen sonek. Örnekler: aort stenozu (aort kapak darlığı), koroner arter stenozu, spinal stenoz (omurga kanalının daralması).","nl":"Achtervoegsel met de betekenis vernauwing of constrictie. Voorbeelden: aortastenose (vernauwing van de aortaklep), coronaire arteriële stenose, spinale stenose (vernauwing van het wervelkanaal).","ru":"Суффикс, означающий сужение или стеноз. Примеры: стеноз аорты (сужение аортального клапана), стеноз коронарных артерий, стеноз позвоночного канала.","zh":"表示狭窄或收缩的后缀。示例：主动脉瓣狭窄（主动脉瓣收窄）、冠状动脉狭窄、椎管狭窄（椎管收窄）。","pt_BR":"Sufixo que significa estreitamento ou constrição. Exemplos: estenose aórtica (estreitamento da válvula aórtica), estenose da artéria coronária, estenose espinhal (estreitamento do canal espinhal).","pt_PT":"Sufixo que significa estreitamento ou constrição. Exemplos: estenose aórtica (estreitamento da válvula aórtica), estenose da artéria coronária, estenose espinhal (estreitamento do canal espinhal)."}},
  { id: 'dc-medical-0012', deck_id: 'deck-medical', sort_order: 12, front: "-megaly", back: "Suffix meaning enlargement. Examples: cardiomegaly (enlarged heart), splenomegaly (enlarged spleen), hepatomegaly (enlarged liver), acromegaly (enlargement of extremities due to excess GH)." , front_translations: {"es":"-megalia","de":"-megalie","fr":"-mégalie","tr":"-megali","nl":"-megalie","ru":"-мегалия","zh":"-肥大","pt_BR":"-megalia","pt_PT":"-megalia"}, back_translations: {"es":"Sufijo que significa aumento o alargamento. Ejemplos: cardiomegalia (corazón aumentado), esplenomegalia (baço aumentado), hepatomegalia (hígado aumentado), acromegalia (aumento de las extremidades por exceso de GH).","de":"Suffix mit der Bedeutung Vergrößerung. Beispiele: Kardiomegalie (vergrößertes Herz), Splenomegalie (vergrößerte Milz), Hepatomegalie (vergrößerte Leber), Akromegalie (Vergrößerung der Extremitäten durch überschüssiges Wachstumshormon).","fr":"Suffixe signifiant hypertrophie. Exemples : cardiomégalie (cœur hypertrophié), splénomégalie (rate hypertrophiée), hépatomégalie (foie hypertrophié), acromégalie (hypertrophie des extrémités due à un excès d'hormone de croissance).","tr":"Büyüme anlamına gelen sonek. Örnekler: kardiyomegali (büyümüş kalp), splenomegali (büyümüş dalak), hepatomegali (büyümüş karaciğer), akromegali (aşırı büyüme hormonu nedeniyle ekstremite büyümesi).","nl":"Achtervoegsel met de betekenis vergroting. Voorbeelden: cardiomegalie (vergroot hart), splenomegalie (vergrote milt), hepatomegalie (vergrote lever), acromegalie (vergroting van de ledematen door overmatig groeihormoon).","ru":"Суффикс, означающий увеличение. Примеры: кардиомегалия (увеличенное сердце), спленомегалия (увеличенная селезёнка), гепатомегалия (увеличенная печень), акромегалия (увеличение конечностей вследствие избытка СТГ).","zh":"表示肥大或增大的后缀。示例：心脏肥大（心脏增大）、脾肿大（脾脏增大）、肝肿大（肝脏增大）、肢端肥大症（因生长激素过多导致肢体增大）。","pt_BR":"Sufixo que significa aumento ou alargamento. Exemplos: cardiomegalia (coração aumentado), esplenomegalia (baço aumentado), hepatomegalia (fígado aumentado), acromegalia (aumento das extremidades por excesso de GH).","pt_PT":"Sufixo que significa aumento ou alargamento. Exemplos: cardiomegalia (coração aumentado), esplenomegalia (baço aumentado), hepatomegalia (fígado aumentado), acromegalia (aumento das extremidades por excesso de GH)."}},
  { id: 'dc-medical-0013', deck_id: 'deck-medical', sort_order: 13, front: "Cardio-", back: "Prefix relating to the heart. Examples: cardiomegaly (enlarged heart), cardiomyopathy (heart muscle disease), cardiovascular (pertaining to heart and blood vessels)." , front_translations: {"es":"Cardio-","de":"Kardio-","fr":"Cardio-","tr":"Kardio-","nl":"Cardio-","ru":"Кардио-","zh":"心-","pt_BR":"Cardio-","pt_PT":"Cardio-"}, back_translations: {"es":"Prefijo relacionado al corazón. Ejemplos: cardiomegalia (corazón aumentado), cardiomiopatia (enfermedad del músculo cardíaco), cardiovascular (relativo al corazón y vasos sanguíneos).","de":"Präfix mit Bezug zum Herzen. Beispiele: Kardiomegalie (vergrößertes Herz), Kardiomyopathie (Herzmuskelerkrankung), kardiovaskulär (das Herz und die Blutgefäße betreffend).","fr":"Préfixe relatif au cœur. Exemples : cardiomégalie (cœur hypertrophié), cardiomyopathie (maladie du muscle cardiaque), cardiovasculaire (relatif au cœur et aux vaisseaux sanguins).","tr":"Kalpla ilgili ön ek. Örnekler: kardiyomegali (büyümüş kalp), kardiyomiyopati (kalp kası hastalığı), kardiyovasküler (kalp ve kan damarlarına ilişkin).","nl":"Voorvoegsel dat betrekking heeft op het hart. Voorbeelden: cardiomegalie (vergroot hart), cardiomyopathie (hartspierziekte), cardiovasculair (betrekking hebbend op hart en bloedvaten).","ru":"Префикс, относящийся к сердцу. Примеры: кардиомегалия (увеличенное сердце), кардиомиопатия (болезнь сердечной мышцы), сердечно-сосудистый (относящийся к сердцу и сосудам).","zh":"与心脏相关的前缀。示例：心脏肥大（心脏增大）、心肌病（心肌疾病）、心血管（涉及心脏和血管）。","pt_BR":"Prefixo relacionado ao coração. Exemplos: cardiomegalia (coração aumentado), cardiomiopatia (doença do músculo cardíaco), cardiovascular (relativo ao coração e vasos sanguíneos).","pt_PT":"Prefixo relacionado com o coração. Exemplos: cardiomegalia (coração aumentado), cardiomiopatia (doença do músculo cardíaco), cardiovascular (relativo ao coração e vasos sanguíneos)."}},
  { id: 'dc-medical-0014', deck_id: 'deck-medical', sort_order: 14, front: "Neuro-", back: "Prefix relating to the nervous system. Examples: neurology (study of the nervous system), neuralgia (nerve pain), neuropathy (nerve disease), neurosurgery." , front_translations: {"es":"Neuro-","de":"Neuro-","fr":"Neuro-","tr":"Nöro-","nl":"Neuro-","ru":"Нейро-","zh":"神经-","pt_BR":"Neuro-","pt_PT":"Neuro-"}, back_translations: {"es":"Prefijo relacionado al sistema nervioso. Ejemplos: neurologia (estudio del sistema nervioso), neuralgia (dor nervosa), neuropatia (enfermedad nervosa), neurocirurgia.","de":"Präfix mit Bezug zum Nervensystem. Beispiele: Neurologie (Lehre vom Nervensystem), Neuralgie (Nervenschmerz), Neuropathie (Nervenerkrankung), Neurochirurgie.","fr":"Préfixe relatif au système nerveux. Exemples : neurologie (étude du système nerveux), névralgie (douleur nerveuse), neuropathie (maladie des nerfs), neurochirurgie.","tr":"Sinir sistemiyle ilgili ön ek. Örnekler: nöroloji (sinir sisteminin incelenmesi), nevralji (sinir ağrısı), nöropati (sinir hastalığı), nöroşirürji.","nl":"Voorvoegsel dat betrekking heeft op het zenuwstelsel. Voorbeelden: neurologie (studie van het zenuwstelsel), neuralgie (zenuwpijn), neuropathie (zenuwziekte), neurochirurgie.","ru":"Префикс, относящийся к нервной системе. Примеры: неврология (изучение нервной системы), невралгия (боль в нерве), нейропатия (болезнь нервов), нейрохирургия.","zh":"与神经系统相关的前缀。示例：神经学（神经系统研究）、神经痛（神经疼痛）、神经病变（神经疾病）、神经外科。","pt_BR":"Prefixo relacionado ao sistema nervoso. Exemplos: neurologia (estudo do sistema nervoso), neuralgia (dor nervosa), neuropatia (doença nervosa), neurocirurgia.","pt_PT":"Prefixo relacionado com o sistema nervoso. Exemplos: neurologia (estudo do sistema nervoso), nevralgia (dor nervosa), neuropatia (doença nervosa), neurocirurgia."}},
  { id: 'dc-medical-0015', deck_id: 'deck-medical', sort_order: 15, front: "Hepato-", back: "Prefix relating to the liver. Examples: hepatitis (liver inflammation), hepatomegaly (enlarged liver), hepatocyte (liver cell), hepatotoxic (toxic to the liver)." , front_translations: {"es":"Hepato-","de":"Hepato-","fr":"Hépato-","tr":"Hepato-","nl":"Hepato-","ru":"Гепато-","zh":"肝-","pt_BR":"Hepato-","pt_PT":"Hepato-"}, back_translations: {"es":"Prefijo relacionado al hígado. Ejemplos: hepatite (inflamación del hígado), hepatomegalia (hígado aumentado), hepatócito (célula hepática), hepatotóxico (tóxico para el hígado).","de":"Präfix mit Bezug zur Leber. Beispiele: Hepatitis (Leberentzündung), Hepatomegalie (vergrößerte Leber), Hepatozyt (Leberzelle), hepatotoxisch (leberschädigend).","fr":"Préfixe relatif au foie. Exemples : hépatite (inflammation du foie), hépatomégalie (foie hypertrophié), hépatocyte (cellule hépatique), hépatotoxique (toxique pour le foie).","tr":"Karaciğerle ilgili ön ek. Örnekler: hepatit (karaciğer iltihabı), hepatomegali (büyümüş karaciğer), hepatosit (karaciğer hücresi), hepatotoksik (karaciğere toksik).","nl":"Voorvoegsel dat betrekking heeft op de lever. Voorbeelden: hepatitis (leverkontsteking), hepatomegalie (vergrote lever), hepatocyt (levercel), hepatotoxisch (giftig voor de lever).","ru":"Префикс, относящийся к печени. Примеры: гепатит (воспаление печени), гепатомегалия (увеличенная печень), гепатоцит (клетка печени), гепатотоксичный (токсичный для печени).","zh":"与肝脏相关的前缀。示例：肝炎（肝脏炎症）、肝肿大（肝脏增大）、肝细胞（肝脏细胞）、肝毒性（对肝脏有毒）。","pt_BR":"Prefixo relacionado ao fígado. Exemplos: hepatite (inflamação do fígado), hepatomegalia (fígado aumentado), hepatócito (célula hepática), hepatotóxico (tóxico para o fígado).","pt_PT":"Prefixo relacionado com o fígado. Exemplos: hepatite (inflamação do fígado), hepatomegalia (fígado aumentado), hepatócito (célula hepática), hepatotóxico (tóxico para o fígado)."}},
  { id: 'dc-medical-0016', deck_id: 'deck-medical', sort_order: 16, front: "Nephro-", back: "Prefix relating to the kidneys. Examples: nephritis (kidney inflammation), nephrology (study of kidneys), nephrotic syndrome (kidney disease causing protein loss in urine)." , front_translations: {"es":"Nefro-","de":"Nephro-","fr":"Néphro-","tr":"Nefro-","nl":"Nephro-","ru":"Нефро-","zh":"肾-","pt_BR":"Nefro-","pt_PT":"Nefro-"}, back_translations: {"es":"Prefijo relacionado a los riñones. Ejemplos: nefrite (inflamación de los riñones), nefrologia (estudio de los riñones), síndrome nefrótica (enfermedad renal causando perda de proteína en la urina).","de":"Präfix mit Bezug zu den Nieren. Beispiele: Nephritis (Nierenentzündung), Nephrologie (Lehre von den Nieren), nephrotisches Syndrom (Nierenerkrankung mit Eiweißverlust im Urin).","fr":"Préfixe relatif aux reins. Exemples : néphrite (inflammation des reins), néphrologie (étude des reins), syndrome néphrotique (maladie rénale entraînant une perte de protéines dans l'urine).","tr":"Böbreklerle ilgili ön ek. Örnekler: nefrit (böbrek iltihabı), nefroloji (böbreklerin incelenmesi), nefrotik sendrom (idrarda protein kaybına neden olan böbrek hastalığı).","nl":"Voorvoegsel dat betrekking heeft op de nieren. Voorbeelden: nefritis (nierontsteking), nefrologie (studie van de nieren), nefrotisch syndroom (nierziekte met eiwitverlies in de urine).","ru":"Префикс, относящийся к почкам. Примеры: нефрит (воспаление почек), нефрология (изучение почек), нефротический синдром (болезнь почек с потерей белка в моче).","zh":"与肾脏相关的前缀。示例：肾炎（肾脏炎症）、肾脏病学（肾脏研究）、肾病综合征（导致尿液中蛋白质丢失的肾脏疾病）。","pt_BR":"Prefixo relacionado aos rins. Exemplos: nefrite (inflamação dos rins), nefrologia (estudo dos rins), síndrome nefrótica (doença renal causando perda de proteína na urina).","pt_PT":"Prefixo relacionado com os rins. Exemplos: nefrite (inflamação dos rins), nefrologia (estudo dos rins), síndrome nefrótica (doença renal causando perda de proteína na urina)."}},
  { id: 'dc-medical-0017', deck_id: 'deck-medical', sort_order: 17, front: "Osteo-", back: "Prefix relating to bone. Examples: osteoporosis (porous bones), osteomyelitis (bone infection), osteoarthritis (joint degeneration), osteosarcoma (bone cancer)." , front_translations: {"es":"Osteo-","de":"Osteo-","fr":"Ostéo-","tr":"Osteo-","nl":"Osteo-","ru":"Остео-","zh":"骨-","pt_BR":"Osteo-","pt_PT":"Osteo-"}, back_translations: {"es":"Prefijo relacionado a los huesos. Ejemplos: osteoporose (huesos porosos), osteomielite (infección ósea), osteoartrite (degeneración articular), osteossarcoma (cancer óseo).","de":"Präfix mit Bezug zu Knochen. Beispiele: Osteoporose (poröse Knochen), Osteomyelitis (Knocheninfektion), Osteoarthritis (Gelenkdegeneration), Osteosarkom (Knochenkrebs).","fr":"Préfixe relatif aux os. Exemples : ostéoporose (os poreux), ostéomyélite (infection osseuse), ostéoarthrite (dégénérescence articulaire), ostéosarcome (cancer des os).","tr":"Kemikle ilgili ön ek. Örnekler: osteoporoz (gözenekli kemikler), osteomiyelit (kemik enfeksiyonu), osteoartrit (eklem dejenerasyonu), osteosarkom (kemik kanseri).","nl":"Voorvoegsel dat betrekking heeft op botten. Voorbeelden: osteoporose (poreuze botten), osteomyelitis (botinfectie), osteoartritis (gewrichtsdegeneratie), osteosarcoom (botkanker).","ru":"Префикс, относящийся к костям. Примеры: остеопороз (пористые кости), остеомиелит (инфекция кости), остеоартрит (дегенерация суставов), остеосаркома (рак кости).","zh":"与骨骼相关的前缀。示例：骨质疏松症（骨骼多孔）、骨髓炎（骨骼感染）、骨关节炎（关节退变）、骨肉瘤（骨癌）。","pt_BR":"Prefixo relacionado aos ossos. Exemplos: osteoporose (ossos porosos), osteomielite (infecção óssea), osteoartrite (degeneração articular), osteossarcoma (câncer ósseo).","pt_PT":"Prefixo relacionado com os ossos. Exemplos: osteoporose (ossos porosos), osteomielite (infecção óssea), osteoartrite (degeneração articular), osteossarcoma (cancro ósseo)."}},
  { id: 'dc-medical-0018', deck_id: 'deck-medical', sort_order: 18, front: "Dermo- / Dermato-", back: "Prefix relating to the skin. Examples: dermatitis (skin inflammation), dermatology (study of skin), dermatome (area of skin supplied by a single spinal nerve)." , front_translations: {"es":"Dermo- / Dermato-","de":"Dermo- / Dermato-","fr":"Dermo- / Dermato-","tr":"Dermo- / Dermato-","nl":"Dermo- / Dermato-","ru":"Дермо- / Дермато-","zh":"皮肤-","pt_BR":"Dermo- / Dermato-","pt_PT":"Dermo- / Dermato-"}, back_translations: {"es":"Prefijo relacionado a la piel. Ejemplos: dermatite (inflamación de la piel), dermatologia (estudio de la piel), dermátomo (área de la piel suprida por un único nervio espinhal).","de":"Präfix mit Bezug zur Haut. Beispiele: Dermatitis (Hautentzündung), Dermatologie (Lehre von der Haut), Dermatom (Hautbereich, der von einem einzelnen Spinalnerv versorgt wird).","fr":"Préfixe relatif à la peau. Exemples : dermatite (inflammation de la peau), dermatologie (étude de la peau), dermatome (zone cutanée innervée par un seul nerf spinal).","tr":"Deriyle ilgili ön ek. Örnekler: dermatit (deri iltihabı), dermatoloji (derinin incelenmesi), dermatom (tek bir spinal sinir tarafından inerve edilen deri alanı).","nl":"Voorvoegsel dat betrekking heeft op de huid. Voorbeelden: dermatitis (huidontsteking), dermatologie (studie van de huid), dermatoom (huidgebied dat door één spinaalzenuw wordt geïnnerveerd).","ru":"Префикс, относящийся к коже. Примеры: дерматит (воспаление кожи), дерматология (изучение кожи), дерматом (участок кожи, иннервируемый одним спинномозговым нервом).","zh":"与皮肤相关的前缀。示例：皮炎（皮肤炎症）、皮肤病学（皮肤研究）、皮节（由单根脊神经支配的皮肤区域）。","pt_BR":"Prefixo relacionado à pele. Exemplos: dermatite (inflamação da pele), dermatologia (estudo da pele), dermátomo (área da pele suprida por um único nervo espinhal).","pt_PT":"Prefixo relacionado com a pele. Exemplos: dermatite (inflamação da pele), dermatologia (estudo da pele), dermátomo (área da pele suprida por um único nervo espinhal)."}},
  { id: 'dc-medical-0019', deck_id: 'deck-medical', sort_order: 19, front: "Gastro-", back: "Prefix relating to the stomach. Examples: gastritis (stomach inflammation), gastroenterology (study of GI tract), gastroesophageal reflux disease (GERD), gastroparesis (delayed gastric emptying)." , front_translations: {"es":"Gastro-","de":"Gastro-","fr":"Gastro-","tr":"Gastro-","nl":"Gastro-","ru":"Гастро-","zh":"胃-","pt_BR":"Gastro-","pt_PT":"Gastro-"}, back_translations: {"es":"Prefijo relacionado al estomago. Ejemplos: gastrite (inflamación del estomago), gastroenterologia (estudio del trato gastrointestinal), enfermedad del refluxo gastroesofágico (DRGE), gastroparesia (esvaziamento gástrico retardado).","de":"Präfix mit Bezug zum Magen. Beispiele: Gastritis (Magenentzündung), Gastroenterologie (Lehre vom Magen-Darm-Trakt), gastroösophageale Refluxkrankheit (GERD), Gastroparese (verzögerte Magenentleerung).","fr":"Préfixe relatif à l'estomac. Exemples : gastrite (inflammation de l'estomac), gastroentérologie (étude du tractus gastro-intestinal), reflux gastro-œsophagien (RGO), gastroparésie (vidange gastrique retardée).","tr":"Mideyle ilgili ön ek. Örnekler: gastrit (mide iltihabı), gastroenteroloji (sindirim sistemi incelemesi), gastroözofajeal reflü hastalığı (GÖRH), gastroparezi (gecikmiş mide boşalması).","nl":"Voorvoegsel dat betrekking heeft op de maag. Voorbeelden: gastritis (maagontsteking), gastro-enterologie (studie van het maag-darmkanaal), gastro-oesofageale refluxziekte (GERD), gastroparese (vertraagde maagontlediging).","ru":"Префикс, относящийся к желудку. Примеры: гастрит (воспаление желудка), гастроэнтерология (изучение ЖКТ), гастроэзофагеальная рефлюксная болезнь (ГЭРБ), гастропарез (задержка опорожнения желудка).","zh":"与胃部相关的前缀。示例：胃炎（胃部炎症）、胃肠病学（消化道研究）、胃食管反流病（GERD）、胃轻瘫（胃排空延迟）。","pt_BR":"Prefixo relacionado ao estômago. Exemplos: gastrite (inflamação do estômago), gastroenterologia (estudo do trato gastrointestinal), doença do refluxo gastroesofágico (DRGE), gastroparesia (esvaziamento gástrico retardado).","pt_PT":"Prefixo relacionado com o estômago. Exemplos: gastrite (inflamação do estômago), gastroenterologia (estudo do trato gastrointestinal), doença de refluxo gastroesofágico (DRGE), gastroparésia (esvaziamento gástrico retardado)."}},
  { id: 'dc-medical-0020', deck_id: 'deck-medical', sort_order: 20, front: "Pulmo- / Pneumo-", back: "Prefix relating to the lungs. Examples: pulmonology (lung medicine), pulmonary embolism (clot in lung), pneumonia (lung infection), pneumothorax (air in pleural space)." , front_translations: {"es":"Pulmo- / Pneumo-","de":"Pulmo- / Pneumo-","fr":"Pulmo- / Pneumo-","tr":"Pulmo- / Pnömo-","nl":"Pulmo- / Pneumo-","ru":"Пульмо- / Пневмо-","zh":"肺-","pt_BR":"Pulmo- / Pneumo-","pt_PT":"Pulmo- / Pneumo-"}, back_translations: {"es":"Prefijo relacionado a los pulmones. Ejemplos: pneumologia (medicina pulmonar), embolia pulmonar (coágulo en el pulmón), pneumonia (infección pulmonar), pneumotórax (aire en el espacio pleural).","de":"Präfix mit Bezug zu den Lungen. Beispiele: Pulmonologie (Lungenheilkunde), Lungenembolie (Gerinnsel in der Lunge), Pneumonie (Lungenentzündung), Pneumothorax (Luft im Pleuraspalt).","fr":"Préfixe relatif aux poumons. Exemples : pneumologie (médecine pulmonaire), embolie pulmonaire (caillot dans le poumon), pneumonie (infection pulmonaire), pneumothorax (air dans la plèvre).","tr":"Akciğerlerle ilgili ön ek. Örnekler: pulmونoloji (akciğer tıbbı), pulmoner emboli (akciğerde pıhtı), pnömoni (akciğer enfeksiyonu), pnömotoraks (plevra boşluğunda hava).","nl":"Voorvoegsel dat betrekking heeft op de longen. Voorbeelden: pulmonologie (longeneeskunde), longembolie (stolsel in de long), pneumonie (longontsteking), pneumothorax (lucht in de pleurale ruimte).","ru":"Префикс, относящийся к лёгким. Примеры: пульмонология (медицина лёгких), тромбоэмболия лёгочной артерии (сгусток в лёгком), пневмония (инфекция лёгких), пневмоторакс (воздух в плевральном пространстве).","zh":"与肺部相关的前缀。示例：肺科学（肺部医学）、肺栓塞（肺部血栓）、肺炎（肺部感染）、气胸（胸膜腔内有气体）。","pt_BR":"Prefixo relacionado aos pulmões. Exemplos: pneumologia (medicina pulmonar), embolia pulmonar (coágulo no pulmão), pneumonia (infecção pulmonar), pneumotórax (ar no espaço pleural).","pt_PT":"Prefixo relacionado com os pulmões. Exemplos: pneumologia (medicina pulmonar), embolia pulmonar (coágulo no pulmão), pneumonia (infecção pulmonar), pneumotórax (ar no espaço pleural)."}},
  { id: 'dc-medical-0021', deck_id: 'deck-medical', sort_order: 21, front: "Hemo- / Hemato-", back: "Prefix relating to blood. Examples: hematology (study of blood), hemoglobin (blood oxygen carrier), hemostasis (stopping bleeding), hemolysis (destruction of red blood cells)." , front_translations: {"es":"Hemo- / Hemato-","de":"Hämo- / Hämato-","fr":"Hémo- / Hémato-","tr":"Hemo- / Hemato-","nl":"Hemo- / Hemato-","ru":"Гемо- / Гемато-","zh":"血-","pt_BR":"Hemo- / Hemato-","pt_PT":"Hemo- / Hemato-"}, back_translations: {"es":"Prefijo relacionado al sangre. Ejemplos: hematologia (estudio del sangre), hemoglobina (transportador de oxígeno en el sangre), hemostasia (parada del sangramento), hemólise (destrucción de glóbulos vermelhos).","de":"Präfix mit Bezug zum Blut. Beispiele: Hämatologie (Lehre vom Blut), Hämoglobin (Sauerstoffträger im Blut), Hämostase (Blutstillung), Hämolyse (Zerstörung roter Blutkörperchen).","fr":"Préfixe relatif au sang. Exemples : hématologie (étude du sang), hémoglobine (transporteur d'oxygène sanguin), hémostase (arrêt du saignement), hémolyse (destruction des globules rouges).","tr":"Kanla ilgili ön ek. Örnekler: hematoloji (kanın incelenmesi), hemoglobin (kanın oksijen taşıyıcısı), hemostaz (kanamanın durdurulması), hemoliz (kırmızı kan hücrelerinin yıkımı).","nl":"Voorvoegsel dat betrekking heeft op bloed. Voorbeelden: hematologie (studie van het bloed), hemoglobine (zuurstofdrager in het bloed), hemostase (stoppen van bloeding), hemolyse (vernietiging van rode bloedcellen).","ru":"Префикс, относящийся к крови. Примеры: гематология (изучение крови), гемоглобин (переносчик кислорода в крови), гемостаз (остановка кровотечения), гемолиз (разрушение эритроцитов).","zh":"与血液相关的前缀。示例：血液学（血液研究）、血红蛋白（血液中的载氧体）、止血（停止出血）、溶血（红细胞的破坏）。","pt_BR":"Prefixo relacionado ao sangue. Exemplos: hematologia (estudo do sangue), hemoglobina (transportador de oxigênio no sangue), hemostasia (parada do sangramento), hemólise (destruição de glóbulos vermelhos).","pt_PT":"Prefixo relacionado com o sangue. Exemplos: hematologia (estudo do sangue), hemoglobina (transportador de oxigénio no sangue), hemostase (paragem da hemorragia), hemólise (destruição de glóbulos vermelhos)."}},
  { id: 'dc-medical-0022', deck_id: 'deck-medical', sort_order: 22, front: "Arthro-", back: "Prefix relating to joints. Examples: arthroscopy (joint examination), arthritis (joint inflammation), arthroplasty (joint repair), arthralgia (joint pain)." , front_translations: {"es":"Artro-","de":"Arthro-","fr":"Arthro-","tr":"Artro-","nl":"Arthro-","ru":"Артро-","zh":"关节-","pt_BR":"Artro-","pt_PT":"Artro-"}, back_translations: {"es":"Prefijo relacionado a las articulaciones. Ejemplos: artroscopia (examen articular), artrite (inflamación articular), artroplastia (reparación articular), artralgia (dor articular).","de":"Präfix mit Bezug zu Gelenken. Beispiele: Arthroskopie (Gelenkuntersuchung), Arthritis (Gelenkentzündung), Arthroplastik (Gelenkreparatur), Arthralgie (Gelenkschmerz).","fr":"Préfixe relatif aux articulations. Exemples : arthroscopie (examen articulaire), arthrite (inflammation articulaire), arthroplastie (réparation articulaire), arthralgie (douleur articulaire).","tr":"Eklemlerle ilgili ön ek. Örnekler: artroskopi (eklem incelemesi), artrit (eklem iltihabı), artroplasti (eklem onarımı), artralji (eklem ağrısı).","nl":"Voorvoegsel dat betrekking heeft op gewrichten. Voorbeelden: artroscopie (gewrichtsonderzoek), artritis (gewrichtsontsteking), artroplastiek (gewrichtsherstel), artralgie (gewrichtspijn).","ru":"Префикс, относящийся к суставам. Примеры: артроскопия (исследование сустава), артрит (воспаление суставов), артропластика (восстановление сустава), артралгия (боль в суставе).","zh":"与关节相关的前缀。示例：关节镜检查（关节检查）、关节炎（关节炎症）、关节成形术（关节修复）、关节痛（关节疼痛）。","pt_BR":"Prefixo relacionado às articulações. Exemplos: artroscopia (exame articular), artrite (inflamação articular), artroplastia (reparação articular), artralgia (dor articular).","pt_PT":"Prefixo relacionado com as articulações. Exemplos: artroscopia (exame articular), artrite (inflamação articular), artroplastia (reparação articular), artralgia (dor articular)."}},
  { id: 'dc-medical-0023', deck_id: 'deck-medical', sort_order: 23, front: "Myo-", back: "Prefix relating to muscle. Examples: myalgia (muscle pain), myocardial (relating to heart muscle), myopathy (muscle disease), myositis (muscle inflammation)." , front_translations: {"es":"Mio-","de":"Myo-","fr":"Myo-","tr":"Mio-","nl":"Myo-","ru":"Мио-","zh":"肌-","pt_BR":"Mio-","pt_PT":"Mio-"}, back_translations: {"es":"Prefijo relacionado a los músculos. Ejemplos: mialgia (dor muscular), miocárdico (relativo al músculo cardíaco), miopatia (enfermedad muscular), miosite (inflamación muscular).","de":"Präfix mit Bezug zu Muskeln. Beispiele: Myalgie (Muskelschmerz), myokardial (den Herzmuskel betreffend), Myopathie (Muskelerkrankung), Myositis (Muskelentzündung).","fr":"Préfixe relatif aux muscles. Exemples : myalgie (douleur musculaire), myocardique (relatif au muscle cardiaque), myopathie (maladie musculaire), myosite (inflammation musculaire).","tr":"Kaslarla ilgili ön ek. Örnekler: miyalji (kas ağrısı), miyokardiyal (kalp kasıyla ilgili), miyopati (kas hastalığı), miyozit (kas iltihabı).","nl":"Voorvoegsel dat betrekking heeft op spieren. Voorbeelden: myalgie (spierpijn), myocardiaal (betrekking hebbend op de hartspier), myopathie (spierziekte), myositis (spierontsteking).","ru":"Префикс, относящийся к мышцам. Примеры: миалгия (мышечная боль), миокардиальный (относящийся к сердечной мышце), миопатия (болезнь мышц), миозит (воспаление мышц).","zh":"与肌肉相关的前缀。示例：肌痛（肌肉疼痛）、心肌（与心肌相关）、肌病（肌肉疾病）、肌炎（肌肉炎症）。","pt_BR":"Prefixo relacionado aos músculos. Exemplos: mialgia (dor muscular), miocárdico (relativo ao músculo cardíaco), miopatia (doença muscular), miosite (inflamação muscular).","pt_PT":"Prefixo relacionado com os músculos. Exemplos: mialgia (dor muscular), miocárdico (relativo ao músculo cardíaco), miopatia (doença muscular), miosite (inflamação muscular)."}},
  { id: 'dc-medical-0024', deck_id: 'deck-medical', sort_order: 24, front: "Onco-", back: "Prefix relating to tumors or cancer. Examples: oncology (study and treatment of cancer), oncogene (cancer-causing gene), oncologist (cancer specialist)." , front_translations: {"es":"Onco-","de":"Onko-","fr":"Onco-","tr":"Onko-","nl":"Onco-","ru":"Онко-","zh":"肿瘤-","pt_BR":"Onco-","pt_PT":"Onco-"}, back_translations: {"es":"Prefijo relacionado a tumores o cancer. Ejemplos: oncologia (estudio y tratamiento del cancer), oncogene (gen causador de cancer), oncologista (especialista en cancer).","de":"Präfix mit Bezug zu Tumoren oder Krebs. Beispiele: Onkologie (Erforschung und Behandlung von Krebs), Onkogen (krebsauslösendes Gen), Onkologe (Krebsspezialist).","fr":"Préfixe relatif aux tumeurs ou au cancer. Exemples : oncologie (étude et traitement du cancer), oncogène (gène causant le cancer), oncologue (spécialiste du cancer).","tr":"Tümörler veya kanserle ilgili ön ek. Örnekler: onkoloji (kanserin incelenmesi ve tedavisi), onkojen (kansere neden olan gen), onkolog (kanser uzmanı).","nl":"Voorvoegsel dat betrekking heeft op tumoren of kanker. Voorbeelden: oncologie (studie en behandeling van kanker), oncogen (kankerverwekkend gen), oncoloog (kankerspecialist).","ru":"Префикс, относящийся к опухолям или раку. Примеры: онкология (изучение и лечение рака), онкоген (ген, вызывающий рак), онколог (специалист по онкологии).","zh":"与肿瘤或癌症相关的前缀。示例：肿瘤学（癌症研究与治疗）、癌基因（致癌基因）、肿瘤科医生（癌症专科医生）。","pt_BR":"Prefixo relacionado a tumores ou câncer. Exemplos: oncologia (estudo e tratamento do câncer), oncogene (gene causador de câncer), oncologista (especialista em câncer).","pt_PT":"Prefixo relacionado com tumores ou cancro. Exemplos: oncologia (estudo e tratamento do cancro), oncogene (gene causador de cancro), oncologista (especialista em cancro)."}},
  { id: 'dc-medical-0025', deck_id: 'deck-medical', sort_order: 25, front: "Brady-", back: "Prefix meaning slow. Examples: bradycardia (slow heart rate, <60 bpm), bradypnea (slow breathing), bradykinesia (slowness of movement, as in Parkinson's disease)." , front_translations: {"es":"Bradi-","de":"Brady-","fr":"Brady-","tr":"Brady-","nl":"Brady-","ru":"Брадо-","zh":"缓-","pt_BR":"Bradi-","pt_PT":"Bradi-"}, back_translations: {"es":"Prefijo que significa lento. Ejemplos: bradicardia (frecuencia cardíaca lenta, <60 bpm), bradipneia (respiración lenta), bradicinesia (lentidão de los movimientos, como en la enfermedad de Parkinson).","de":"Präfix mit der Bedeutung langsam. Beispiele: Bradykardie (langsamer Herzschlag, <60 bpm), Bradypnoe (langsame Atmung), Bradykinesie (Langsamkeit der Bewegungen, wie bei Morbus Parkinson).","fr":"Préfixe signifiant lent. Exemples : bradycardie (rythme cardiaque lent, <60 bpm), bradypnée (respiration lente), bradykinésie (lenteur des mouvements, comme dans la maladie de Parkinson).","tr":"Yavaş anlamına gelen ön ek. Örnekler: bradikardi (yavaş kalp atışı, <60 bpm), bradipne (yavaş solunum), bradikinezi (Parkinson hastalığında olduğu gibi hareket yavaşlığı).","nl":"Voorvoegsel met de betekenis langzaam. Voorbeelden: bradycardie (trage hartslag, <60 slagen/min), bradypneu (trage ademhaling), bradykinesie (traagheid van beweging, zoals bij de ziekte van Parkinson).","ru":"Префикс, означающий медленный. Примеры: брадикардия (медленный сердечный ритм, <60 уд/мин), брадипноэ (медленное дыхание), брадикинезия (замедленность движений, как при болезни Паркинсона).","zh":"表示缓慢的前缀。示例：心动过缓（心率缓慢，<60次/分钟）、呼吸缓慢、运动迟缓（如帕金森病中的运动迟缓）。","pt_BR":"Prefixo que significa lento. Exemplos: bradicardia (frequência cardíaca lenta, <60 bpm), bradipneia (respiração lenta), bradicinesia (lentidão dos movimentos, como na doença de Parkinson).","pt_PT":"Prefixo que significa lento. Exemplos: bradicardia (frequência cardíaca lenta, <60 bpm), bradipneia (respiração lenta), bradicinesia (lentidão dos movimentos, como na doença de Parkinson)."}},
  { id: 'dc-medical-0026', deck_id: 'deck-medical', sort_order: 26, front: "Tachy-", back: "Prefix meaning fast. Examples: tachycardia (fast heart rate, >100 bpm), tachypnea (rapid breathing), tachyarrhythmia (fast abnormal heart rhythm)." , front_translations: {"es":"Taqui-","de":"Tachy-","fr":"Tachy-","tr":"Tachy-","nl":"Tachy-","ru":"Тахи-","zh":"速-（Tachy-）","pt_BR":"Taqui-","pt_PT":"Taqui-"}, back_translations: {"es":"Prefijo que significa rápido. Ejemplos: taquicardia (frecuencia cardíaca rápida, >100 bpm), taquipneia (respiración rápida), taquiarritmia (ritmo cardíaco anormal y rápido).","de":"Präfix mit der Bedeutung schnell. Beispiele: Tachykardie (schnelle Herzfrequenz, >100 bpm), Tachypnoe (schnelle Atmung), Tachyarrhythmie (schnelle abnorme Herzrhythmusstörung).","fr":"Préfixe signifiant rapide. Exemples : tachycardie (fréquence cardiaque rapide, >100 bpm), tachypnée (respiration rapide), tachyarythmie (rythme cardiaque anormal et rapide).","tr":"Hızlı anlamına gelen önek. Örnekler: taşikardi (hızlı kalp atış hızı, >100 bpm), taşipne (hızlı solunum), taşiaritmi (hızlı anormal kalp ritmi).","nl":"Voorvoegsel dat snel betekent. Voorbeelden: tachycardie (snelle hartslag, >100 bpm), tachypneu (snelle ademhaling), tachyaritmie (snelle abnormale hartritme).","ru":"Префикс, означающий быстрый. Примеры: тахикардия (учащённое сердцебиение, >100 уд/мин), тахипноэ (учащённое дыхание), тахиаритмия (быстрый патологический сердечный ритм).","zh":"表示\"快速\"的前缀。例：心动过速（心率>100次/分）、呼吸过速（呼吸加快）、快速心律失常（快速异常心律）。","pt_BR":"Prefixo que significa rápido. Exemplos: taquicardia (frequência cardíaca rápida, >100 bpm), taquipneia (respiração rápida), taquiarritmia (ritmo cardíaco anormal e rápido).","pt_PT":"Prefixo que significa rápido. Exemplos: taquicardia (frequência cardíaca rápida, >100 bpm), taquipneia (respiração rápida), taquiarritmia (ritmo cardíaco anormal e rápido)."}},
  { id: 'dc-medical-0027', deck_id: 'deck-medical', sort_order: 27, front: "Hyper-", back: "Prefix meaning above normal or excessive. Examples: hypertension (high blood pressure), hyperglycemia (high blood sugar), hyperthyroidism (overactive thyroid), hypercalcemia (high blood calcium)." , front_translations: {"es":"Hiper-","de":"Hyper-","fr":"Hyper-","tr":"Hiper-","nl":"Hyper-","ru":"Гипер-","zh":"高-/过-（Hyper-）","pt_BR":"Hiper-","pt_PT":"Hiper-"}, back_translations: {"es":"Prefijo que significa encima del normal o excessivo. Ejemplos: hipertensão (presión arterial alta), hiperglicemia (glicemia alta), hipertireoidismo (tireoide hiperativa), hipercalcemia (cálcio sanguíneo alto).","de":"Präfix mit der Bedeutung über normal oder übermäßig. Beispiele: Hypertonie (hoher Blutdruck), Hyperglykämie (hoher Blutzucker), Hyperthyreose (überaktive Schilddrüse), Hyperkalzämie (hoher Kalziumgehalt im Blut).","fr":"Préfixe signifiant au-dessus de la normale ou excessif. Exemples : hypertension (pression artérielle élevée), hyperglycémie (glycémie élevée), hyperthyroïdie (thyroïde hyperactive), hypercalcémie (calcium sanguin élevé).","tr":"Normalin üstünde veya aşırı anlamına gelen önek. Örnekler: hipertansiyon (yüksek kan basıncı), hiperglisemi (yüksek kan şekeri), hipertiroidi (aşırı aktif tiroid), hiperkalsemi (yüksek kan kalsiyumu).","nl":"Voorvoegsel dat boven normaal of overmatig betekent. Voorbeelden: hypertensie (hoge bloeddruk), hyperglykemie (hoge bloedsuiker), hyperthyreoïdie (overactieve schildklier), hypercalciëmie (hoog bloedcalcium).","ru":"Префикс, означающий выше нормы или чрезмерный. Примеры: гипертония (высокое артериальное давление), гипергликемия (высокий сахар в крови), гипертиреоз (гиперактивная щитовидная железа), гиперкальциемия (высокий кальций в крови).","zh":"表示\"超出正常或过度\"的前缀。例：高血压、高血糖、甲状腺功能亢进（甲亢）、高钙血症。","pt_BR":"Prefixo que significa acima do normal ou excessivo. Exemplos: hipertensão (pressão arterial alta), hiperglicemia (glicemia alta), hipertireoidismo (tireoide hiperativa), hipercalcemia (cálcio sanguíneo alto).","pt_PT":"Prefixo que significa acima do normal ou excessivo. Exemplos: hipertensão (pressão arterial alta), hiperglicemia (glicemia alta), hipertiroidismo (tiróide hiperativa), hipercalcemia (cálcio sanguíneo alto)."}},
  { id: 'dc-medical-0028', deck_id: 'deck-medical', sort_order: 28, front: "Hypo-", back: "Prefix meaning below normal or deficient. Examples: hypotension (low blood pressure), hypoglycemia (low blood sugar), hypothyroidism (underactive thyroid), hypothermia (low body temperature)." , front_translations: {"es":"Hipo-","de":"Hypo-","fr":"Hypo-","tr":"Hipo-","nl":"Hypo-","ru":"Гипо-","zh":"低-/不足-（Hypo-）","pt_BR":"Hipo-","pt_PT":"Hipo-"}, back_translations: {"es":"Prefijo que significa debajo del normal o deficiente. Ejemplos: hipotensão (presión arterial baja), hipoglicemia (glicemia baja), hipotireoidismo (tireoide hipoativa), hipotermia (temperatura corporal baja).","de":"Präfix mit der Bedeutung unter normal oder defizitär. Beispiele: Hypotonie (niedriger Blutdruck), Hypoglykämie (niedriger Blutzucker), Hypothyreose (unterfunktionsfähige Schilddrüse), Hypothermie (niedrige Körpertemperatur).","fr":"Préfixe signifiant en dessous de la normale ou déficitaire. Exemples : hypotension (pression artérielle basse), hypoglycémie (glycémie basse), hypothyroïdie (thyroïde sous-active), hypothermie (température corporelle basse).","tr":"Normalin altında veya eksik anlamına gelen önek. Örnekler: hipotansiyon (düşük kan basıncı), hipoglisemi (düşük kan şekeri), hipotiroidi (yetersiz aktif tiroid), hipotermi (düşük vücut sıcaklığı).","nl":"Voorvoegsel dat onder normaal of tekortschietend betekent. Voorbeelden: hypotensie (lage bloeddruk), hypoglykemie (lage bloedsuiker), hypothyreoïdie (onderactieve schildklier), hypothermie (lage lichaamstemperatuur).","ru":"Префикс, означающий ниже нормы или недостаточный. Примеры: гипотония (низкое давление), гипогликемия (низкий сахар в крови), гипотиреоз (недостаточная функция щитовидной железы), гипотермия (низкая температура тела).","zh":"表示\"低于正常或不足\"的前缀。例：低血压、低血糖、甲状腺功能减退（甲减）、低体温。","pt_BR":"Prefixo que significa abaixo do normal ou deficiente. Exemplos: hipotensão (pressão arterial baixa), hipoglicemia (glicemia baixa), hipotireoidismo (tireoide hipoativa), hipotermia (temperatura corporal baixa).","pt_PT":"Prefixo que significa abaixo do normal ou deficiente. Exemplos: hipotensão (pressão arterial baixa), hipoglicemia (glicemia baixa), hipotiroidismo (tiróide hipoativa), hipotermia (temperatura corporal baixa)."}},
  { id: 'dc-medical-0029', deck_id: 'deck-medical', sort_order: 29, front: "Peri-", back: "Prefix meaning around or surrounding. Examples: pericardium (sac surrounding the heart), peritoneum (lining of abdominal cavity), peripheral (away from center), periodontal (around the tooth)." , front_translations: {"es":"Peri-","de":"Peri-","fr":"Péri-","tr":"Peri-","nl":"Peri-","ru":"Пери-","zh":"周围-/环-（Peri-）","pt_BR":"Peri-","pt_PT":"Peri-"}, back_translations: {"es":"Prefijo que significa al redor o en volta. Ejemplos: pericárdio (saco alrededor del corazón), peritonio (revestimento de la cavidad abdominal), periférico (longe del centro), periodontal (alrededor del dente).","de":"Präfix mit der Bedeutung um oder herum. Beispiele: Perikard (Herzbeutel), Peritoneum (Auskleidung der Bauchhöhle), peripher (vom Zentrum entfernt), parodontal (um den Zahn herum).","fr":"Préfixe signifiant autour ou entourant. Exemples : péricarde (sac entourant le cœur), péritoine (revêtement de la cavité abdominale), périphérique (loin du centre), parodontal (autour de la dent).","tr":"Etrafında veya çevresinde anlamına gelen önek. Örnekler: perikard (kalbi çevreleyen kese), periton (karın boşluğunun astarı), periferik (merkezden uzak), periodontal (dişin etrafında).","nl":"Voorvoegsel dat rondom of omringend betekent. Voorbeelden: pericardium (zak rondom het hart), peritoneum (bekleding van de buikholte), perifeer (weg van het centrum), parodontaal (rondom de tand).","ru":"Префикс, означающий вокруг или окружающий. Примеры: перикард (сумка вокруг сердца), брюшина (выстилка брюшной полости), периферический (вдали от центра), пародонт (вокруг зуба).","zh":"表示\"周围或环绕\"的前缀。例：心包（包绕心脏的囊）、腹膜（腹腔内衬）、外周（远离中心）、牙周（牙齿周围）。","pt_BR":"Prefixo que significa ao redor ou em volta. Exemplos: pericárdio (saco ao redor do coração), peritônio (revestimento da cavidade abdominal), periférico (longe do centro), periodontal (ao redor do dente).","pt_PT":"Prefixo que significa à volta ou em redor. Exemplos: pericárdio (saco à volta do coração), peritoneu (revestimento da cavidade abdominal), periférico (longe do centro), periodontal (à volta do dente)."}},
  { id: 'dc-medical-0030', deck_id: 'deck-medical', sort_order: 30, front: "Endo-", back: "Prefix meaning within or inner. Examples: endoscopy (examining inside a cavity), endocardium (inner lining of the heart), endocrine (secreting into the bloodstream)." , front_translations: {"es":"Endo-","de":"Endo-","fr":"Endo-","tr":"Endo-","nl":"Endo-","ru":"Эндо-","zh":"内-（Endo-）","pt_BR":"Endo-","pt_PT":"Endo-"}, back_translations: {"es":"Prefijo que significa dentro o interno. Ejemplos: endoscopia (examen del interior de una cavidad), endocárdio (revestimento interno del corazón), endócrino (secreción en la corrente sanguínea).","de":"Präfix mit der Bedeutung innerhalb oder innen. Beispiele: Endoskopie (Untersuchung einer Körperhöhle von innen), Endokard (innere Herzauskleidung), endokrin (Sekretierung in den Blutkreislauf).","fr":"Préfixe signifiant à l'intérieur ou interne. Exemples : endoscopie (examen de l'intérieur d'une cavité), endocarde (revêtement interne du cœur), endocrine (sécrétion dans la circulation sanguine).","tr":"İçinde veya iç anlamına gelen önek. Örnekler: endoskopi (bir kaviteyi içeriden muayene etmek), endokard (kalbin iç astarı), endokrin (kan dolaşımına salgılama).","nl":"Voorvoegsel dat binnen of inner betekent. Voorbeelden: endoscopie (onderzoek van de binnenkant van een holte), endocard (binnenste bekleding van het hart), endocrien (afscheiding in de bloedbaan).","ru":"Префикс, означающий внутри или внутренний. Примеры: эндоскопия (осмотр полости изнутри), эндокард (внутренняя выстилка сердца), эндокринный (секреция в кровоток).","zh":"表示\"内部或内侧\"的前缀。例：内窥镜检查（查看腔体内部）、心内膜（心脏内层）、内分泌（向血液分泌）。","pt_BR":"Prefixo que significa dentro ou interno. Exemplos: endoscopia (exame do interior de uma cavidade), endocárdio (revestimento interno do coração), endócrino (secreção na corrente sanguínea).","pt_PT":"Prefixo que significa dentro ou interno. Exemplos: endoscopia (exame do interior de uma cavidade), endocárdio (revestimento interno do coração), endócrino (secreção na corrente sanguínea)."}},
  { id: 'dc-medical-0031', deck_id: 'deck-medical', sort_order: 31, front: "BP — Blood Pressure", back: "The force exerted by circulating blood on artery walls. Expressed as systolic/diastolic (e.g., 120/80 mmHg). Normal: <120/80. Hypertension: ≥130/80. Measured with a sphygmomanometer." , front_translations: {"es":"PA — Presión Arterial","de":"RR / BD — Blutdruck","fr":"TA — Tension Artérielle","tr":"KB — Kan Basıncı","nl":"BD — Bloeddruk","ru":"АД — Артериальное давление","zh":"BP — 血压","pt_BR":"PA — Pressão Arterial","pt_PT":"PA — Pressão Arterial"}, back_translations: {"es":"La fuerza exercida por el sangre circulante en las paredes de las arterias. Expressa como sistólica/diastólica (ex.: 120/80 mmHg). Normal: <120/80. Hipertensão: ≥130/80. Medida con esfigmomanometro.","de":"Die Kraft, die das zirkulierende Blut auf die Arterienwände ausübt. Angegeben als systolisch/diastolisch (z. B. 120/80 mmHg). Normal: <120/80. Hypertonie: ≥130/80. Gemessen mit einem Blutdruckmessgerät (Sphygmomanometer).","fr":"La force exercée par le sang circulant sur les parois des artères. Exprimée en systolique/diastolique (ex. 120/80 mmHg). Normale : <120/80. Hypertension : ≥130/80. Mesurée avec un sphygmomanomètre.","tr":"Dolaşan kanın atardamar duvarlarına uyguladığı kuvvet. Sistolik/diyastolik olarak ifade edilir (örn. 120/80 mmHg). Normal: <120/80. Hipertansiyon: ≥130/80. Sfigmomanometre ile ölçülür.","nl":"De kracht die het circulerende bloed uitoefent op de slagaderwanden. Uitgedrukt als systolisch/diastolisch (bijv. 120/80 mmHg). Normaal: <120/80. Hypertensie: ≥130/80. Gemeten met een sfygmomanometer.","ru":"Сила, которую циркулирующая кровь оказывает на стенки артерий. Выражается как систолическое/диастолическое (например, 120/80 мм рт. ст.). Норма: <120/80. Гипертония: ≥130/80. Измеряется сфигмоманометром.","zh":"循环血液对动脉壁施加的压力，以收缩压/舒张压表示（如120/80 mmHg）。正常：<120/80；高血压：≥130/80。用血压计（血压袖带）测量。","pt_BR":"A força exercida pelo sangue circulante nas paredes das artérias. Expressa como sistólica/diastólica (ex.: 120/80 mmHg). Normal: <120/80. Hipertensão: ≥130/80. Medida com esfigmomanômetro.","pt_PT":"A força exercida pelo sangue circulante nas paredes das artérias. Expressa como sistólica/diastólica (ex.: 120/80 mmHg). Normal: <120/80. Hipertensão: ≥130/80. Medida com esfigmomanómetro."}},
  { id: 'dc-medical-0032', deck_id: 'deck-medical', sort_order: 32, front: "HR — Heart Rate", back: "The number of heartbeats per minute. Normal adult resting range: 60–100 bpm. Bradycardia: <60 bpm. Tachycardia: >100 bpm. Measured by palpation, pulse oximeter, or ECG." , front_translations: {"es":"FC — Frecuencia Cardíaca","de":"HF — Herzfrequenz","fr":"FC — Fréquence Cardiaque","tr":"KH — Kalp Hızı","nl":"HF — Hartfrequentie","ru":"ЧСС — Частота сердечных сокращений","zh":"HR — 心率","pt_BR":"FC — Frequência Cardíaca","pt_PT":"FC — Frequência Cardíaca"}, back_translations: {"es":"El número de batimentos cardíacos por minuto. Frecuencia de reposo normal en adultos: 60–100 bpm. Bradicardia: <60 bpm. Taquicardia: >100 bpm. Medida por palpación, oxímetro de muñeca o ECG.","de":"Die Anzahl der Herzschläge pro Minute. Normale Ruheherzfrequenz Erwachsener: 60–100 bpm. Bradykardie: <60 bpm. Tachykardie: >100 bpm. Gemessen durch Palpation, Pulsoximeter oder EKG.","fr":"Le nombre de battements cardiaques par minute. Plage normale au repos chez l'adulte : 60–100 bpm. Bradycardie : <60 bpm. Tachycardie : >100 bpm. Mesurée par palpation, oxymètre de pouls ou ECG.","tr":"Dakikadaki kalp atışı sayısı. Normal yetişkin istirahat aralığı: 60–100 bpm. Bradikardi: <60 bpm. Taşikardi: >100 bpm. Palpasyon, nabız oksimetresi veya EKG ile ölçülür.","nl":"Het aantal hartslagen per minuut. Normale rusthartslag volwassene: 60–100 bpm. Bradycardie: <60 bpm. Tachycardie: >100 bpm. Gemeten via palpatie, pulsoximeter of ECG.","ru":"Количество ударов сердца в минуту. Нормальный диапазон в покое у взрослых: 60–100 уд/мин. Брадикардия: <60 уд/мин. Тахикардия: >100 уд/мин. Измеряется пальпацией, пульсоксиметром или ЭКГ.","zh":"每分钟心跳次数。成人正常静息心率：60–100次/分。心动过缓：<60次/分；心动过速：>100次/分。通过触诊、脉搏血氧仪或心电图测量。","pt_BR":"O número de batimentos cardíacos por minuto. Frequência de repouso normal em adultos: 60–100 bpm. Bradicardia: <60 bpm. Taquicardia: >100 bpm. Medida por palpação, oxímetro de pulso ou ECG.","pt_PT":"O número de batimentos cardíacos por minuto. Frequência de repouso normal em adultos: 60–100 bpm. Bradicardia: <60 bpm. Taquicardia: >100 bpm. Medida por palpação, oxímetro de pulso ou ECG."}},
  { id: 'dc-medical-0033', deck_id: 'deck-medical', sort_order: 33, front: "SOB — Shortness of Breath", back: "Dyspnea; the subjective feeling of difficulty breathing. Can result from respiratory (asthma, pneumonia, COPD), cardiac (heart failure, PE), anemia, or anxiety causes. A common chief complaint." , front_translations: {"es":"Dispneia — Falta de Aire","de":"Dyspnoe — Atemnot","fr":"Dyspnée — Essoufflement","tr":"Dispne — Nefes Darlığı","nl":"Dyspneu — Kortademigheid","ru":"Диспноэ — Одышка","zh":"呼吸困难（气促）","pt_BR":"Dispneia — Falta de Ar","pt_PT":"Dispneia — Falta de Ar"}, back_translations: {"es":"Dispneia; a sensación subjetiva de dificuldad para respirar. Puede resultar de causas respiratórias (asma, pneumonia, DPOC), cardíacas (insuficiencia cardíaca, EP), anemia o ansiedad. Una queixa principal comum.","de":"Dyspnoe; das subjektive Gefühl von Atembeschwerden. Kann respiratorische (Asthma, Pneumonie, COPD), kardiale (Herzinsuffizienz, Lungenembolie), anämische oder angstbedingte Ursachen haben. Ein häufiges Leitsymptom.","fr":"Dyspnée ; la sensation subjective de difficulté à respirer. Peut résulter de causes respiratoires (asthme, pneumonie, BPCO), cardiaques (insuffisance cardiaque, EP), d'anémie ou d'anxiété. Un motif de consultation fréquent.","tr":"Dispne; nefes almakta güçlük çekme subjektif hissi. Solunum (astım, pnömoni, KOAH), kardiyak (kalp yetmezliği, PE), anemi veya anksiyete nedenlerinden kaynaklanabilir. Sık görülen bir şikayet.","nl":"Dyspneu; het subjectieve gevoel van moeite met ademhalen. Kan resulteren uit respiratoire (astma, pneumonie, COPD), cardiale (hartfalen, PE), anemische of angstgerelateerde oorzaken. Een veelvoorkomende klacht.","ru":"Диспноэ; субъективное ощущение затруднённого дыхания. Может быть вызвана респираторными (астма, пневмония, ХОБЛ), сердечными (сердечная недостаточность, ТЭЛА), анемическими или тревожными причинами. Частая жалоба пациентов.","zh":"呼吸困难；主观感到呼吸费力。可由呼吸系统（哮喘、肺炎、慢阻肺）、心脏（心力衰竭、肺栓塞）、贫血或焦虑等原因引起，是常见的主诉症状。","pt_BR":"Dispneia; a sensação subjetiva de dificuldade para respirar. Pode resultar de causas respiratórias (asma, pneumonia, DPOC), cardíacas (insuficiência cardíaca, EP), anemia ou ansiedade. Uma queixa principal comum.","pt_PT":"Dispneia; a sensação subjetiva de dificuldade em respirar. Pode resultar de causas respiratórias (asma, pneumonia, DPOC), cardíacas (insuficiência cardíaca, EP), anemia ou ansiedade. Uma queixa principal comum."}},
  { id: 'dc-medical-0034', deck_id: 'deck-medical', sort_order: 34, front: "Hx — History", back: "A patient's medical history, including past medical history (PMHx), family history (FHx), social history (SHx), and history of present illness (HPI). The foundation of any clinical assessment." , front_translations: {"es":"Hx — Histórico / Anamnese","de":"Hx — Anamnese","fr":"ATCD — Antécédents / Anamnèse","tr":"Öykü — Tıbbi Anamnez","nl":"Hx — Anamnese","ru":"Анамнез","zh":"Hx — 病史","pt_BR":"Hx — Histórico / Anamnese","pt_PT":"Hx — História / Anamnese"}, back_translations: {"es":"El histórico médico de un paciente, incluyendo antecedentes pessoais, histórico familiar, histórico social y historia de la enfermedad atual. La base de cualquier avaliación clínica.","de":"Die Krankengeschichte eines Patienten, einschließlich Vorgeschichte (VG), Familienanamnese (FA), Sozialanamnese (SA) und aktueller Krankengeschichte. Die Grundlage jeder klinischen Beurteilung.","fr":"L'historique médical d'un patient, incluant les antécédents médicaux personnels, familiaux, sociaux et l'histoire de la maladie actuelle. La base de toute évaluation clinique.","tr":"Bir hastanın tıbbi geçmişi; geçmiş tıbbi öykü, aile öyküsü, sosyal öykü ve mevcut hastalık öyküsünü içerir. Her klinik değerlendirmenin temeli.","nl":"De medische geschiedenis van een patiënt, inclusief voorgeschiedenis, familiegeschiedenis, sociale geschiedenis en de huidige klacht. De basis van elke klinische beoordeling.","ru":"История болезни пациента, включая прошлый медицинский анамнез, семейный анамнез, социальный анамнез и историю настоящего заболевания. Основа любой клинической оценки.","zh":"患者的医疗史，包括既往病史（PMHx）、家族史（FHx）、社会史（SHx）及现病史（HPI）。是临床评估的基础。","pt_BR":"O histórico médico de um paciente, incluindo antecedentes pessoais, histórico familiar, histórico social e história da doença atual. A base de qualquer avaliação clínica.","pt_PT":"O historial médico de um doente, incluindo antecedentes pessoais, história familiar, história social e história da doença atual. A base de qualquer avaliação clínica."}},
  { id: 'dc-medical-0035', deck_id: 'deck-medical', sort_order: 35, front: "Dx — Diagnosis", back: "The identification of a disease or condition based on symptoms, clinical findings, and investigations. Differential diagnosis (DDx) is a list of possible diagnoses ranked by likelihood." , front_translations: {"es":"Dx — Diagnóstico","de":"Dx — Diagnose","fr":"Dx — Diagnostic","tr":"Dx — Tanı","nl":"Dx — Diagnose","ru":"Ds — Диагноз","zh":"Dx — 诊断","pt_BR":"Dx — Diagnóstico","pt_PT":"Dx — Diagnóstico"}, back_translations: {"es":"La identificación de una enfermedad o condición con base en síntomas, achados clínicos y exámenes. Diagnóstico diferencial (DDx) es una lista de posibles diagnósticos ordenados por probabilidad.","de":"Die Identifikation einer Krankheit oder eines Zustands anhand von Symptomen, klinischen Befunden und Untersuchungen. Differentialdiagnose (DDx) ist eine Liste möglicher Diagnosen, geordnet nach Wahrscheinlichkeit.","fr":"L'identification d'une maladie ou d'un état basée sur les symptômes, les résultats cliniques et les examens. Le diagnostic différentiel (DDx) est une liste de diagnostics possibles classés par probabilité.","tr":"Belirtiler, klinik bulgular ve tetkiklere dayanılarak bir hastalık veya durumun tanımlanması. Ayırıcı tanı (DDx), olasılığa göre sıralanmış olası tanıların listesidir.","nl":"De identificatie van een ziekte of aandoening op basis van symptomen, klinische bevindingen en onderzoeken. Differentiaaldiagnose (DDx) is een lijst van mogelijke diagnoses gerangschikt naar waarschijnlijkheid.","ru":"Определение заболевания или состояния на основании симптомов, клинических данных и исследований. Дифференциальный диагноз (ДД) — список возможных диагнозов, упорядоченных по вероятности.","zh":"根据症状、临床发现和检查结果确定疾病或状况。鉴别诊断（DDx）是按可能性排列的可能诊断列表。","pt_BR":"A identificação de uma doença ou condição com base em sintomas, achados clínicos e exames. Diagnóstico diferencial (DDx) é uma lista de possíveis diagnósticos ordenados por probabilidade.","pt_PT":"A identificação de uma doença ou condição com base em sintomas, achados clínicos e exames. Diagnóstico diferencial (DDx) é uma lista de possíveis diagnósticos ordenados por probabilidade."}},
  { id: 'dc-medical-0036', deck_id: 'deck-medical', sort_order: 36, front: "Rx — Prescription / Treatment", back: "The symbol for a prescription or the treatment plan. From the Latin 'recipe' (take). Used on prescriptions; also broadly refers to the therapeutic management of a condition." , front_translations: {"es":"Rx — Ingreso / Tratamiento","de":"Rx — Rezept / Behandlung","fr":"Rx — Ordonnance / Traitement","tr":"Rx — Reçete / Tedavi","nl":"Rx — Recept / Behandeling","ru":"Rp — Рецепт / Лечение","zh":"Rx — 处方/治疗","pt_BR":"Rx — Receita / Tratamento","pt_PT":"Rx — Receita / Tratamento"}, back_translations: {"es":"El símbolo para una ingreso o plano de tratamiento. Do latim 'recipe' (tome). Usado en ingresos médicas; también se refere amplamente al manejo terapeutico de una condición.","de":"Das Symbol für ein Rezept oder den Behandlungsplan. Vom lateinischen 'recipe' (nimm). Wird auf Rezepten verwendet; bezieht sich auch allgemein auf das therapeutische Management eines Zustands.","fr":"Le symbole d'une ordonnance ou du plan de traitement. Du latin 'recipe' (prendre). Utilisé sur les ordonnances ; désigne aussi plus largement la prise en charge thérapeutique d'une maladie.","tr":"Reçete veya tedavi planı için kullanılan sembol. Latince 'recipe' (al) kelimesinden gelir. Reçetelerde kullanılır; ayrıca bir durumun terapötik yönetimini genel olarak ifade eder.","nl":"Het symbool voor een recept of het behandelplan. Van het Latijnse 'recipe' (neem). Gebruikt op recepten; verwijst ook meer algemeen naar de therapeutische behandeling van een aandoening.","ru":"Символ рецепта или плана лечения. От латинского 'recipe' (возьми). Используется на рецептах; также широко относится к терапевтическому ведению состояния.","zh":"处方或治疗方案的符号，源自拉丁语\"recipe\"（取用）。用于处方签；也泛指对某种疾病的治疗管理。","pt_BR":"O símbolo para uma receita ou plano de tratamento. Do latim 'recipe' (tome). Usado em receitas médicas; também se refere amplamente ao manejo terapêutico de uma condição.","pt_PT":"O símbolo para uma receita ou plano de tratamento. Do latim 'recipe' (tome). Usado em receitas médicas; também se refere amplamente ao tratamento terapêutico de uma condição."}},
  { id: 'dc-medical-0037', deck_id: 'deck-medical', sort_order: 37, front: "PRN — Pro Re Nata", back: "Latin for 'as needed.' A medication instruction indicating it should be taken only when required (e.g., PRN pain medication) rather than on a fixed schedule." , front_translations: {"es":"PRN — Pro Re Nata","de":"PRN — Pro Re Nata","fr":"PRN — Pro Re Nata","tr":"PRN — Pro Re Nata","nl":"PRN — Pro Re Nata","ru":"PRN — Pro Re Nata","zh":"PRN — 按需给药（Pro Re Nata）","pt_BR":"PRN — Pro Re Nata","pt_PT":"PRN — Pro Re Nata"}, back_translations: {"es":"Latim para 'conforme necesario.' Una instrucción medicamentosa indicando que el medicamento deve ser tomado solo cuando necesario (ex.: medicamento para dor PRN), y no en horário fixo.","de":"Lateinisch für 'bei Bedarf.' Eine Medikamentenanweisung, die besagt, dass das Medikament nur bei Bedarf eingenommen werden soll (z. B. PRN-Schmerzmedikamente) und nicht nach einem festen Zeitplan.","fr":"Latin pour 'selon le besoin.' Une instruction médicamenteuse indiquant que le médicament ne doit être pris qu'en cas de nécessité (ex. médicament antidouleur en PRN) plutôt que selon un horaire fixe.","tr":"Latince 'gerektiğinde' demektir. Bir ilacın yalnızca gerektiğinde alınması gerektiğini belirten ilaç talimatı (örn. PRN ağrı kesici), sabit bir programa göre değil.","nl":"Latijn voor 'naar behoefte.' Een medicatie-instructie die aangeeft dat het medicijn alleen ingenomen moet worden wanneer nodig (bijv. PRN pijnmedicatie) en niet op een vast schema.","ru":"Латинское выражение «по необходимости». Назначение лекарства, предписывающее принимать его только по мере необходимости (например, обезболивающее PRN), а не по фиксированному расписанию.","zh":"拉丁语\"按需\"之意。药物医嘱，指仅在需要时服药（如PRN镇痛药），而非按固定时间表服用。","pt_BR":"Latim para 'conforme necessário.' Uma instrução medicamentosa indicando que o medicamento deve ser tomado apenas quando necessário (ex.: medicamento para dor PRN), e não em horário fixo.","pt_PT":"Latim para 'conforme necessário.' Uma instrução medicamentosa indicando que o medicamento deve ser tomado apenas quando necessário (ex.: medicamento para dor PRN), e não em horário fixo."}},
  { id: 'dc-medical-0038', deck_id: 'deck-medical', sort_order: 38, front: "NPO — Nil Per Os", back: "Nothing by mouth. A medical instruction to withhold all food and fluids, typically before surgery or certain procedures to prevent aspiration under anesthesia." , front_translations: {"es":"NPO — Nil Per Los","de":"NPO — Nil Per Os","fr":"NPO — Nil Per Os","tr":"NPO — Nil Per Os","nl":"NPO — Nil Per Os","ru":"NPO — Nil Per Os","zh":"NPO — 禁食禁饮（Nil Per Os）","pt_BR":"NPO — Nil Per Os","pt_PT":"NPO — Nil Per Os"}, back_translations: {"es":"Nada por via oral. Una instrucción médica para suspender todos los alimentos y líquidos, generalmente antes de cirugía o certos procedimentos, para prevenir aspiración sob anestesia.","de":"Nichts durch den Mund. Eine medizinische Anweisung, alle Nahrung und Flüssigkeiten zurückzuhalten, typischerweise vor einer Operation oder bestimmten Eingriffen, um eine Aspiration unter Narkose zu verhindern.","fr":"Rien par la bouche. Une instruction médicale de ne donner aucun aliment ni liquide, généralement avant une intervention chirurgicale ou certaines procédures, pour prévenir l'inhalation sous anesthésie.","tr":"Ağızdan hiçbir şey yok. Anestezi altında aspirasyonu önlemek için genellikle ameliyat veya belirli prosedürlerden önce tüm yiyecek ve sıvıların kesilmesini emreden tıbbi talimat.","nl":"Niets door de mond. Een medische instructie om alle voedsel en vloeistoffen te onthouden, meestal vóór een operatie of bepaalde ingrepen om aspiratie onder anesthesie te voorkomen.","ru":"Ничего через рот. Медицинское предписание не давать никакой пищи и жидкости, как правило перед операцией или определёнными процедурами, чтобы предотвратить аспирацию под анестезией.","zh":"拉丁语\"口不进食\"之意。医嘱禁止任何食物和液体摄入，通常用于手术或特定操作前，以防止麻醉下误吸。","pt_BR":"Nada por via oral. Uma instrução médica para suspender todos os alimentos e líquidos, geralmente antes de cirurgia ou certos procedimentos, para prevenir aspiração sob anestesia.","pt_PT":"Nada por via oral. Uma instrução médica para suspender todos os alimentos e líquidos, geralmente antes de cirurgia ou certos procedimentos, para prevenir aspiração sob anestesia."}},
  { id: 'dc-medical-0039', deck_id: 'deck-medical', sort_order: 39, front: "STAT", back: "From Latin 'statim' — immediately. Indicates a medication, test, or procedure must be performed right away. Signals urgency in clinical orders." , front_translations: {"es":"STAT","de":"STAT","fr":"STAT","tr":"STAT","nl":"STAT","ru":"STAT (срочно)","zh":"STAT — 即刻执行","pt_BR":"STAT","pt_PT":"STAT"}, back_translations: {"es":"Do latim 'statim' — imediatamente. Indica que un medicamento, examen o procedimento deve ser realizado imediatamente. Sinaliza urgencia en prescriciones clínicas.","de":"Vom lateinischen 'statim' — sofort. Gibt an, dass ein Medikament, ein Test oder ein Verfahren sofort durchgeführt werden muss. Signalisiert Dringlichkeit bei klinischen Aufträgen.","fr":"Du latin 'statim' — immédiatement. Indique qu'un médicament, un test ou une procédure doit être réalisé immédiatement. Signale l'urgence dans les prescriptions cliniques.","tr":"Latince 'statim'den — hemen. Bir ilaç, test veya prosedürün hemen gerçekleştirilmesi gerektiğini belirtir. Klinik emirlerde aciliyeti gösterir.","nl":"Van het Latijnse 'statim' — onmiddellijk. Geeft aan dat een medicijn, test of procedure direct moet worden uitgevoerd. Signaleert urgentie bij klinische opdrachten.","ru":"От латинского 'statim' — немедленно. Указывает на то, что лекарство, анализ или процедура должны быть выполнены прямо сейчас. Сигнализирует о срочности клинических назначений.","zh":"源自拉丁语\"statim\"，意为\"立即\"。表示某项药物、检查或操作必须立刻执行，在临床医嘱中标示紧急程度。","pt_BR":"Do latim 'statim' — imediatamente. Indica que um medicamento, exame ou procedimento deve ser realizado imediatamente. Sinaliza urgência em prescrições clínicas.","pt_PT":"Do latim 'statim' — imediatamente. Indica que um medicamento, exame ou procedimento deve ser realizado de imediato. Sinaliza urgência em prescrições clínicas."}},
  { id: 'dc-medical-0040', deck_id: 'deck-medical', sort_order: 40, front: "ECG / EKG — Electrocardiogram", back: "A recording of the heart's electrical activity over time. Detects arrhythmias, myocardial infarction, conduction defects, and chamber enlargement. Consists of P wave (atrial depolarization), QRS complex (ventricular depolarization), and T wave (ventricular repolarization)." , front_translations: {"es":"ECG — Eletrocardiograma","de":"EKG — Elektrokardiogramm","fr":"ECG — Électrocardiogramme","tr":"EKG — Elektrokardiyogram","nl":"ECG — Elektrocardiogram","ru":"ЭКГ — Электрокардиограмма","zh":"ECG/EKG — 心电图","pt_BR":"ECG — Eletrocardiograma","pt_PT":"ECG — Eletrocardiograma"}, back_translations: {"es":"Un registro de la atividad eléctrica del corazón a lo ancho del tiempo. Detecta arritmias, infarto del miocárdio, defeitos de condución y aumento de las camaras. Consiste en la onda P (despolarización atrial), complexo QRS (despolarización ventricular) y onda T (repolarización ventricular).","de":"Eine Aufzeichnung der elektrischen Herzaktivität über die Zeit. Erkennt Arrhythmien, Myokardinfarkt, Leitungsdefekte und Kammervergrößerung. Besteht aus P-Welle (atriale Depolarisation), QRS-Komplex (ventrikuläre Depolarisation) und T-Welle (ventrikuläre Repolarisation).","fr":"Un enregistrement de l'activité électrique du cœur au fil du temps. Détecte les arythmies, l'infarctus du myocarde, les troubles de conduction et l'hypertrophie des cavités. Comprend l'onde P (dépolarisation atriale), le complexe QRS (dépolarisation ventriculaire) et l'onde T (repolarisation ventriculaire).","tr":"Kalbin elektriksel aktivitesinin zamanla kaydı. Aritmileri, miyokard enfarktüsünü, iletim defektlerini ve odacık büyümesini tespit eder. P dalgası (atriyal depolarizasyon), QRS kompleksi (ventriküler depolarizasyon) ve T dalgasından (ventriküler repolarizasyon) oluşur.","nl":"Een registratie van de elektrische activiteit van het hart over tijd. Detecteert aritmieën, myocardinfarct, geleidingsstoornissen en kamervergroting. Bestaat uit P-golf (atriale depolarisatie), QRS-complex (ventriculaire depolarisatie) en T-golf (ventriculaire repolarisatie).","ru":"Запись электрической активности сердца во времени. Выявляет аритмии, инфаркт миокарда, нарушения проводимости и гипертрофию камер. Состоит из зубца P (деполяризация предсердий), комплекса QRS (деполяризация желудочков) и зубца T (реполяризация желудочков).","zh":"随时间记录心脏电活动的检查。可检测心律失常、心肌梗死、传导缺陷和心腔扩大。由P波（心房除极）、QRS波群（心室除极）和T波（心室复极）组成。","pt_BR":"Um registro da atividade elétrica do coração ao longo do tempo. Detecta arritmias, infarto do miocárdio, defeitos de condução e aumento das câmaras. Consiste na onda P (despolarização atrial), complexo QRS (despolarização ventricular) e onda T (repolarização ventricular).","pt_PT":"Um registo da atividade elétrica do coração ao longo do tempo. Deteta arritmias, enfarte do miocárdio, defeitos de condução e aumento das câmaras. Consiste na onda P (despolarização atrial), complexo QRS (despolarização ventricular) e onda T (repolarização ventricular)."}},
  { id: 'dc-medical-0041', deck_id: 'deck-medical', sort_order: 41, front: "Myocardial Infarction (MI)", back: "Commonly called a heart attack. Occurs when blood flow to part of the heart muscle is blocked long enough to cause tissue death, typically due to a coronary artery blockage." , front_translations: {"es":"Infarto del Miocárdio (IAM)","de":"Myokardinfarkt (MI)","fr":"Infarctus du Myocarde (IDM)","tr":"Miyokard Enfarktüsü (MI)","nl":"Myocardinfarct (MI)","ru":"Инфаркт миокарда (ИМ)","zh":"心肌梗死（MI）","pt_BR":"Infarto do Miocárdio (IAM)","pt_PT":"Enfarte do Miocárdio (EAM)"}, back_translations: {"es":"Comúnmente llamado de ataque cardíaco. Ocurre cuando el flujo sanguíneo para parte del músculo cardíaco es bloqueado por tiempo suficiente para causar muerte tecidual, generalmente debido a una obstrución de arteria coronária.","de":"Umgangssprachlich als Herzinfarkt bezeichnet. Tritt auf, wenn die Blutversorgung eines Teils des Herzmuskels lange genug unterbrochen wird, um Gewebetod zu verursachen – typischerweise durch einen Koronararterienblock.","fr":"Communément appelé crise cardiaque. Se produit lorsque le flux sanguin vers une partie du muscle cardiaque est bloqué assez longtemps pour provoquer la mort tissulaire, généralement due à une obstruction d'une artère coronaire.","tr":"Yaygın olarak kalp krizi olarak bilinir. Kalp kasının bir bölümüne kan akışı, doku ölümüne yol açacak kadar uzun süre engellendiğinde ortaya çıkar; genellikle bir koroner arter tıkanıklığından kaynaklanır.","nl":"Gewoonlijk hartaanval genoemd. Treedt op wanneer de bloedtoevoer naar een deel van de hartspier lang genoeg geblokkeerd is om weefseldood te veroorzaken, doorgaans door een blokkade van een kransslagader.","ru":"Широко известен как сердечный приступ. Возникает при достаточно длительном нарушении кровоснабжения части сердечной мышцы, приводящем к гибели ткани — как правило, вследствие закупорки коронарной артерии.","zh":"俗称\"心脏病发作\"。当供应心肌某部分的血流受阻时间足够长，导致组织坏死时发生，通常由冠状动脉阻塞引起。","pt_BR":"Comumente chamado de ataque cardíaco. Ocorre quando o fluxo sanguíneo para parte do músculo cardíaco é bloqueado por tempo suficiente para causar morte tecidual, geralmente devido a uma obstrução de artéria coronária.","pt_PT":"Comumente chamado de ataque cardíaco. Ocorre quando o fluxo sanguíneo para parte do músculo cardíaco é bloqueado por tempo suficiente para causar morte tecidual, geralmente devido a uma obstrução de artéria coronária."}},
  { id: 'dc-medical-0042', deck_id: 'deck-medical', sort_order: 42, front: "Angina Pectoris", back: "Chest pain or discomfort caused by reduced blood flow to the heart muscle. Stable angina: predictable, occurs with exertion. Unstable angina: unpredictable, occurs at rest; a medical emergency." , front_translations: {"es":"Angina Pectoris","de":"Angina Pectoris","fr":"Angor (Angine de Poitrine)","tr":"Angina Pektoris","nl":"Angina Pectoris","ru":"Стенокардия (Angina Pectoris)","zh":"心绞痛（Angina Pectoris）","pt_BR":"Angina Pectoris","pt_PT":"Angina de Peito"}, back_translations: {"es":"Dor o malestar torácico causado por la reducción del flujo sanguíneo para el músculo cardíaco. Angina estable: previsible, ocurre con esforço. Angina instable: imprevisible, ocurre en reposo; emergencia médica.","de":"Brustschmerz oder Engegefühl durch verminderten Blutfluss zum Herzmuskel. Stabile Angina: vorhersehbar, tritt bei Belastung auf. Instabile Angina: unvorhersehbar, tritt in Ruhe auf; medizinischer Notfall.","fr":"Douleur ou gêne thoracique causée par une réduction du flux sanguin vers le muscle cardiaque. Angor stable : prévisible, survient à l'effort. Angor instable : imprévisible, survient au repos ; urgence médicale.","tr":"Kalp kasına azalan kan akışından kaynaklanan göğüs ağrısı veya rahatsızlığı. Stabil angina: öngörülebilir, egzersizle ortaya çıkar. Kararsız angina: öngörülemeyen, istirahatte ortaya çıkar; tıbbi acil durum.","nl":"Pijn of ongemak op de borst door verminderde bloedtoevoer naar de hartspier. Stabiele angina: voorspelbaar, treedt op bij inspanning. Instabiele angina: onvoorspelbaar, treedt op in rust; medisch noodgeval.","ru":"Боль или дискомфорт в груди, вызванные снижением кровотока к сердечной мышце. Стабильная стенокардия: предсказуемая, возникает при нагрузке. Нестабильная стенокардия: непредсказуемая, возникает в покое; неотложное состояние.","zh":"由心肌血流减少引起的胸痛或不适。稳定型心绞痛：可预测，因运动诱发；不稳定型心绞痛：不可预测，在休息时发作，属于医疗紧急情况。","pt_BR":"Dor ou desconforto torácico causado pela redução do fluxo sanguíneo para o músculo cardíaco. Angina estável: previsível, ocorre com esforço. Angina instável: imprevisível, ocorre em repouso; emergência médica.","pt_PT":"Dor ou desconforto torácico causado pela redução do fluxo sanguíneo para o músculo cardíaco. Angina estável: previsível, ocorre com esforço. Angina instável: imprevisível, ocorre em repouso; emergência médica."}},
  { id: 'dc-medical-0043', deck_id: 'deck-medical', sort_order: 43, front: "Heart Failure (CHF)", back: "Congestive heart failure; the heart cannot pump enough blood to meet the body's needs. Left-sided: causes pulmonary edema (fluid in lungs). Right-sided: causes peripheral edema, ascites." , front_translations: {"es":"Insuficiencia Cardíaca (IC)","de":"Herzinsuffizienz (HI)","fr":"Insuffisance Cardiaque (IC)","tr":"Kalp Yetmezliği (KY)","nl":"Hartfalen","ru":"Сердечная недостаточность (СН)","zh":"心力衰竭（心衰，CHF）","pt_BR":"Insuficiência Cardíaca (IC)","pt_PT":"Insuficiência Cardíaca (IC)"}, back_translations: {"es":"Insuficiencia cardíaca congestiva; el corazón no consegue bombear sangre suficiente para atender a las necesidades del cuerpo. Esquerda: causa edema pulmonar (líquido en los pulmones). Direita: causa edema periférico y ascite.","de":"Kongestive Herzinsuffizienz; das Herz kann nicht genug Blut pumpen, um den Körperbedarf zu decken. Linksherzinsuffizienz: verursacht Lungenödem (Flüssigkeit in der Lunge). Rechtsherzinsuffizienz: verursacht periphere Ödeme, Aszites.","fr":"Insuffisance cardiaque congestive ; le cœur ne peut pas pomper suffisamment de sang pour répondre aux besoins de l'organisme. Gauche : provoque un œdème pulmonaire (liquide dans les poumons). Droite : provoque des œdèmes périphériques, une ascite.","tr":"Konjestif kalp yetmezliği; kalp, vücudun ihtiyaçlarını karşılamak için yeterli kan pompalayamaz. Sol taraflı: pulmoner ödeme (akciğerlerde sıvı) yol açar. Sağ taraflı: periferik ödem ve asit oluşturur.","nl":"Congestief hartfalen; het hart kan niet genoeg bloed pompen om aan de behoeften van het lichaam te voldoen. Linkszijdig: veroorzaakt longoedeem (vocht in de longen). Rechtszijdig: veroorzaakt perifeer oedeem en ascites.","ru":"Застойная сердечная недостаточность; сердце не способно перекачивать достаточно крови для удовлетворения потребностей организма. Левожелудочковая: вызывает отёк лёгких. Правожелудочковая: вызывает периферические отёки, асцит.","zh":"充血性心力衰竭；心脏无法泵出足够血液以满足机体需求。左心衰竭：导致肺水肿（肺内积液）。右心衰竭：导致外周水肿、腹水。","pt_BR":"Insuficiência cardíaca congestiva; o coração não consegue bombear sangue suficiente para atender às necessidades do corpo. Esquerda: causa edema pulmonar (líquido nos pulmões). Direita: causa edema periférico e ascite.","pt_PT":"Insuficiência cardíaca congestiva; o coração não consegue bombear sangue suficiente para satisfazer as necessidades do organismo. Esquerda: causa edema pulmonar (líquido nos pulmões). Direita: causa edema periférico e ascite."}},
  { id: 'dc-medical-0044', deck_id: 'deck-medical', sort_order: 44, front: "Atrial Fibrillation (AFib)", back: "An irregular, often rapid heart rhythm in which the atria quiver rather than contract properly. Increases stroke risk due to blood pooling and clot formation. Managed with rate control, rhythm control, and anticoagulation." , front_translations: {"es":"Fibrilación Atrial (FA)","de":"Vorhofflimmern (VHF)","fr":"Fibrillation Auriculaire (FA)","tr":"Atriyal Fibrilasyon (AF)","nl":"Atriumfibrilleren (AF)","ru":"Фибрилляция предсердий (ФП)","zh":"心房颤动（房颤，AFib）","pt_BR":"Fibrilação Atrial (FA)","pt_PT":"Fibrilhação Auricular (FA)"}, back_translations: {"es":"Un ritmo cardíaco irregular y frecuentemente rápido en que los átrios tremem en vez de se contrair adequadamente. Aumenta el riesgo de AVC debido al estase sanguíneo y formación de coágulos. Tratada con controle de frecuencia, controle de ritmo y anticoagulación.","de":"Ein unregelmäßiger, oft schneller Herzrhythmus, bei dem die Vorhöfe zittern statt sich geordnet zusammenzuziehen. Erhöht das Schlaganfallrisiko durch Blutansammlung und Gerinnselbildung. Behandlung: Frequenzkontrolle, Rhythmuskontrolle und Antikoagulation.","fr":"Un rythme cardiaque irrégulier et souvent rapide dans lequel les oreillettes frémissent plutôt que de se contracter correctement. Augmente le risque d'AVC en raison de la stase sanguine et de la formation de caillots. Prise en charge : contrôle de la fréquence, du rythme et anticoagulation.","tr":"Atriyal odacıkların düzgün kasılmak yerine titreştiği düzensiz ve sıklıkla hızlı bir kalp ritmi. Kan birikmesi ve pıhtı oluşumu nedeniyle inme riskini artırır. Hız kontrolü, ritim kontrolü ve antikoagülasyon ile yönetilir.","nl":"Een onregelmatig, vaak snel hartritme waarbij de boezems trillen in plaats van goed samentrekken. Verhoogt het risico op beroerte door bloedstase en klontervorming. Behandeld met frequentiecontrole, ritmecontrole en antistolling.","ru":"Нерегулярный, нередко учащённый сердечный ритм, при котором предсердия дрожат вместо нормального сокращения. Повышает риск инсульта из-за застоя крови и образования тромбов. Лечение: контроль ЧСС, восстановление ритма, антикоагуляция.","zh":"一种不规则、常为快速的心律，心房颤动而非正常收缩。由于血液淤积和血栓形成，增加卒中风险。治疗包括控制心室率、转复并维持窦律及抗凝治疗。","pt_BR":"Um ritmo cardíaco irregular e frequentemente rápido em que os átrios tremem em vez de se contrair adequadamente. Aumenta o risco de AVC devido ao estase sanguíneo e formação de coágulos. Tratada com controle de frequência, controle de ritmo e anticoagulação.","pt_PT":"Um ritmo cardíaco irregular e frequentemente rápido em que as aurículas tremem em vez de se contrair adequadamente. Aumenta o risco de AVC devido à estase sanguínea e formação de coágulos. Tratada com controlo de frequência, controlo de ritmo e anticoagulação."}},
  { id: 'dc-medical-0045', deck_id: 'deck-medical', sort_order: 45, front: "Hypertension", back: "Blood pressure consistently ≥130/80 mmHg. Often asymptomatic ('silent killer'). Major risk factor for MI, stroke, kidney disease, and heart failure. Managed with lifestyle changes and antihypertensives." , front_translations: {"es":"Hipertensão Arterial","de":"Hypertonie","fr":"Hypertension Artérielle","tr":"Hipertansiyon","nl":"Hypertensie","ru":"Артериальная гипертония","zh":"高血压","pt_BR":"Hipertensão Arterial","pt_PT":"Hipertensão Arterial"}, back_translations: {"es":"Presión arterial consistentemente ≥130/80 mmHg. Frecuentemente assintomática ('assassino silencioso'). Principal fator de riesgo para IAM, AVC, enfermedad renal y insuficiencia cardíaca. Tratada con cambios de estilo de vida y anti-hipertensivos.","de":"Blutdruck dauerhaft ≥130/80 mmHg. Oft asymptomatisch ('stiller Killer'). Wesentlicher Risikofaktor für MI, Schlaganfall, Nierenerkrankungen und Herzinsuffizienz. Behandlung mit Lebensstiländerungen und Antihypertensiva.","fr":"Pression artérielle régulièrement ≥130/80 mmHg. Souvent asymptomatique ('tueur silencieux'). Principal facteur de risque d'IDM, d'AVC, de maladie rénale et d'insuffisance cardiaque. Prise en charge par modifications du mode de vie et antihypertenseurs.","tr":"Sürekli olarak ≥130/80 mmHg kan basıncı. Genellikle belirtisizdir ('sessiz katil'). MI, inme, böbrek hastalığı ve kalp yetmezliği için önemli risk faktörü. Yaşam tarzı değişiklikleri ve antihipertansiflerle yönetilir.","nl":"Bloeddruk continu ≥130/80 mmHg. Vaak symptoomloos ('stille moordenaar'). Belangrijke risicofactor voor hartinfarct, beroerte, nierziekte en hartfalen. Behandeld met leefstijlveranderingen en antihypertensiva.","ru":"Артериальное давление постоянно ≥130/80 мм рт. ст. Часто протекает бессимптомно («тихий убийца»). Главный фактор риска ИМ, инсульта, болезней почек и сердечной недостаточности. Лечение: изменение образа жизни и антигипертензивные препараты.","zh":"血压持续≥130/80 mmHg。通常无症状（\"无声杀手\"）。是心肌梗死、卒中、肾病和心力衰竭的主要危险因素。通过生活方式改变和降压药物管理。","pt_BR":"Pressão arterial consistentemente ≥130/80 mmHg. Frequentemente assintomática ('assassino silencioso'). Principal fator de risco para IAM, AVC, doença renal e insuficiência cardíaca. Tratada com mudanças de estilo de vida e anti-hipertensivos.","pt_PT":"Pressão arterial consistentemente ≥130/80 mmHg. Frequentemente assintomática ('assassino silencioso'). Principal fator de risco para EAM, AVC, doença renal e insuficiência cardíaca. Tratada com mudanças de estilo de vida e anti-hipertensivos."}},
  { id: 'dc-medical-0046', deck_id: 'deck-medical', sort_order: 46, front: "Stroke (CVA)", back: "Cerebrovascular accident; sudden loss of brain function due to interruption of blood supply. Ischemic stroke (clot, ~87%) or hemorrhagic stroke (bleeding). FAST mnemonic: Face drooping, Arm weakness, Speech difficulty, Time to call." , front_translations: {"es":"Acidente Vascular Cerebral (AVC)","de":"Schlaganfall (CVA)","fr":"Accident Vasculaire Cérébral (AVC)","tr":"İnme (Serebrovasküler Olay, SVO)","nl":"Beroerte (CVA)","ru":"Инсульт (ОНМК)","zh":"卒中（脑血管意外，CVA）","pt_BR":"Acidente Vascular Cerebral (AVC)","pt_PT":"Acidente Vascular Cerebral (AVC)"}, back_translations: {"es":"Acidente cerebrovascular; perda súbita de la función cerebral por interrupción del suprimento sanguíneo. AVC isquemico (coágulo, ~87%) o hemorrágico (sangramento). Mnemonico FAST: Face caída, Arm débil (brazo), Speech (fala difícil), Time (ligue imediatamente).","de":"Zerebrovaskuläres Ereignis; plötzlicher Verlust der Gehirnfunktion durch Unterbrechung der Blutversorgung. Ischämischer Schlaganfall (Blutgerinnsel, ~87 %) oder hämorrhagischer Schlaganfall (Blutung). FAST-Mnemonic: Gesicht (hängt herab), Arm (schwach), Sprache (gestört), Zeit (sofort handeln).","fr":"Accident cérébrovasculaire ; perte soudaine de la fonction cérébrale due à une interruption de l'apport sanguin. AVC ischémique (caillot, ~87 %) ou hémorragique (saignement). Mnémotechnique FAST : Visage tombant, Bras faible, Speech (trouble de la parole), Temps d'appel.","tr":"Serebrovasküler kaza; kan akışının kesilmesine bağlı ani beyin fonksiyonu kaybı. İskemik inme (pıhtı, ~%87) veya hemorajik inme (kanama). FAST kısaltması: Yüz sarkması, Kol güçsüzlüğü, Söz güçlüğü, Telefon etme zamanı.","nl":"Cerebrovasculair accident; plotseling verlies van hersenfunctie door onderbreking van de bloedtoevoer. Ischemische beroerte (stolsel, ~87%) of hemorragische beroerte (bloeding). FAST-mnemonic: Face (hangende gezicht), Arm (zwakte), Speech (spraakproblemen), Time (bel onmiddellijk).","ru":"Острое нарушение мозгового кровообращения; внезапная утрата функции мозга вследствие нарушения кровоснабжения. Ишемический инсульт (тромб, ~87%) или геморрагический (кровоизлияние). Мнемоника FAST: лицо (асимметрия), рука (слабость), речь (нарушение), телефон (срочно вызвать).","zh":"脑血管意外；因脑血供中断导致的突发脑功能丧失。缺血性卒中（血栓，约87%）或出血性卒中（脑出血）。FAST口诀：面部下垂（F）、手臂无力（A）、言语困难（S）、立即拨打急救电话（T）。","pt_BR":"Acidente cerebrovascular; perda súbita da função cerebral por interrupção do suprimento sanguíneo. AVC isquêmico (coágulo, ~87%) ou hemorrágico (sangramento). Mnemônico FAST: Face caída, Arm fraca (braço), Speech (fala difícil), Time (ligue imediatamente).","pt_PT":"Acidente cerebrovascular; perda súbita da função cerebral por interrupção do fornecimento sanguíneo. AVC isquémico (coágulo, ~87%) ou hemorrágico (hemorragia). Mnemónico FAST: Face descaída, Arm fraca (braço), Speech (dificuldade de fala), Time (ligue imediatamente)."}},
  { id: 'dc-medical-0047', deck_id: 'deck-medical', sort_order: 47, front: "Diabetes Mellitus Type 1", back: "Autoimmune destruction of pancreatic beta cells leading to absolute insulin deficiency. Onset typically in childhood/young adults. Requires insulin therapy. Risk of DKA (diabetic ketoacidosis)." , front_translations: {"es":"Diabetes Mellitus Tipo 1","de":"Diabetes mellitus Typ 1","fr":"Diabète de type 1","tr":"Tip 1 Diabetes Mellitus","nl":"Diabetes Mellitus Type 1","ru":"Сахарный диабет 1-го типа","zh":"1型糖尿病","pt_BR":"Diabetes Mellitus Tipo 1","pt_PT":"Diabetes Mellitus Tipo 1"}, back_translations: {"es":"Destrucción autoimune de las células beta pancreáticas levando a la deficiencia absoluta de insulina. Início típicamente en la infancia o en adultos jovens. Requiere insulinoterapia. Riesgo de CAD (cetoacidose diabética).","de":"Autoimmune Zerstörung der pankreatischen Betazellen, die zu absolutem Insulinmangel führt. Beginn typischerweise im Kindes- oder Jugendalter. Erfordert Insulintherapie. Risiko einer DKA (diabetische Ketoazidose).","fr":"Destruction auto-immune des cellules bêta du pancréas entraînant une carence absolue en insuline. Début généralement dans l'enfance ou chez le jeune adulte. Nécessite une insulinothérapie. Risque d'acidocétose diabétique (ACD).","tr":"Pankreas beta hücrelerinin otoimmün yıkımı ile mutlak insülin eksikliğine yol açar. Başlangıç genellikle çocukluk veya genç yetişkinlik dönemindedir. İnsülin tedavisi gerektirir. DKA (diyabetik ketoasidoz) riski taşır.","nl":"Auto-immuunvernietiging van pancreatische bètacellen, leidend tot absolute insulinedeficiëntie. Aanvang typisch in de kindertijd of bij jonge volwassenen. Vereist insulinetherapie. Risico op DKA (diabetische ketoacidose).","ru":"Аутоиммунное разрушение бета-клеток поджелудочной железы, приводящее к абсолютному дефициту инсулина. Дебют обычно в детском или юношеском возрасте. Требует инсулинотерапии. Риск развития ДКА (диабетического кетоацидоза).","zh":"自身免疫性破坏胰腺β细胞，导致胰岛素绝对缺乏。通常在儿童或青年期发病，需要胰岛素治疗，存在发生糖尿病酮症酸中毒（DKA）的风险。","pt_BR":"Destruição autoimune das células beta pancreáticas levando à deficiência absoluta de insulina. Início tipicamente na infância ou em adultos jovens. Requer insulinoterapia. Risco de CAD (cetoacidose diabética).","pt_PT":"Destruição autoimune das células beta pancreáticas levando a deficiência absoluta de insulina. Início tipicamente na infância ou em adultos jovens. Requer insulinoterapia. Risco de CAD (cetoacidose diabética)."}},
  { id: 'dc-medical-0048', deck_id: 'deck-medical', sort_order: 48, front: "Diabetes Mellitus Type 2", back: "Insulin resistance followed by progressive beta cell dysfunction. Associated with obesity and sedentary lifestyle. Managed with diet, exercise, oral agents (metformin first-line), and eventually insulin." , front_translations: {"es":"Diabetes Mellitus Tipo 2","de":"Diabetes mellitus Typ 2","fr":"Diabète de type 2","tr":"Tip 2 Diabetes Mellitus","nl":"Diabetes Mellitus Type 2","ru":"Сахарный диабет 2-го типа","zh":"2型糖尿病","pt_BR":"Diabetes Mellitus Tipo 2","pt_PT":"Diabetes Mellitus Tipo 2"}, back_translations: {"es":"Resistencia a la insulina seguida de disfunción progressiva de las células beta. Associada a la obesidad y al estilo de vida sedentário. Tratada con dieta, ejercicio, agentes orais (metformina de primera línea) y eventualmente insulina.","de":"Insulinresistenz, gefolgt von progressiver Betazell-Dysfunktion. Assoziiert mit Adipositas und Bewegungsmangel. Behandlung mit Diät, Sport, oralen Antidiabetika (Metformin als erste Wahl) und schließlich Insulin.","fr":"Résistance à l'insuline suivie d'une dysfonction progressive des cellules bêta. Associé à l'obésité et à la sédentarité. Pris en charge par régime, exercice, agents oraux (metformine en première intention) et finalement insuline.","tr":"İnsülin direnci ardından ilerleyici beta hücresi disfonksiyonu. Obezite ve sedanter yaşam tarzıyla ilişkilidir. Diyet, egzersiz, oral ajanlar (birinci basamak metformin) ve nihayetinde insülin ile yönetilir.","nl":"Insulineresistentie gevolgd door progressieve bètaceldisfunctie. Geassocieerd met obesitas en sedentaire leefstijl. Behandeld met dieet, beweging, orale middelen (metformine als eerste keus) en uiteindelijk insuline.","ru":"Инсулинорезистентность с последующей прогрессирующей дисфункцией бета-клеток. Ассоциирован с ожирением и малоподвижным образом жизни. Лечение: диета, физическая активность, пероральные препараты (метформин — первая линия), в дальнейшем — инсулин.","zh":"先为胰岛素抵抗，继而出现进行性β细胞功能障碍。与肥胖和久坐生活方式相关。通过饮食、运动、口服降糖药（二甲双胍为一线）及最终使用胰岛素管理。","pt_BR":"Resistência à insulina seguida de disfunção progressiva das células beta. Associada à obesidade e ao estilo de vida sedentário. Tratada com dieta, exercício, agentes orais (metformina de primeira linha) e eventualmente insulina.","pt_PT":"Resistência à insulina seguida de disfunção progressiva das células beta. Associada à obesidade e ao estilo de vida sedentário. Tratada com dieta, exercício, agentes orais (metformina de primeira linha) e eventualmente insulina."}},
  { id: 'dc-medical-0049', deck_id: 'deck-medical', sort_order: 49, front: "Pneumonia", back: "Infection and inflammation of the lung parenchyma (alveoli). Caused by bacteria (S. pneumoniae most common), viruses, or fungi. Presents with cough, fever, dyspnea, and focal consolidation on chest X-ray." , front_translations: {"es":"Pneumonia","de":"Pneumonie","fr":"Pneumonie","tr":"Pnömoni","nl":"Pneumonie","ru":"Пневмония","zh":"肺炎","pt_BR":"Pneumonia","pt_PT":"Pneumonia"}, back_translations: {"es":"Infección y inflamación del parenquima pulmonar (alvéolos). Causada por bacterias (S. pneumoniae más comum), virus o fungos. Se presenta con tosse, febre, dispneia y consolidación focal en la radiografia de tórax.","de":"Infektion und Entzündung des Lungenparenchyms (Alveolen). Verursacht durch Bakterien (S. pneumoniae am häufigsten), Viren oder Pilze. Symptome: Husten, Fieber, Dyspnoe und fokale Verdichtung im Röntgenbild des Thorax.","fr":"Infection et inflammation du parenchyme pulmonaire (alvéoles). Causée par des bactéries (S. pneumoniae le plus fréquent), des virus ou des champignons. Se présente par toux, fièvre, dyspnée et condensation focale à la radiographie thoracique.","tr":"Akciğer parankiminin (alveollerin) enfeksiyon ve iltihabı. Bakteriler (en yaygın S. pneumoniae), virüsler veya mantarlar tarafından oluşturulur. Öksürük, ateş, nefes darlığı ve akciğer röntgeninde fokal konsolidasyon ile prezente olur.","nl":"Infectie en ontsteking van het longparenchym (alveoli). Veroorzaakt door bacteriën (S. pneumoniae meest voorkomend), virussen of schimmels. Presenteert met hoest, koorts, dyspneu en focale consolidatie op thoraxfoto.","ru":"Инфекционно-воспалительное поражение паренхимы лёгких (альвеол). Вызывается бактериями (чаще всего S. pneumoniae), вирусами или грибками. Проявляется кашлем, лихорадкой, одышкой и очаговым затемнением на рентгенограмме грудной клетки.","zh":"肺实质（肺泡）的感染和炎症。由细菌（最常见为肺炎链球菌）、病毒或真菌引起。表现为咳嗽、发热、呼吸困难和胸部X线上的局限性实变。","pt_BR":"Infecção e inflamação do parênquima pulmonar (alvéolos). Causada por bactérias (S. pneumoniae mais comum), vírus ou fungos. Apresenta-se com tosse, febre, dispneia e consolidação focal na radiografia de tórax.","pt_PT":"Infeção e inflamação do parênquima pulmonar (alvéolos). Causada por bactérias (S. pneumoniae mais comum), vírus ou fungos. Apresenta-se com tosse, febre, dispneia e consolidação focal na radiografia torácica."}},
  { id: 'dc-medical-0050', deck_id: 'deck-medical', sort_order: 50, front: "COPD — Chronic Obstructive Pulmonary Disease", back: "Progressive lung disease characterized by airflow obstruction. Emphysema: alveolar destruction. Chronic bronchitis: mucus hypersecretion. Primarily caused by smoking. Managed with bronchodilators, steroids, smoking cessation." , front_translations: {"es":"DPOC — Enfermedad Pulmonar Obstrutiva Crónica","de":"COPD — Chronisch obstruktive Lungenerkrankung","fr":"BPCO — Bronchopneumopathie Chronique Obstructive","tr":"KOAH — Kronik Obstrüktif Akciğer Hastalığı","nl":"COPD — Chronische Obstructieve Longziekte","ru":"ХОБЛ — Хроническая обструктивная болезнь лёгких","zh":"慢阻肺（COPD）— 慢性阻塞性肺疾病","pt_BR":"DPOC — Doença Pulmonar Obstrutiva Crônica","pt_PT":"DPOC — Doença Pulmonar Obstrutiva Crónica"}, back_translations: {"es":"Enfermedad pulmonar progressiva caracterizada por obstrución del flujo aéreo. Enfisema: destrucción alveolar. Bronquite crónica: hipersecreción de muco. Causada principalmente por el tabagismo. Tratada con broncodilatadores, corticosteroides y cessación del tabagismo.","de":"Progressive Lungenerkrankung mit Atemwegsobstruktion. Emphysem: Zerstörung der Alveolen. Chronische Bronchitis: Hypersekretio von Schleim. Hauptursache: Rauchen. Behandlung mit Bronchodilatoren, Steroiden und Raucherentwöhnung.","fr":"Maladie pulmonaire progressive caractérisée par une obstruction des voies aériennes. Emphysème : destruction alvéolaire. Bronchite chronique : hypersécrétion de mucus. Principalement causée par le tabagisme. Prise en charge par bronchodilatateurs, corticoïdes et sevrage tabagique.","tr":"Hava akışı obstrüksiyonu ile karakterize ilerleyici akciğer hastalığı. Amfizem: alveol yıkımı. Kronik bronşit: mukus hipersekresyonu. Başlıca sigara içiminden kaynaklanır. Bronkodilatörler, steroidler ve sigarayı bırakma ile yönetilir.","nl":"Progressieve longziekte gekenmerkt door luchtwegobstructie. Emfyseem: alveolaire destructie. Chronische bronchitis: slijmhypersecretie. Voornamelijk veroorzaakt door roken. Behandeld met bronchodilatoren, steroïden en stoppen met roken.","ru":"Прогрессирующее заболевание лёгких с обструкцией дыхательных путей. Эмфизема: деструкция альвеол. Хронический бронхит: гиперсекреция слизи. Основная причина — курение. Лечение: бронходилататоры, кортикостероиды, отказ от курения.","zh":"以气流受限为特征的进行性肺部疾病。肺气肿：肺泡破坏；慢性支气管炎：黏液分泌过多。主要由吸烟引起。通过支气管扩张剂、糖皮质激素和戒烟进行管理。","pt_BR":"Doença pulmonar progressiva caracterizada por obstrução do fluxo aéreo. Enfisema: destruição alveolar. Bronquite crônica: hipersecreção de muco. Causada principalmente pelo tabagismo. Tratada com broncodilatadores, corticosteroides e cessação do tabagismo.","pt_PT":"Doença pulmonar progressiva caracterizada por obstrução do fluxo aéreo. Enfisema: destruição alveolar. Bronquite crónica: hipersecreção de muco. Causada principalmente pelo tabagismo. Tratada com broncodilatadores, corticosteroides e cessação tabágica."}},
  { id: 'dc-medical-0051', deck_id: 'deck-medical', sort_order: 51, front: "Asthma", back: "Chronic inflammatory airway disease with reversible bronchoconstriction triggered by allergens, exercise, cold air, or infection. Symptoms: wheezing, cough, chest tightness. Managed with bronchodilators (SABAs) and inhaled corticosteroids." , front_translations: {"es":"Asma","de":"Asthma","fr":"Asthme","tr":"Astım","nl":"Astma","ru":"Астма","zh":"哮喘","pt_BR":"Asma","pt_PT":"Asma"}, back_translations: {"es":"Enfermedad inflamatória crónica de las vias aéreas con broncoconstrición reversible desencadeada por alérgenos, ejercicio, aire frio o infección. Síntomas: sibilancia, tosse, aperto en el pecho. Tratada con broncodilatadores (BABA) y corticosteroides inalatórios.","de":"Chronisch-entzündliche Atemwegserkrankung mit reversibler Bronchokonstriktion, ausgelöst durch Allergene, körperliche Belastung, Kälte oder Infektionen. Symptome: Keuchen, Husten, Engegefühl in der Brust. Behandlung mit Bronchodilatatoren (SABAs) und inhalativen Kortikosteroiden.","fr":"Maladie inflammatoire chronique des voies respiratoires avec bronchoconstriction réversible déclenchée par des allergènes, l'exercice, l'air froid ou une infection. Symptômes : sibilances, toux, oppression thoracique. Prise en charge par bronchodilatateurs (BACA) et corticoïdes inhalés.","tr":"Alerjenler, egzersiz, soğuk hava veya enfeksiyonla tetiklenen geri dönüşümlü bronkokonstriksiyon ile seyreden kronik inflamatuar hava yolu hastalığı. Belirtiler: hırıltı, öksürük, göğüste sıkışma hissi. Bronkodilatörler (KABA) ve inhale kortikosteroidlerle tedavi edilir.","nl":"Chronisch ontstekingsziekte van de luchtwegen met reversibele bronchoconstructie uitgelokt door allergenen, inspanning, koude lucht of infectie. Symptomen: piepende ademhaling, hoest, beklemming op de borst. Behandeld met bronchusverwijders (SABA's) en inhalatiecorticosteroïden.","ru":"Хроническое воспалительное заболевание дыхательных путей с обратимой бронхоконстрикцией, вызываемой аллергенами, физической нагрузкой, холодным воздухом или инфекцией. Симптомы: свистящее дыхание, кашель, сдавленность в груди. Лечение: бронходилататоры (КДБА) и ингаляционные кортикостероиды.","zh":"慢性气道炎症性疾病，表现为可逆性支气管收缩，由过敏原、运动、冷空气或感染诱发。症状：喘鸣、咳嗽、胸闷。使用支气管扩张剂（SABA）和吸入性皮质类固醇治疗。","pt_BR":"Doença inflamatória crônica das vias aéreas com broncoconstrição reversível desencadeada por alérgenos, exercício, ar frio ou infecção. Sintomas: sibilância, tosse, aperto no peito. Tratada com broncodilatadores (BABA) e corticosteroides inalatórios.","pt_PT":"Doença inflamatória crónica das vias respiratórias com broncoconstrição reversível desencadeada por alergénios, exercício, ar frio ou infecção. Sintomas: pieira, tosse, aperto no peito. Tratada com broncodilatadores (BACA) e corticosteroides inalados."}},
  { id: 'dc-medical-0052', deck_id: 'deck-medical', sort_order: 52, front: "Pulmonary Embolism (PE)", back: "Blockage of a pulmonary artery, usually by a blood clot from a DVT (deep vein thrombosis). Presents with sudden dyspnea, chest pain, tachycardia. Diagnosed by CT pulmonary angiography. Treated with anticoagulation." , front_translations: {"es":"Embolia Pulmonar (EP)","de":"Lungenembolie (LE)","fr":"Embolie pulmonaire (EP)","tr":"Pulmoner Emboli (PE)","nl":"Longembolie (LE)","ru":"Тромбоэмболия лёгочной артерии (ТЭЛА)","zh":"肺栓塞（PE）","pt_BR":"Embolia Pulmonar (EP)","pt_PT":"Embolia Pulmonar (EP)"}, back_translations: {"es":"Obstrución de una arteria pulmonar, generalmente por coágulo sanguíneo proveniente de trombose venosa profunda (TVP). Apresenta dispneia súbita, dor torácica, taquicardia. Diagnosticada por angiotomografia pulmonar. Tratada con anticoagulación.","de":"Verschluss einer Lungenarterie, meist durch einen Blutgerinnsel aus einer tiefen Venenthrombose (TVT). Präsentation: plötzliche Dyspnoe, Brustschmerzen, Tachykardie. Diagnose mittels CT-Pulmonalis-Angiographie. Behandlung mit Antikoagulation.","fr":"Obstruction d'une artère pulmonaire, généralement par un caillot sanguin provenant d'une thrombose veineuse profonde (TVP). Se manifeste par une dyspnée soudaine, des douleurs thoraciques, une tachycardie. Diagnostiqué par angioscanner pulmonaire. Traité par anticoagulation.","tr":"Bir pulmoner arterin, genellikle derin ven trombozundan (DVT) kaynaklanan bir kan pıhtısıyla tıkanması. Ani dispne, göğüs ağrısı, taşikardiyle prezente olur. BT pulmoner anjiyografi ile tanı konur. Antikoagülasyon ile tedavi edilir.","nl":"Afsluiting van een longslagader, meestal door een bloedstolsel afkomstig van een diepveneuze trombose (DVT). Presenteert zich met plotselinge dyspneu, pijn op de borst, tachycardie. Gediagnosticeerd met CT-pulmonale angiografie. Behandeld met antistolling.","ru":"Закупорка лёгочной артерии, как правило, тромбом из глубоких вен (ТГВ). Проявляется внезапной одышкой, болью в груди, тахикардией. Диагноз устанавливается с помощью КТ-ангиографии лёгочных артерий. Лечение: антикоагулянты.","zh":"肺动脉阻塞，通常由深静脉血栓（DVT）脱落形成。表现为突发呼吸困难、胸痛、心动过速。通过CT肺动脉造影诊断。使用抗凝治疗。","pt_BR":"Obstrução de uma artéria pulmonar, geralmente por coágulo sanguíneo proveniente de trombose venosa profunda (TVP). Apresenta dispneia súbita, dor torácica, taquicardia. Diagnosticada por angiotomografia pulmonar. Tratada com anticoagulação.","pt_PT":"Obstrução de uma artéria pulmonar, geralmente por coágulo sanguíneo proveniente de trombose venosa profunda (TVP). Apresenta dispneia súbita, dor torácica, taquicardia. Diagnosticada por angiotomografia pulmonar. Tratada com anticoagulação."}},
  { id: 'dc-medical-0053', deck_id: 'deck-medical', sort_order: 53, front: "Appendicitis", back: "Inflammation of the vermiform appendix, typically due to obstruction by fecalith or lymphoid hyperplasia. Presents with periumbilical pain migrating to the right iliac fossa (McBurney's point), fever, nausea. Treatment: appendectomy." , front_translations: {"es":"Apendicite","de":"Appendizitis","fr":"Appendicite","tr":"Apandisit","nl":"Appendicitis","ru":"Аппендицит","zh":"阑尾炎","pt_BR":"Apendicite","pt_PT":"Apendicite"}, back_translations: {"es":"Inflamación del apéndice vermiforme, típicamente por obstrución por fecalito o hiperplasia linfoide. Apresenta dor periumbilical migrando para a fossa ilíaca direita (punto de McBurney), febre, náusea. Tratamiento: apendicectomia.","de":"Entzündung des Wurmfortsatzes, typischerweise durch Obstruktion durch Kotstein oder lymphoide Hyperplasie. Präsentation: periumbilicaler Schmerz, der in den rechten Unterbauch zieht (McBurney-Punkt), Fieber, Übelkeit. Behandlung: Appendektomie.","fr":"Inflammation de l'appendice vermiculaire, généralement due à une obstruction par un stercolithe ou une hyperplasie lymphoïde. Se manifeste par une douleur périombilicale migrant vers la fosse iliaque droite (point de McBurney), fièvre, nausées. Traitement : appendicectomie.","tr":"Genellikle fekalit veya lenfoid hiperplazi nedeniyle tıkanmaya bağlı vermiform apandiksin iltihabı. Periumbilikal ağrının sağ iliyak fossaya (McBurney noktası) yayılması, ateş, mide bulantısıyla prezente olur. Tedavi: apendektomi.","nl":"Ontsteking van de appendix, meestal door obstructie door een fecaalsteentje of lymfoïde hyperplasie. Presenteert zich met periumbilicale pijn die verplaatst naar de rechter fossa iliaca (punt van McBurney), koorts, misselijkheid. Behandeling: appendectomie.","ru":"Воспаление червеобразного отростка, как правило, вследствие обструкции каловым камнем или лимфоидной гиперплазии. Проявляется болью в области пупка, смещающейся в правую подвздошную ямку (точка Мак-Бёрни), лихорадкой, тошнотой. Лечение: аппендэктомия.","zh":"阑尾炎症，通常由粪石或淋巴组织增生引起阻塞所致。表现为脐周疼痛转移至右髂窝（麦氏点）、发热、恶心。治疗：阑尾切除术。","pt_BR":"Inflamação do apêndice vermiforme, tipicamente por obstrução por fecalito ou hiperplasia linfoide. Apresenta dor periumbilical migrando para a fossa ilíaca direita (ponto de McBurney), febre, náusea. Tratamento: apendicectomia.","pt_PT":"Inflamação do apêndice vermicular, tipicamente por obstrução por fecalito ou hiperplasia linfoide. Apresenta dor periumbilical que migra para a fossa ilíaca direita (ponto de McBurney), febre, náusea. Tratamento: apendicectomia."}},
  { id: 'dc-medical-0054', deck_id: 'deck-medical', sort_order: 54, front: "Peptic Ulcer Disease (PUD)", back: "Erosion of the gastrointestinal mucosa by stomach acid. Most caused by H. pylori infection or NSAID use. Presents with epigastric pain. Duodenal ulcers improve with eating; gastric ulcers worsen." , front_translations: {"es":"Úlcera Péptica (UP)","de":"Peptisches Ulkus (PUD)","fr":"Ulcère gastro-duodénal","tr":"Peptik Ülser Hastalığı (PÜH)","nl":"Peptische ulcusziekte (PUD)","ru":"Язвенная болезнь желудка и двенадцатиперстной кишки","zh":"消化性溃疡病（PUD）","pt_BR":"Úlcera Péptica (UP)","pt_PT":"Doença Ulcerosa Péptica (DUP)"}, back_translations: {"es":"Erosão de la mucosa gastrointestinal por el ácido gástrico. Más causada por infección por H. pylori o uso de AINEs. Apresenta dor epigástrica. Úlceras duodenais melhoram con alimentación; úlceras gástricas pioram.","de":"Erosion der gastrointestinalen Schleimhaut durch Magensäure. Häufigste Ursachen: H.-pylori-Infektion oder NSAR-Einnahme. Präsentation: epigastrischer Schmerz. Duodenalulzera bessern sich nach dem Essen; Magenulzera verschlechtern sich.","fr":"Érosion de la muqueuse gastro-intestinale par l'acide gastrique. Principalement causée par l'infection à H. pylori ou la prise d'AINS. Se manifeste par une douleur épigastrique. Les ulcères duodénaux s'améliorent après les repas ; les ulcères gastriques s'aggravent.","tr":"Mide asidinin gastrointestinal mukozayı aşındırması. Çoğunlukla H. pylori enfeksiyonu veya NSAID kullanımından kaynaklanır. Epigastrik ağrıyla prezente olur. Duodenal ülserler yemekle düzelir; gastrik ülserler kötüleşir.","nl":"Erosie van het maag-darmslijmvlies door maagzuur. Meest veroorzaakt door H. pylori-infectie of NSAID-gebruik. Presenteert zich met epigastrische pijn. Duodenale ulcera verbeteren na eten; maagulcera verslechteren.","ru":"Эрозия слизистой оболочки желудочно-кишечного тракта под воздействием кислоты. Основные причины: инфекция H. pylori или приём НПВС. Проявляется болью в эпигастрии. Дуоденальные язвы уменьшаются после еды; желудочные — усиливаются.","zh":"胃酸侵蚀胃肠道黏膜。最常见原因：幽门螺旋杆菌感染或NSAID使用。表现为上腹痛。十二指肠溃疡进食后缓解；胃溃疡进食后加重。","pt_BR":"Erosão da mucosa gastrointestinal pelo ácido gástrico. Mais causada por infecção por H. pylori ou uso de AINEs. Apresenta dor epigástrica. Úlceras duodenais melhoram com alimentação; úlceras gástricas pioram.","pt_PT":"Erosão da mucosa gastrointestinal pelo ácido gástrico. Principalmente causada por infecção por H. pylori ou uso de AINEs. Apresenta dor epigástrica. Úlceras duodenais melhoram com a alimentação; úlceras gástricas pioram."}},
  { id: 'dc-medical-0055', deck_id: 'deck-medical', sort_order: 55, front: "GERD — Gastroesophageal Reflux Disease", back: "Chronic backflow of stomach acid into the esophagus due to a weakened lower esophageal sphincter. Causes heartburn and regurgitation. Managed with PPIs (proton pump inhibitors), H2-blockers, and lifestyle changes." , front_translations: {"es":"DRGE — Enfermedad del Refluxo Gastroesofágico","de":"GERD — Gastroösophageale Refluxkrankheit","fr":"RGO — Reflux gastro-œsophagien","tr":"GÖRH — Gastroözofajeal Reflü Hastalığı","nl":"GERD — Gastro-oesofageale refluxziekte","ru":"ГЭРБ — Гастроэзофагеальная рефлюксная болезнь","zh":"GERD — 胃食管反流病","pt_BR":"DRGE — Doença do Refluxo Gastroesofágico","pt_PT":"DRGE — Doença de Refluxo Gastroesofágico"}, back_translations: {"es":"Refluxo crónico de ácido gástrico para el esofago debido al enfraquecimento del esfíncter esofagiano inferior. Causa azia y regurgitación. Tratada con IBPs (inibidores de la bomba de protones), bloqueadores H2 y cambios en el estilo de vida.","de":"Chronischer Rückfluss von Magensäure in die Speiseröhre aufgrund eines geschwächten unteren Ösophagussphinkters. Verursacht Sodbrennen und Regurgitation. Behandlung mit PPIs (Protonenpumpenhemmer), H2-Blockern und Lebensstiländerungen.","fr":"Reflux chronique d'acide gastrique dans l'œsophage dû à un relâchement du sphincter inférieur de l'œsophage. Provoque des brûlures d'estomac et des régurgitations. Pris en charge avec des IPP (inhibiteurs de la pompe à protons), des anti-H2 et des modifications du mode de vie.","tr":"Zayıflamış alt özofagus sfinkteri nedeniyle mide asidinin özofagusa kronik geri kaçışı. Mide yanması ve regürgitasyona neden olur. PPI (proton pompa inhibitörleri), H2 blokerler ve yaşam tarzı değişiklikleriyle yönetilir.","nl":"Chronische terugvloei van maagzuur in de slokdarm door een verzwakte onderste slokdarmsfincter. Veroorzaakt zuurbranden en regurgitatie. Behandeld met PPI's (protonpompremmers), H2-blokkers en leefstijlveranderingen.","ru":"Хронический заброс желудочной кислоты в пищевод из-за слабости нижнего пищеводного сфинктера. Вызывает изжогу и регургитацию. Лечение: ИПП (ингибиторы протонной помпы), H2-блокаторы и изменение образа жизни.","zh":"由于下食管括约肌功能减弱，胃酸慢性反流入食管。引起烧心和反酸。使用PPI（质子泵抑制剂）、H2受体拮抗剂及生活方式调整治疗。","pt_BR":"Refluxo crônico de ácido gástrico para o esôfago devido ao enfraquecimento do esfíncter esofagiano inferior. Causa azia e regurgitação. Tratada com IBPs (inibidores da bomba de prótons), bloqueadores H2 e mudanças no estilo de vida.","pt_PT":"Refluxo crónico de ácido gástrico para o esófago devido ao enfraquecimento do esfíncter esofágico inferior. Causa azia e regurgitação. Tratada com IBPs (inibidores da bomba de protões), bloqueadores H2 e alterações no estilo de vida."}},
  { id: 'dc-medical-0056', deck_id: 'deck-medical', sort_order: 56, front: "Cholecystitis", back: "Inflammation of the gallbladder, usually due to gallstones blocking the cystic duct. Presents with right upper quadrant pain, fever, and nausea (Murphy's sign positive). Treated with cholecystectomy." , front_translations: {"es":"Colecistite","de":"Cholezystitis","fr":"Cholécystite","tr":"Kolesistit","nl":"Cholecystitis","ru":"Холецистит","zh":"胆囊炎","pt_BR":"Colecistite","pt_PT":"Colecistite"}, back_translations: {"es":"Inflamación de la vesícula biliar, generalmente causada por cálculos biliares que bloqueiam el ducto cístico. Apresenta dor en el quadrante superior derecho, febre y náusea (señal de Murphy positivo). Tratada con colecistectomia.","de":"Entzündung der Gallenblase, meist durch Gallensteine, die den Ductus cysticus blockieren. Präsentation: Schmerzen im rechten Oberbauch, Fieber, Übelkeit (Murphy-Zeichen positiv). Behandlung mit Cholezystektomie.","fr":"Inflammation de la vésicule biliaire, généralement due à des calculs biliaires obstruant le canal cystique. Se manifeste par des douleurs dans le quadrant supérieur droit, de la fièvre et des nausées (signe de Murphy positif). Traitement par cholécystectomie.","tr":"Genellikle safra taşlarının kistik kanalı tıkaması nedeniyle safra kesesinin iltihabı. Sağ üst kadran ağrısı, ateş ve bulantıyla prezente olur (Murphy bulgusu pozitif). Kolesistektomi ile tedavi edilir.","nl":"Ontsteking van de galblaas, meestal door galstenen die de ductus cysticus blokkeren. Presenteert zich met pijn in het rechter bovenkwadrant, koorts en misselijkheid (teken van Murphy positief). Behandeld met cholecystectomie.","ru":"Воспаление желчного пузыря, как правило, из-за желчных камней, блокирующих пузырный проток. Проявляется болью в правом подреберье, лихорадкой и тошнотой (положительный симптом Мёрфи). Лечение: холецистэктомия.","zh":"胆囊炎症，通常由胆石阻塞胆囊管引起。表现为右上腹疼痛、发热、恶心（墨菲征阳性）。使用胆囊切除术治疗。","pt_BR":"Inflamação da vesícula biliar, geralmente causada por cálculos biliares que bloqueiam o ducto cístico. Apresenta dor no quadrante superior direito, febre e náusea (sinal de Murphy positivo). Tratada com colecistectomia.","pt_PT":"Inflamação da vesícula biliar, geralmente por cálculos biliares que obstruem o ducto cístico. Apresenta dor no quadrante superior direito, febre e náusea (sinal de Murphy positivo). Tratada com colecistectomia."}},
  { id: 'dc-medical-0057', deck_id: 'deck-medical', sort_order: 57, front: "Pancreatitis", back: "Inflammation of the pancreas. Most common causes: gallstones and alcohol. Acute: severe epigastric pain radiating to the back, elevated amylase and lipase. Chronic: leads to exocrine and endocrine insufficiency." , front_translations: {"es":"Pancreatite","de":"Pankreatitis","fr":"Pancréatite","tr":"Pankreatit","nl":"Pancreatitis","ru":"Панкреатит","zh":"胰腺炎","pt_BR":"Pancreatite","pt_PT":"Pancreatite"}, back_translations: {"es":"Inflamación del pancreas. Causas más comuns: cálculos biliares y álcool. Aguda: dor epigástrica intensa irradiando para las costas, amilase y lipase elevadas. Crónica: leva a la insuficiencia exócrina y endócrina.","de":"Entzündung der Bauchspeicheldrüse. Häufigste Ursachen: Gallensteine und Alkohol. Akut: starke epigastrische Schmerzen mit Ausstrahlung in den Rücken, erhöhte Amylase und Lipase. Chronisch: führt zu exokriner und endokriner Insuffizienz.","fr":"Inflammation du pancréas. Causes les plus fréquentes : calculs biliaires et alcool. Aiguë : douleur épigastrique sévère irradiant dans le dos, amylase et lipase élevées. Chronique : entraîne une insuffisance exocrine et endocrine.","tr":"Pankreasın iltihabı. En yaygın nedenler: safra taşları ve alkol. Akut: sırta yayılan şiddetli epigastrik ağrı, yüksek amilaz ve lipaz. Kronik: ekzokrin ve endokrin yetmezliğe yol açar.","nl":"Ontsteking van de alvleesklier. Meest voorkomende oorzaken: galstenen en alcohol. Acuut: ernstige epigastrische pijn uitstralend naar de rug, verhoogde amylase en lipase. Chronisch: leidt tot exocriene en endocriene insufficiëntie.","ru":"Воспаление поджелудочной железы. Наиболее частые причины: желчные камни и алкоголь. Острый: сильная боль в эпигастрии с иррадиацией в спину, повышение амилазы и липазы. Хронический: приводит к экзокринной и эндокринной недостаточности.","zh":"胰腺炎症。最常见原因：胆石和酒精。急性：剧烈上腹痛向背部放射，淀粉酶和脂肪酶升高。慢性：导致外分泌和内分泌功能不全。","pt_BR":"Inflamação do pâncreas. Causas mais comuns: cálculos biliares e álcool. Aguda: dor epigástrica intensa irradiando para as costas, amilase e lipase elevadas. Crônica: leva à insuficiência exócrina e endócrina.","pt_PT":"Inflamação do pâncreas. Causas mais comuns: cálculos biliares e álcool. Aguda: dor epigástrica intensa irradiando para as costas, amilase e lipase elevadas. Crónica: leva a insuficiência exócrina e endócrina."}},
  { id: 'dc-medical-0058', deck_id: 'deck-medical', sort_order: 58, front: "Cirrhosis", back: "End-stage liver disease characterized by fibrosis and nodular regeneration. Causes: alcohol, hepatitis B/C, NAFLD. Complications: portal hypertension, ascites, varices, hepatic encephalopathy, hepatocellular carcinoma." , front_translations: {"es":"Cirrose Hepática","de":"Leberzirrhose","fr":"Cirrhose hépatique","tr":"Siroz","nl":"Levercirrose","ru":"Цирроз печени","zh":"肝硬化","pt_BR":"Cirrose Hepática","pt_PT":"Cirrose Hepática"}, back_translations: {"es":"Enfermedad hepática en etapa terminal caracterizada por fibrose y regeneración nodular. Causas: álcool, hepatite B/C, DHGNA. Complicaciones: hipertensão portal, ascite, varizes, encefalopatia hepática, carcinoma hepatocelular.","de":"Endstadium der Lebererkrankung, gekennzeichnet durch Fibrose und noduläre Regeneration. Ursachen: Alkohol, Hepatitis B/C, NAFLD. Komplikationen: portale Hypertension, Aszites, Varizen, hepatische Enzephalopathie, hepatozelluläres Karzinom.","fr":"Maladie hépatique en phase terminale caractérisée par une fibrose et une régénération nodulaire. Causes : alcool, hépatite B/C, NAFLD. Complications : hypertension portale, ascite, varices, encéphalopathie hépatique, carcinome hépatocellulaire.","tr":"Fibrozis ve nodüler rejenerasyonla karakterize son dönem karaciğer hastalığı. Nedenler: alkol, hepatit B/C, NAFLD. Komplikasyonlar: portal hipertansiyon, asit, varis, hepatik ensefalopati, hepatoselüler karsinom.","nl":"Eindstadium leverziekte gekenmerkt door fibrose en nodulaire regeneratie. Oorzaken: alcohol, hepatitis B/C, NAFLD. Complicaties: portale hypertensie, ascites, varices, hepatische encefalopathie, hepatocellulair carcinoom.","ru":"Терминальная стадия заболевания печени, характеризующаяся фиброзом и узловой регенерацией. Причины: алкоголь, гепатит B/C, НАЖБП. Осложнения: портальная гипертензия, асцит, варикоз, печёночная энцефалопатия, гепатоцеллюлярная карцинома.","zh":"以纤维化和结节性再生为特征的终末期肝病。原因：酒精、乙型/丙型肝炎、NAFLD。并发症：门静脉高压、腹水、静脉曲张、肝性脑病、肝细胞癌。","pt_BR":"Doença hepática em estágio terminal caracterizada por fibrose e regeneração nodular. Causas: álcool, hepatite B/C, DHGNA. Complicações: hipertensão portal, ascite, varizes, encefalopatia hepática, carcinoma hepatocelular.","pt_PT":"Doença hepática em fase terminal caracterizada por fibrose e regeneração nodular. Causas: álcool, hepatite B/C, DHGNA. Complicações: hipertensão portal, ascite, varizes, encefalopatia hepática, carcinoma hepatocelular."}},
  { id: 'dc-medical-0059', deck_id: 'deck-medical', sort_order: 59, front: "Urinary Tract Infection (UTI)", back: "Bacterial infection of the urinary tract. Lower UTI (cystitis): dysuria, frequency, urgency. Upper UTI (pyelonephritis): fever, flank pain, systemic symptoms. Most common pathogen: E. coli. Treated with antibiotics." , front_translations: {"es":"Infección del Trato Urinário (ITU)","de":"Harnwegsinfekt (HWI)","fr":"Infection urinaire (IU)","tr":"İdrar Yolu Enfeksiyonu (İYE)","nl":"Urineweginfectie (UWI)","ru":"Инфекция мочевых путей (ИМП)","zh":"尿路感染（UTI）","pt_BR":"Infecção do Trato Urinário (ITU)","pt_PT":"Infeção do Trato Urinário (ITU)"}, back_translations: {"es":"Infección bacteriana del trato urinário. ITU baja (cistite): disúria, frecuencia, urgencia. ITU alta (pielonefrite): febre, dor en el flanco, síntomas sistemicos. Patógeno más comum: Y. coli. Tratada con antibióticos.","de":"Bakterielle Infektion der Harnwege. Unterer HWI (Zystitis): Dysurie, Harndrang, Pollakisurie. Oberer HWI (Pyelonephritis): Fieber, Flankenschmerz, systemische Symptome. Häufigster Erreger: E. coli. Behandlung mit Antibiotika.","fr":"Infection bactérienne du tractus urinaire. IU basse (cystite) : dysurie, pollakiurie, urgence mictionnelle. IU haute (pyélonéphrite) : fièvre, douleur lombaire, symptômes systémiques. Pathogène le plus fréquent : E. coli. Traité par antibiotiques.","tr":"İdrar yolunun bakteriyel enfeksiyonu. Alt İYE (sistit): dizüri, sık idrara çıkma, urgency. Üst İYE (piyelonefrit): ateş, yan ağrısı, sistemik semptomlar. En yaygın patojen: E. coli. Antibiyotiklerle tedavi edilir.","nl":"Bacteriële infectie van de urinewegen. Lagere UWI (cystitis): dysurie, frequentie, urgentie. Hogere UWI (pyelonefritis): koorts, flankpijn, systemische symptomen. Meest voorkomend pathogeen: E. coli. Behandeld met antibiotica.","ru":"Бактериальная инфекция мочевых путей. Нижняя ИМП (цистит): дизурия, учащённое мочеиспускание, ургентность. Верхняя ИМП (пиелонефрит): лихорадка, боль в пояснице, системные симптомы. Наиболее частый возбудитель: E. coli. Лечение: антибиотики.","zh":"尿道细菌感染。下尿路感染（膀胱炎）：排尿困难、尿频、尿急。上尿路感染（肾盂肾炎）：发热、腰痛、全身症状。最常见病原体：大肠杆菌。使用抗生素治疗。","pt_BR":"Infecção bacteriana do trato urinário. ITU baixa (cistite): disúria, frequência, urgência. ITU alta (pielonefrite): febre, dor no flanco, sintomas sistêmicos. Patógeno mais comum: E. coli. Tratada com antibióticos.","pt_PT":"Infeção bacteriana do trato urinário. ITU baixa (cistite): disúria, frequência, urgência. ITU alta (pielonefrite): febre, dor no flanco, sintomas sistémicos. Patógeno mais comum: E. coli. Tratada com antibióticos."}},
  { id: 'dc-medical-0060', deck_id: 'deck-medical', sort_order: 60, front: "Acute Kidney Injury (AKI)", back: "Sudden decrease in kidney function. Pre-renal (decreased blood flow), intrinsic renal (direct damage, e.g., ATN), or post-renal (obstruction). Manifests as rising creatinine and urea; may require dialysis." , front_translations: {"es":"Lesão Renal Aguda (LRA)","de":"Akute Nierenschädigung (AKI)","fr":"Insuffisance rénale aiguë (IRA)","tr":"Akut Böbrek Hasarı (ABH)","nl":"Acuut nierfalen (AKI)","ru":"Острое повреждение почек (ОПП)","zh":"急性肾损伤（AKI）","pt_BR":"Lesão Renal Aguda (LRA)","pt_PT":"Lesão Renal Aguda (LRA)"}, back_translations: {"es":"Disminución súbita de la función renal. Pré-renal (disminución del flujo sanguíneo), renal intrínseca (lesão direta, ex.: NTA) o pós-renal (obstrución). Se manifiesta con elevación de creatinina y ureia; puede requerer diálise.","de":"Plötzliche Abnahme der Nierenfunktion. Prärenalem (verminderter Blutfluss), intrinsisch renal (direkter Schaden, z. B. ATN) oder postrenalem (Obstruktion) Ursprungs. Manifestiert sich als Anstieg von Kreatinin und Harnstoff; kann Dialyse erfordern.","fr":"Diminution soudaine de la fonction rénale. Pré-rénale (diminution du débit sanguin), intrarénale (lésion directe, ex. NTA) ou post-rénale (obstruction). Se manifeste par une augmentation de la créatinine et de l'urée ; peut nécessiter une dialyse.","tr":"Böbrek fonksiyonunda ani azalma. Prerenal (azalmış kan akışı), intrinsik renal (doğrudan hasar, örn. ATN) veya postrenal (obstrüksiyon) kökenli olabilir. Yükselen kreatinin ve üre ile kendini gösterir; diyaliz gerektirebilir.","nl":"Plotselinge afname van de nierfunctie. Prerenaal (verminderde bloedstroom), intrinsiek renaal (directe schade, bijv. ATN) of postrenaal (obstructie). Manifesteert zich als stijgend creatinine en ureum; kan dialyse vereisen.","ru":"Внезапное снижение функции почек. Причины: преренальные (снижение кровотока), ренальные (прямое повреждение, например ОКН) или постренальные (обструкция). Проявляется повышением креатинина и мочевины; может потребоваться диализ.","zh":"肾功能突然下降。肾前性（血流减少）、肾性（直接损伤，如ATN）或肾后性（梗阻）。表现为肌酐和尿素氮升高；可能需要透析。","pt_BR":"Diminuição súbita da função renal. Pré-renal (diminuição do fluxo sanguíneo), renal intrínseca (lesão direta, ex.: NTA) ou pós-renal (obstrução). Manifesta-se com elevação de creatinina e ureia; pode requerer diálise.","pt_PT":"Diminuição súbita da função renal. Pré-renal (diminuição do fluxo sanguíneo), renal intrínseca (lesão direta, ex.: NTA) ou pós-renal (obstrução). Manifesta-se com elevação de creatinina e ureia; pode requerer diálise."}},
  { id: 'dc-medical-0061', deck_id: 'deck-medical', sort_order: 61, front: "Chronic Kidney Disease (CKD)", back: "Progressive loss of kidney function over months/years, defined by GFR <60 mL/min for >3 months. Staged 1–5; stage 5 is end-stage renal disease (ESRD) requiring dialysis or transplant." , front_translations: {"es":"Enfermedad Renal Crónica (DRC)","de":"Chronische Nierenerkrankung (CKD)","fr":"Maladie rénale chronique (MRC)","tr":"Kronik Böbrek Hastalığı (KBH)","nl":"Chronische nierziekte (CKD)","ru":"Хроническая болезнь почек (ХБП)","zh":"慢性肾脏病（CKD）","pt_BR":"Doença Renal Crônica (DRC)","pt_PT":"Doença Renal Crónica (DRC)"}, back_translations: {"es":"Perda progressiva de la función renal a lo ancho de meses/anos, definida por TFG <60 mL/min por >3 meses. Estadiada en 1–5; etapa 5 es a enfermedad renal en etapa terminal (DRET), exigindo diálise o transplante.","de":"Progressiver Verlust der Nierenfunktion über Monate/Jahre, definiert durch GFR <60 ml/min für >3 Monate. Stadien 1–5; Stadium 5 ist die terminale Niereninsuffizienz (ESRD), die Dialyse oder Transplantation erfordert.","fr":"Perte progressive de la fonction rénale sur des mois/années, définie par un DFG <60 mL/min pendant >3 mois. Stades 1 à 5 ; le stade 5 est l'insuffisance rénale terminale (IRT) nécessitant une dialyse ou une transplantation.","tr":"Aylar/yıllar içinde ilerleyici böbrek fonksiyon kaybı; GFR'nin >3 ay boyunca <60 mL/dak olması ile tanımlanır. Evre 1–5; evre 5, diyaliz veya transplantasyon gerektiren son dönem böbrek hastalığıdır (SDBY).","nl":"Progressief verlies van nierfunctie over maanden/jaren, gedefinieerd door GFR <60 mL/min gedurende >3 maanden. Stadia 1–5; stadium 5 is eindstadium nierziekte (ESRD) die dialyse of transplantatie vereist.","ru":"Прогрессирующая потеря функции почек на протяжении месяцев/лет, определяемая как СКФ <60 мл/мин в течение >3 месяцев. Стадии 1–5; стадия 5 — терминальная почечная недостаточность (ТПН), требующая диализа или трансплантации.","zh":"肾功能在数月/数年内逐渐丧失，定义为GFR <60 mL/min持续超过3个月。分为1–5期；第5期为终末期肾病（ESRD），需要透析或移植。","pt_BR":"Perda progressiva da função renal ao longo de meses/anos, definida por TFG <60 mL/min por >3 meses. Estadiada em 1–5; estágio 5 é a doença renal em estágio terminal (DRET), exigindo diálise ou transplante.","pt_PT":"Perda progressiva da função renal ao longo de meses/anos, definida por TFG <60 mL/min por >3 meses. Estadiada de 1 a 5; o estadio 5 é a doença renal em estadio terminal (DRET), requerendo diálise ou transplante."}},
  { id: 'dc-medical-0062', deck_id: 'deck-medical', sort_order: 62, front: "Sepsis", back: "A life-threatening organ dysfunction caused by a dysregulated host response to infection. Septic shock: sepsis plus circulatory failure (vasopressors required, lactate >2 mmol/L). Treated with early antibiotics and fluid resuscitation." , front_translations: {"es":"Sepse","de":"Sepsis","fr":"Sepsis","tr":"Sepsis","nl":"Sepsis","ru":"Сепсис","zh":"脓毒症","pt_BR":"Sepse","pt_PT":"Sépsis"}, back_translations: {"es":"Disfunción orgánica con riesgo de vida causada por respuesta desregulada del hospedero a la infección. Choque séptico: sepse con falencia circulatória (vasopressores necesarios, lactato >2 mmol/L). Tratada con antibióticos precoces y ressuscitación volemica.","de":"Lebensbedrohliches Organversagen durch eine dysregulierte Wirtsreaktion auf eine Infektion. Septischer Schock: Sepsis plus Kreislaufversagen (Vasopressoren erforderlich, Laktat >2 mmol/l). Behandlung: frühzeitige Antibiotikagabe und Volumentherapie.","fr":"Dysfonction organique mettant en jeu le pronostic vital causée par une réponse de l'hôte dérégulée à une infection. Choc septique : sepsis avec défaillance circulatoire (vasopresseurs nécessaires, lactate >2 mmol/L). Traité par antibiothérapie précoce et réanimation liquidienne.","tr":"Enfeksiyona karşı düzensiz bir konak yanıtından kaynaklanan yaşamı tehdit eden organ disfonksiyonu. Septik şok: sepsis artı dolaşım yetmezliği (vazopressör gerektirir, laktat >2 mmol/L). Erken antibiyotik ve sıvı resüsitasyonuyla tedavi edilir.","nl":"Levensbedreigende orgaandisfunctie veroorzaakt door een ontregelde reactie van de gastheer op een infectie. Septische shock: sepsis plus circulatoir falen (vasopressoren vereist, lactaat >2 mmol/L). Behandeld met vroege antibiotica en vochtresuscitatie.","ru":"Жизнеугрожающая органная дисфункция, вызванная нарушенным ответом организма на инфекцию. Септический шок: сепсис с циркуляторной недостаточностью (требуются вазопрессоры, лактат >2 ммоль/л). Лечение: ранняя антибиотикотерапия и инфузионная реанимация.","zh":"由宿主对感染的失调反应引起的危及生命的器官功能障碍。脓毒性休克：脓毒症合并循环衰竭（需要血管升压药，乳酸>2 mmol/L）。早期抗生素和液体复苏治疗。","pt_BR":"Disfunção orgânica com risco de vida causada por resposta desregulada do hospedeiro à infecção. Choque séptico: sepse com falência circulatória (vasopressores necessários, lactato >2 mmol/L). Tratada com antibióticos precoces e ressuscitação volêmica.","pt_PT":"Disfunção orgânica com risco de vida causada por resposta desregulada do hospedeiro à infeção. Choque séptico: sépsis com falência circulatória (vasopressores necessários, lactato >2 mmol/L). Tratada com antibióticos precoces e ressuscitação com fluidos."}},
  { id: 'dc-medical-0063', deck_id: 'deck-medical', sort_order: 63, front: "Anemia", back: "Decrease in the number of red blood cells or hemoglobin, reducing oxygen-carrying capacity. Classified by cause (iron deficiency, B12/folate deficiency, hemolysis, bone marrow failure) and by MCV (micro/normo/macrocytic)." , front_translations: {"es":"Anemia","de":"Anämie","fr":"Anémie","tr":"Anemi","nl":"Anemie","ru":"Анемия","zh":"贫血","pt_BR":"Anemia","pt_PT":"Anemia"}, back_translations: {"es":"Disminución del número de eritrócitos o hemoglobina, reduciendo a capacidad de transporte de oxígeno. Classificada por causa (deficiencia de ferro, B12/folato, hemólise, falencia de la médula ósea) y por VCM (micro/normo/macrocítica).","de":"Abnahme der Anzahl roter Blutkörperchen oder des Hämoglobins, was die Sauerstofftransportkapazität verringert. Klassifiziert nach Ursache (Eisenmangel, B12-/Folatmangel, Hämolyse, Knochenmarksversagen) und MCV (mikro-/normo-/makrozytär).","fr":"Diminution du nombre de globules rouges ou de l'hémoglobine, réduisant la capacité de transport de l'oxygène. Classifiée par cause (carence en fer, en B12/folates, hémolyse, insuffisance médullaire) et par VGM (micro/normo/macrocytaire).","tr":"Oksijen taşıma kapasitesini azaltan eritrosit sayısı veya hemoglobin düzeyindeki düşüş. Nedene göre (demir eksikliği, B12/folat eksikliği, hemoliz, kemik iliği yetmezliği) ve MCV'ye göre (mikro/normo/makrositik) sınıflandırılır.","nl":"Afname van het aantal rode bloedcellen of hemoglobine, waardoor de zuurstoftransportcapaciteit vermindert. Geclassificeerd naar oorzaak (ijzergebrek, B12-/folaatgebrek, hemolyse, beenmergfalen) en MCV (micro/normo/macrocytair).","ru":"Снижение количества эритроцитов или гемоглобина, уменьшающее способность крови переносить кислород. Классифицируется по причине (дефицит железа, B12/фолата, гемолиз, недостаточность костного мозга) и MCV (микро-/нормо-/макроцитарная).","zh":"红细胞数量或血红蛋白减少，降低氧气运输能力。按病因分类（缺铁性、B12/叶酸缺乏、溶血、骨髓衰竭）及按MCV分类（小细胞性/正细胞性/大细胞性）。","pt_BR":"Diminuição do número de eritrócitos ou hemoglobina, reduzindo a capacidade de transporte de oxigênio. Classificada por causa (deficiência de ferro, B12/folato, hemólise, falência da medula óssea) e por VCM (micro/normo/macrocítica).","pt_PT":"Diminuição do número de eritrócitos ou hemoglobina, reduzindo a capacidade de transporte de oxigénio. Classificada por causa (deficiência de ferro, B12/folato, hemólise, falência da medula óssea) e por VCM (micro/normo/macrocítica)."}},
  { id: 'dc-medical-0064', deck_id: 'deck-medical', sort_order: 64, front: "Deep Vein Thrombosis (DVT)", back: "A blood clot in a deep vein, usually in the leg. Risk factors: immobility, surgery, cancer, oral contraceptives, thrombophilia. Can dislodge and cause pulmonary embolism. Treated with anticoagulants." , front_translations: {"es":"Trombose Venosa Profunda (TVP)","de":"Tiefe Venenthrombose (TVT)","fr":"Thrombose veineuse profonde (TVP)","tr":"Derin Ven Trombozu (DVT)","nl":"Diepveneuze trombose (DVT)","ru":"Тромбоз глубоких вен (ТГВ)","zh":"深静脉血栓（DVT）","pt_BR":"Trombose Venosa Profunda (TVP)","pt_PT":"Trombose Venosa Profunda (TVP)"}, back_translations: {"es":"Coágulo sanguíneo en vena profunda, generalmente en la pierna. Fatores de riesgo: imobilidad, cirugía, cancer, anticoncepcionais orais, trombofilia. Puede se desprender y causar embolia pulmonar. Tratada con anticoagulantes.","de":"Blutgerinnsel in einer tiefen Vene, meist im Bein. Risikofaktoren: Immobilisation, Operationen, Krebs, orale Kontrazeptiva, Thrombophilie. Kann sich lösen und eine Lungenembolie verursachen. Behandlung mit Antikoagulanzien.","fr":"Caillot sanguin dans une veine profonde, généralement dans la jambe. Facteurs de risque : immobilité, chirurgie, cancer, contraceptifs oraux, thrombophilie. Peut se détacher et provoquer une embolie pulmonaire. Traité par anticoagulants.","tr":"Genellikle bacakta derin bir vende kan pıhtısı. Risk faktörleri: hareketsizlik, cerrahi, kanser, oral kontraseptifler, trombofili. Koparak pulmoner emboliye yol açabilir. Antikoagülanlarla tedavi edilir.","nl":"Een bloedstolsel in een diepe ader, meestal in het been. Risicofactoren: immobiliteit, operatie, kanker, orale anticonceptiva, trombofilie. Kan loslaten en longembolie veroorzaken. Behandeld met antistollingsmiddelen.","ru":"Тромб в глубокой вене, как правило, в ноге. Факторы риска: неподвижность, хирургические вмешательства, онкология, оральные контрацептивы, тромбофилия. Может оторваться и вызвать ТЭЛА. Лечение: антикоагулянты.","zh":"深静脉中的血栓，通常在腿部。危险因素：制动、手术、癌症、口服避孕药、易栓症。可脱落引起肺栓塞。使用抗凝药物治疗。","pt_BR":"Coágulo sanguíneo em veia profunda, geralmente na perna. Fatores de risco: imobilidade, cirurgia, câncer, anticoncepcionais orais, trombofilia. Pode se desprender e causar embolia pulmonar. Tratada com anticoagulantes.","pt_PT":"Coágulo sanguíneo numa veia profunda, geralmente na perna. Fatores de risco: imobilidade, cirurgia, cancro, contracetivos orais, trombofilia. Pode desprender-se e causar embolia pulmonar. Tratada com anticoagulantes."}},
  { id: 'dc-medical-0065', deck_id: 'deck-medical', sort_order: 65, front: "Osteoporosis", back: "Reduced bone mineral density (T-score ≤ −2.5 on DXA scan) increasing fracture risk, especially spine, hip, and wrist. Common in postmenopausal women. Treated with bisphosphonates, calcium, and vitamin D." , front_translations: {"es":"Osteoporose","de":"Osteoporose","fr":"Ostéoporose","tr":"Osteoporoz","nl":"Osteoporose","ru":"Остеопороз","zh":"骨质疏松症","pt_BR":"Osteoporose","pt_PT":"Osteoporose"}, back_translations: {"es":"Reducción de la densidad mineral ósea (T-escore ≤ −2,5 en la densitometria) con aumento del riesgo de fraturas, especialmente columna vertebral, cadera y muñeca. Comum en mujeres pós-menopáusicas. Tratada con bisfosfonatos, cálcio y vitamina D.","de":"Reduzierte Knochenmineraldichte (T-Score ≤ −2,5 im DXA-Scan) mit erhöhtem Frakturrisiko, besonders Wirbelsäule, Hüfte und Handgelenk. Häufig bei postmenopausalen Frauen. Behandlung mit Bisphosphonaten, Kalzium und Vitamin D.","fr":"Réduction de la densité minérale osseuse (T-score ≤ −2,5 à la densitométrie osseuse) augmentant le risque de fracture, notamment de la colonne vertébrale, de la hanche et du poignet. Fréquent chez les femmes ménopausées. Traité par bisphosphonates, calcium et vitamine D.","tr":"Artan kırık riskiyle birlikte azalmış kemik mineral yoğunluğu (DXA taramada T skoru ≤ −2,5); özellikle omurga, kalça ve bilek etkilenir. Postmenopozal kadınlarda yaygındır. Bifosfonatlar, kalsiyum ve D vitamini ile tedavi edilir.","nl":"Verminderde botmineraaldichtheid (T-score ≤ −2,5 op DXA-scan) met verhoogd fractuurrisico, vooral wervelkolom, heup en pols. Veel voorkomend bij postmenopauzale vrouwen. Behandeld met bisfosfonaten, calcium en vitamine D.","ru":"Снижение минеральной плотности костей (Т-балл ≤ −2,5 по DXA-денситометрии) с повышенным риском переломов, особенно позвоночника, бедра и запястья. Часто встречается у женщин в постменопаузе. Лечение: бисфосфонаты, кальций и витамин D.","zh":"骨矿物质密度降低（DXA扫描T值≤−2.5），骨折风险增加，尤其是脊椎、髋部和手腕。常见于绝经后女性。使用双膦酸盐、钙和维生素D治疗。","pt_BR":"Redução da densidade mineral óssea (T-escore ≤ −2,5 na densitometria) com aumento do risco de fraturas, especialmente coluna vertebral, quadril e pulso. Comum em mulheres pós-menopáusicas. Tratada com bisfosfonatos, cálcio e vitamina D.","pt_PT":"Redução da densidade mineral óssea (T-score ≤ −2,5 na densitometria óssea) com aumento do risco de fraturas, especialmente na coluna vertebral, anca e pulso. Comum em mulheres pós-menopáusicas. Tratada com bifosfonatos, cálcio e vitamina D."}},
  { id: 'dc-medical-0066', deck_id: 'deck-medical', sort_order: 66, front: "Rheumatoid Arthritis (RA)", back: "A chronic autoimmune inflammatory disease primarily affecting synovial joints symmetrically. Presents with morning stiffness >1 hour, swelling, erosions. Anti-CCP antibodies and RF positive. Treated with DMARDs (methotrexate first-line)." , front_translations: {"es":"Artrite Reumatoide (AR)","de":"Rheumatoide Arthritis (RA)","fr":"Polyarthrite rhumatoïde (PR)","tr":"Romatoid Artrit (RA)","nl":"Reumatoïde artritis (RA)","ru":"Ревматоидный артрит (РА)","zh":"类风湿关节炎（RA）","pt_BR":"Artrite Reumatoide (AR)","pt_PT":"Artrite Reumatoide (AR)"}, back_translations: {"es":"Enfermedad inflamatória autoimune crónica que afecta principalmente las articulaciones sinoviais de forma simétrica. Rigidez matinal >1 hora, edema, erosões. Anti-CCP y FR positivos. Tratada con DMARDs (metotrexato de primera línea).","de":"Chronisch autoimmune Entzündungserkrankung, die symmetrisch die Synovialgelenke betrifft. Morgensteifigkeit >1 Stunde, Schwellung, Erosionen. Anti-CCP-Antikörper und RF positiv. Behandlung mit DMARDs (Methotrexat als erste Wahl).","fr":"Maladie inflammatoire auto-immune chronique affectant principalement les articulations synoviales de manière symétrique. Raideur matinale >1 heure, gonflement, érosions. Anticorps anti-CCP et FR positifs. Traité par DMARDs (méthotrexate en première ligne).","tr":"Esas olarak sinoviyal eklemleri simetrik olarak etkileyen kronik otoimmün inflamatuar hastalık. Sabah tutukluğu >1 saat, şişlik, erozyon. Anti-CCP antikoru ve RF pozitif. DMARDs ile tedavi (ilk seçenek metotreksat).","nl":"Chronische auto-immuun inflammatoire aandoening die voornamelijk synoviale gewrichten symmetrisch aantast. Ochtendstijfheid >1 uur, zwelling, erosies. Anti-CCP-antistoffen en RF positief. Behandeld met DMARDs (methotrexaat als eerste keuze).","ru":"Хроническое аутоиммунное воспалительное заболевание, симметрично поражающее синовиальные суставы. Утренняя скованность >1 часа, отёк, эрозии. Антитела к ЦЦП и РФ положительные. Лечение: БПВП (метотрексат — препарат первого ряда).","zh":"慢性自身免疫性炎症性疾病，主要对称性累及滑膜关节。晨僵>1小时、肿胀、侵蚀。抗CCP抗体和RF阳性。使用DMARDs治疗（甲氨蝶呤为一线用药）。","pt_BR":"Doença inflamatória autoimune crônica que afeta principalmente as articulações sinoviais de forma simétrica. Rigidez matinal >1 hora, edema, erosões. Anti-CCP e FR positivos. Tratada com DMARDs (metotrexato de primeira linha).","pt_PT":"Doença inflamatória autoimune crónica que afeta principalmente as articulações sinoviais de forma simétrica. Rigidez matinal >1 hora, edema, erosões. Anti-CCP e FR positivos. Tratada com DMARDs (metotrexato em primeira linha)."}},
  { id: 'dc-medical-0067', deck_id: 'deck-medical', sort_order: 67, front: "Osteoarthritis (OA)", back: "Degenerative joint disease caused by wear and tear of cartilage. Most common in weight-bearing joints (knees, hips) and hands. Pain worsens with activity and improves with rest. Treatment is symptomatic." , front_translations: {"es":"Osteoartrite (OA)","de":"Arthrose (OA)","fr":"Arthrose","tr":"Osteoartrit (OA)","nl":"Artrose (OA)","ru":"Остеоартрит (ОА)","zh":"骨关节炎（OA）","pt_BR":"Osteoartrite (OA)","pt_PT":"Osteoartrose (OA)"}, back_translations: {"es":"Enfermedad articular degenerativa causada por el desgaste de la cartílago. Más comum en las articulaciones de suporte de carga (rodillas, quadris) y manos. La dor piora con a atividad y melhora con el reposo. El tratamiento es sintomático.","de":"Degenerative Gelenkerkrankung durch Verschleiß des Knorpels. Am häufigsten in gewichttragenden Gelenken (Knie, Hüfte) und den Händen. Schmerzen verschlimmern sich bei körperlicher Aktivität und bessern sich in Ruhe. Behandlung ist symptomatisch.","fr":"Maladie articulaire dégénérative causée par l'usure du cartilage. La plus fréquente dans les articulations portantes (genoux, hanches) et les mains. La douleur s'aggrave à l'activité et s'améliore au repos. Le traitement est symptomatique.","tr":"Kıkırdağın aşınmasından kaynaklanan dejeneratif eklem hastalığı. En sık ağırlık taşıyan eklemlerde (diz, kalça) ve ellerde görülür. Ağrı aktiviteyle artar, istirahatle azalır. Tedavi semptomatiktir.","nl":"Degeneratieve gewrichtsaandoening veroorzaakt door slijtage van het kraakbeen. Meest voorkomend in gewichtdragende gewrichten (knieën, heupen) en handen. Pijn verergert bij activiteit en verbetert met rust. Behandeling is symptomatisch.","ru":"Дегенеративное заболевание суставов, вызванное износом хряща. Чаще всего поражаются нагрузочные суставы (колени, бёдра) и кисти рук. Боль усиливается при нагрузке и уменьшается в покое. Лечение симптоматическое.","zh":"由软骨磨损引起的退行性关节病。最常见于承重关节（膝、髋）和手部。活动时疼痛加重，休息后缓解。治疗以对症为主。","pt_BR":"Doença articular degenerativa causada pelo desgaste da cartilagem. Mais comum nas articulações de suporte de carga (joelhos, quadris) e mãos. A dor piora com a atividade e melhora com o repouso. O tratamento é sintomático.","pt_PT":"Doença articular degenerativa causada pelo desgaste da cartilagem. Mais comum nas articulações de suporte de carga (joelhos, ancas) e mãos. A dor agrava com a atividade e melhora com o repouso. O tratamento é sintomático."}},
  { id: 'dc-medical-0068', deck_id: 'deck-medical', sort_order: 68, front: "Hypothyroidism", back: "Insufficient thyroid hormone production. Causes: Hashimoto's thyroiditis (autoimmune, most common), iodine deficiency. Symptoms: fatigue, weight gain, cold intolerance, constipation, bradycardia, myxedema. Treated with levothyroxine." , front_translations: {"es":"Hipotireoidismo","de":"Hypothyreose","fr":"Hypothyroïdie","tr":"Hipotiroidizm","nl":"Hypothyreoïdie","ru":"Гипотиреоз","zh":"甲状腺功能减退症","pt_BR":"Hipotireoidismo","pt_PT":"Hipotiroidismo"}, back_translations: {"es":"Producción insuficiente de hormona tireoidiano. Causas: tireoidite de Hashimoto (autoimune, más comum), deficiencia de iodo. Síntomas: fadiga, ganho de peso, intolerancia al frio, constipación, bradicardia, mixedema. Tratado con levotiroxina.","de":"Unzureichende Schilddrüsenhormonproduktion. Ursachen: Hashimoto-Thyreoiditis (Autoimmun, häufigste), Jodmangel. Symptome: Erschöpfung, Gewichtszunahme, Kälteintoleranz, Verstopfung, Bradykardie, Myxödem. Behandlung mit Levothyroxin.","fr":"Production insuffisante d'hormones thyroïdiennes. Causes : thyroïdite de Hashimoto (auto-immune, la plus fréquente), carence en iode. Symptômes : fatigue, prise de poids, intolérance au froid, constipation, bradycardie, myxœdème. Traité par lévothyroxine.","tr":"Yetersiz tiroid hormonu üretimi. Nedenler: Hashimoto tiroiditi (otoimmün, en yaygın), iyot eksikliği. Belirtiler: yorgunluk, kilo alımı, soğuk intoleransı, kabızlık, bradikardi, miksödem. Levotiroksin ile tedavi edilir.","nl":"Onvoldoende productie van schildklierhormoon. Oorzaken: Hashimoto-thyroïditis (auto-immuun, meest voorkomend), jodiumtekort. Symptomen: vermoeidheid, gewichtstoename, koudegevoeligheid, obstipatie, bradycardie, myxoedeem. Behandeld met levothyroxine.","ru":"Недостаточная выработка гормонов щитовидной железы. Причины: тиреоидит Хашимото (аутоиммунный, наиболее частый), дефицит йода. Симптомы: утомляемость, прибавка в весе, непереносимость холода, запоры, брадикардия, микседема. Лечение: левотироксин.","zh":"甲状腺激素分泌不足。原因：桥本甲状腺炎（自身免疫性，最常见）、碘缺乏。症状：乏力、体重增加、怕冷、便秘、心动过缓、黏液性水肿。使用左甲状腺素治疗。","pt_BR":"Produção insuficiente de hormônio tireoidiano. Causas: tireoidite de Hashimoto (autoimune, mais comum), deficiência de iodo. Sintomas: fadiga, ganho de peso, intolerância ao frio, constipação, bradicardia, mixedema. Tratado com levotiroxina.","pt_PT":"Produção insuficiente de hormona tiroideia. Causas: tiroidite de Hashimoto (autoimune, mais comum), deficiência de iodo. Sintomas: fadiga, aumento de peso, intolerância ao frio, obstipação, bradicardia, mixedema. Tratado com levotiroxina."}},
  { id: 'dc-medical-0069', deck_id: 'deck-medical', sort_order: 69, front: "Hyperthyroidism", back: "Excess thyroid hormone production. Causes: Graves' disease (autoimmune, most common), toxic nodule. Symptoms: weight loss, heat intolerance, tachycardia, tremor, exophthalmos (Graves'). Treated with antithyroids, radioiodine, or surgery." , front_translations: {"es":"Hipertireoidismo","de":"Hyperthyreose","fr":"Hyperthyroïdie","tr":"Hipertiroidizm","nl":"Hyperthyreoïdie","ru":"Гипертиреоз","zh":"甲状腺功能亢进症","pt_BR":"Hipertireoidismo","pt_PT":"Hipertiroidismo"}, back_translations: {"es":"Producción excessiva de hormona tireoidiano. Causas: enfermedad de Graves (autoimune, más comum), nódulo tóxico. Síntomas: perda de peso, intolerancia al calor, taquicardia, tremor, exoftalmia (Graves). Tratado con antitireoideos, radioiodo o cirugía.","de":"Übermäßige Schilddrüsenhormonproduktion. Ursachen: Morbus Basedow (Autoimmun, häufigste), toxisches Adenom. Symptome: Gewichtsverlust, Wärmeintoleranz, Tachykardie, Tremor, Exophthalmus (Basedow). Behandlung mit Thyreostatika, Radioiod oder Operation.","fr":"Excès de production d'hormones thyroïdiennes. Causes : maladie de Basedow (auto-immune, la plus fréquente), nodule toxique. Symptômes : perte de poids, intolérance à la chaleur, tachycardie, tremblements, exophtalmie (Basedow). Traité par antithyroïdiens, iode radioactif ou chirurgie.","tr":"Aşırı tiroid hormonu üretimi. Nedenler: Graves hastalığı (otoimmün, en yaygın), toksik nodül. Belirtiler: kilo kaybı, sıcak intoleransı, taşikardi, tremor, egzoftalmi (Graves). Antitiroid ilaçlar, radyoiyot veya cerrahi ile tedavi edilir.","nl":"Overmatige productie van schildklierhormoon. Oorzaken: ziekte van Graves (auto-immuun, meest voorkomend), toxisch nodulair. Symptomen: gewichtsverlies, warmte-intolerantie, tachycardie, tremor, exoftalmie (Graves). Behandeld met antithyroïda, radioactief jodium of chirurgie.","ru":"Избыточная выработка гормонов щитовидной железы. Причины: болезнь Грейвса (аутоиммунная, наиболее частая), токсическая аденома. Симптомы: потеря веса, непереносимость тепла, тахикардия, тремор, экзофтальм (при болезни Грейвса). Лечение: тиреостатики, радиойод или операция.","zh":"甲状腺激素分泌过多。原因：Graves病（自身免疫性，最常见）、毒性结节。症状：体重减轻、怕热、心动过速、震颤、眼球突出（Graves病）。使用抗甲状腺药物、放射性碘或手术治疗。","pt_BR":"Produção excessiva de hormônio tireoidiano. Causas: doença de Graves (autoimune, mais comum), nódulo tóxico. Sintomas: perda de peso, intolerância ao calor, taquicardia, tremor, exoftalmia (Graves). Tratado com antitireoideos, radioiodo ou cirurgia.","pt_PT":"Produção excessiva de hormona tiroideia. Causas: doença de Graves (autoimune, mais comum), nódulo tóxico. Sintomas: perda de peso, intolerância ao calor, taquicardia, tremor, exoftalmia (Graves). Tratado com antitiróideos, radioiodo ou cirurgia."}},
  { id: 'dc-medical-0070', deck_id: 'deck-medical', sort_order: 70, front: "Epilepsy", back: "A neurological disorder characterized by recurrent unprovoked seizures due to abnormal electrical activity in the brain. Classified by seizure type (focal vs. generalized). Treated with antiepileptic drugs (AEDs)." , front_translations: {"es":"Epilepsia","de":"Epilepsie","fr":"Épilepsie","tr":"Epilepsi","nl":"Epilepsie","ru":"Эпилепсия","zh":"癫痫","pt_BR":"Epilepsia","pt_PT":"Epilepsia"}, back_translations: {"es":"Enfermedad neurológica caracterizada por convulsões no provocadas recorrentes debido a atividad eléctrica anormal en el cerebro. Classificada por tipo de convulsão (focal vs. generalizada). Tratada con antiepilépticos (AED).","de":"Neurologische Erkrankung, charakterisiert durch wiederkehrende unprovozierte Anfälle aufgrund abnormaler elektrischer Aktivität im Gehirn. Klassifiziert nach Anfallstyp (fokal vs. generalisiert). Behandlung mit Antiepileptika (AED).","fr":"Trouble neurologique caractérisé par des crises récurrentes non provoquées dues à une activité électrique anormale dans le cerveau. Classifié par type de crise (focale vs. généralisée). Traité par antiépileptiques (AED).","tr":"Beyindeki anormal elektriksel aktivite nedeniyle tekrarlayan provoke edilmemiş nöbetlerle karakterize nörolojik bozukluk. Nöbet tipine göre sınıflandırılır (fokal ve jeneralize). Antiepileptik ilaçlarla (AEİ) tedavi edilir.","nl":"Neurologische aandoening gekenmerkt door recidiverende ongeprovoceerde aanvallen door abnormale elektrische activiteit in de hersenen. Geclassificeerd naar aanvalstype (focaal vs. gegeneraliseerd). Behandeld met anti-epileptica (AED).","ru":"Неврологическое расстройство, характеризующееся повторяющимися неспровоцированными судорожными приступами, вызванными аномальной электрической активностью в мозге. Классифицируется по типу приступов (фокальные и генерализованные). Лечение: противоэпилептические препараты (ПЭП).","zh":"以脑内异常电活动导致的反复无诱因发作为特征的神经系统疾病。按发作类型分类（局灶性与全面性）。使用抗癫痫药（AED）治疗。","pt_BR":"Doença neurológica caracterizada por convulsões não provocadas recorrentes devido a atividade elétrica anormal no cérebro. Classificada por tipo de convulsão (focal vs. generalizada). Tratada com antiepilépticos (AED).","pt_PT":"Doença neurológica caracterizada por convulsões não provocadas recorrentes devido a atividade elétrica anormal no cérebro. Classificada por tipo de convulsão (focal vs. generalizada). Tratada com antiepilépticos (AED)."}},
  { id: 'dc-medical-0071', deck_id: 'deck-medical', sort_order: 71, front: "Meningitis", back: "Inflammation of the meninges (protective membranes surrounding the brain and spinal cord). Classic triad: headache, fever, neck stiffness. Bacterial (medical emergency) or viral. Lumbar puncture is diagnostic." , front_translations: {"es":"Meningite","de":"Meningitis","fr":"Méningite","tr":"Menenjit","nl":"Meningitis","ru":"Менингит","zh":"脑膜炎","pt_BR":"Meningite","pt_PT":"Meningite"}, back_translations: {"es":"Inflamación de las meninges (membranas protetoras alrededor del cerebro y de la medula espinal). Tríade clássica: cefaleia, febre, rigidez de nuca. Bacteriana (emergencia médica) o viral. La punción lombar es diagnóstica.","de":"Entzündung der Meningen (Schutzschichten um Gehirn und Rückenmark). Klassische Trias: Kopfschmerzen, Fieber, Nackensteife. Bakteriell (medizinischer Notfall) oder viral. Lumbalpunktion ist diagnostisch.","fr":"Inflammation des méninges (membranes protectrices entourant le cerveau et la moelle épinière). Triade classique : céphalées, fièvre, raideur nucale. Bactérienne (urgence médicale) ou virale. La ponction lombaire est diagnostique.","tr":"Meninkslerin (beyin ve omurilik etrafındaki koruyucu zarlar) iltihabı. Klasik triad: baş ağrısı, ateş, ense sertliği. Bakteriyel (tıbbi acil durum) veya viral. Lomber ponksiyon tanısaldır.","nl":"Ontsteking van de hersenvliezen (beschermende membranen rond de hersenen en het ruggenmerg). Klassieke triade: hoofdpijn, koorts, nekstijfheid. Bacterieel (medische noodtoestand) of viraal. Lumbale punctie is diagnostisch.","ru":"Воспаление мозговых оболочек (защитных оболочек головного и спинного мозга). Классическая триада: головная боль, лихорадка, ригидность затылочных мышц. Бактериальный (неотложное состояние) или вирусный. Диагноз устанавливается при люмбальной пункции.","zh":"脑膜（包绕脑和脊髓的保护膜）炎症。经典三联征：头痛、发热、颈项强直。细菌性（急症）或病毒性。腰椎穿刺确诊。","pt_BR":"Inflamação das meninges (membranas protetoras ao redor do cérebro e da medula espinal). Tríade clássica: cefaleia, febre, rigidez de nuca. Bacteriana (emergência médica) ou viral. A punção lombar é diagnóstica.","pt_PT":"Inflamação das meninges (membranas protetoras que envolvem o cérebro e a medula espinal). Tríade clássica: cefaleia, febre, rigidez da nuca. Bacteriana (emergência médica) ou viral. A punção lombar é diagnóstica."}},
  { id: 'dc-medical-0072', deck_id: 'deck-medical', sort_order: 72, front: "Multiple Sclerosis (MS)", back: "An autoimmune demyelinating disease of the CNS. Lesions (plaques) disrupt nerve signal conduction. Symptoms vary widely; relapsing-remitting MS is most common. MRI shows white matter lesions." , front_translations: {"es":"Esclerose Múltipla (EM)","de":"Multiple Sklerose (MS)","fr":"Sclérose en plaques (SEP)","tr":"Multipl Skleroz (MS)","nl":"Multiple sclerose (MS)","ru":"Рассеянный склероз (РС)","zh":"多发性硬化症（MS）","pt_BR":"Esclerose Múltipla (EM)","pt_PT":"Esclerose Múltipla (EM)"}, back_translations: {"es":"Enfermedad desmielinizante autoimune del SNC. Lesões (placas) perturbam a condución nervosa. Los síntomas variam amplamente; a EM remitente-recorrente es a más comum. La RMN mostra lesões en la sustancia branca.","de":"Autoimmune demyelinisierende Erkrankung des ZNS. Läsionen (Plaques) stören die Nervenleitung. Symptome sind vielfältig; schubförmig-remittierende MS ist am häufigsten. MRT zeigt Läsionen der weißen Substanz.","fr":"Maladie démyélinisante auto-immune du SNC. Les lésions (plaques) perturbent la conduction nerveuse. Les symptômes sont très variés ; la SEP rémittente-récurrente est la plus fréquente. L'IRM montre des lésions de la substance blanche.","tr":"MSS'nin otoimmün demiyelinizan hastalığı. Lezyonlar (plaklar) sinir iletimini bozar. Semptomlar geniş bir yelpazede yer alır; relapsing-remitting MS en yaygın formdur. MRI beyaz cevher lezyonlarını gösterir.","nl":"Auto-immuun demyeliniserende aandoening van het CZS. Laesies (plaques) verstoren de zenuwgeleiding. Symptomen variëren sterk; relapsing-remitting MS is het meest voorkomend. MRI toont witte stoflaesies.","ru":"Аутоиммунное демиелинизирующее заболевание ЦНС. Очаги (бляшки) нарушают проведение нервных импульсов. Симптомы разнообразны; ремиттирующий РС — наиболее распространённая форма. МРТ выявляет очаги в белом веществе.","zh":"中枢神经系统自身免疫性脱髓鞘疾病。病灶（斑块）破坏神经传导。症状多样；复发-缓解型MS最常见。MRI显示白质病灶。","pt_BR":"Doença desmielinizante autoimune do SNC. Lesões (placas) perturbam a condução nervosa. Os sintomas variam amplamente; a EM remitente-recorrente é a mais comum. A RMN mostra lesões na substância branca.","pt_PT":"Doença desmielinizante autoimune do SNC. Lesões (placas) perturbam a condução nervosa. Os sintomas são muito variados; a EM remitente-recorrente é a forma mais comum. A RM mostra lesões na substância branca."}},
  { id: 'dc-medical-0073', deck_id: 'deck-medical', sort_order: 73, front: "Parkinson's Disease", back: "A neurodegenerative disorder caused by loss of dopaminergic neurons in the substantia nigra. Triad: resting tremor, rigidity, bradykinesia. Also: postural instability. Lewy bodies (α-synuclein) are the pathological hallmark. Treated with levodopa." , front_translations: {"es":"Enfermedad de Parkinson","de":"Parkinson-Krankheit","fr":"Maladie de Parkinson","tr":"Parkinson Hastalığı","nl":"Ziekte van Parkinson","ru":"Болезнь Паркинсона","zh":"帕金森病","pt_BR":"Doença de Parkinson","pt_PT":"Doença de Parkinson"}, back_translations: {"es":"Enfermedad neurodegenerativa causada por la perda de neuronas dopaminérgicos en la sustancia negra. Tríade: tremor de reposo, rigidez, bradicinesia. También: instabilidad postural. Cuerpos de Lewy (α-sinucleína) son el marcador patológico. Tratada con levodopa.","de":"Neurodegenerative Erkrankung durch Verlust dopaminerger Neurone in der Substantia nigra. Trias: Ruhetremor, Rigidität, Bradykinese. Auch: posturale Instabilität. Lewy-Körperchen (α-Synuklein) sind das pathologische Kennzeichen. Behandlung mit Levodopa.","fr":"Maladie neurodégénérative causée par la perte de neurones dopaminergiques dans la substance noire. Triade : tremblement de repos, rigidité, bradykinésie. Également : instabilité posturale. Les corps de Lewy (α-synucléine) sont la marque pathologique. Traité par lévodopa.","tr":"Substantia nigra'daki dopaminerjik nöronların kaybından kaynaklanan nörodejeneratif bozukluk. Triad: istirahat tremoru, rijidite, bradikinezi. Aynı zamanda: postüral instabilite. Lewy cisimcikleri (α-sinüklein) patolojik belirteçtir. Levodopa ile tedavi edilir.","nl":"Neurodegeneratieve aandoening veroorzaakt door verlies van dopaminerge neuronen in de substantia nigra. Triade: rusttremor, rigiditeit, bradykinesie. Ook: posturale instabiliteit. Lewy-lichaampjes (α-synucleïne) zijn het pathologische kenmerk. Behandeld met levodopa.","ru":"Нейродегенеративное заболевание, вызванное гибелью дофаминергических нейронов в чёрной субстанции. Триада: тремор покоя, ригидность, брадикинезия. Также: постуральная нестабильность. Тельца Леви (α-синуклеин) — патоморфологический маркёр. Лечение: леводопа.","zh":"由黑质多巴胺能神经元丧失引起的神经退行性疾病。三联征：静止性震颤、强直、运动迟缓。还有：姿势不稳。路易体（α-突触核蛋白）是病理学标志。使用左旋多巴治疗。","pt_BR":"Doença neurodegenerativa causada pela perda de neurônios dopaminérgicos na substância negra. Tríade: tremor de repouso, rigidez, bradicinesia. Também: instabilidade postural. Corpos de Lewy (α-sinucleína) são o marcador patológico. Tratada com levodopa.","pt_PT":"Doença neurodegenerativa causada pela perda de neurónios dopaminérgicos na substância negra. Tríade: tremor de repouso, rigidez, bradicinesia. Também: instabilidade postural. Corpos de Lewy (α-sinucleína) são o marcador patológico. Tratada com levodopa."}},
  { id: 'dc-medical-0074', deck_id: 'deck-medical', sort_order: 74, front: "Alzheimer's Disease", back: "The most common cause of dementia. Progressive loss of memory and cognitive function. Pathology: amyloid plaques (Aβ) and neurofibrillary tangles (tau). No cure; acetylcholinesterase inhibitors may slow progression." , front_translations: {"es":"Enfermedad de Alzheimer","de":"Alzheimer-Krankheit","fr":"Maladie d'Alzheimer","tr":"Alzheimer Hastalığı","nl":"Ziekte van Alzheimer","ru":"Болезнь Альцгеймера","zh":"阿尔茨海默病","pt_BR":"Doença de Alzheimer","pt_PT":"Doença de Alzheimer"}, back_translations: {"es":"La causa más comum de demencia. Perda progressiva de memoria y función cognitiva. Patologia: placas amiloides (Aβ) y emaranhados neurofibrilares (tau). Sin cura; inibidores de la acetilcolinesterase pueden retardar a progresión.","de":"Häufigste Ursache der Demenz. Progressiver Verlust von Gedächtnis und kognitiver Funktion. Pathologie: Amyloid-Plaques (Aβ) und neurofibrilläre Tangles (Tau). Keine Heilung; Acetylcholinesterase-Hemmer können die Progression verlangsamen.","fr":"La cause la plus fréquente de démence. Perte progressive de la mémoire et des fonctions cognitives. Pathologie : plaques amyloïdes (Aβ) et dégénérescences neurofibrillaires (tau). Pas de guérison ; les inhibiteurs de l'acétylcholinestérase peuvent ralentir la progression.","tr":"Demansın en yaygın nedeni. Bellek ve bilişsel fonksiyonun ilerleyici kaybı. Patoloji: amiloid plakları (Aβ) ve nörofibriler yumaklar (tau). Tedavisi yoktur; asetilkolinesteraz inhibitörleri ilerlemeyi yavaşlatabilir.","nl":"De meest voorkomende oorzaak van dementie. Progressief verlies van geheugen en cognitieve functie. Pathologie: amyloïde plaques (Aβ) en neurofibrillaire tangles (tau). Geen genezing; acetylcholinesteraseremmers kunnen de progressie vertragen.","ru":"Наиболее частая причина деменции. Прогрессирующая потеря памяти и когнитивных функций. Патология: амилоидные бляшки (Aβ) и нейрофибриллярные клубки (тау). Лечения нет; ингибиторы ацетилхолинэстеразы могут замедлить прогрессирование.","zh":"痴呆最常见的原因。记忆和认知功能进行性丧失。病理：淀粉样蛋白斑块（Aβ）和神经原纤维缠结（tau蛋白）。无法治愈；乙酰胆碱酯酶抑制剂可能减缓进展。","pt_BR":"A causa mais comum de demência. Perda progressiva de memória e função cognitiva. Patologia: placas amiloides (Aβ) e emaranhados neurofibrilares (tau). Sem cura; inibidores da acetilcolinesterase podem retardar a progressão.","pt_PT":"A causa mais comum de demência. Perda progressiva de memória e função cognitiva. Patologia: placas amiloides (Aβ) e emaranhados neurofibrilares (tau). Sem cura; os inibidores da acetilcolinesterase podem abrandar a progressão."}},
  { id: 'dc-medical-0075', deck_id: 'deck-medical', sort_order: 75, front: "Depression (Major Depressive Disorder)", back: "Persistent depressed mood and loss of interest lasting ≥2 weeks plus ≥5 symptoms (sleep, appetite, energy, concentration, guilt, psychomotor changes, suicidal ideation). Treated with SSRIs and psychotherapy." , front_translations: {"es":"Depresión (Trastorno Depressivo Mayor)","de":"Depression (Major Depression)","fr":"Dépression (Trouble dépressif majeur)","tr":"Depresyon (Majör Depresif Bozukluk)","nl":"Depressie (Majeure depressieve stoornis)","ru":"Депрессия (Большое депрессивное расстройство)","zh":"抑郁症（重度抑郁障碍）","pt_BR":"Depressão (Transtorno Depressivo Maior)","pt_PT":"Depressão (Perturbação Depressiva Major)"}, back_translations: {"es":"Humor deprimido persistente y perda de interesse por ≥2 semanas más ≥5 síntomas (sono, apetite, energía, concentración, culpa, alteraciones psicomotoras, ideación suicida). Tratada con ISRS y psicoterapia.","de":"Anhaltend depressive Stimmung und Interessenverlust über ≥2 Wochen plus ≥5 Symptome (Schlaf, Appetit, Energie, Konzentration, Schuldgefühle, psychomotorische Veränderungen, Suizidgedanken). Behandlung mit SSRIs und Psychotherapie.","fr":"Humeur dépressive persistante et perte d'intérêt pendant ≥2 semaines plus ≥5 symptômes (sommeil, appétit, énergie, concentration, culpabilité, changements psychomoteurs, idées suicidaires). Traité par ISRS et psychothérapie.","tr":"≥2 hafta süren kalıcı depresif ruh hali ve ilgi kaybı ile birlikte ≥5 semptom (uyku, iştah, enerji, konsantrasyon, suçluluk, psikomotor değişiklikler, intihar düşünceleri). SSRI ve psikoterapi ile tedavi edilir.","nl":"Aanhoudend depressieve stemming en verlies van interesse gedurende ≥2 weken plus ≥5 symptomen (slaap, eetlust, energie, concentratie, schuldgevoel, psychomotorische veranderingen, suïcidale gedachten). Behandeld met SSRI's en psychotherapie.","ru":"Стойко сниженное настроение и утрата интереса продолжительностью ≥2 недель плюс ≥5 симптомов (сон, аппетит, энергия, концентрация, чувство вины, психомоторные изменения, суицидальные мысли). Лечение: СИОЗС и психотерапия.","zh":"持续≥2周的抑郁情绪和兴趣丧失，加上≥5项症状（睡眠、食欲、精力、注意力、内疚感、精神运动改变、自杀念头）。使用SSRIs和心理治疗。","pt_BR":"Humor deprimido persistente e perda de interesse por ≥2 semanas mais ≥5 sintomas (sono, apetite, energia, concentração, culpa, alterações psicomotoras, ideação suicida). Tratada com ISRS e psicoterapia.","pt_PT":"Humor deprimido persistente e perda de interesse por ≥2 semanas mais ≥5 sintomas (sono, apetite, energia, concentração, culpa, alterações psicomotoras, ideação suicida). Tratada com ISRS e psicoterapia."}},
  { id: 'dc-medical-0076', deck_id: 'deck-medical', sort_order: 76, front: "GFR — Glomerular Filtration Rate", back: "The rate at which the kidneys filter blood (mL/min). Normal >90 mL/min. Used to stage CKD. Estimated (eGFR) using serum creatinine, age, and sex (CKD-EPI equation)." , front_translations: {"es":"TFG — Taxa de Filtración Glomerular","de":"GFR — Glomeruläre Filtrationsrate","fr":"DFG — Débit de Filtration Glomérulaire","tr":"GFR — Glomerüler Filtrasyon Hızı","nl":"GFR — Glomerulaire Filtratiesnelheid","ru":"СКФ — Скорость клубочковой фильтрации","zh":"GFR — 肾小球滤过率","pt_BR":"TFG — Taxa de Filtração Glomerular","pt_PT":"TFG — Taxa de Filtração Glomerular"}, back_translations: {"es":"La taxa en la qual los riñones filtram el sangre (mL/min). Normal >90 mL/min. Usada para estadiar a DRC. Estimada (TFGe) usando creatinina sérica, edad y sexo (ecuación CKD-EPI).","de":"Die Rate, mit der die Nieren Blut filtern (mL/min). Normal >90 mL/min. Zur Stadieneinteilung der CKD verwendet. Geschätzt (eGFR) anhand von Serumkreatinin, Alter und Geschlecht (CKD-EPI-Gleichung).","fr":"La vitesse à laquelle les reins filtrent le sang (mL/min). Normal >90 mL/min. Utilisé pour stadifier la MRC. Estimé (DFGe) à partir de la créatinine sérique, de l'âge et du sexe (équation CKD-EPI).","tr":"Böbreklerin kanı filtreleme hızı (mL/dak). Normal >90 mL/dak. KBH evrelemesinde kullanılır. Serum kreatinini, yaş ve cinsiyet kullanılarak tahmin edilir (eGFR) (CKD-EPI denklemi).","nl":"De snelheid waarmee de nieren bloed filteren (mL/min). Normaal >90 mL/min. Gebruikt voor stadiëring van CNI. Geschat (eGFR) op basis van serumcreatinine, leeftijd en geslacht (CKD-EPI-vergelijking).","ru":"Скорость фильтрации крови почками (мл/мин). Норма >90 мл/мин. Используется для стадирования ХБП. Оценивается (рСКФ) по сывороточному креатинину, возрасту и полу (уравнение CKD-EPI).","zh":"肾脏过滤血液的速率（mL/min）。正常值 >90 mL/min。用于慢性肾病分期。通过血清肌酐、年龄和性别估算（eGFR）（CKD-EPI公式）。","pt_BR":"A taxa na qual os rins filtram o sangue (mL/min). Normal >90 mL/min. Usada para estadiar a DRC. Estimada (TFGe) usando creatinina sérica, idade e sexo (equação CKD-EPI).","pt_PT":"A taxa à qual os rins filtram o sangue (mL/min). Normal >90 mL/min. Usada para estadiar a DRC. Estimada (TFGe) usando creatinina sérica, idade e sexo (equação CKD-EPI)."}},
  { id: 'dc-medical-0077', deck_id: 'deck-medical', sort_order: 77, front: "CBC — Complete Blood Count", back: "A blood test measuring RBC count, hemoglobin, hematocrit, WBC count and differential, and platelet count. Screens for anemia, infection, coagulopathies, and hematological malignancies." , front_translations: {"es":"Hemograma Completo","de":"CBC — Großes Blutbild","fr":"NFS — Numération Formule Sanguine","tr":"CBC — Tam Kan Sayımı","nl":"CBC — Volledig Bloedbeeld","ru":"ОАК — Общий анализ крови","zh":"CBC — 全血细胞计数","pt_BR":"Hemograma Completo","pt_PT":"Hemograma Completo"}, back_translations: {"es":"Examen de sangre que mide contaje de hemácias, hemoglobina, hematócrito, contaje y diferencial de leucócitos y contaje de plaquetas. Rastreia anemia, infección, coagulopatias y neoplasias hematológicas.","de":"Ein Bluttest, der die Anzahl der Erythrozyten, Hämoglobin, Hämatokrit, Leukozytenzahl und -differenzierung sowie die Thrombozytenzahl misst. Screening auf Anämie, Infektionen, Koagulopathien und hämatologische Malignome.","fr":"Un test sanguin mesurant le nombre de globules rouges, l'hémoglobine, l'hématocrite, le nombre et la formule leucocytaire, et le nombre de plaquettes. Dépistage de l'anémie, des infections, des coagulopathies et des hémopathies malignes.","tr":"Eritrosit sayısı, hemoglobin, hematokrit, lökosit sayısı ve diferansiyeli ile trombosit sayısını ölçen bir kan testi. Anemi, enfeksiyon, koagülopati ve hematolojik maligniteleri tarar.","nl":"Een bloedtest die het aantal rode bloedcellen, hemoglobine, hematocriet, aantal en differentiatie van witte bloedcellen, en het aantal bloedplaatjes meet. Screening op anemie, infectie, coagulopathieën en hematologische maligniteiten.","ru":"Анализ крови, измеряющий количество эритроцитов, гемоглобин, гематокрит, количество и дифференцировку лейкоцитов, а также количество тромбоцитов. Скрининг анемии, инфекций, коагулопатий и гематологических злокачественных новообразований.","zh":"测量红细胞计数、血红蛋白、红细胞压积、白细胞计数及分类、血小板计数的血液检测。用于筛查贫血、感染、凝血病和血液系统恶性肿瘤。","pt_BR":"Exame de sangue que mede contagem de hemácias, hemoglobina, hematócrito, contagem e diferencial de leucócitos e contagem de plaquetas. Rastreia anemia, infecção, coagulopatias e neoplasias hematológicas.","pt_PT":"Análise ao sangue que mede a contagem de eritrócitos, hemoglobina, hematócrito, contagem e diferencial de leucócitos e contagem de plaquetas. Rastreia anemia, infeção, coagulopatias e neoplasias hematológicas."}},
  { id: 'dc-medical-0078', deck_id: 'deck-medical', sort_order: 78, front: "ABG — Arterial Blood Gas", back: "Measures pH, PaO₂, PaCO₂, HCO₃⁻, and O₂ saturation from arterial blood. Used to assess respiratory function, acid-base balance, and ventilation adequacy. Normal pH: 7.35–7.45." , front_translations: {"es":"GAS — Gasometria Arterial","de":"ABG — Arterielle Blutgasanalyse","fr":"GDS — Gaz du Sang Artériel","tr":"ABG — Arteriyel Kan Gazı","nl":"ABG — Arterieel Bloedgas","ru":"АГК — Анализ газов крови (артериальный)","zh":"ABG — 动脉血气分析","pt_BR":"GAS — Gasometria Arterial","pt_PT":"Gasimetria Arterial"}, back_translations: {"es":"Mide pH, PaO₂, PaCO₂, HCO₃⁻ y saturación de El₂ en el sangre arterial. Usado para avaliar función respiratória, equilíbrio ácido-base y adequación de la ventilación. pH normal: 7,35–7,45.","de":"Misst pH, PaO₂, PaCO₂, HCO₃⁻ und O₂-Sättigung aus arteriellem Blut. Zur Beurteilung der Atemfunktion, des Säure-Basen-Haushalts und der Beatmungsadäquanz. Normaler pH: 7,35–7,45.","fr":"Mesure le pH, la PaO₂, la PaCO₂, les HCO₃⁻ et la saturation en O₂ à partir du sang artériel. Utilisé pour évaluer la fonction respiratoire, l'équilibre acido-basique et l'adéquation de la ventilation. pH normal : 7,35–7,45.","tr":"Arteriyel kandan pH, PaO₂, PaCO₂, HCO₃⁻ ve O₂ satürasyonunu ölçer. Solunum fonksiyonu, asit-baz dengesi ve ventilasyon yeterliliğini değerlendirmek için kullanılır. Normal pH: 7,35–7,45.","nl":"Meet pH, PaO₂, PaCO₂, HCO₃⁻ en O₂-saturatie uit arterieel bloed. Gebruikt om de longfunctie, zuur-base-evenwicht en ventilatie-adequaatheid te beoordelen. Normaal pH: 7,35–7,45.","ru":"Измеряет pH, PaO₂, PaCO₂, HCO₃⁻ и насыщение O₂ из артериальной крови. Используется для оценки функции дыхания, кислотно-основного баланса и адекватности вентиляции. Нормальный pH: 7,35–7,45.","zh":"测量动脉血中的pH、PaO₂、PaCO₂、HCO₃⁻和O₂饱和度。用于评估呼吸功能、酸碱平衡和通气充分性。正常pH：7.35–7.45。","pt_BR":"Mede pH, PaO₂, PaCO₂, HCO₃⁻ e saturação de O₂ no sangue arterial. Usado para avaliar função respiratória, equilíbrio ácido-base e adequação da ventilação. pH normal: 7,35–7,45.","pt_PT":"Mede pH, PaO₂, PaCO₂, HCO₃⁻ e saturação de O₂ no sangue arterial. Usado para avaliar a função respiratória, o equilíbrio ácido-base e a adequação da ventilação. pH normal: 7,35–7,45."}},
  { id: 'dc-medical-0079', deck_id: 'deck-medical', sort_order: 79, front: "Metabolic Acidosis", back: "Low blood pH with low HCO₃⁻. Causes (with increased anion gap): DKA, lactic acidosis, renal failure, toxins (MUDPILES). Normal anion gap causes: diarrhea, RTA. Compensated by hyperventilation (↓PaCO₂)." , front_translations: {"es":"Acidose Metabólica","de":"Metabolische Azidose","fr":"Acidose Métabolique","tr":"Metabolik Asidoz","nl":"Metabole Acidose","ru":"Метаболический ацидоз","zh":"代谢性酸中毒","pt_BR":"Acidose Metabólica","pt_PT":"Acidose Metabólica"}, back_translations: {"es":"pH sanguíneo bajo con HCO₃⁻ bajo. Causas (con anion gap elevado): CAD, acidose lática, insuficiencia renal, toxinas (MUDPILES). Ânion gap normal: diarreia, ATR. Compensada por hiperventilación (↓PaCO₂).","de":"Niedriger Blut-pH mit niedrigem HCO₃⁻. Ursachen (mit erhöhter Anionenlücke): DKA, Laktatazidose, Nierenversagen, Toxine (MUDPILES). Normale Anionenlücke: Diarrhö, RTA. Kompensation durch Hyperventilation (↓PaCO₂).","fr":"pH sanguin bas avec HCO₃⁻ bas. Causes (avec trou anionique élevé) : acidocétose diabétique, acidose lactique, insuffisance rénale, toxines (MUDPILES). Trou anionique normal : diarrhée, ATR. Compensée par hyperventilation (↓PaCO₂).","tr":"Düşük kan pH'ı ile düşük HCO₃⁻. Nedenler (artmış anyon açığı ile): DKA, laktik asidoz, böbrek yetmezliği, toksinler (MUDPILES). Normal anyon açığı nedenleri: ishal, RTA. Hiperventilasyon ile kompanse edilir (↓PaCO₂).","nl":"Lage bloed-pH met laag HCO₃⁻. Oorzaken (met verhoogd anionengat): DKA, melkzuuracidose, nierfalen, toxines (MUDPILES). Normaal anionengat: diarree, RTA. Gecompenseerd door hyperventilatie (↓PaCO₂).","ru":"Низкий pH крови с низким HCO₃⁻. Причины (с повышенным анионным интервалом): ДКА, лактоацидоз, почечная недостаточность, токсины (MUDPILES). Нормальный анионный интервал: диарея, ПКА. Компенсируется гипервентиляцией (↓PaCO₂).","zh":"血液pH低，HCO₃⁻低。原因（阴离子间隙升高）：DKA、乳酸酸中毒、肾衰竭、毒素（MUDPILES）。正常阴离子间隙原因：腹泻、RTA。通过过度换气代偿（↓PaCO₂）。","pt_BR":"pH sanguíneo baixo com HCO₃⁻ baixo. Causas (com ânion gap elevado): CAD, acidose lática, insuficiência renal, toxinas (MUDPILES). Ânion gap normal: diarreia, ATR. Compensada por hiperventilação (↓PaCO₂).","pt_PT":"pH sanguíneo baixo com HCO₃⁻ baixo. Causas (com hiato aniónico elevado): CAD, acidose láctica, insuficiência renal, toxinas (MUDPILES). Hiato aniónico normal: diarreia, ATR. Compensada por hiperventilação (↓PaCO₂)."}},
  { id: 'dc-medical-0080', deck_id: 'deck-medical', sort_order: 80, front: "Respiratory Acidosis", back: "Low blood pH with high PaCO₂ due to inadequate ventilation (hypoventilation). Causes: COPD, opioid overdose, neuromuscular disease. Compensated by renal retention of HCO₃⁻ (chronic compensation)." , front_translations: {"es":"Acidose Respiratória","de":"Respiratorische Azidose","fr":"Acidose Respiratoire","tr":"Solunum Asidozu","nl":"Respiratoire Acidose","ru":"Респираторный ацидоз","zh":"呼吸性酸中毒","pt_BR":"Acidose Respiratória","pt_PT":"Acidose Respiratória"}, back_translations: {"es":"pH sanguíneo bajo con PaCO₂ elevado por ventilación inadequada (hipoventilación). Causas: DPOC, overdose de opioide, enfermedad neuromuscular. Compensada por retención renal de HCO₃⁻ (compensación crónica).","de":"Niedriger Blut-pH mit hohem PaCO₂ durch unzureichende Beatmung (Hypoventilation). Ursachen: COPD, Opioid-Überdosierung, neuromuskuläre Erkrankungen. Kompensiert durch renale HCO₃⁻-Retention (chronische Kompensation).","fr":"pH sanguin bas avec PaCO₂ élevée due à une ventilation inadéquate (hypoventilation). Causes : BPCO, surdosage aux opioïdes, maladie neuromusculaire. Compensée par rétention rénale de HCO₃⁻ (compensation chronique).","tr":"Yetersiz ventilasyon (hipoventilasyon) nedeniyle yüksek PaCO₂ ile düşük kan pH'ı. Nedenler: KOAH, opioid aşırı dozu, nöromüsküler hastalık. Renal HCO₃⁻ retansiyonu ile kompanse edilir (kronik kompansasyon).","nl":"Lage bloed-pH met hoge PaCO₂ door onvoldoende ventilatie (hypoventilatie). Oorzaken: COPD, opiaat-overdosis, neuromusculaire ziekte. Gecompenseerd door renale retentie van HCO₃⁻ (chronische compensatie).","ru":"Низкий pH крови с высоким PaCO₂ из-за неадекватной вентиляции (гиповентиляция). Причины: ХОБЛ, передозировка опиоидов, нервно-мышечные заболевания. Компенсируется почечной задержкой HCO₃⁻ (хроническая компенсация).","zh":"因通气不足（低通气）导致PaCO₂升高，血液pH降低。原因：慢阻肺、阿片类药物过量、神经肌肉疾病。通过肾脏保留HCO₃⁻代偿（慢性代偿）。","pt_BR":"pH sanguíneo baixo com PaCO₂ elevado por ventilação inadequada (hipoventilação). Causas: DPOC, overdose de opioide, doença neuromuscular. Compensada por retenção renal de HCO₃⁻ (compensação crônica).","pt_PT":"pH sanguíneo baixo com PaCO₂ elevado por ventilação inadequada (hipoventilação). Causas: DPOC, sobredosagem de opioides, doença neuromuscular. Compensada por retenção renal de HCO₃⁻ (compensação crónica)."}},
  { id: 'dc-medical-0081', deck_id: 'deck-medical', sort_order: 81, front: "Metabolic Alkalosis", back: "High blood pH with high HCO₃⁻. Causes: vomiting (loss of HCl), diuretics (loop/thiazide), excess alkali intake. Compensated by hypoventilation (↑PaCO₂). Often associated with hypokalemia." , front_translations: {"es":"Alcalose Metabólica","de":"Metabolische Alkalose","fr":"Alcalose Métabolique","tr":"Metabolik Alkaloz","nl":"Metabole Alkalose","ru":"Метаболический алкалоз","zh":"代谢性碱中毒","pt_BR":"Alcalose Metabólica","pt_PT":"Alcalose Metabólica"}, back_translations: {"es":"pH sanguíneo alto con HCO₃⁻ elevado. Causas: vomitos (perda de HCl), diuréticos (de alça/tiazídicos), ingestão excessiva de álcali. Compensada por hipoventilación (↑PaCO₂). Frecuentemente associada a hipocalemia.","de":"Hoher Blut-pH mit hohem HCO₃⁻. Ursachen: Erbrechen (HCl-Verlust), Diuretika (Schleifen-/Thiaziddiuretika), übermäßige Alkalizufuhr. Kompensiert durch Hypoventilation (↑PaCO₂). Häufig mit Hypokaliämie assoziiert.","fr":"pH sanguin élevé avec HCO₃⁻ élevé. Causes : vomissements (perte de HCl), diurétiques (de l'anse/thiazidiques), apport excessif en alcali. Compensée par hypoventilation (↑PaCO₂). Souvent associée à une hypokaliémie.","tr":"Yüksek HCO₃⁻ ile yüksek kan pH'ı. Nedenler: kusma (HCl kaybı), diüretikler (loop/tiazid), aşırı alkali alımı. Hipoventilasyon ile kompanse edilir (↑PaCO₂). Sıklıkla hipokaliemi ile ilişkilidir.","nl":"Hoge bloed-pH met hoog HCO₃⁻. Oorzaken: braken (verlies van HCl), diuretica (lus/thiazide), overmatige alkali-inname. Gecompenseerd door hypoventilatie (↑PaCO₂). Vaak geassocieerd met hypokaliëmie.","ru":"Высокий pH крови с высоким HCO₃⁻. Причины: рвота (потеря HCl), диуретики (петлевые/тиазидные), избыточное потребление щелочи. Компенсируется гиповентиляцией (↑PaCO₂). Часто ассоциируется с гипокалиемией.","zh":"血液pH升高，HCO₃⁻升高。原因：呕吐（HCl丢失）、利尿剂（袢/噻嗪类）、过量碱摄入。通过低通气代偿（↑PaCO₂）。常伴低钾血症。","pt_BR":"pH sanguíneo alto com HCO₃⁻ elevado. Causas: vômitos (perda de HCl), diuréticos (de alça/tiazídicos), ingestão excessiva de álcali. Compensada por hipoventilação (↑PaCO₂). Frequentemente associada a hipocalemia.","pt_PT":"pH sanguíneo elevado com HCO₃⁻ elevado. Causas: vómitos (perda de HCl), diuréticos (da ansa/tiazídicos), ingestão excessiva de álcali. Compensada por hipoventilação (↑PaCO₂). Frequentemente associada a hipocaliemia."}},
  { id: 'dc-medical-0082', deck_id: 'deck-medical', sort_order: 82, front: "Respiratory Alkalosis", back: "High blood pH with low PaCO₂ due to hyperventilation. Causes: anxiety, pain, high altitude, sepsis (early), pregnancy. Compensated by renal excretion of HCO₃⁻." , front_translations: {"es":"Alcalose Respiratória","de":"Respiratorische Alkalose","fr":"Alcalose Respiratoire","tr":"Solunum Alkalozü","nl":"Respiratoire Alkalose","ru":"Респираторный алкалоз","zh":"呼吸性碱中毒","pt_BR":"Alcalose Respiratória","pt_PT":"Alcalose Respiratória"}, back_translations: {"es":"pH sanguíneo alto con PaCO₂ bajo por hiperventilación. Causas: ansiedad, dor, altitude elevada, sepse (precoce), gravidez. Compensada por excreción renal de HCO₃⁻.","de":"Hoher Blut-pH mit niedrigem PaCO₂ durch Hyperventilation. Ursachen: Angst, Schmerzen, Höhenlage, Sepsis (früh), Schwangerschaft. Kompensiert durch renale Ausscheidung von HCO₃⁻.","fr":"pH sanguin élevé avec PaCO₂ bas dû à une hyperventilation. Causes : anxiété, douleur, altitude, sepsis (précoce), grossesse. Compensée par l'excrétion rénale de HCO₃⁻.","tr":"Hiperventilasyon nedeniyle düşük PaCO₂ ile yüksek kan pH'ı. Nedenler: anksiyete, ağrı, yüksek irtifa, sepsis (erken), gebelik. Renal HCO₃⁻ atılımı ile kompanse edilir.","nl":"Hoge bloed-pH met lage PaCO₂ door hyperventilatie. Oorzaken: angst, pijn, grote hoogte, sepsis (vroeg), zwangerschap. Gecompenseerd door renale uitscheiding van HCO₃⁻.","ru":"Высокий pH крови с низким PaCO₂ из-за гипервентиляции. Причины: тревога, боль, высокогорье, сепсис (ранний), беременность. Компенсируется почечной экскрецией HCO₃⁻.","zh":"因过度换气导致PaCO₂降低，血液pH升高。原因：焦虑、疼痛、高海拔、脓毒症（早期）、妊娠。通过肾脏排出HCO₃⁻代偿。","pt_BR":"pH sanguíneo alto com PaCO₂ baixo por hiperventilação. Causas: ansiedade, dor, altitude elevada, sepse (precoce), gravidez. Compensada por excreção renal de HCO₃⁻.","pt_PT":"pH sanguíneo elevado com PaCO₂ baixo por hiperventilação. Causas: ansiedade, dor, altitude elevada, sépsis (precoce), gravidez. Compensada por excreção renal de HCO₃⁻."}},
  { id: 'dc-medical-0083', deck_id: 'deck-medical', sort_order: 83, front: "Anion Gap", back: "AG = Na⁺ − (Cl⁻ + HCO₃⁻). Normal: 8–12 mEq/L. Elevated in metabolic acidosis from accumulation of unmeasured anions (lactate, ketones, salicylate, uremic acids). Normal gap = loss of HCO₃⁻." , front_translations: {"es":"Ânion Gap","de":"Anionenlücke","fr":"Trou Anionique","tr":"Anyon Açığı","nl":"Anionengat","ru":"Анионный интервал","zh":"阴离子间隙","pt_BR":"Ânion Gap","pt_PT":"Hiato Aniónico"}, back_translations: {"es":"AG = Na⁺ − (Cl⁻ + HCO₃⁻). Normal: 8–12 mEq/L. Elevado en la acidose metabólica por acúmulo de anions no medidos (lactato, cetonas, salicilato, ácidos uremicos). Gap normal = perda de HCO₃⁻.","de":"AG = Na⁺ − (Cl⁻ + HCO₃⁻). Normal: 8–12 mEq/L. Erhöht bei metabolischer Azidose durch Akkumulation ungemessener Anionen (Laktat, Ketone, Salicylat, urämische Säuren). Normale Lücke = HCO₃⁻-Verlust.","fr":"TA = Na⁺ − (Cl⁻ + HCO₃⁻). Normal : 8–12 mEq/L. Élevé dans l'acidose métabolique par accumulation d'anions non mesurés (lactate, cétones, salicylate, acides urémiques). Trou normal = perte de HCO₃⁻.","tr":"AG = Na⁺ − (Cl⁻ + HCO₃⁻). Normal: 8–12 mEq/L. Ölçülmemiş anyonların (laktat, ketonlar, salisilatlar, üremik asitler) birikmesinden kaynaklanan metabolik asidozda yükselir. Normal açık = HCO₃⁻ kaybı.","nl":"AG = Na⁺ − (Cl⁻ + HCO₃⁻). Normaal: 8–12 mEq/L. Verhoogd bij metabole acidose door accumulatie van niet-gemeten anionen (lactaat, ketonen, salicylaat, uremische zuren). Normaal gat = verlies van HCO₃⁻.","ru":"АИ = Na⁺ − (Cl⁻ + HCO₃⁻). Норма: 8–12 мЭкв/л. Повышен при метаболическом ацидозе вследствие накопления неизмеряемых анионов (лактат, кетоны, салицилат, уремические кислоты). Нормальный интервал = потеря HCO₃⁻.","zh":"AG = Na⁺ − (Cl⁻ + HCO₃⁻)。正常：8–12 mEq/L。代谢性酸中毒时因未测量阴离子（乳酸、酮体、水杨酸盐、尿毒症酸）蓄积而升高。正常间隙 = HCO₃⁻丢失。","pt_BR":"AG = Na⁺ − (Cl⁻ + HCO₃⁻). Normal: 8–12 mEq/L. Elevado na acidose metabólica por acúmulo de ânions não medidos (lactato, cetonas, salicilato, ácidos urêmicos). Gap normal = perda de HCO₃⁻.","pt_PT":"HA = Na⁺ − (Cl⁻ + HCO₃⁻). Normal: 8–12 mEq/L. Elevado na acidose metabólica por acumulação de aniões não medidos (lactato, cetonas, salicilato, ácidos urémicos). Hiato normal = perda de HCO₃⁻."}},
  { id: 'dc-medical-0084', deck_id: 'deck-medical', sort_order: 84, front: "O2 Saturation (SpO₂)", back: "The percentage of hemoglobin saturated with oxygen, measured non-invasively by pulse oximetry. Normal ≥95%. <90% indicates significant hypoxemia. Unreliable in carbon monoxide poisoning (reads falsely normal)." , front_translations: {"es":"Saturación de El2 (SpO₂)","de":"O2-Sättigung (SpO₂)","fr":"Saturation en O2 (SpO₂)","tr":"O2 Saturasyonu (SpO₂)","nl":"O2-Saturatie (SpO₂)","ru":"Насыщение O₂ (SpO₂)","zh":"血氧饱和度（SpO₂）","pt_BR":"Saturação de O2 (SpO₂)","pt_PT":"Saturação de O2 (SpO₂)"}, back_translations: {"es":"La porcentaje de hemoglobina saturada con oxígeno, medida de forma no invasiva por oximetria de muñeca. Normal ≥95%. <90% indica hipoxemia significativa. No confiable en intoxicación por monóxido de carbono (leitura falsamente normal).","de":"Der Prozentsatz des mit Sauerstoff gesättigten Hämoglobins, nichtinvasiv durch Pulsoximetrie gemessen. Normal ≥95%. <90% weist auf signifikante Hypoxämie hin. Unzuverlässig bei Kohlenmonoxidvergiftung (zeigt fälschlicherweise Normalwerte).","fr":"Le pourcentage d'hémoglobine saturée en oxygène, mesuré de façon non invasive par oxymétrie de pouls. Normal ≥95%. <90% indique une hypoxémie significative. Non fiable en cas d'intoxication au monoxyde de carbone (lecture faussement normale).","tr":"Hemoglobinin oksijenle doygunluk yüzdesi, pulse oksimetre ile non-invazif olarak ölçülür. Normal ≥%95. <%90 önemli hipoksemiyi gösterir. Karbon monoksit zehirlenmesinde güvenilmez (yanlış normal sonuç verir).","nl":"Het percentage hemoglobine dat verzadigd is met zuurstof, niet-invasief gemeten door pulsoxymetrie. Normaal ≥95%. <90% duidt op significante hypoxemie. Onbetrouwbaar bij koolmonoxidevergiftiging (geeft vals-normaal waarde).","ru":"Процент гемоглобина, насыщенного кислородом, измеряется неинвазивно пульсоксиметром. Норма ≥95%. <90% указывает на значительную гипоксемию. Ненадёжен при отравлении угарным газом (даёт ложно нормальный результат).","zh":"血红蛋白与氧气结合的百分比，通过脉搏血氧仪无创测量。正常≥95%。<90%提示明显低氧血症。一氧化碳中毒时不可靠（读数假性正常）。","pt_BR":"A porcentagem de hemoglobina saturada com oxigênio, medida de forma não invasiva por oximetria de pulso. Normal ≥95%. <90% indica hipoxemia significativa. Não confiável em intoxicação por monóxido de carbono (leitura falsamente normal).","pt_PT":"A percentagem de hemoglobina saturada com oxigénio, medida de forma não invasiva por oximetria de pulso. Normal ≥95%. <90% indica hipoxemia significativa. Não fiável em intoxicação por monóxido de carbono (leitura falsamente normal)."}},
  { id: 'dc-medical-0085', deck_id: 'deck-medical', sort_order: 85, front: "Pharmacology: Half-Life (t½)", back: "The time required for the plasma concentration of a drug to decrease by 50%. Determines dosing frequency. After ~5 half-lives, a drug is effectively eliminated (97% gone) or reaches steady state during repeated dosing." , front_translations: {"es":"Farmacologia: Media-vida (t½)","de":"Pharmakologie: Halbwertszeit (t½)","fr":"Pharmacologie : Demi-vie (t½)","tr":"Farmakoloji: Yarı Ömür (t½)","nl":"Farmacologie: Halfwaardetijd (t½)","ru":"Фармакология: период полувыведения (t½)","zh":"药理学：半衰期（t½）","pt_BR":"Farmacologia: Meia-vida (t½)","pt_PT":"Farmacologia: Semivida (t½)"}, back_translations: {"es":"El tiempo necesario para que a concentración plasmática de un fármaco diminua 50%. Determina a frecuencia de dosaje. Após ~5 meias-vidas, un fármaco es efetivamente eliminado (97% eliminado) o alcanza estado de equilíbrio durante dosaje repetida.","de":"Die Zeit, die benötigt wird, um die Plasmakonzentration eines Medikaments um 50% zu senken. Bestimmt die Dosierungshäufigkeit. Nach ~5 Halbwertszeiten ist ein Medikament praktisch eliminiert (97% abgebaut) oder erreicht bei wiederholter Dosierung den Steady State.","fr":"Le temps nécessaire pour que la concentration plasmatique d'un médicament diminue de 50%. Détermine la fréquence de dosage. Après ~5 demi-vies, un médicament est effectivement éliminé (97% éliminé) ou atteint un état d'équilibre lors de dosages répétés.","tr":"Bir ilacın plazma konsantrasyonunun %50 azalması için gereken süre. Dozlama sıklığını belirler. ~5 yarı ömür sonra ilaç etkin biçimde elimine edilir (%97 kaybolur) veya tekrarlanan dozlamada kararlı duruma ulaşır.","nl":"De tijd die nodig is om de plasmaconcentratie van een geneesmiddel met 50% te verlagen. Bepaalt de doseringsfrequentie. Na ~5 halfwaardetijden is een geneesmiddel effectief geëlimineerd (97% verdwenen) of bereikt een steady state bij herhaalde dosering.","ru":"Время, необходимое для снижения плазменной концентрации препарата на 50%. Определяет частоту дозирования. После ~5 периодов полувыведения препарат практически элиминирован (97% выведено) или достигает равновесного состояния при повторном приёме.","zh":"药物血浆浓度降低50%所需的时间。决定给药频率。经过约5个半衰期后，药物基本被清除（97%消除），或在反复给药时达到稳态。","pt_BR":"O tempo necessário para que a concentração plasmática de um fármaco diminua 50%. Determina a frequência de dosagem. Após ~5 meias-vidas, um fármaco é efetivamente eliminado (97% eliminado) ou atinge estado de equilíbrio durante dosagem repetida.","pt_PT":"O tempo necessário para que a concentração plasmática de um fármaco diminua 50%. Determina a frequência de dosagem. Após ~5 semividas, um fármaco é efetivamente eliminado (97% eliminado) ou atinge estado de equilíbrio durante dosagem repetida."}},
  { id: 'dc-medical-0086', deck_id: 'deck-medical', sort_order: 86, front: "Pharmacology: Bioavailability", back: "The fraction (F) of an administered drug that reaches the systemic circulation in active form. IV administration has 100% bioavailability. Oral bioavailability is reduced by first-pass metabolism in the liver." , front_translations: {"es":"Farmacologia: Biodisponibilidad","de":"Pharmakologie: Bioverfügbarkeit","fr":"Pharmacologie : Biodisponibilité","tr":"Farmakoloji: Biyoyararlanım","nl":"Farmacologie: Biologische beschikbaarheid","ru":"Фармакология: биодоступность","zh":"药理学：生物利用度","pt_BR":"Farmacologia: Biodisponibilidade","pt_PT":"Farmacologia: Biodisponibilidade"}, back_translations: {"es":"La fracción (F) de un fármaco administrado que chega a la circulación sistemica en la forma ativa. La administración IV tiene biodisponibilidad de 100%. La biodisponibilidad oral es reduzida por el metabolismo de primera passaje en el hígado.","de":"Der Anteil (F) eines verabreichten Medikaments, der in aktiver Form den systemischen Kreislauf erreicht. Intravenöse Gabe hat 100% Bioverfügbarkeit. Orale Bioverfügbarkeit wird durch den First-Pass-Metabolismus in der Leber reduziert.","fr":"La fraction (F) d'un médicament administré qui atteint la circulation systémique sous forme active. L'administration IV a une biodisponibilité de 100%. La biodisponibilité orale est réduite par le métabolisme de premier passage hépatique.","tr":"Uygulanan bir ilacın aktif formda sistemik dolaşıma ulaşan fraksiyonu (F). İntravenöz uygulama %100 biyoyararlanıma sahiptir. Oral biyoyararlanım, karaciğerdeki ilk geçiş metabolizması ile azalır.","nl":"De fractie (F) van een toegediend geneesmiddel die de systemische circulatie in actieve vorm bereikt. Intraveneuze toediening heeft 100% biologische beschikbaarheid. Orale biologische beschikbaarheid wordt verminderd door first-pass metabolisme in de lever.","ru":"Доля (F) введённого препарата, достигающая системного кровотока в активной форме. При внутривенном введении биодоступность составляет 100%. Пероральная биодоступность снижается за счёт метаболизма первого прохождения через печень.","zh":"给药后以活性形式到达体循环的药物分数（F）。静脉给药的生物利用度为100%。口服生物利用度因肝脏首过代谢而降低。","pt_BR":"A fração (F) de um fármaco administrado que chega à circulação sistêmica na forma ativa. A administração IV tem biodisponibilidade de 100%. A biodisponibilidade oral é reduzida pelo metabolismo de primeira passagem no fígado.","pt_PT":"A fração (F) de um fármaco administrado que atinge a circulação sistémica na forma ativa. A administração IV tem biodisponibilidade de 100%. A biodisponibilidade oral é reduzida pelo metabolismo de primeira passagem no fígado."}},
  { id: 'dc-medical-0087', deck_id: 'deck-medical', sort_order: 87, front: "Pharmacology: Agonist", back: "A drug that binds to a receptor and activates it, producing the same effect as the endogenous ligand. Full agonists produce maximal response; partial agonists produce a submaximal response even at full receptor occupancy." , front_translations: {"es":"Farmacologia: Agonista","de":"Pharmakologie: Agonist","fr":"Pharmacologie : Agoniste","tr":"Farmakoloji: Agonist","nl":"Farmacologie: Agonist","ru":"Фармакология: агонист","zh":"药理学：激动剂","pt_BR":"Farmacologia: Agonista","pt_PT":"Farmacologia: Agonista"}, back_translations: {"es":"Un fármaco que se liga a un receptor y el ativa, produciendo el mismo efecto del ligante endógeno. Agonistas totais producen respuesta máxima; agonistas parciais producen respuesta submáxima mismo con ocupación total del receptor.","de":"Ein Medikament, das an einen Rezeptor bindet und ihn aktiviert und den gleichen Effekt wie der endogene Ligand erzeugt. Volle Agonisten erzeugen eine maximale Reaktion; partielle Agonisten erzeugen eine submaximale Reaktion auch bei voller Rezeptorbesetzung.","fr":"Un médicament qui se lie à un récepteur et l'active, produisant le même effet que le ligand endogène. Les agonistes complets produisent une réponse maximale ; les agonistes partiels produisent une réponse sous-maximale même à occupation totale du récepteur.","tr":"Bir reseptöre bağlanan ve onu aktive ederek endojen ligandla aynı etkiyi üreten bir ilaç. Tam agonistler maksimal yanıt üretir; parsiyel agonistler tam reseptör dolulukta bile submaksimal yanıt üretir.","nl":"Een geneesmiddel dat aan een receptor bindt en deze activeert, hetzelfde effect produceert als de endogene ligand. Volledige agonisten produceren maximale respons; partiële agonisten produceren een submaximale respons zelfs bij volledige receptorbezetting.","ru":"Препарат, который связывается с рецептором и активирует его, производя тот же эффект, что и эндогенный лиганд. Полные агонисты вызывают максимальный ответ; частичные агонисты вызывают субмаксимальный ответ даже при полном занятии рецептора.","zh":"与受体结合并激活受体、产生与内源性配体相同效果的药物。完全激动剂产生最大反应；部分激动剂即使在受体完全占据时也只产生次最大反应。","pt_BR":"Um fármaco que se liga a um receptor e o ativa, produzindo o mesmo efeito do ligante endógeno. Agonistas totais produzem resposta máxima; agonistas parciais produzem resposta submáxima mesmo com ocupação total do receptor.","pt_PT":"Um fármaco que se liga a um receptor e o ativa, produzindo o mesmo efeito do ligando endógeno. Agonistas totais produzem resposta máxima; agonistas parciais produzem resposta submáxima mesmo com ocupação total do receptor."}},
  { id: 'dc-medical-0088', deck_id: 'deck-medical', sort_order: 88, front: "Pharmacology: Antagonist", back: "A drug that binds to a receptor and blocks it without activating it, preventing the endogenous ligand or agonist from acting. Competitive antagonists can be overcome by increasing agonist concentration." , front_translations: {"es":"Farmacologia: Antagonista","de":"Pharmakologie: Antagonist","fr":"Pharmacologie : Antagoniste","tr":"Farmakoloji: Antagonist","nl":"Farmacologie: Antagonist","ru":"Фармакология: антагонист","zh":"药理学：拮抗剂","pt_BR":"Farmacologia: Antagonista","pt_PT":"Farmacologia: Antagonista"}, back_translations: {"es":"Un fármaco que se liga a un receptor y el bloqueia sin ativá-lo, impidiendo el ligante endógeno o agonista de agir. Antagonistas competitivos pueden ser superados aumentando a concentración del agonista.","de":"Ein Medikament, das an einen Rezeptor bindet und ihn blockiert, ohne ihn zu aktivieren, und so verhindert, dass der endogene Ligand oder Agonist wirkt. Kompetitive Antagonisten können durch Erhöhung der Agonistenkonzentration überwunden werden.","fr":"Un médicament qui se lie à un récepteur et le bloque sans l'activer, empêchant le ligand endogène ou l'agoniste d'agir. Les antagonistes compétitifs peuvent être surmontés en augmentant la concentration d'agoniste.","tr":"Bir reseptöre bağlanan ve onu aktive etmeden bloke eden, endojen ligandın veya agonistin etkimesini önleyen bir ilaç. Kompetitif antagonistler, agonist konsantrasyonu artırılarak etkisizleştirilebilir.","nl":"Een geneesmiddel dat aan een receptor bindt en deze blokkeert zonder hem te activeren, waardoor de endogene ligand of agonist niet kan werken. Competitieve antagonisten kunnen worden overwonnen door de agonistconcentratie te verhogen.","ru":"Препарат, который связывается с рецептором и блокирует его, не активируя, предотвращая действие эндогенного лиганда или агониста. Конкурентные антагонисты можно преодолеть, увеличив концентрацию агониста.","zh":"与受体结合并阻断受体而不激活它的药物，阻止内源性配体或激动剂发挥作用。竞争性拮抗剂可通过增加激动剂浓度来克服。","pt_BR":"Um fármaco que se liga a um receptor e o bloqueia sem ativá-lo, impedindo o ligante endógeno ou agonista de agir. Antagonistas competitivos podem ser superados aumentando a concentração do agonista.","pt_PT":"Um fármaco que se liga a um receptor e o bloqueia sem o ativar, impedindo o ligando endógeno ou o agonista de agir. Os antagonistas competitivos podem ser superados aumentando a concentração do agonista."}},
  { id: 'dc-medical-0089', deck_id: 'deck-medical', sort_order: 89, front: "Pharmacology: Contraindication", back: "A condition or factor that makes a particular treatment or procedure inadvisable. Absolute contraindication: benefit never outweighs risk. Relative contraindication: may be used with caution if benefit outweighs risk." , front_translations: {"es":"Farmacologia: Contraindicación","de":"Pharmakologie: Kontraindikation","fr":"Pharmacologie : Contre-indication","tr":"Farmakoloji: Kontrendikasyon","nl":"Farmacologie: Contra-indicatie","ru":"Фармакология: противопоказание","zh":"药理学：禁忌症","pt_BR":"Farmacologia: Contraindicação","pt_PT":"Farmacologia: Contraindicação"}, back_translations: {"es":"Una condición o fator que torna un tratamiento o procedimento específico desaconselhable. Contraindicación absoluta: el benefício nunca supera el riesgo. Contraindicación relativa: puede ser usada con cautela se el benefício superar el riesgo.","de":"Eine Erkrankung oder ein Faktor, der eine bestimmte Behandlung oder ein Verfahren unratsam macht. Absolute Kontraindikation: Nutzen überwiegt nie das Risiko. Relative Kontraindikation: kann mit Vorsicht angewendet werden, wenn Nutzen das Risiko überwiegt.","fr":"Une condition ou un facteur qui rend un traitement ou une procédure particulière déconseillée. Contre-indication absolue : le bénéfice ne l'emporte jamais sur le risque. Contre-indication relative : peut être utilisée avec précaution si le bénéfice l'emporte sur le risque.","tr":"Belirli bir tedavi veya prosedürü uygunsuz kılan bir durum veya faktör. Mutlak kontrendikasyon: fayda hiçbir zaman riski geçmez. Rölatif kontrendikasyon: fayda riski geçiyorsa dikkatli kullanılabilir.","nl":"Een aandoening of factor die een bepaalde behandeling of procedure ongewenst maakt. Absolute contra-indicatie: voordeel weegt nooit op tegen risico. Relatieve contra-indicatie: kan voorzichtig worden gebruikt als voordeel opweegt tegen risico.","ru":"Состояние или фактор, делающий определённое лечение или процедуру нецелесообразными. Абсолютное противопоказание: польза никогда не превышает риск. Относительное противопоказание: может применяться с осторожностью, если польза превышает риск.","zh":"使特定治疗或操作不适宜的条件或因素。绝对禁忌症：获益永远不会超过风险。相对禁忌症：如获益超过风险，可谨慎使用。","pt_BR":"Uma condição ou fator que torna um tratamento ou procedimento específico desaconselhável. Contraindicação absoluta: o benefício nunca supera o risco. Contraindicação relativa: pode ser usada com cautela se o benefício superar o risco.","pt_PT":"Uma condição ou fator que torna um tratamento ou procedimento específico desaconselhável. Contraindicação absoluta: o benefício nunca supera o risco. Contraindicação relativa: pode ser usada com precaução se o benefício superar o risco."}},
  { id: 'dc-medical-0090', deck_id: 'deck-medical', sort_order: 90, front: "Pharmacology: First-Pass Effect", back: "Metabolism of an orally administered drug by the liver before it reaches the systemic circulation, significantly reducing bioavailability. Drugs with high first-pass effect (e.g., nitroglycerin, lidocaine) must be given by alternative routes." , front_translations: {"es":"Farmacologia: Efecto de Primera Passaje","de":"Pharmakologie: First-Pass-Effekt","fr":"Pharmacologie : Effet de premier passage","tr":"Farmakoloji: İlk Geçiş Etkisi","nl":"Farmacologie: First-pass effect","ru":"Фармакология: эффект первого прохождения","zh":"药理学：首过效应","pt_BR":"Farmacologia: Efeito de Primeira Passagem","pt_PT":"Farmacologia: Efeito de Primeira Passagem"}, back_translations: {"es":"Metabolización de un fármaco administrado por via oral por el hígado antes de atingir a circulación sistemica, reduciendo significativamente a biodisponibilidad. Fármacos con alto efecto de primera passaje (ex.: nitroglicerina, lidocaína) devem ser administrados por vias alternativas.","de":"Metabolisierung eines oral verabreichten Medikaments durch die Leber, bevor es den systemischen Kreislauf erreicht, was die Bioverfügbarkeit erheblich reduziert. Medikamente mit hohem First-Pass-Effekt (z.B. Nitroglycerin, Lidocain) müssen auf alternativen Wegen verabreicht werden.","fr":"Métabolisme d'un médicament administré par voie orale par le foie avant d'atteindre la circulation systémique, réduisant significativement la biodisponibilité. Les médicaments avec un effet de premier passage élevé (ex. nitroglycérine, lidocaïne) doivent être administrés par d'autres voies.","tr":"Oral olarak uygulanan bir ilacın sistemik dolaşıma ulaşmadan önce karaciğer tarafından metabolize edilmesi, biyoyararlanımı önemli ölçüde azaltır. Yüksek ilk geçiş etkili ilaçlar (örn. nitrogliserin, lidokain) alternatif yollarla verilmelidir.","nl":"Metabolisme van een oraal toegediend geneesmiddel door de lever voordat het de systemische circulatie bereikt, wat de biologische beschikbaarheid aanzienlijk vermindert. Geneesmiddelen met een hoog first-pass effect (bijv. nitroglycerine, lidocaïne) moeten via alternatieve routes worden toegediend.","ru":"Метаболизм перорально введённого препарата в печени до достижения системного кровотока, значительно снижающий биодоступность. Препараты с высоким эффектом первого прохождения (например, нитроглицерин, лидокаин) следует вводить альтернативными путями.","zh":"口服药物在到达体循环之前被肝脏代谢，显著降低生物利用度。具有高首过效应的药物（如硝酸甘油、利多卡因）必须通过其他途径给药。","pt_BR":"Metabolização de um fármaco administrado por via oral pelo fígado antes de atingir a circulação sistêmica, reduzindo significativamente a biodisponibilidade. Fármacos com alto efeito de primeira passagem (ex.: nitroglicerina, lidocaína) devem ser administrados por vias alternativas.","pt_PT":"Metabolização de um fármaco administrado por via oral pelo fígado antes de atingir a circulação sistémica, reduzindo significativamente a biodisponibilidade. Fármacos com elevado efeito de primeira passagem (ex.: nitroglicerina, lidocaína) devem ser administrados por vias alternativas."}},
  { id: 'dc-medical-0091', deck_id: 'deck-medical', sort_order: 91, front: "Pharmacology: Volume of Distribution (Vd)", back: "A hypothetical volume in which the total drug dose would need to be uniformly distributed to equal the observed plasma concentration. High Vd indicates drug distributes into tissues; low Vd means it stays in plasma." , front_translations: {"es":"Farmacologia: Volumen de Distribución (Vd)","de":"Pharmakologie: Verteilungsvolumen (Vd)","fr":"Pharmacologie : Volume de distribution (Vd)","tr":"Farmakoloji: Dağılım Hacmi (Vd)","nl":"Farmacologie: Distributievolume (Vd)","ru":"Фармакология: объём распределения (Vd)","zh":"药理学：表观分布容积（Vd）","pt_BR":"Farmacologia: Volume de Distribuição (Vd)","pt_PT":"Farmacologia: Volume de Distribuição (Vd)"}, back_translations: {"es":"Un volumen hipotético en el qual a dose total del fármaco precisaria ser uniformemente distribuída para igualar a concentración plasmática observada. Vd alto indica que el fármaco se distribuye en los tejidos; Vd bajo significa que permanece en el plasma.","de":"Ein hypothetisches Volumen, in dem die gesamte Arzneimitteldosis gleichmäßig verteilt sein müsste, um der beobachteten Plasmakonzentration zu entsprechen. Hohes Vd zeigt Gewebeverteilung an; niedriges Vd bedeutet, es bleibt im Plasma.","fr":"Un volume hypothétique dans lequel la dose totale de médicament devrait être uniformément distribuée pour égaler la concentration plasmatique observée. Un Vd élevé indique que le médicament se distribue dans les tissus ; un faible Vd signifie qu'il reste dans le plasma.","tr":"Gözlenen plazma konsantrasyonuna eşit olması için toplam ilaç dozunun eşit dağılması gereken varsayımsal hacim. Yüksek Vd ilacın dokulara dağıldığını gösterir; düşük Vd plazmada kaldığı anlamına gelir.","nl":"Een hypothetisch volume waarin de totale geneesmiddeldosis uniform verdeeld zou moeten zijn om gelijk te zijn aan de waargenomen plasmaconcentratie. Hoog Vd geeft aan dat het geneesmiddel zich in weefsels verdeelt; laag Vd betekent dat het in plasma blijft.","ru":"Гипотетический объём, в котором полная доза препарата должна была бы равномерно распределиться, чтобы соответствовать наблюдаемой плазменной концентрации. Высокий Vd указывает на распределение препарата в тканях; низкий Vd означает, что он остаётся в плазме.","zh":"假设药物均匀分布时，总药量与观测到的血浆浓度相等所需的假设容积。高Vd表示药物分布到组织中；低Vd意味着药物留在血浆中。","pt_BR":"Um volume hipotético no qual a dose total do fármaco precisaria ser uniformemente distribuída para igualar a concentração plasmática observada. Vd alto indica que o fármaco se distribui nos tecidos; Vd baixo significa que permanece no plasma.","pt_PT":"Um volume hipotético no qual a dose total do fármaco teria de ser uniformemente distribuída para igualar a concentração plasmática observada. Vd elevado indica que o fármaco se distribui nos tecidos; Vd baixo significa que permanece no plasma."}},
  { id: 'dc-medical-0092', deck_id: 'deck-medical', sort_order: 92, front: "Pharmacology: Therapeutic Index (TI)", back: "TI = TD₅₀/ED₅₀. Ratio of toxic dose to effective dose. A high TI means a wide safety margin (e.g., penicillin). A narrow TI (e.g., digoxin, lithium, warfarin) requires careful monitoring." , front_translations: {"es":"Farmacologia: Índice Terapeutico (IT)","de":"Pharmakologie: Therapeutischer Index (TI)","fr":"Pharmacologie : Index thérapeutique (IT)","tr":"Farmakoloji: Terapötik İndeks (TI)","nl":"Farmacologie: Therapeutische Index (TI)","ru":"Фармакология: терапевтический индекс (ТИ)","zh":"药理学：治疗指数（TI）","pt_BR":"Farmacologia: Índice Terapêutico (IT)","pt_PT":"Farmacologia: Índice Terapêutico (IT)"}, back_translations: {"es":"IT = DT₅₀/DE₅₀. Razão de la dose tóxica para a dose efetiva. Un IT alto significa ampla margem de seguridad (ex.: penicilina). Un IT estrecho (ex.: digoxina, lítio, varfarina) requiere monitoramento cuidadoso.","de":"TI = TD₅₀/ED₅₀. Verhältnis der toxischen zur wirksamen Dosis. Ein hoher TI bedeutet eine große Sicherheitsspanne (z.B. Penicillin). Ein enger TI (z.B. Digoxin, Lithium, Warfarin) erfordert sorgfältiges Monitoring.","fr":"IT = DT₅₀/DE₅₀. Rapport de la dose toxique à la dose efficace. Un IT élevé signifie une large marge de sécurité (ex. pénicilline). Un IT étroit (ex. digoxine, lithium, warfarine) nécessite une surveillance attentive.","tr":"TI = TD₅₀/ED₅₀. Toksik dozun etkili doza oranı. Yüksek TI geniş güvenlik marjı anlamına gelir (örn. penisilin). Dar TI (örn. digoksin, lityum, varfarin) dikkatli izleme gerektirir.","nl":"TI = TD₅₀/ED₅₀. Verhouding van toxische dosis tot effectieve dosis. Een hoge TI betekent een brede veiligheidsmarge (bijv. penicilline). Een smalle TI (bijv. digoxine, lithium, warfarine) vereist zorgvuldige monitoring.","ru":"ТИ = TD₅₀/ED₅₀. Отношение токсической дозы к эффективной. Высокий ТИ означает широкий запас безопасности (например, пенициллин). Узкий ТИ (например, дигоксин, литий, варфарин) требует тщательного мониторинга.","zh":"TI = TD₅₀/ED₅₀。毒性剂量与有效剂量之比。高TI意味着宽安全窗（如青霉素）。窄TI（如地高辛、锂盐、华法林）需要仔细监测。","pt_BR":"IT = DT₅₀/DE₅₀. Razão da dose tóxica para a dose efetiva. Um IT alto significa ampla margem de segurança (ex.: penicilina). Um IT estreito (ex.: digoxina, lítio, varfarina) requer monitoramento cuidadoso.","pt_PT":"IT = DT₅₀/DE₅₀. Razão da dose tóxica para a dose eficaz. Um IT elevado significa ampla margem de segurança (ex.: penicilina). Um IT estreito (ex.: digoxina, lítio, varfarina) requer monitorização cuidadosa."}},
  { id: 'dc-medical-0093', deck_id: 'deck-medical', sort_order: 93, front: "Beta-Blockers", back: "Drugs that block β-adrenergic receptors, slowing heart rate and reducing blood pressure. Used for hypertension, angina, heart failure, arrhythmias. Side effects: bradycardia, bronchospasm, fatigue. Examples: metoprolol, atenolol." , front_translations: {"es":"Betabloqueadores","de":"Betablocker","fr":"Bêta-bloquants","tr":"Beta Blokerler","nl":"Bètablokkers","ru":"Бета-блокаторы","zh":"β受体阻滞剂","pt_BR":"Betabloqueadores","pt_PT":"Betabloqueadores"}, back_translations: {"es":"Fármacos que bloqueiam receptores β-adrenérgicos, reduciendo a frecuencia cardíaca y a presión arterial. Usados en hipertensão, angina, insuficiencia cardíaca, arritmias. Efectos colaterais: bradicardia, broncoespasmo, fadiga. Ejemplos: metoprolol, atenolol.","de":"Medikamente, die β-adrenerge Rezeptoren blockieren, die Herzfrequenz senken und den Blutdruck reduzieren. Eingesetzt bei Hypertonie, Angina, Herzinsuffizienz, Arrhythmien. Nebenwirkungen: Bradykardie, Bronchospasmus, Müdigkeit. Beispiele: Metoprolol, Atenolol.","fr":"Médicaments bloquant les récepteurs β-adrénergiques, réduisant la fréquence cardiaque et la pression artérielle. Utilisés pour l'hypertension, l'angine, l'insuffisance cardiaque, les arythmies. Effets secondaires : bradycardie, bronchospasme, fatigue. Exemples : métoprolol, aténolol.","tr":"β-adrenerjik reseptörleri bloke ederek kalp hızını düşüren ve kan basıncını azaltan ilaçlar. Hipertansiyon, anjina, kalp yetmezliği, aritmilerde kullanılır. Yan etkiler: bradikardi, bronkospazm, yorgunluk. Örnekler: metoprolol, atenolol.","nl":"Geneesmiddelen die β-adrenerge receptoren blokkeren, de hartfrequentie verlagen en de bloeddruk verminderen. Gebruikt bij hypertensie, angina, hartfalen, aritmieën. Bijwerkingen: bradycardie, bronchospasmen, vermoeidheid. Voorbeelden: metoprolol, atenolol.","ru":"Препараты, блокирующие β-адренергические рецепторы, снижающие частоту сердечных сокращений и артериальное давление. Применяются при гипертонии, стенокардии, сердечной недостаточности, аритмиях. Побочные эффекты: брадикардия, бронхоспазм, усталость. Примеры: метопролол, атенолол.","zh":"阻断β肾上腺素能受体、减慢心率、降低血压的药物。用于高血压、心绞痛、心力衰竭、心律失常。副作用：心动过缓、支气管痉挛、疲劳。例子：美托洛尔、阿替洛尔。","pt_BR":"Fármacos que bloqueiam receptores β-adrenérgicos, reduzindo a frequência cardíaca e a pressão arterial. Usados em hipertensão, angina, insuficiência cardíaca, arritmias. Efeitos colaterais: bradicardia, broncoespasmo, fadiga. Exemplos: metoprolol, atenolol.","pt_PT":"Fármacos que bloqueiam os receptores β-adrenérgicos, reduzindo a frequência cardíaca e a pressão arterial. Usados em hipertensão, angina, insuficiência cardíaca, arritmias. Efeitos secundários: bradicardia, broncoespasmo, fadiga. Exemplos: metoprolol, atenolol."}},
  { id: 'dc-medical-0094', deck_id: 'deck-medical', sort_order: 94, front: "ACE Inhibitors", back: "Block angiotensin-converting enzyme, preventing conversion of angiotensin I to angiotensin II. Reduce blood pressure and protect kidneys. Used in hypertension, heart failure, CKD. Side effect: dry cough (class effect)." , front_translations: {"es":"Inibidores de la ECA","de":"ACE-Hemmer","fr":"Inhibiteurs de l'ECA","tr":"ACE İnhibitörleri","nl":"ACE-remmers","ru":"Ингибиторы АПФ","zh":"ACE抑制剂","pt_BR":"Inibidores da ECA","pt_PT":"Inibidores da ECA"}, back_translations: {"es":"Bloqueiam a enzima conversora de angiotensina, impidiendo a conversão de angiotensina I en angiotensina II. Reducen a presión arterial y protegen los riñones. Usados en hipertensão, insuficiencia cardíaca, DRC. Efecto colateral: tosse seca (efecto de clase).","de":"Blockieren das Angiotensin-konvertierende Enzym und verhindern die Umwandlung von Angiotensin I in Angiotensin II. Senken den Blutdruck und schützen die Nieren. Eingesetzt bei Hypertonie, Herzinsuffizienz, CKD. Nebenwirkung: Trockenhusten (Klasseneffekt).","fr":"Bloquent l'enzyme de conversion de l'angiotensine, empêchant la conversion de l'angiotensine I en angiotensine II. Réduisent la pression artérielle et protègent les reins. Utilisés dans l'hypertension, l'insuffisance cardiaque, la MRC. Effet secondaire : toux sèche (effet de classe).","tr":"Anjiotensin I'in anjiotensin II'ye dönüşümünü önleyerek anjiyotensin dönüştürücü enzimi bloke eder. Kan basıncını düşürür ve böbrekleri korur. Hipertansiyon, kalp yetmezliği, KBH'de kullanılır. Yan etki: kuru öksürük (sınıf etkisi).","nl":"Blokkeren het angiotensine-converterend enzym, waardoor de omzetting van angiotensine I naar angiotensine II wordt voorkomen. Verlagen de bloeddruk en beschermen de nieren. Gebruikt bij hypertensie, hartfalen, CNI. Bijwerking: droge hoest (klasse-effect).","ru":"Блокируют ангиотензинпревращающий фермент, предотвращая превращение ангиотензина I в ангиотензин II. Снижают артериальное давление и защищают почки. Применяются при гипертонии, сердечной недостаточности, ХБП. Побочный эффект: сухой кашель (классовый эффект).","zh":"阻断血管紧张素转换酶，阻止血管紧张素I转化为血管紧张素II。降低血压，保护肾脏。用于高血压、心力衰竭、慢性肾病。副作用：干咳（类效应）。","pt_BR":"Bloqueiam a enzima conversora de angiotensina, impedindo a conversão de angiotensina I em angiotensina II. Reduzem a pressão arterial e protegem os rins. Usados em hipertensão, insuficiência cardíaca, DRC. Efeito colateral: tosse seca (efeito de classe).","pt_PT":"Bloqueiam a enzima de conversão da angiotensina, impedindo a conversão da angiotensina I em angiotensina II. Reduzem a pressão arterial e protegem os rins. Usados em hipertensão, insuficiência cardíaca, DRC. Efeito secundário: tosse seca (efeito de classe)."}},
  { id: 'dc-medical-0095', deck_id: 'deck-medical', sort_order: 95, front: "Statins", back: "HMG-CoA reductase inhibitors; lower LDL cholesterol by inhibiting its synthesis in the liver. First-line for cardiovascular risk reduction. Side effects: myopathy, rhabdomyolysis (rare), elevated liver enzymes." , front_translations: {"es":"Estatinas","de":"Statine","fr":"Statines","tr":"Statinler","nl":"Statines","ru":"Статины","zh":"他汀类药物","pt_BR":"Estatinas","pt_PT":"Estatinas"}, back_translations: {"es":"Inibidores de la HMG-CoA redutase; reducen el LDL-colesterol inibindo su síntese en el hígado. Tratamiento de primera línea para reducción del riesgo cardiovascular. Efectos colaterais: miopatia, rabdomiólise (rara), elevación de enzimas hepáticas.","de":"HMG-CoA-Reduktase-Hemmer; senken LDL-Cholesterin durch Hemmung seiner Synthese in der Leber. Erstlinientherapie zur kardiovaskulären Risikoreduktion. Nebenwirkungen: Myopathie, Rhabdomyolyse (selten), erhöhte Leberenzyme.","fr":"Inhibiteurs de la HMG-CoA réductase ; réduisent le LDL-cholestérol en inhibant sa synthèse dans le foie. Traitement de première ligne pour la réduction du risque cardiovasculaire. Effets secondaires : myopathie, rhabdomyolyse (rare), élévation des enzymes hépatiques.","tr":"HMG-CoA redüktaz inhibitörleri; karaciğerde sentezini inhibe ederek LDL kolesterolü düşürür. Kardiyovasküler risk azaltmada birinci basamak tedavi. Yan etkiler: miyopati, rabdomiyoliz (nadir), yüksek karaciğer enzimleri.","nl":"HMG-CoA-reductaseremmers; verlagen LDL-cholesterol door de synthese ervan in de lever te remmen. Eerstelijnsbehandeling voor cardiovasculaire risicovermindering. Bijwerkingen: myopathie, rabdomyolyse (zeldzaam), verhoogde leverenzymen.","ru":"Ингибиторы ГМГ-КоА-редуктазы; снижают ЛПНП-холестерин, подавляя его синтез в печени. Препараты первой линии для снижения сердечно-сосудистого риска. Побочные эффекты: миопатия, рабдомиолиз (редко), повышение печёночных ферментов.","zh":"HMG-CoA还原酶抑制剂；通过抑制肝脏合成来降低LDL胆固醇。心血管风险降低的一线治疗。副作用：肌病、横纹肌溶解症（罕见）、肝酶升高。","pt_BR":"Inibidores da HMG-CoA redutase; reduzem o LDL-colesterol inibindo sua síntese no fígado. Tratamento de primeira linha para redução do risco cardiovascular. Efeitos colaterais: miopatia, rabdomiólise (rara), elevação de enzimas hepáticas.","pt_PT":"Inibidores da HMG-CoA redutase; reduzem o colesterol LDL inibindo a sua síntese no fígado. Tratamento de primeira linha para redução do risco cardiovascular. Efeitos secundários: miopatia, rabdomiólise (rara), elevação de enzimas hepáticas."}},
  { id: 'dc-medical-0096', deck_id: 'deck-medical', sort_order: 96, front: "Antibiotics: Penicillins", back: "Beta-lactam antibiotics that inhibit bacterial cell wall synthesis. Bactericidal; effective against gram-positive organisms. Amoxicillin is the most common oral penicillin. Resistance via beta-lactamases." , front_translations: {"es":"Antibióticos: Penicilinas","de":"Antibiotika: Penicilline","fr":"Antibiotiques : Pénicillines","tr":"Antibiyotikler: Penisilinler","nl":"Antibiotica: Penicillines","ru":"Антибиотики: пенициллины","zh":"抗生素：青霉素类","pt_BR":"Antibióticos: Penicilinas","pt_PT":"Antibióticos: Penicilinas"}, back_translations: {"es":"Antibióticos beta-lactamicos que inibem a síntese de la pared celular bacteriana. Bactericidas; eficazes contra organismos Gram-positivos. La amoxicilina es a penicilina oral más comum. Resistencia por beta-lactamases.","de":"Beta-Laktam-Antibiotika, die die bakterielle Zellwandsynthese hemmen. Bakterizid; wirksam gegen grampositive Erreger. Amoxicillin ist das gebräuchlichste orale Penicillin. Resistenz durch Beta-Laktamasen.","fr":"Antibiotiques bêta-lactamines qui inhibent la synthèse de la paroi cellulaire bactérienne. Bactéricides ; efficaces contre les organismes Gram-positifs. L'amoxicilline est la pénicilline orale la plus courante. Résistance via les bêta-lactamases.","tr":"Bakteriyel hücre duvarı sentezini inhibe eden beta-laktam antibiyotikler. Bakterisidal; gram-pozitif organizmalara karşı etkili. Amoksisilin en yaygın oral penisilindir. Beta-laktamazlar aracılığıyla direnç.","nl":"Beta-lactam antibiotica die de bacteriële celwandsynthese remmen. Bactericide; effectief tegen gram-positieve organismen. Amoxicilline is het meest gebruikte orale penicilline. Resistentie via beta-lactamasen.","ru":"Бета-лактамные антибиотики, подавляющие синтез клеточной стенки бактерий. Бактерицидные; эффективны против грамположительных микроорганизмов. Амоксициллин — наиболее распространённый пероральный пенициллин. Устойчивость обусловлена бета-лактамазами.","zh":"抑制细菌细胞壁合成的β-内酰胺类抗生素。杀菌性；对革兰阳性菌有效。阿莫西林是最常用的口服青霉素。通过β-内酰胺酶产生耐药性。","pt_BR":"Antibióticos beta-lactâmicos que inibem a síntese da parede celular bacteriana. Bactericidas; eficazes contra organismos Gram-positivos. A amoxicilina é a penicilina oral mais comum. Resistência por beta-lactamases.","pt_PT":"Antibióticos beta-lactâmicos que inibem a síntese da parede celular bacteriana. Bactericidas; eficazes contra organismos Gram-positivos. A amoxicilina é a penicilina oral mais comum. Resistência por beta-lactamases."}},
  { id: 'dc-medical-0097', deck_id: 'deck-medical', sort_order: 97, front: "Antibiotics: Macrolides", back: "Inhibit bacterial protein synthesis by binding the 50S ribosomal subunit. Bacteriostatic. Used for atypical pneumonias, H. pylori, STIs. Examples: azithromycin, erythromycin, clarithromycin. Side effect: QT prolongation." , front_translations: {"es":"Antibióticos: Macrolídeos","de":"Antibiotika: Makrolide","fr":"Antibiotiques : Macrolides","tr":"Antibiyotikler: Makrolidler","nl":"Antibiotica: Macroliden","ru":"Антибиотики: макролиды","zh":"抗生素：大环内酯类","pt_BR":"Antibióticos: Macrolídeos","pt_PT":"Antibióticos: Macrólidos"}, back_translations: {"es":"Inibem a síntese proteica bacteriana ligando-se a la subunidad ribossomal 50S. Bacteriostáticos. Usados para pneumonias atípicas, H. pylori, ISTs. Ejemplos: azitromicina, eritromicina, claritromicina. Efecto colateral: prolongamento del QT.","de":"Hemmen die bakterielle Proteinsynthese durch Bindung an die 50S-ribosomale Untereinheit. Bakteriostatisch. Eingesetzt bei atypischen Pneumonien, H. pylori, STIs. Beispiele: Azithromycin, Erythromycin, Clarithromycin. Nebenwirkung: QT-Verlängerung.","fr":"Inhibent la synthèse protéique bactérienne en se liant à la sous-unité ribosomale 50S. Bactériostatiques. Utilisés pour les pneumonies atypiques, H. pylori, les IST. Exemples : azithromycine, érythromycine, clarithromycine. Effet secondaire : allongement du QT.","tr":"50S ribozomal alt birime bağlanarak bakteriyel protein sentezini inhibe eder. Bakteriyostatik. Atipik pnömoniler, H. pylori, STI'larda kullanılır. Örnekler: azitromisin, eritromisin, klaritromisin. Yan etki: QT uzaması.","nl":"Remmen bacteriële eiwitsynthese door binding aan de 50S ribosomale subunit. Bacteriostatisch. Gebruikt voor atypische pneumonieën, H. pylori, SOA's. Voorbeelden: azitromycine, erytromycine, claritromycine. Bijwerking: QT-verlenging.","ru":"Подавляют синтез бактериального белка, связываясь с 50S рибосомальной субъединицей. Бактериостатические. Применяются при атипичных пневмониях, H. pylori, ИППП. Примеры: азитромицин, эритромицин, кларитромицин. Побочный эффект: удлинение интервала QT.","zh":"通过与50S核糖体亚基结合抑制细菌蛋白质合成。抑菌性。用于非典型肺炎、幽门螺杆菌、性传播感染。例子：阿奇霉素、红霉素、克拉霉素。副作用：QT延长。","pt_BR":"Inibem a síntese proteica bacteriana ligando-se à subunidade ribossomal 50S. Bacteriostáticos. Usados para pneumonias atípicas, H. pylori, ISTs. Exemplos: azitromicina, eritromicina, claritromicina. Efeito colateral: prolongamento do QT.","pt_PT":"Inibem a síntese proteica bacteriana ligando-se à subunidade ribossomal 50S. Bacteriostáticos. Usados para pneumonias atípicas, H. pylori, ISTs. Exemplos: azitromicina, eritromicina, claritromicina. Efeito secundário: prolongamento do QT."}},
  { id: 'dc-medical-0098', deck_id: 'deck-medical', sort_order: 98, front: "Opioid Analgesics", back: "Act on opioid receptors (μ, κ, δ) in the CNS to produce analgesia. Examples: morphine, oxycodone, fentanyl. Risks: respiratory depression, dependence, constipation. Reversed by naloxone." , front_translations: {"es":"Analgésicos Opioides","de":"Opioid-Analgetika","fr":"Analgésiques opioïdes","tr":"Opioid Analjezikler","nl":"Opioïde analgetica","ru":"Опиоидные анальгетики","zh":"阿片类镇痛药","pt_BR":"Analgésicos Opioides","pt_PT":"Analgésicos Opioides"}, back_translations: {"es":"Actúan en los receptores opioides (μ, κ, δ) en el SNC para produzir analgesia. Ejemplos: morfina, oxicodona, fentanil. Riesgos: depresión respiratória, dependencia, constipación. Revertidos por naloxona.","de":"Wirken auf Opioid-Rezeptoren (μ, κ, δ) im ZNS, um Analgesie zu erzeugen. Beispiele: Morphin, Oxycodon, Fentanyl. Risiken: Atemdepression, Abhängigkeit, Verstopfung. Durch Naloxon umkehrbar.","fr":"Agissent sur les récepteurs opioïdes (μ, κ, δ) dans le SNC pour produire une analgésie. Exemples : morphine, oxycodone, fentanyl. Risques : dépression respiratoire, dépendance, constipation. Réversés par la naloxone.","tr":"Analjezi üretmek için MSS'deki opioid reseptörlerine (μ, κ, δ) etki eder. Örnekler: morfin, oksikodone, fentanil. Riskler: solunum depresyonu, bağımlılık, kabızlık. Nalokson ile geri döndürülür.","nl":"Werken op opioïde receptoren (μ, κ, δ) in het CZS om analgesie te produceren. Voorbeelden: morfine, oxycodon, fentanyl. Risico's: ademdepressie, afhankelijkheid, constipatie. Omgekeerd door naloxon.","ru":"Действуют на опиоидные рецепторы (μ, κ, δ) в ЦНС, вызывая анальгезию. Примеры: морфин, оксикодон, фентанил. Риски: угнетение дыхания, зависимость, запор. Обратимы налоксоном.","zh":"作用于中枢神经系统的阿片受体（μ、κ、δ）产生镇痛效果。例子：吗啡、羟考酮、芬太尼。风险：呼吸抑制、依赖性、便秘。可用纳洛酮逆转。","pt_BR":"Atuam nos receptores opioides (μ, κ, δ) no SNC para produzir analgesia. Exemplos: morfina, oxicodona, fentanil. Riscos: depressão respiratória, dependência, constipação. Revertidos por naloxona.","pt_PT":"Atuam nos receptores opioides (μ, κ, δ) no SNC para produzir analgesia. Exemplos: morfina, oxicodona, fentanil. Riscos: depressão respiratória, dependência, obstipação. Revertidos por naloxona."}},
  { id: 'dc-medical-0099', deck_id: 'deck-medical', sort_order: 99, front: "NSAIDs — Non-Steroidal Anti-Inflammatory Drugs", back: "Inhibit COX-1 and COX-2 enzymes, reducing prostaglandin synthesis. Provide analgesia, antipyresis, and anti-inflammatory effects. Examples: ibuprofen, naproxen. Side effects: GI ulcers, renal impairment, platelet inhibition." , front_translations: {"es":"AINEs — Anti-Inflamatórios No Esteroides","de":"NSAIDs — Nicht-steroidale Antirheumatika","fr":"AINS — Anti-Inflammatoires Non Stéroïdiens","tr":"NSAİİ'ler — Non-Steroid Anti-İnflamatuar İlaçlar","nl":"NSAID's — Niet-Steroïde Anti-Inflammatoire Geneesmiddelen","ru":"НПВС — нестероидные противовоспалительные средства","zh":"NSAIDs — 非甾体抗炎药","pt_BR":"AINEs — Anti-Inflamatórios Não Esteroides","pt_PT":"AINEs — Anti-Inflamatórios Não Esteroides"}, back_translations: {"es":"Inibem las enzimas COX-1 y COX-2, reduciendo a síntese de prostaglandinas. Proporcionan analgesia, antipirese y efectos anti-inflamatórios. Ejemplos: ibuprofeno, naproxeno. Efectos colaterais: úlceras gastrointestinais, comprometimento renal, inibición plaquetária.","de":"Hemmen COX-1- und COX-2-Enzyme und reduzieren die Prostaglandinsynthese. Bieten Analgesie, Antipyrese und entzündungshemmende Wirkung. Beispiele: Ibuprofen, Naproxen. Nebenwirkungen: Magengeschwüre, Nierenschäden, Thrombozytenhemmung.","fr":"Inhibent les enzymes COX-1 et COX-2, réduisant la synthèse des prostaglandines. Fournissent analgésie, antipyrésie et effets anti-inflammatoires. Exemples : ibuprofène, naproxène. Effets secondaires : ulcères gastro-intestinaux, insuffisance rénale, inhibition plaquettaire.","tr":"COX-1 ve COX-2 enzimlerini inhibe ederek prostaglandin sentezini azaltır. Analjezi, antipirez ve anti-inflamatuar etki sağlar. Örnekler: ibuprofen, naproksen. Yan etkiler: GI ülserler, renal yetmezlik, trombosit inhibisyonu.","nl":"Remmen COX-1 en COX-2 enzymen, verminderen prostaglandinesynthese. Bieden analgesie, antipyrese en anti-inflammatoire effecten. Voorbeelden: ibuprofen, naproxen. Bijwerkingen: gastro-intestinale ulcera, nierinsufficiëntie, remming van bloedplaatjes.","ru":"Ингибируют ферменты ЦОГ-1 и ЦОГ-2, снижая синтез простагландинов. Обеспечивают анальгезию, жаропонижающий и противовоспалительный эффекты. Примеры: ибупрофен, напроксен. Побочные эффекты: язвы ЖКТ, нарушение функции почек, ингибирование тромбоцитов.","zh":"抑制COX-1和COX-2酶，减少前列腺素合成。提供镇痛、退热和抗炎作用。例子：布洛芬、萘普生。副作用：胃肠道溃疡、肾损害、血小板抑制。","pt_BR":"Inibem as enzimas COX-1 e COX-2, reduzindo a síntese de prostaglandinas. Fornecem analgesia, antipirese e efeitos anti-inflamatórios. Exemplos: ibuprofeno, naproxeno. Efeitos colaterais: úlceras gastrointestinais, comprometimento renal, inibição plaquetária.","pt_PT":"Inibem as enzimas COX-1 e COX-2, reduzindo a síntese de prostaglandinas. Fornecem analgesia, antipirese e efeitos anti-inflamatórios. Exemplos: ibuprofeno, naproxeno. Efeitos secundários: úlceras gastrointestinais, compromisso renal, inibição plaquetária."}},
  { id: 'dc-medical-0100', deck_id: 'deck-medical', sort_order: 100, front: "Corticosteroids", back: "Anti-inflammatory and immunosuppressive drugs that mimic cortisol. Used in asthma, autoimmune diseases, adrenal insufficiency. Long-term side effects: Cushing's syndrome, osteoporosis, hyperglycemia, immunosuppression." , front_translations: {"es":"Corticosteroides","de":"Kortikosteroide","fr":"Corticostéroïdes","tr":"Kortikosteroidler","nl":"Corticosteroïden","ru":"Кортикостероиды","zh":"皮质类固醇","pt_BR":"Corticosteroides","pt_PT":"Corticosteroides"}, back_translations: {"es":"Fármacos anti-inflamatórios y imunossupressores que mimetizam el cortisol. Usados en asma, enfermedades autoimunes, insuficiencia adrenal. Efectos colaterais a ancho prazo: síndrome de Cushing, osteoporose, hiperglicemia, imunossupresión.","de":"Entzündungshemmende und immunsuppressive Medikamente, die Cortisol nachahmen. Eingesetzt bei Asthma, Autoimmunerkrankungen, Nebenniereninsuffizienz. Langzeitnebenwirkungen: Cushing-Syndrom, Osteoporose, Hyperglykämie, Immunsuppression.","fr":"Médicaments anti-inflammatoires et immunosuppresseurs qui imitent le cortisol. Utilisés dans l'asthme, les maladies auto-immunes, l'insuffisance surrénale. Effets secondaires à long terme : syndrome de Cushing, ostéoporose, hyperglycémie, immunosuppression.","tr":"Kortizolu taklit eden anti-inflamatuar ve immünsüpresif ilaçlar. Astım, otoimmün hastalıklar, adrenal yetmezlikte kullanılır. Uzun vadeli yan etkiler: Cushing sendromu, osteoporoz, hiperglisemi, immünsüpresyon.","nl":"Anti-inflammatoire en immunosuppressieve geneesmiddelen die cortisol nabootsen. Gebruikt bij astma, auto-immuunziekten, bijnierschorsinsufficiëntie. Langetermijn bijwerkingen: syndroom van Cushing, osteoporose, hyperglykemie, immunosuppressie.","ru":"Противовоспалительные и иммунодепрессивные препараты, имитирующие кортизол. Применяются при бронхиальной астме, аутоиммунных заболеваниях, надпочечниковой недостаточности. Долгосрочные побочные эффекты: синдром Кушинга, остеопороз, гипергликемия, иммуносупрессия.","zh":"模拟皮质醇的抗炎和免疫抑制药物。用于哮喘、自身免疫性疾病、肾上腺功能不全。长期副作用：库欣综合征、骨质疏松症、高血糖、免疫抑制。","pt_BR":"Fármacos anti-inflamatórios e imunossupressores que mimetizam o cortisol. Usados em asma, doenças autoimunes, insuficiência adrenal. Efeitos colaterais a longo prazo: síndrome de Cushing, osteoporose, hiperglicemia, imunossupressão.","pt_PT":"Fármacos anti-inflamatórios e imunossupressores que mimetizam o cortisol. Usados em asma, doenças autoimunes, insuficiência suprarrenal. Efeitos secundários a longo prazo: síndrome de Cushing, osteoporose, hiperglicemia, imunossupressão."}},
  { id: 'dc-medical-0101', deck_id: 'deck-medical', sort_order: 101, front: "IV — Intravenous", back: "Administration of medication or fluids directly into a vein. Fastest onset and 100% bioavailability. Used when rapid action is needed (STAT medications, fluids) or when oral route is unavailable." , front_translations: {"es":"IV — Intravenoso","de":"IV — Intravenös","fr":"IV — Intraveineux","tr":"IV — İntravenöz","nl":"IV — Intraveneus","ru":"IV — Внутривенно","zh":"IV — 静脉注射","pt_BR":"IV — Intravenoso","pt_PT":"IV — Intravenoso"}, back_translations: {"es":"Administración de medicamentos o fluidos directamente en una vena. Início de acción más rápido y 100% de biodisponibilidad.","de":"Verabreichung von Medikamenten oder Flüssigkeiten direkt in eine Vene. Schnellster Wirkungseintritt und 100 % Bioverfügbarkeit.","fr":"Administration de médicaments ou de liquides directement dans une veine. Délai d'action le plus rapide et biodisponibilité de 100 %.","tr":"İlaç veya sıvıların doğrudan damar içine verilmesi. En hızlı etki başlangıcı ve %100 biyoyararlanım.","nl":"Toediening van medicatie of vloeistoffen rechtstreeks in een ader. Snelste werkingsintreding en 100% biologische beschikbaarheid.","ru":"Введение лекарственных препаратов или жидкостей непосредственно в вену. Самое быстрое начало действия и 100% биодоступность.","zh":"将药物或液体直接注入静脉。起效最快，生物利用度为100%。","pt_BR":"Administração de medicamentos ou fluidos diretamente em uma veia. Início de ação mais rápido e 100% de biodisponibilidade.","pt_PT":"Administração de medicamentos ou fluidos diretamente numa veia. Início de ação mais rápido e 100% de biodisponibilidade."}},
  { id: 'dc-medical-0102', deck_id: 'deck-medical', sort_order: 102, front: "IM — Intramuscular", back: "Injection of medication into muscle tissue. Faster onset than oral or subcutaneous. Used for vaccines, some antibiotics, and hormones. Absorption depends on muscle blood flow." , front_translations: {"es":"IM — Intramuscular","de":"IM — Intramuskulär","fr":"IM — Intramusculaire","tr":"IM — İntramüsküler","nl":"IM — Intramusculair","ru":"IM — Внутримышечно","zh":"IM — 肌肉注射","pt_BR":"IM — Intramuscular","pt_PT":"IM — Intramuscular"}, back_translations: {"es":"Injeción de medicamento en el tejido muscular. Início de acción más rápido que a via oral o subcutanea. Usado para vacinas, algunos antibióticos y injeciones hormonais.","de":"Injektion von Medikamenten in das Muskelgewebe. Schnellerer Wirkungseintritt als oral oder subkutan. Verwendet für Impfungen, einige Antibiotika und Hormoninjektionen.","fr":"Injection de médicaments dans le tissu musculaire. Délai d'action plus rapide que la voie orale ou sous-cutanée. Utilisée pour les vaccins, certains antibiotiques et les injections hormonales.","tr":"İlacın kas dokusuna enjekte edilmesi. Oral veya subkutan yoldan daha hızlı etki başlangıcı. Aşılar, bazı antibiyotikler ve hormon enjeksiyonları için kullanılır.","nl":"Injectie van medicatie in spierweefsel. Snellere werkingsintreding dan oraal of subcutaan. Gebruikt voor vaccins, sommige antibiotica en hormooninjecties.","ru":"Инъекция лекарственного препарата в мышечную ткань. Более быстрое начало действия, чем при пероральном или подкожном введении. Применяется для вакцин, некоторых антибиотиков и гормональных инъекций.","zh":"将药物注射到肌肉组织中。比口服或皮下注射起效更快。用于疫苗、某些抗生素和激素注射。","pt_BR":"Injeção de medicamento no tecido muscular. Início de ação mais rápido que a via oral ou subcutânea. Usado para vacinas, alguns antibióticos e injeções hormonais.","pt_PT":"Injeção de medicamento no tecido muscular. Início de ação mais rápido que a via oral ou subcutânea. Utilizado para vacinas, alguns antibióticos e injeções hormonais."}},
  { id: 'dc-medical-0103', deck_id: 'deck-medical', sort_order: 103, front: "SC / SQ — Subcutaneous", back: "Injection into the subcutaneous fat layer beneath the skin. Slower absorption than IV or IM. Used for insulin, heparin, vaccines. Self-injectable; convenient for long-term therapy." , front_translations: {"es":"SC / SQ — Subcutaneo","de":"SC / SQ — Subkutan","fr":"SC / SQ — Sous-cutané","tr":"SC / SQ — Subkutan (Deri Altı)","nl":"SC / SQ — Subcutaan","ru":"SC / SQ — Подкожно","zh":"SC / SQ — 皮下注射","pt_BR":"SC / SQ — Subcutâneo","pt_PT":"SC / SQ — Subcutâneo"}, back_translations: {"es":"Injeción en la capa de gordura subcutanea debajo de la piel. Absorción más lenta que IV o IM. Usado para insulina, heparina y algunas vacinas.","de":"Injektion in die subkutane Fettschicht unter der Haut. Langsamere Absorption als IV oder IM. Verwendet für Insulin, Heparin und einige Impfstoffe.","fr":"Injection dans la couche de graisse sous-cutanée sous la peau. Absorption plus lente que IV ou IM. Utilisée pour l'insuline, l'héparine et certains vaccins.","tr":"Derinin altındaki subkutan yağ tabakasına enjeksiyon. IV veya IM'den daha yavaş emilim. İnsülin, heparin ve bazı aşılar için kullanılır.","nl":"Injectie in de subcutane vetlaag onder de huid. Langzamere absorptie dan IV of IM. Gebruikt voor insuline, heparine en sommige vaccins.","ru":"Инъекция в подкожную жировую клетчатку. Более медленное всасывание, чем при IV или IM введении. Используется для инсулина, гепарина и некоторых вакцин.","zh":"注射到皮肤下方的皮下脂肪层。吸收速度比IV或IM慢。用于胰岛素、肝素和某些疫苗。","pt_BR":"Injeção na camada de gordura subcutânea abaixo da pele. Absorção mais lenta que IV ou IM. Usado para insulina, heparina e algumas vacinas.","pt_PT":"Injeção na camada de gordura subcutânea abaixo da pele. Absorção mais lenta que IV ou IM. Utilizado para insulina, heparina e algumas vacinas."}},
  { id: 'dc-medical-0104', deck_id: 'deck-medical', sort_order: 104, front: "PO — Per Os", back: "Latin for 'by mouth.' Indicates oral administration of a medication. The most common and convenient route. Subject to first-pass metabolism, which may reduce bioavailability." , front_translations: {"es":"PO — Per Los","de":"PO — Per Os","fr":"PO — Per Os","tr":"PO — Per Os (Ağız Yoluyla)","nl":"PO — Per Os","ru":"PO — Per Os (Перорально)","zh":"PO — Per Os（口服）","pt_BR":"PO — Per Os","pt_PT":"PO — Per Os"}, back_translations: {"es":"Do latim 'por la boca'. Indica administración oral de un medicamento. La via de administración más comum y conveniente.","de":"Lateinisch für 'durch den Mund'. Bezeichnet die orale Verabreichung eines Medikaments. Der häufigste und bequemste Weg der Medikamentengabe.","fr":"Du latin 'par la bouche'. Indique l'administration orale d'un médicament. La voie d'administration la plus courante et la plus pratique.","tr":"Latince 'ağız yoluyla' anlamına gelir. İlacın ağızdan verilmesini belirtir. En yaygın ve pratik ilaç uygulama yoludur.","nl":"Latijn voor 'via de mond'. Geeft orale toediening van een geneesmiddel aan. De meest gebruikelijke en gemakkelijkste toedieningsweg.","ru":"С латинского — 'через рот'. Означает пероральный приём лекарственного препарата. Наиболее распространённый и удобный путь введения лекарств.","zh":"拉丁语，意为'经口'。指药物的口服给药方式。最常见、最便捷的给药途径。","pt_BR":"Do latim 'pela boca'. Indica administração oral de um medicamento. A via de administração mais comum e conveniente.","pt_PT":"Do latim 'pela boca'. Indica administração oral de um medicamento. A via de administração mais comum e conveniente."}},
  { id: 'dc-medical-0105', deck_id: 'deck-medical', sort_order: 105, front: "BID / TID / QID", back: "Frequency abbreviations: BID (bis in die) = twice daily; TID (ter in die) = three times daily; QID (quater in die) = four times daily. QD = once daily; QHS = at bedtime." , front_translations: {"es":"BID / TID / QID","de":"BID / TID / QID","fr":"BID / TID / QID","tr":"BID / TID / QID","nl":"BID / TID / QID","ru":"BID / TID / QID","zh":"BID / TID / QID","pt_BR":"BID / TID / QID","pt_PT":"BID / TID / QID"}, back_translations: {"es":"Abreviaciones de frecuencia: BID (bis in die) = de los veces al dia; TID (ter in die) = tres veces al dia; QID (quater in die) = cuatro veces al dia.","de":"Häufigkeitsabkürzungen: BID (bis in die) = zweimal täglich; TID (ter in die) = dreimal täglich; QID (quater in die) = viermal täglich.","fr":"Abréviations de fréquence : BID (bis in die) = deux fois par jour ; TID (ter in die) = trois fois par jour ; QID (quater in die) = quatre fois par jour.","tr":"Sıklık kısaltmaları: BID (bis in die) = günde iki kez; TID (ter in die) = günde üç kez; QID (quater in die) = günde dört kez.","nl":"Frequentieafkortingen: BID (bis in die) = tweemaal daags; TID (ter in die) = driemaal daags; QID (quater in die) = viermaal daags.","ru":"Сокращения частоты приёма: BID (bis in die) = дважды в день; TID (ter in die) = трижды в день; QID (quater in die) = четыре раза в день.","zh":"频次缩写：BID（bis in die）= 每日两次；TID（ter in die）= 每日三次；QID（quater in die）= 每日四次。","pt_BR":"Abreviações de frequência: BID (bis in die) = duas vezes ao dia; TID (ter in die) = três vezes ao dia; QID (quater in die) = quatro vezes ao dia.","pt_PT":"Abreviaturas de frequência: BID (bis in die) = duas vezes ao dia; TID (ter in die) = três vezes ao dia; QID (quater in die) = quatro vezes ao dia."}},
  { id: 'dc-medical-0106', deck_id: 'deck-medical', sort_order: 106, front: "MRI — Magnetic Resonance Imaging", back: "Uses strong magnetic fields and radiofrequency pulses to produce detailed images of soft tissues. Superior to CT for brain, spinal cord, joints, and soft tissue tumors. No ionizing radiation." , front_translations: {"es":"MRI — Ressonancia Magnética","de":"MRI — Magnetresonanztomographie","fr":"IRM — Imagerie par Résonance Magnétique","tr":"MRI — Manyetik Rezonans Görüntüleme","nl":"MRI — Magnetische Resonantie Beeldvorming","ru":"MRI — Магнитно-резонансная томография","zh":"MRI — 磁共振成像","pt_BR":"MRI — Ressonância Magnética","pt_PT":"MRI — Ressonância Magnética"}, back_translations: {"es":"Utiliza campos magnéticos fuertes y pulsos de radiofrequencia para produzir imajes detalhadas de tejidos moles. Superior para cerebro, médula espinal, articulaciones y tumores de tejidos moles. Sin radiación ionizante.","de":"Verwendet starke Magnetfelder und Hochfrequenzimpulse zur Erzeugung detaillierter Bilder von Weichgewebe. Überlegen für Gehirn, Rückenmark, Gelenke und Weichteiltumoren. Keine ionisierende Strahlung.","fr":"Utilise des champs magnétiques puissants et des impulsions radiofréquences pour produire des images détaillées des tissus mous. Supérieure pour le cerveau, la moelle épinière, les articulations et les tumeurs des tissus mous. Pas de rayonnement ionisant.","tr":"Yumuşak dokuların ayrıntılı görüntülerini elde etmek için güçlü manyetik alanlar ve radyofrekans darbeler kullanır. Beyin, omurilik, eklemler ve yumuşak doku tümörleri için üstündür. İyonlaştırıcı radyasyon yoktur.","nl":"Gebruikt sterke magnetische velden en radiofrequente pulsen om gedetailleerde beelden van weke delen te produceren. Superieur voor hersenen, ruggenmerg, gewrichten en wekedelentumoren. Geen ioniserende straling.","ru":"Использует сильные магнитные поля и радиочастотные импульсы для получения детальных изображений мягких тканей. Превосходит другие методы при исследовании головного и спинного мозга, суставов и опухолей мягких тканей. Без ионизирующего излучения.","zh":"利用强磁场和射频脉冲生成软组织的详细图像。在脑、脊髓、关节和软组织肿瘤方面表现优异。无电离辐射。","pt_BR":"Utiliza campos magnéticos fortes e pulsos de radiofrequência para produzir imagens detalhadas de tecidos moles. Superior para cérebro, medula espinhal, articulações e tumores de tecidos moles. Sem radiação ionizante.","pt_PT":"Utiliza campos magnéticos fortes e pulsos de radiofrequência para produzir imagens detalhadas de tecidos moles. Superior para cérebro, medula espinal, articulações e tumores de tecidos moles. Sem radiação ionizante."}},
  { id: 'dc-medical-0107', deck_id: 'deck-medical', sort_order: 107, front: "CT — Computed Tomography", back: "Uses X-rays from multiple angles processed by computer to produce cross-sectional images. Excellent for bone, chest (PE protocol), and abdominal imaging. Faster than MRI; uses ionizing radiation." , front_translations: {"es":"CT — Tomografia Computadorizada","de":"CT — Computertomographie","fr":"CT — Tomodensitométrie","tr":"CT — Bilgisayarlı Tomografi","nl":"CT — Computertomografie","ru":"CT — Компьютерная томография","zh":"CT — 计算机断层扫描","pt_BR":"CT — Tomografia Computadorizada","pt_PT":"CT — Tomografia Computorizada"}, back_translations: {"es":"Utiliza raios X de múltiplos ángulos processados por computadora para produzir imajes en corte transversal. Excelente para huesos, tórax, abdome y trauma agudo. Más rápido que MRI, pero involucra radiación.","de":"Verwendet Röntgenstrahlen aus verschiedenen Winkeln, die vom Computer verarbeitet werden, um Querschnittsbilder zu erzeugen. Hervorragend für Knochen, Thorax, Abdomen und akutes Trauma. Schneller als MRI, jedoch mit Strahlenbelastung.","fr":"Utilise des rayons X sous plusieurs angles, traités par ordinateur, pour produire des images en coupe transversale. Excellent pour les os, le thorax, l'abdomen et les traumatismes aigus. Plus rapide que l'IRM mais implique une irradiation.","tr":"Bilgisayar tarafından işlenen çok açılı X-ışınlarını kullanarak kesitsel görüntüler üretir. Kemik, göğüs, karın ve akut travma için mükemmeldir. MRI'dan daha hızlıdır ancak radyasyon içerir.","nl":"Gebruikt röntgenstralen vanuit meerdere hoeken, verwerkt door een computer, om dwarsdoorsnedebeelden te produceren. Uitstekend voor bot, thorax, abdomen en acuut trauma. Sneller dan MRI maar met stralingsbelasting.","ru":"Использует рентгеновские лучи с разных углов, обработанные компьютером, для получения поперечных срезов. Отлично подходит для костей, грудной клетки, брюшной полости и острой травмы. Быстрее, чем MRI, но связана с облучением.","zh":"利用多角度X射线经计算机处理生成横截面图像。适用于骨骼、胸部、腹部和急性创伤。比MRI快，但涉及辐射。","pt_BR":"Utiliza raios X de múltiplos ângulos processados por computador para produzir imagens em corte transversal. Excelente para ossos, tórax, abdome e trauma agudo. Mais rápido que MRI, mas envolve radiação.","pt_PT":"Utiliza raios X de múltiplos ângulos processados por computador para produzir imagens em corte transversal. Excelente para ossos, tórax, abdómen e trauma agudo. Mais rápido que MRI, mas envolve radiação."}},
  { id: 'dc-medical-0108', deck_id: 'deck-medical', sort_order: 108, front: "Ultrasound (US)", back: "Uses high-frequency sound waves to produce real-time images of soft tissues and organs. No radiation; safe in pregnancy. Excellent for gallbladder, kidneys, heart (echocardiography), and guided procedures." , front_translations: {"es":"Ultrassonografia (US)","de":"Ultraschall (US)","fr":"Échographie (US)","tr":"Ultrason (US)","nl":"Echografie (US)","ru":"Ультразвуковое исследование (УЗИ)","zh":"超声检查（US）","pt_BR":"Ultrassonografia (US)","pt_PT":"Ecografia (US)"}, back_translations: {"es":"Utiliza ondas sonoras de alta frecuencia para produzir imajes en tiempo real de tejidos moles y órganos. Sin radiación. Principales usos: obstetrícia, cardíaco (eco), abdominal, avaliación vascular.","de":"Verwendet hochfrequente Schallwellen zur Erzeugung von Echtzeitbildern von Weichgeweben und Organen. Keine Strahlung. Wichtige Anwendungen: Geburtshilfe, Kardiologie (Echo), Abdomen, Gefäßbeurteilung.","fr":"Utilise des ondes sonores à haute fréquence pour produire des images en temps réel des tissus mous et des organes. Pas de radiation. Utilisations principales : obstétrique, cardiaque (écho), abdominale, évaluation vasculaire.","tr":"Yumuşak doku ve organların gerçek zamanlı görüntülerini elde etmek için yüksek frekanslı ses dalgaları kullanır. Radyasyon yoktur. Başlıca kullanım alanları: obstetrik, kardiyak (eko), abdominal, vasküler değerlendirme.","nl":"Gebruikt hoogfrequente geluidsgolven om real-time beelden van weke delen en organen te produceren. Geen straling. Belangrijke toepassingen: verloskunde, cardiaal (echo), abdominaal, vasculaire beoordeling.","ru":"Использует высокочастотные звуковые волны для получения изображений мягких тканей и органов в реальном времени. Без радиации. Основные применения: акушерство, кардиология (ЭхоКГ), абдоминальное и сосудистое исследование.","zh":"利用高频声波实时生成软组织和器官的图像。无辐射。主要用途：产科、心脏（超声心动图）、腹部、血管评估。","pt_BR":"Utiliza ondas sonoras de alta frequência para produzir imagens em tempo real de tecidos moles e órgãos. Sem radiação. Principais usos: obstetrícia, cardíaco (eco), abdominal, avaliação vascular.","pt_PT":"Utiliza ondas sonoras de alta frequência para produzir imagens em tempo real de tecidos moles e órgãos. Sem radiação. Principais utilizações: obstetrícia, cardíaco (eco), abdominal, avaliação vascular."}},
  { id: 'dc-medical-0109', deck_id: 'deck-medical', sort_order: 109, front: "Triage", back: "The process of sorting patients based on urgency and severity of their condition to allocate limited medical resources effectively. Originates from military medicine; widely used in emergency departments." , front_translations: {"es":"Triaje","de":"Triage","fr":"Triage","tr":"Triaj","nl":"Triage","ru":"Триаж","zh":"分诊","pt_BR":"Triagem","pt_PT":"Triagem"}, back_translations: {"es":"Proceso de classificación de pacientes con base en la urgencia y gravidad de su condición para alocar recursos limitados de forma eficiente. Utilizado en departamentos de emergencia y cenários de desastre.","de":"Der Prozess der Einteilung von Patienten nach Dringlichkeit und Schwere ihres Zustands, um begrenzte Ressourcen effizient zuzuteilen. Anwendung in Notaufnahmen und bei Katastrophen.","fr":"Processus de tri des patients selon l'urgence et la gravité de leur état afin d'allouer efficacement les ressources limitées. Utilisé aux urgences et en situation de catastrophe.","tr":"Sınırlı kaynakları verimli şekilde dağıtmak amacıyla hastaları durumlarının aciliyetine ve ciddiyetine göre sınıflandırma süreci. Acil servislerde ve afet ortamlarında kullanılır.","nl":"Het proces van het sorteren van patiënten op basis van urgentie en ernst van hun toestand om beperkte middelen efficiënt in te zetten. Gebruikt op spoedeisende hulpafdelingen en bij rampen.","ru":"Процесс сортировки пациентов по срочности и тяжести состояния для эффективного распределения ограниченных ресурсов. Применяется в отделениях неотложной помощи и при катастрофах.","zh":"根据患者病情的紧迫程度和严重性进行分类的过程，以高效分配有限资源。用于急诊科和灾难场景。","pt_BR":"Processo de classificação de pacientes com base na urgência e gravidade de sua condição para alocar recursos limitados de forma eficiente. Utilizado em departamentos de emergência e cenários de desastre.","pt_PT":"Processo de classificação de doentes com base na urgência e gravidade da sua condição para alocar recursos limitados de forma eficiente. Utilizado em serviços de urgência e cenários de catástrofe."}},
  { id: 'dc-medical-0110', deck_id: 'deck-medical', sort_order: 110, front: "Vital Signs", back: "Basic clinical measurements: temperature (normal 36.1–37.2°C), pulse (60–100 bpm), respiratory rate (12–20/min), blood pressure (normal <120/80 mmHg), and oxygen saturation (≥95%). Often includes pain as the '5th vital sign.'" , front_translations: {"es":"Señales Vitais","de":"Vitalzeichen","fr":"Signes vitaux","tr":"Vital Bulgular","nl":"Vitale functies","ru":"Жизненные показатели","zh":"生命体征","pt_BR":"Sinais Vitais","pt_PT":"Sinais Vitais"}, back_translations: {"es":"Mediciones clínicas básicas: temperatura (normal 36,1–37,2 °C), muñeca (60–100 bpm), frecuencia respiratória (12–20/min), presión arterial (normal ~120/80 mmHg) y saturación de oxígeno (>95%).","de":"Grundlegende klinische Messungen: Temperatur (normal 36,1–37,2 °C), Puls (60–100 bpm), Atemfrequenz (12–20/min), Blutdruck (normal ~120/80 mmHg) und Sauerstoffsättigung (>95 %).","fr":"Mesures cliniques de base : température (normale 36,1–37,2 °C), pouls (60–100 bpm), fréquence respiratoire (12–20/min), pression artérielle (normale ~120/80 mmHg) et saturation en oxygène (>95 %).","tr":"Temel klinik ölçümler: vücut sıcaklığı (normal 36,1–37,2 °C), nabız (60–100 bpm), solunum hızı (12–20/dk), kan basıncı (normal ~120/80 mmHg) ve oksijen satürasyonu (>%95).","nl":"Basis klinische metingen: temperatuur (normaal 36,1–37,2 °C), pols (60–100 bpm), ademhalingsfrequentie (12–20/min), bloeddruk (normaal ~120/80 mmHg) en zuurstofsaturatie (>95%).","ru":"Основные клинические измерения: температура (норма 36,1–37,2 °C), пульс (60–100 уд/мин), частота дыхания (12–20/мин), артериальное давление (норма ~120/80 мм рт. ст.) и сатурация кислорода (>95%).","zh":"基本临床测量指标：体温（正常36.1–37.2°C）、脉搏（60–100次/分）、呼吸频率（12–20次/分）、血压（正常约120/80 mmHg）和血氧饱和度（>95%）。","pt_BR":"Medições clínicas básicas: temperatura (normal 36,1–37,2 °C), pulso (60–100 bpm), frequência respiratória (12–20/min), pressão arterial (normal ~120/80 mmHg) e saturação de oxigênio (>95%).","pt_PT":"Medições clínicas básicas: temperatura (normal 36,1–37,2 °C), pulso (60–100 bpm), frequência respiratória (12–20/min), pressão arterial (normal ~120/80 mmHg) e saturação de oxigénio (>95%)."}},
  { id: 'dc-medical-0111', deck_id: 'deck-medical', sort_order: 111, front: "Informed Consent", back: "A patient's voluntary agreement to a procedure or treatment after receiving and understanding all relevant information (risks, benefits, alternatives). Ethically and legally required before most medical interventions." , front_translations: {"es":"Consentimento Informado","de":"Einwilligungserklärung (Informed Consent)","fr":"Consentement éclairé","tr":"Bilgilendirilmiş Onam","nl":"Geïnformeerde toestemming","ru":"Информированное согласие","zh":"知情同意","pt_BR":"Consentimento Informado","pt_PT":"Consentimento Informado"}, back_translations: {"es":"Acuerdo voluntário del paciente para un procedimento o tratamiento após recibir y compreender todas las informaciones relevantes, incluyendo riesgos, benefícios y alternativas.","de":"Die freiwillige Zustimmung eines Patienten zu einem Eingriff oder einer Behandlung, nachdem er alle relevanten Informationen einschließlich Risiken, Nutzen und Alternativen erhalten und verstanden hat.","fr":"Accord volontaire du patient à une procédure ou un traitement après avoir reçu et compris toutes les informations pertinentes, y compris les risques, les bénéfices et les alternatives.","tr":"Hastanın riskler, faydalar ve alternatifler dahil tüm ilgili bilgileri aldıktan ve anladıktan sonra bir prosedür veya tedaviye gönüllü olarak onay vermesi.","nl":"De vrijwillige instemming van een patiënt met een procedure of behandeling nadat alle relevante informatie is ontvangen en begrepen, inclusief risico's, voordelen en alternatieven.","ru":"Добровольное согласие пациента на процедуру или лечение после получения и понимания всей необходимой информации, включая риски, преимущества и альтернативы.","zh":"患者在接收并理解所有相关信息（包括风险、益处和替代方案）后，自愿同意接受某项手术或治疗。","pt_BR":"Acordo voluntário do paciente para um procedimento ou tratamento após receber e compreender todas as informações relevantes, incluindo riscos, benefícios e alternativas.","pt_PT":"Acordo voluntário do doente para um procedimento ou tratamento após receber e compreender todas as informações relevantes, incluindo riscos, benefícios e alternativas."}},
  { id: 'dc-medical-0112', deck_id: 'deck-medical', sort_order: 112, front: "Palliative Care", back: "Specialized medical care focused on relief from symptoms, pain, and stress of serious illness, not on curing it. Aims to improve quality of life for patient and family. Given alongside curative treatment." , front_translations: {"es":"Cuidados Paliativos","de":"Palliativmedizin","fr":"Soins palliatifs","tr":"Palyatif Bakım","nl":"Palliatieve zorg","ru":"Паллиативная помощь","zh":"姑息治疗","pt_BR":"Cuidados Paliativos","pt_PT":"Cuidados Paliativos"}, back_translations: {"es":"Cuidados médicos especializados focados en el alívio de síntomas, dor y estresse de enfermedades graves, no en la cura. Pueden ser oferecidos junto con el tratamiento curativo en cualquier etapa de la enfermedad.","de":"Spezialisierte medizinische Versorgung zur Linderung von Symptomen, Schmerzen und Belastungen bei schweren Erkrankungen, nicht auf Heilung ausgerichtet. Kann in jedem Krankheitsstadium parallel zur kurativen Behandlung erfolgen.","fr":"Soins médicaux spécialisés axés sur le soulagement des symptômes, de la douleur et du stress liés à une maladie grave, et non sur la guérison. Peuvent être prodigués parallèlement au traitement curatif à tout stade de la maladie.","tr":"Ciddi hastalıkların semptomlarından, ağrısından ve stresinden kurtulmaya odaklanan özel tıbbi bakım; tedavi amaçlı değildir. Hastalığın herhangi bir aşamasında küratif tedaviyle birlikte uygulanabilir.","nl":"Gespecialiseerde medische zorg gericht op verlichting van symptomen, pijn en stress bij ernstige ziekte, niet op genezing. Kan in elk ziektestadium naast curatieve behandeling worden geboden.","ru":"Специализированная медицинская помощь, направленная на облегчение симптомов, боли и стресса при тяжёлых заболеваниях, а не на излечение. Может оказываться наряду с лечебной терапией на любой стадии заболевания.","zh":"专门针对严重疾病的症状、疼痛和压力进行缓解的医疗护理，而非以治愈为目的。可在疾病的任何阶段与治愈性治疗同时进行。","pt_BR":"Cuidados médicos especializados focados no alívio de sintomas, dor e estresse de doenças graves, não na cura. Podem ser oferecidos junto com o tratamento curativo em qualquer estágio da doença.","pt_PT":"Cuidados médicos especializados focados no alívio de sintomas, dor e sofrimento de doenças graves, não na cura. Podem ser prestados em paralelo com o tratamento curativo em qualquer fase da doença."}},
  { id: 'dc-medical-0113', deck_id: 'deck-medical', sort_order: 113, front: "DNR / DNAR", back: "Do Not Resuscitate / Do Not Attempt Resuscitation. A medical order instructing healthcare providers not to perform CPR if the patient's heart or breathing stops. Must be documented and legally valid." , front_translations: {"es":"DNR / DNAR","de":"DNR / DNAR","fr":"DNR / DNAR","tr":"DNR / DNAR","nl":"DNR / DNAR","ru":"DNR / DNAR","zh":"DNR / DNAR（不予复苏）","pt_BR":"DNR / DNAR","pt_PT":"DNR / DNAR"}, back_translations: {"es":"Do Not Resuscitate / Do Not Attempt Resuscitation (No Ressuscitar). Una ordem médica que instrui los profissionais de salud a no realizar RCP se el corazón o a respiración del paciente parar.","de":"Do Not Resuscitate / Do Not Attempt Resuscitation. Eine ärztliche Anordnung, die das medizinische Personal anweist, keine Herz-Lungen-Wiederbelebung (CPR) durchzuführen, wenn das Herz oder die Atmung des Patienten aussetzt.","fr":"Do Not Resuscitate / Do Not Attempt Resuscitation (Ne pas réanimer). Un ordre médical demandant au personnel soignant de ne pas pratiquer de réanimation cardio-pulmonaire (RCP) si le cœur ou la respiration du patient s'arrête.","tr":"Do Not Resuscitate / Do Not Attempt Resuscitation (Resüsite Etmeyin). Hastanın kalbi veya solunumu durursa sağlık personelinin CPR uygulamamasını bildiren tıbbi bir talimattır.","nl":"Do Not Resuscitate / Do Not Attempt Resuscitation (Niet reanimeren). Een medisch bevel dat zorgverleners instrueert geen cardiopulmonale reanimatie (CPR) uit te voeren als het hart of de ademhaling van de patiënt stopt.","ru":"Do Not Resuscitate / Do Not Attempt Resuscitation (Не реанимировать). Медицинское распоряжение, предписывающее медработникам не проводить сердечно-лёгочную реанимацию (СЛР) в случае остановки сердца или дыхания пациента.","zh":"Do Not Resuscitate / Do Not Attempt Resuscitation（不予复苏/不尝试复苏）。一项医嘱，指示医护人员在患者心脏或呼吸骤停时不进行心肺复苏（CPR）。","pt_BR":"Do Not Resuscitate / Do Not Attempt Resuscitation (Não Ressuscitar). Uma ordem médica que instrui os profissionais de saúde a não realizar RCP se o coração ou a respiração do paciente parar.","pt_PT":"Do Not Resuscitate / Do Not Attempt Resuscitation (Não Reanimar). Uma ordem médica que instrui os profissionais de saúde a não realizar RCP se o coração ou a respiração do doente parar."}},
  { id: 'dc-medical-0114', deck_id: 'deck-medical', sort_order: 114, front: "SOAP Note", back: "A structured medical documentation format: Subjective (patient's symptoms), Objective (clinical findings, vitals, labs), Assessment (diagnosis), Plan (treatment). Widely used in outpatient and inpatient settings." , front_translations: {"es":"Nota SOAP","de":"SOAP-Dokumentation","fr":"Note SOAP","tr":"SOAP Notu","nl":"SOAP-notitie","ru":"Запись SOAP","zh":"SOAP病历记录","pt_BR":"Nota SOAP","pt_PT":"Nota SOAP"}, back_translations: {"es":"Formato estruturado de documentación médica: Subjetivo (síntomas del paciente), Objetivo (achados clínicos), Avaliación (diagnóstico), Plano (tratamiento). Padrão para consultas clínicas.","de":"Ein strukturiertes medizinisches Dokumentationsformat: Subjektiv (Symptome des Patienten), Objektiv (klinische Befunde), Assessment (Diagnose), Plan (Behandlung). Standard für klinische Konsultationen.","fr":"Un format structuré de documentation médicale : Subjectif (symptômes du patient), Objectif (constatations cliniques), Assessment/Analyse (diagnostic), Plan (traitement). Standard pour les consultations cliniques.","tr":"Yapılandırılmış tıbbi dokümantasyon formatı: Subjektif (hastanın semptomları), Objektif (klinik bulgular), Değerlendirme (tanı), Plan (tedavi). Klinik görüşmeler için standarttır.","nl":"Een gestructureerd medisch documentatieformaat: Subjectief (klachten van de patiënt), Objectief (klinische bevindingen), Assessment (diagnose), Plan (behandeling). Standaard voor klinische consulten.","ru":"Структурированный формат медицинской документации: Subjective (жалобы пациента), Objective (клинические данные), Assessment (диагноз), Plan (план лечения). Стандарт для клинических осмотров.","zh":"结构化病历记录格式：主观（患者症状）、客观（临床检查结果）、评估（诊断）、计划（治疗方案）。临床诊疗的标准记录格式。","pt_BR":"Formato estruturado de documentação médica: Subjetivo (sintomas do paciente), Objetivo (achados clínicos), Avaliação (diagnóstico), Plano (tratamento). Padrão para consultas clínicas.","pt_PT":"Formato estruturado de documentação médica: Subjetivo (sintomas do doente), Objetivo (achados clínicos), Avaliação (diagnóstico), Plano (tratamento). Padrão para consultas clínicas."}},
  { id: 'dc-medical-0115', deck_id: 'deck-medical', sort_order: 115, front: "Differential Diagnosis (DDx)", back: "A ranked list of possible diagnoses consistent with the patient's symptoms, signs, and test results. Clinicians work through the DDx to identify the most likely diagnosis and rule out dangerous conditions." , front_translations: {"es":"Diagnóstico Diferencial (DDx)","de":"Differentialdiagnose (DDx)","fr":"Diagnostic différentiel (DDx)","tr":"Ayırıcı Tanı (DDx)","nl":"Differentiaaldiagnose (DDx)","ru":"Дифференциальный диагноз (DDx)","zh":"鉴别诊断（DDx）","pt_BR":"Diagnóstico Diferencial (DDx)","pt_PT":"Diagnóstico Diferencial (DDx)"}, back_translations: {"es":"Una lista classificada de posibles diagnósticos consistentes con los síntomas, señales y resultados de exámenes del paciente. Refinada por investigación adicional y raciocínio clínico.","de":"Eine nach Wahrscheinlichkeit geordnete Liste möglicher Diagnosen, die mit den Symptomen, Befunden und Testergebnissen des Patienten vereinbar sind. Wird durch weitere Untersuchungen und klinisches Denken eingegrenzt.","fr":"Une liste hiérarchisée de diagnostics possibles compatibles avec les symptômes, les signes et les résultats d'examens du patient. Affinée par des investigations complémentaires et le raisonnement clinique.","tr":"Hastanın semptomları, bulguları ve test sonuçlarıyla uyumlu olası tanıların öncelik sırasına göre sıralanmış listesi. İleri tetkikler ve klinik akıl yürütmeyle daraltılır.","nl":"Een op waarschijnlijkheid gerangschikte lijst van mogelijke diagnoses die passen bij de symptomen, tekenen en testresultaten van de patiënt. Wordt verfijnd door verder onderzoek en klinisch redeneren.","ru":"Ранжированный список возможных диагнозов, совместимых с симптомами, признаками и результатами обследований пациента. Сужается путём дальнейших исследований и клинического мышления.","zh":"与患者症状、体征和检查结果相符的可能诊断排序列表。通过进一步检查和临床推理逐步缩小范围。","pt_BR":"Uma lista classificada de possíveis diagnósticos consistentes com os sintomas, sinais e resultados de exames do paciente. Refinada por investigação adicional e raciocínio clínico.","pt_PT":"Uma lista classificada de possíveis diagnósticos consistentes com os sintomas, sinais e resultados de exames do doente. Refinada por investigação adicional e raciocínio clínico."}},
  { id: 'dc-medical-0116', deck_id: 'deck-medical', sort_order: 116, front: "Sensitivity vs. Specificity", back: "Sensitivity: proportion of true positives (ability to detect disease). Specificity: proportion of true negatives (ability to rule out disease). High sensitivity = good screening test; high specificity = good confirmatory test." , front_translations: {"es":"Sensibilidad vs. Especificidad","de":"Sensitivität vs. Spezifität","fr":"Sensibilité vs. Spécificité","tr":"Duyarlılık ve Özgüllük","nl":"Sensitiviteit vs. Specificiteit","ru":"Чувствительность и специфичность","zh":"敏感性与特异性","pt_BR":"Sensibilidade vs. Especificidade","pt_PT":"Sensibilidade vs. Especificidade"}, back_translations: {"es":"Sensibilidad: proporción de verdaderos positivos (capacidad de detectar a enfermedad). Especificidad: proporción de verdaderos negativos (capacidad de excluir a enfermedad). Pruebas ideais tienen ambos próximos de 100%.","de":"Sensitivität: Anteil der richtig Positiven (Fähigkeit, die Krankheit zu erkennen). Spezifität: Anteil der richtig Negativen (Fähigkeit, die Krankheit auszuschließen). Ideale Tests haben beide nahe 100 %.","fr":"Sensibilité : proportion de vrais positifs (capacité à détecter la maladie). Spécificité : proportion de vrais négatifs (capacité à exclure la maladie). Les tests idéaux ont les deux proches de 100 %.","tr":"Duyarlılık: gerçek pozitiflerin oranı (hastalığı saptama yeteneği). Özgüllük: gerçek negatiflerin oranı (hastalığı dışlama yeteneği). İdeal testlerde her ikisi de %100'e yakındır.","nl":"Sensitiviteit: proportie terecht positieven (vermogen om ziekte te detecteren). Specificiteit: proportie terecht negatieven (vermogen om ziekte uit te sluiten). Ideale tests hebben beide dicht bij 100%.","ru":"Чувствительность: доля истинно положительных результатов (способность выявить заболевание). Специфичность: доля истинно отрицательных результатов (способность исключить заболевание). Идеальные тесты имеют оба показателя близкими к 100%.","zh":"敏感性：真阳性比例（检测疾病的能力）。特异性：真阴性比例（排除疾病的能力）。理想的检测两者均接近100%。","pt_BR":"Sensibilidade: proporção de verdadeiros positivos (capacidade de detectar a doença). Especificidade: proporção de verdadeiros negativos (capacidade de excluir a doença). Testes ideais têm ambos próximos de 100%.","pt_PT":"Sensibilidade: proporção de verdadeiros positivos (capacidade de detetar a doença). Especificidade: proporção de verdadeiros negativos (capacidade de excluir a doença). Testes ideais têm ambos próximos de 100%."}},
  { id: 'dc-medical-0117', deck_id: 'deck-medical', sort_order: 117, front: "Positive Predictive Value (PPV)", back: "The probability that a patient with a positive test result truly has the disease. Influenced by disease prevalence. PPV is higher when the disease is more common in the population tested." , front_translations: {"es":"Valor Preditivo Positivo (VPP)","de":"Positiver prädiktiver Wert (PPV)","fr":"Valeur prédictive positive (VPP)","tr":"Pozitif Prediktif Değer (PPV)","nl":"Positief voorspellende waarde (PPV)","ru":"Положительная прогностическая ценность (PPV)","zh":"阳性预测值（PPV）","pt_BR":"Valor Preditivo Positivo (VPP)","pt_PT":"Valor Preditivo Positivo (VPP)"}, back_translations: {"es":"La probabilidad de que un paciente con resultado positivo realmente tenha a enfermedad. Influenciado por la prevalencia de la enfermedad — mayor prevalencia aumenta el VPP.","de":"Die Wahrscheinlichkeit, dass ein Patient mit positivem Testergebnis tatsächlich an der Krankheit leidet. Beeinflusst durch die Krankheitsprävalenz — höhere Prävalenz erhöht den PPV.","fr":"La probabilité qu'un patient avec un résultat de test positif soit réellement atteint de la maladie. Influencée par la prévalence — une prévalence plus élevée augmente la VPP.","tr":"Pozitif test sonucu olan bir hastanın gerçekten hastalığa sahip olma olasılığı. Hastalık prevalansından etkilenir — prevalans arttıkça PPV yükselir.","nl":"De waarschijnlijkheid dat een patiënt met een positief testresultaat daadwerkelijk de ziekte heeft. Beïnvloed door ziekte-prevalentie — hogere prevalentie verhoogt de PPV.","ru":"Вероятность того, что пациент с положительным результатом теста действительно болен. Зависит от распространённости заболевания — более высокая распространённость увеличивает PPV.","zh":"检测结果为阳性的患者真正患有该疾病的概率。受疾病患病率影响——患病率越高，PPV越高。","pt_BR":"A probabilidade de que um paciente com resultado positivo realmente tenha a doença. Influenciado pela prevalência da doença — maior prevalência aumenta o VPP.","pt_PT":"A probabilidade de que um doente com resultado positivo tenha realmente a doença. Influenciado pela prevalência da doença — maior prevalência aumenta o VPP."}},
  { id: 'dc-medical-0118', deck_id: 'deck-medical', sort_order: 118, front: "Negative Predictive Value (NPV)", back: "The probability that a patient with a negative test result truly does not have the disease. High NPV is most important for ruling out serious diagnoses. Increases when prevalence is low." , front_translations: {"es":"Valor Preditivo Negativo (VPN)","de":"Negativer prädiktiver Wert (NPV)","fr":"Valeur prédictive négative (VPN)","tr":"Negatif Prediktif Değer (NPV)","nl":"Negatief voorspellende waarde (NPV)","ru":"Отрицательная прогностическая ценность (NPV)","zh":"阴性预测值（NPV）","pt_BR":"Valor Preditivo Negativo (VPN)","pt_PT":"Valor Preditivo Negativo (VPN)"}, back_translations: {"es":"La probabilidad de que un paciente con resultado negativo realmente no tenha a enfermedad. Un VPN alto es crítico para pruebas de rastreamento para evitar diagnósticos perdidos.","de":"Die Wahrscheinlichkeit, dass ein Patient mit negativem Testergebnis tatsächlich nicht an der Krankheit leidet. Ein hoher NPV ist bei Screening-Tests entscheidend, um verpasste Diagnosen zu vermeiden.","fr":"La probabilité qu'un patient avec un résultat de test négatif ne soit réellement pas atteint de la maladie. Une VPN élevée est essentielle pour les tests de dépistage afin d'éviter les diagnostics manqués.","tr":"Negatif test sonucu olan bir hastanın gerçekten hastalığa sahip olmama olasılığı. Yüksek NPV, kaçırılan tanıları önlemek için tarama testlerinde kritik öneme sahiptir.","nl":"De waarschijnlijkheid dat een patiënt met een negatief testresultaat daadwerkelijk niet ziek is. Een hoge NPV is cruciaal bij screeningstests om gemiste diagnoses te voorkomen.","ru":"Вероятность того, что пациент с отрицательным результатом теста действительно здоров. Высокий NPV критически важен для скрининговых тестов, чтобы избежать пропущенных диагнозов.","zh":"检测结果为阴性的患者确实未患该疾病的概率。高NPV对筛查试验至关重要，以避免漏诊。","pt_BR":"A probabilidade de que um paciente com resultado negativo realmente não tenha a doença. Um VPN alto é crítico para testes de rastreamento para evitar diagnósticos perdidos.","pt_PT":"A probabilidade de que um doente com resultado negativo realmente não tenha a doença. Um VPN elevado é crítico para testes de rastreio para evitar diagnósticos perdidos."}},
  { id: 'dc-medical-0119', deck_id: 'deck-medical', sort_order: 119, front: "Laceration vs. Abrasion vs. Contusion", back: "Laceration: a cut through skin layers. Abrasion: superficial scraping of the skin surface. Contusion: a bruise; damage to subcutaneous tissue without breaking the skin, causing bleeding into soft tissue." , front_translations: {"es":"Laceración vs. Abrasão vs. Contusão","de":"Lazeration vs. Abrasion vs. Kontusion","fr":"Lacération vs. Abrasion vs. Contusion","tr":"Laserasyon, Abrazyon ve Kontüzyon","nl":"Laceratie vs. Abrasie vs. Contusie","ru":"Рваная рана, ссадина и ушиб","zh":"撕裂伤、擦伤与挫伤","pt_BR":"Laceração vs. Abrasão vs. Contusão","pt_PT":"Laceração vs. Abrasão vs. Contusão"}, back_translations: {"es":"Laceración: un corte a través de las capas de la piel. Abrasão: raspaje superficial de la superficie de la piel. Contusão: hematoma causado por fuerza contundente sin romper a piel.","de":"Lazeration: ein Schnitt durch die Hautschichten. Abrasion: oberflächliche Abschürfung der Hautoberfläche. Kontusion: eine Prellung durch stumpfe Gewalteinwirkung ohne Hautverletzung.","fr":"Lacération : une coupure à travers les couches de la peau. Abrasion : éraflure superficielle de la surface cutanée. Contusion : un hématome causé par un choc sans rupture de la peau.","tr":"Laserasyon: deri katmanlarını kesen bir yara. Abrazyon: deri yüzeyinin sıyrılması. Kontüzyon: deriyi yırtmadan künt kuvvetin neden olduğu çürük.","nl":"Laceratie: een snijwond door de huidlagen. Abrasie: oppervlakkige schaafwond van het huidoppervlak. Contusie: een kneuzing door stomp geweld zonder huidbeschadiging.","ru":"Рваная рана: разрез через слои кожи. Ссадина: поверхностное повреждение кожи. Ушиб: кровоподтёк от тупого удара без нарушения целостности кожи.","zh":"撕裂伤：切穿皮肤各层的伤口。擦伤：皮肤表面的浅表刮伤。挫伤：钝力导致的皮下瘀伤，皮肤完整。","pt_BR":"Laceração: um corte através das camadas da pele. Abrasão: raspagem superficial da superfície da pele. Contusão: hematoma causado por força contundente sem romper a pele.","pt_PT":"Laceração: um corte através das camadas da pele. Abrasão: raspagem superficial da superfície da pele. Contusão: hematoma causado por força contundente sem romper a pele."}},
  { id: 'dc-medical-0120', deck_id: 'deck-medical', sort_order: 120, front: "Fracture Types", back: "Closed (bone doesn't break skin), open/compound (bone protrudes), comminuted (multiple fragments), greenstick (incomplete, in children), pathological (through diseased bone), stress (hairline from repetitive force)." , front_translations: {"es":"Tipos de Fratura","de":"Frakturtypen","fr":"Types de fractures","tr":"Kırık Tipleri","nl":"Fractuurtypen","ru":"Типы переломов","zh":"骨折类型","pt_BR":"Tipos de Fratura","pt_PT":"Tipos de Fratura"}, back_translations: {"es":"Fechada (hueso no perfura a piel), aberta/exposta (hueso se projeta), cominutiva (múltiplos fragmentos), galho verde (incompleta, niños), por estresse (microfraturas por sobrecarga), patológica (hueso enfraquecido).","de":"Geschlossen (Knochen durchbricht die Haut nicht), offen/kompliziert (Knochen ragt heraus), Trümmerfraktur (mehrere Fragmente), Grünholzfraktur (unvollständig, bei Kindern), Stressfraktur (Überlastungs-Mikrofrakturen), pathologisch (geschwächter Knochen).","fr":"Fermée (l'os ne perce pas la peau), ouverte/composée (l'os fait saillie), comminutive (fragments multiples), en bois vert (incomplète, enfants), de stress (microfractures de surmenage), pathologique (os fragilisé).","tr":"Kapalı (kemik deriyi delmez), açık/komplike (kemik dışarı çıkar), parçalı (çok sayıda parça), yeşil dal (çocuklarda, tamamlanmamış), stres (aşırı kullanıma bağlı mikrokırıklar), patolojik (zayıflamış kemik).","nl":"Gesloten (bot doorbreekt de huid niet), open/gecompliceerd (bot steekt uit), comminutief (meerdere fragmenten), greenstick (onvolledig, kinderen), stress (overbelasting-microfracturen), pathologisch (verzwakt bot).","ru":"Закрытый (кость не прорывает кожу), открытый/сложный (кость выступает наружу), оскольчатый (множественные фрагменты), по типу 'зелёной ветки' (неполный, у детей), стрессовый (микротрещины от перегрузки), патологический (ослабленная кость).","zh":"闭合性（骨骼未穿透皮肤）、开放性/复合性（骨骼突出）、粉碎性（多个碎片）、青枝（不完全，儿童）、应力性（过度使用微骨折）、病理性（骨骼弱化）。","pt_BR":"Fechada (osso não perfura a pele), aberta/exposta (osso se projeta), cominutiva (múltiplos fragmentos), galho verde (incompleta, crianças), por estresse (microfraturas por sobrecarga), patológica (osso enfraquecido).","pt_PT":"Fechada (osso não perfura a pele), aberta/exposta (osso projeta-se), cominutiva (múltiplos fragmentos), em ramo verde (incompleta, crianças), de stress (microfraturas por sobrecarga), patológica (osso enfraquecido)."}},
  { id: 'dc-medical-0121', deck_id: 'deck-medical', sort_order: 121, front: "Edema", back: "Abnormal accumulation of fluid in the interstitial space, causing swelling. Causes: heart failure, liver disease, kidney disease (low albumin/oncotic pressure), venous obstruction, or increased capillary permeability (inflammation, allergy)." , front_translations: {"es":"Edema","de":"Ödem","fr":"Œdème","tr":"Ödem","nl":"Oedeem","ru":"Отёк","zh":"水肿","pt_BR":"Edema","pt_PT":"Edema"}, back_translations: {"es":"Acúmulo anormal de líquido en el espacio intersticial, causando inchaço. Causas: insuficiencia cardíaca, enfermedad hepática, enfermedad renal, insuficiencia venosa, obstrución linfática o medicamentos.","de":"Abnormale Ansammlung von Flüssigkeit im Interstitium, die Schwellungen verursacht. Ursachen: Herzinsuffizienz, Lebererkrankung, Nierenerkrankung, venöse Insuffizienz, Lymphabflussstörung oder Medikamente.","fr":"Accumulation anormale de liquide dans l'espace interstitiel, provoquant un gonflement. Causes : insuffisance cardiaque, maladie hépatique, maladie rénale, insuffisance veineuse, obstruction lymphatique ou médicaments.","tr":"İnterstisyel alanda anormal sıvı birikmesi sonucu oluşan şişlik. Nedenleri: kalp yetmezliği, karaciğer hastalığı, böbrek hastalığı, venöz yetmezlik, lenfatik obstrüksiyon veya ilaçlar.","nl":"Abnormale ophoping van vocht in de interstitiële ruimte, wat zwelling veroorzaakt. Oorzaken: hartfalen, leverziekte, nierziekte, veneuze insufficiëntie, lymfatische obstructie of medicatie.","ru":"Патологическое скопление жидкости в межтканевом пространстве, вызывающее отёчность. Причины: сердечная недостаточность, заболевания печени, почек, венозная недостаточность, лимфатическая обструкция или лекарственные препараты.","zh":"组织间隙中液体的异常积聚，导致肿胀。病因：心力衰竭、肝病、肾病、静脉功能不全、淋巴阻塞或药物。","pt_BR":"Acúmulo anormal de líquido no espaço intersticial, causando inchaço. Causas: insuficiência cardíaca, doença hepática, doença renal, insuficiência venosa, obstrução linfática ou medicamentos.","pt_PT":"Acumulação anormal de líquido no espaço intersticial, causando inchaço. Causas: insuficiência cardíaca, doença hepática, doença renal, insuficiência venosa, obstrução linfática ou medicamentos."}},
  { id: 'dc-medical-0122', deck_id: 'deck-medical', sort_order: 122, front: "Jaundice (Icterus)", back: "Yellowing of the skin, sclera, and mucous membranes due to elevated bilirubin. Pre-hepatic (hemolysis), hepatic (liver disease), post-hepatic (biliary obstruction, e.g., gallstones, pancreatic cancer)." , front_translations: {"es":"Icterícia","de":"Ikterus (Gelbsucht)","fr":"Ictère (Jaunisse)","tr":"Sarılık (İkter)","nl":"Icterus (Geelzucht)","ru":"Желтуха (иктеричность)","zh":"黄疸","pt_BR":"Icterícia","pt_PT":"Icterícia"}, back_translations: {"es":"Amarelecimento de la piel, escleras y mucosas debido a la elevación de la bilirrubina. Pré-hepática (hemólise), hepática (enfermedad hepática), pós-hepática (obstrución de las vias biliares).","de":"Gelbfärbung der Haut, Skleren und Schleimhäute durch erhöhtes Bilirubin. Prähepatisch (Hämolyse), hepatisch (Lebererkrankung), posthepatisch (Gallengangsobstruktion).","fr":"Coloration jaune de la peau, des sclères et des muqueuses due à une élévation de la bilirubine. Pré-hépatique (hémolyse), hépatique (maladie du foie), post-hépatique (obstruction des voies biliaires).","tr":"Yüksek bilirubin nedeniyle deri, sklera ve mukoza zarlarının sararması. Pre-hepatik (hemoliz), hepatik (karaciğer hastalığı), post-hepatik (safra yolu tıkanıklığı).","nl":"Geelverkleuring van de huid, sclerae en slijmvliezen door verhoogd bilirubine. Pre-hepatisch (hemolyse), hepatisch (leverziekte), post-hepatisch (galwegobstructie).","ru":"Пожелтение кожи, склер и слизистых оболочек вследствие повышенного уровня билирубина. Надпечёночная (гемолиз), печёночная (заболевания печени), подпечёночная (обструкция жёлчных протоков).","zh":"由于胆红素升高导致皮肤、巩膜和黏膜变黄。肝前性（溶血）、肝性（肝脏疾病）、肝后性（胆管梗阻）。","pt_BR":"Amarelecimento da pele, escleras e mucosas devido à elevação da bilirrubina. Pré-hepática (hemólise), hepática (doença hepática), pós-hepática (obstrução das vias biliares).","pt_PT":"Amarelecimento da pele, escleras e mucosas devido à elevação da bilirrubina. Pré-hepática (hemólise), hepática (doença hepática), pós-hepática (obstrução das vias biliares)."}},
  { id: 'dc-medical-0123', deck_id: 'deck-medical', sort_order: 123, front: "Cyanosis", back: "Bluish discoloration of the skin and mucous membranes due to reduced oxygen saturation in the blood. Central cyanosis (lips, tongue) indicates significant hypoxemia. Peripheral cyanosis (extremities) can occur in cold or poor circulation." , front_translations: {"es":"Cianose","de":"Zyanose","fr":"Cyanose","tr":"Siyanoz","nl":"Cyanose","ru":"Цианоз","zh":"发绀","pt_BR":"Cianose","pt_PT":"Cianose"}, back_translations: {"es":"Coloración azulada de la piel y mucosas debido a la reducción de la saturación de oxígeno en el sangre. Cianose central afecta lábios y língua; cianose periférica afecta las extremidades.","de":"Bläuliche Verfärbung der Haut und Schleimhäute aufgrund verminderter Sauerstoffsättigung im Blut. Zentrale Zyanose betrifft Lippen und Zunge; periphere Zyanose betrifft die Extremitäten.","fr":"Coloration bleutée de la peau et des muqueuses due à une diminution de la saturation en oxygène du sang. La cyanose centrale affecte les lèvres et la langue ; la cyanose périphérique affecte les extrémités.","tr":"Kandaki oksijen satürasyonunun düşmesi nedeniyle deri ve mukoza zarlarının mavimsi renk değişimi. Santral siyanoz dudakları ve dili etkiler; periferik siyanoz ekstremiteleri etkiler.","nl":"Blauwige verkleuring van de huid en slijmvliezen door verminderde zuurstofsaturatie in het bloed. Centrale cyanose treft lippen en tong; perifere cyanose treft de extremiteiten.","ru":"Синюшное окрашивание кожи и слизистых оболочек вследствие снижения насыщения крови кислородом. Центральный цианоз затрагивает губы и язык; периферический — конечности.","zh":"由于血液中氧饱和度降低导致皮肤和黏膜呈蓝紫色。中心性发绀影响嘴唇和舌头；外周性发绀影响四肢。","pt_BR":"Coloração azulada da pele e mucosas devido à redução da saturação de oxigênio no sangue. Cianose central afeta lábios e língua; cianose periférica afeta as extremidades.","pt_PT":"Coloração azulada da pele e mucosas devido à redução da saturação de oxigénio no sangue. Cianose central afeta lábios e língua; cianose periférica afeta as extremidades."}},
  { id: 'dc-medical-0124', deck_id: 'deck-medical', sort_order: 124, front: "Ascites", back: "Accumulation of fluid in the peritoneal cavity. Most common causes: liver cirrhosis (portal hypertension), malignancy, heart failure. Detected by dullness on percussion; confirmed by ultrasound. Managed with diuretics and low-sodium diet." , front_translations: {"es":"Ascite","de":"Aszites","fr":"Ascite","tr":"Asit","nl":"Ascites","ru":"Асцит","zh":"腹水","pt_BR":"Ascite","pt_PT":"Ascite"}, back_translations: {"es":"Acúmulo de líquido en la cavidad peritoneal. Causas más comuns: cirrose hepática (hipertensão portal), insuficiencia cardíaca, malignidades y infecciones como tuberculose.","de":"Flüssigkeitsansammlung in der Bauchhöhle. Häufigste Ursachen: Leberzirrhose (portale Hypertension), Herzinsuffizienz, maligne Erkrankungen und Infektionen wie Tuberkulose.","fr":"Accumulation de liquide dans la cavité péritonéale. Causes les plus fréquentes : cirrhose hépatique (hypertension portale), insuffisance cardiaque, néoplasies et infections comme la tuberculose.","tr":"Periton boşluğunda sıvı birikmesi. En sık nedenler: karaciğer sirozu (portal hipertansiyon), kalp yetmezliği, maligniteler ve tüberküloz gibi enfeksiyonlar.","nl":"Ophoping van vocht in de peritoneale holte. Meest voorkomende oorzaken: levercirrose (portale hypertensie), hartfalen, maligniteiten en infecties zoals tuberculose.","ru":"Скопление жидкости в брюшной полости. Наиболее частые причины: цирроз печени (портальная гипертензия), сердечная недостаточность, злокачественные новообразования и инфекции, такие как туберкулёз.","zh":"腹膜腔内液体积聚。最常见病因：肝硬化（门静脉高压）、心力衰竭、恶性肿瘤以及结核等感染。","pt_BR":"Acúmulo de líquido na cavidade peritoneal. Causas mais comuns: cirrose hepática (hipertensão portal), insuficiência cardíaca, malignidades e infecções como tuberculose.","pt_PT":"Acumulação de líquido na cavidade peritoneal. Causas mais comuns: cirrose hepática (hipertensão portal), insuficiência cardíaca, neoplasias e infeções como tuberculose."}},
  { id: 'dc-medical-0125', deck_id: 'deck-medical', sort_order: 125, front: "Auscultation", back: "Listening to internal body sounds using a stethoscope. Heart auscultation assesses heart sounds (S1, S2) and murmurs. Lung auscultation detects wheezes, crackles, and absent breath sounds." , front_translations: {"es":"Ausculta","de":"Auskultation","fr":"Auscultation","tr":"Oskültasyon","nl":"Auscultatie","ru":"Аускультация","zh":"听诊","pt_BR":"Ausculta","pt_PT":"Auscultação"}, back_translations: {"es":"Escuta de los sons internos del cuerpo usando un estetoscópio. La ausculta cardíaca avalia bulhas cardíacas (B1, B2) y sopros; a ausculta pulmonar detecta estertores, sibilos o ausencia de murmúrio vesicular.","de":"Abhören von inneren Körpergeräuschen mit einem Stethoskop. Die Herzauskultation beurteilt Herztöne (S1, S2) und Herzgeräusche; die Lungenauskultation erkennt Rasselgeräusche, Giemen oder fehlende Atemgeräusche.","fr":"Écoute des sons internes du corps à l'aide d'un stéthoscope. L'auscultation cardiaque évalue les bruits du cœur (B1, B2) et les souffles ; l'auscultation pulmonaire détecte les crépitants, les sibilants ou l'absence de murmure vésiculaire.","tr":"Stetoskop kullanarak vücudun iç seslerinin dinlenmesi. Kalp oskültasyonu kalp seslerini (S1, S2) ve üfürümleri değerlendirir; akciğer oskültasyonu ralleri, ronküsleri veya solunum seslerinin yokluğunu tespit eder.","nl":"Luisteren naar interne lichaamsgeluiden met een stethoscoop. Hartauscultatie beoordeelt harttonen (S1, S2) en souffles; longauscultatie detecteert crepitaties, piepende ademhaling of afwezige ademgeluiden.","ru":"Выслушивание внутренних звуков тела с помощью стетоскопа. Аускультация сердца оценивает тоны сердца (S1, S2) и шумы; аускультация лёгких выявляет хрипы, свистящие звуки или отсутствие дыхательных шумов.","zh":"使用听诊器倾听体内声音。心脏听诊评估心音（S1、S2）和杂音；肺部听诊检测啰音、喘鸣或呼吸音消失。","pt_BR":"Escuta dos sons internos do corpo usando um estetoscópio. A ausculta cardíaca avalia bulhas cardíacas (B1, B2) e sopros; a ausculta pulmonar detecta estertores, sibilos ou ausência de murmúrio vesicular.","pt_PT":"Escuta dos sons internos do corpo usando um estetoscópio. A auscultação cardíaca avalia sons cardíacos (S1, S2) e sopros; a auscultação pulmonar deteta crepitações, sibilos ou ausência de murmúrio vesicular."}},
  { id: 'dc-medical-0126', deck_id: 'deck-medical', sort_order: 126, front: "Percussion", back: "Tapping the body surface to produce sounds that indicate the underlying tissue density. Resonant (hollow) over normal lung; dull over fluid or solid tissue; hyperresonant over emphysema or pneumothorax." , front_translations: {"es":"Percusión","de":"Perkussion","fr":"Percussion","tr":"Perküsyon","nl":"Percussie","ru":"Перкуссия","zh":"叩诊","pt_BR":"Percussão","pt_PT":"Percussão"}, back_translations: {"es":"Técnica de bater en la superficie corporal para produzir sons que indican a densidad del tejido subjacente. Sons-chave: ressonante (oco), maciço (órgano sólido) y timpanico (cheio de aire).","de":"Beklopfen der Körperoberfläche zur Erzeugung von Klängen, die auf die Dichte des darunterliegenden Gewebes hinweisen. Wichtige Klänge: sonor (hohl), gedämpft (solides Organ) und tympanisch (luftgefüllt).","fr":"Technique consistant à tapoter la surface du corps pour produire des sons indiquant la densité du tissu sous-jacent. Sons clés : résonnant (creux), mat (organe solide) et tympanique (rempli d'air).","tr":"Alttaki doku yoğunluğunu gösteren sesler üretmek için vücut yüzeyine vurma. Temel sesler: sonorite (içi boş), matite (solid organ) ve timpanik (hava dolu).","nl":"Het bekloppen van het lichaamsoppervlak om geluiden te produceren die de dichtheid van het onderliggende weefsel aangeven. Belangrijke geluiden: sonoor (hol), gedempt (solide orgaan) en tympanisch (luchthoudend).","ru":"Постукивание по поверхности тела для получения звуков, указывающих на плотность подлежащих тканей. Основные звуки: ясный (полый), тупой (плотный орган) и тимпанический (воздухосодержащий).","zh":"叩击体表以产生反映下方组织密度的声音。关键音调：清音（空腔）、浊音（实质脏器）和鼓音（含气）。","pt_BR":"Técnica de bater na superfície corporal para produzir sons que indicam a densidade do tecido subjacente. Sons-chave: ressonante (oco), maciço (órgão sólido) e timpânico (cheio de ar).","pt_PT":"Técnica de percutir a superfície corporal para produzir sons que indicam a densidade do tecido subjacente. Sons-chave: ressonante (oco), maciço (órgão sólido) e timpânico (cheio de ar)."}},
  { id: 'dc-medical-0127', deck_id: 'deck-medical', sort_order: 127, front: "Palpation", back: "Using hands to examine the body by touch. Detects tenderness, masses, organ enlargement (hepatomegaly, splenomegaly), lymph nodes, and pulsations. Light palpation is done before deep palpation." , front_translations: {"es":"Palpación","de":"Palpation","fr":"Palpation","tr":"Palpasyon","nl":"Palpatie","ru":"Пальпация","zh":"触诊","pt_BR":"Palpação","pt_PT":"Palpação"}, back_translations: {"es":"Examen del cuerpo por el toque con las manos. Detecta sensibilidad, massas, aumento de órganos (hepatomegalia, esplenomegalia) y alteraciones en la temperatura de la piel.","de":"Untersuchung des Körpers durch Betasten mit den Händen. Erkennt Druckschmerzhaftigkeit, Raumforderungen, Organvergrößerungen (Hepatomegalie, Splenomegalie) und Hauttemperaturveränderungen.","fr":"Examen du corps par le toucher avec les mains. Détecte la sensibilité, les masses, l'hypertrophie des organes (hépatomégalie, splénomégalie) et les changements de température cutanée.","tr":"Vücudu elle dokunarak muayene etme yöntemi. Hassasiyet, kitle, organ büyümesi (hepatomegali, splenomegali) ve cilt sıcaklık değişikliklerini tespit eder.","nl":"Het onderzoeken van het lichaam door middel van aanraking met de handen. Detecteert gevoeligheid, massa's, orgaanvergroting (hepatomegalie, splenomegalie) en veranderingen in huidtemperatuur.","ru":"Обследование тела путём ощупывания руками. Выявляет болезненность, образования, увеличение органов (гепатомегалия, спленомегалия) и изменения температуры кожи.","zh":"用手触摸检查身体。可检测压痛、肿块、脏器增大（肝大、脾大）及皮肤温度变化。","pt_BR":"Exame do corpo pelo toque com as mãos. Detecta sensibilidade, massas, aumento de órgãos (hepatomegalia, esplenomegalia) e alterações na temperatura da pele.","pt_PT":"Exame do corpo pelo toque com as mãos. Deteta sensibilidade, massas, aumento de órgãos (hepatomegalia, esplenomegalia) e alterações na temperatura da pele."}},
  { id: 'dc-medical-0128', deck_id: 'deck-medical', sort_order: 128, front: "Glasgow Coma Scale (GCS)", back: "Assesses consciousness using three criteria: eye opening (1–4), verbal response (1–5), motor response (1–6). Total = 3–15. GCS ≤8 indicates severe brain injury and need for airway protection." , front_translations: {"es":"Escala de Coma de Glasgow (GCS)","de":"Glasgow Coma Scale (GCS)","fr":"Échelle de Glasgow (GCS)","tr":"Glasgow Koma Skalası (GKS)","nl":"Glasgow Coma Scale (GCS)","ru":"Шкала комы Глазго (ШКГ)","zh":"格拉斯哥昏迷量表 (GCS)","pt_BR":"Escala de Coma de Glasgow (GCS)","pt_PT":"Escala de Coma de Glasgow (GCS)"}, back_translations: {"es":"Avalia el nivel de conciencia usando tres critérios: abertura ocular (1–4), respuesta verbal (1–5), respuesta motora (1–6). Franja total: 3–15. GCS ≤8 indica lesão cerebral grave que requiere intubación.","de":"Bewertet das Bewusstsein anhand dreier Kriterien: Augenöffnung (1–4), verbale Reaktion (1–5), motorische Reaktion (1–6). Gesamtbereich: 3–15. GCS ≤8 weist auf eine schwere Hirnverletzung hin und erfordert eine Intubation.","fr":"Évalue l'état de conscience selon trois critères : ouverture des yeux (1–4), réponse verbale (1–5), réponse motrice (1–6). Score total : 3–15. GCS ≤8 indique un traumatisme crânien grave nécessitant une intubation.","tr":"Bilinci üç kritere göre değerlendirir: göz açma (1–4), sözel yanıt (1–5), motor yanıt (1–6). Toplam aralık: 3–15. GKS ≤8 entübasyon gerektiren ciddi beyin hasarını gösterir.","nl":"Beoordeelt het bewustzijn aan de hand van drie criteria: oogopening (1–4), verbale respons (1–5), motorische respons (1–6). Totaal bereik: 3–15. GCS ≤8 wijst op ernstig hersenletsel dat intubatie vereist.","ru":"Оценивает сознание по трём критериям: открывание глаз (1–4), вербальная реакция (1–5), двигательная реакция (1–6). Диапазон: 3–15. ШКГ ≤8 указывает на тяжёлую черепно-мозговую травму, требующую интубации.","zh":"通过三个标准评估意识：睁眼反应（1–4）、言语反应（1–5）、运动反应（1–6）。总分范围：3–15。GCS ≤8 提示严重脑损伤，需行气管插管。","pt_BR":"Avalia o nível de consciência usando três critérios: abertura ocular (1–4), resposta verbal (1–5), resposta motora (1–6). Faixa total: 3–15. GCS ≤8 indica lesão cerebral grave que requer intubação.","pt_PT":"Avalia o nível de consciência usando três critérios: abertura ocular (1–4), resposta verbal (1–5), resposta motora (1–6). Intervalo total: 3–15. GCS ≤8 indica lesão cerebral grave que requer entubação."}},
  { id: 'dc-medical-0129', deck_id: 'deck-medical', sort_order: 129, front: "AVPU Scale", back: "A quick neurological assessment: Alert, responds to Voice, responds to Pain, Unresponsive. Simpler than GCS; used in pre-hospital and rapid assessments. V or below often indicates significant neurological impairment." , front_translations: {"es":"Escala AVPU","de":"AVPU-Skala","fr":"Échelle AVPU","tr":"AVPU Skalası","nl":"AVPU-schaal","ru":"Шкала AVPU","zh":"AVPU量表","pt_BR":"Escala AVPU","pt_PT":"Escala AVPU"}, back_translations: {"es":"Una avaliación neurológica rápida: Alerta, responde a la Voz, responde a la Dor, No responsivo. Más simples que a GCS para triaje rápida.","de":"Eine schnelle neurologische Beurteilung: Wach (Alert), reagiert auf Ansprache (Voice), reagiert auf Schmerz (Pain), nicht ansprechbar (Unresponsive). Einfacher als GCS für eine schnelle Triage.","fr":"Évaluation neurologique rapide : Alerte, répond à la Voix, répond à la douleur (Pain), non réactif (Unresponsive). Plus simple que le GCS pour un triage rapide.","tr":"Hızlı bir nörolojik değerlendirme: Uyanık (Alert), Sesli uyarana yanıt (Voice), Ağrılı uyarana yanıt (Pain), Yanıtsız (Unresponsive). Hızlı triaj için GKS'den daha basit.","nl":"Een snelle neurologische beoordeling: Alert, reageert op spraak (Voice), reageert op pijn (Pain), niet reagerend (Unresponsive). Eenvoudiger dan GCS voor snelle triage.","ru":"Быстрая неврологическая оценка: в сознании (Alert), реагирует на голос (Voice), реагирует на боль (Pain), без сознания (Unresponsive). Проще, чем ШКГ, для быстрой сортировки пациентов.","zh":"一种快速神经系统评估：清醒（Alert）、对声音有反应（Voice）、对疼痛有反应（Pain）、无反应（Unresponsive）。比GCS更简便，适用于快速分诊。","pt_BR":"Uma avaliação neurológica rápida: Alerta, responde à Voz, responde à Dor, Não responsivo. Mais simples que a GCS para triagem rápida.","pt_PT":"Uma avaliação neurológica rápida: Alerta, responde à Voz, responde à Dor, Sem resposta. Mais simples que a GCS para triagem rápida."}},
  { id: 'dc-medical-0130', deck_id: 'deck-medical', sort_order: 130, front: "Shock", back: "Inadequate tissue perfusion and oxygenation to meet metabolic demands. Types: hypovolemic (blood/fluid loss), cardiogenic (pump failure), distributive (vasodilation; septic, anaphylactic, neurogenic), obstructive (PE, tamponade)." , front_translations: {"es":"Choque","de":"Schock","fr":"Choc","tr":"Şok","nl":"Shock","ru":"Шок","zh":"休克","pt_BR":"Choque","pt_PT":"Choque"}, back_translations: {"es":"Perfusão y oxigenación tecidual inadequadas para atender a las demandas metabólicas. Tipos: hipovolemico (perda de sangre/líquido), cardiogenico (insuficiencia cardíaca), distributivo (séptico, anafilático), obstrutivo (TEP, tamponamento).","de":"Unzureichende Gewebedurchblutung und Sauerstoffversorgung zur Deckung des Stoffwechselbedarfs. Typen: hypovolämisch (Blut-/Flüssigkeitsverlust), kardiogen (Herzversagen), distributiv (septisch, anaphylaktisch), obstruktiv (Lungenembolie, Tamponade).","fr":"Perfusion et oxygénation tissulaires insuffisantes pour répondre aux besoins métaboliques. Types : hypovolémique (perte de sang/liquide), cardiogénique (insuffisance cardiaque), distributif (septique, anaphylactique), obstructif (EP, tamponnade).","tr":"Metabolik gereksinimleri karşılamak için yetersiz doku perfüzyonu ve oksijenasyonu. Türleri: hipovolemik (kan/sıvı kaybı), kardiyojenik (kalp yetmezliği), dağılımsal (septik, anafilaktik), obstrüktif (PE, tamponad).","nl":"Onvoldoende weefselperfusie en oxygenatie om aan de metabole behoeften te voldoen. Typen: hypovolemisch (bloed-/vloeistofverlies), cardiogeen (hartfalen), distributief (septisch, anafylactisch), obstructief (longembolie, tamponade).","ru":"Недостаточная перфузия и оксигенация тканей для удовлетворения метаболических потребностей. Типы: гиповолемический (потеря крови/жидкости), кардиогенный (сердечная недостаточность), дистрибутивный (септический, анафилактический), обструктивный (ТЭЛА, тампонада).","zh":"组织灌注和氧合不足以满足代谢需求。类型：低血容量性（失血/失液）、心源性（心力衰竭）、分布性（感染性、过敏性）、梗阻性（肺栓塞、心包填塞）。","pt_BR":"Perfusão e oxigenação tecidual inadequadas para atender às demandas metabólicas. Tipos: hipovolêmico (perda de sangue/líquido), cardiogênico (insuficiência cardíaca), distributivo (séptico, anafilático), obstrutivo (TEP, tamponamento).","pt_PT":"Perfusão e oxigenação tecidual inadequadas para satisfazer as necessidades metabólicas. Tipos: hipovolémico (perda de sangue/líquido), cardiogénico (insuficiência cardíaca), distributivo (séptico, anafilático), obstrutivo (TEP, tamponamento)."}},
  { id: 'dc-medical-0131', deck_id: 'deck-medical', sort_order: 131, front: "Anaphylaxis", back: "A severe, life-threatening systemic allergic reaction. Features: urticaria, angioedema, hypotension, bronchospasm. Mediated by IgE and mast cell degranulation. Treatment: epinephrine IM immediately, then fluids, antihistamines, steroids." , front_translations: {"es":"Anafilaxia","de":"Anaphylaxie","fr":"Anaphylaxie","tr":"Anafilaksi","nl":"Anafylaxie","ru":"Анафилаксия","zh":"过敏性休克（严重过敏反应）","pt_BR":"Anafilaxia","pt_PT":"Anafilaxia"}, back_translations: {"es":"Reacción alérgica sistemica grave y potencialmente fatal. Características: urticária, angioedema, hipotensão, broncoespasmo. Tratamiento: epinefrina (adrenalina) intramuscular es a terapia de primera línea.","de":"Eine schwere, lebensbedrohliche systemische allergische Reaktion. Merkmale: Urtikaria, Angioödem, Hypotonie, Bronchospasmus. Therapie: intramuskuläres Adrenalin (Epinephrin) ist die Erstlinientherapie.","fr":"Réaction allergique systémique sévère et potentiellement mortelle. Caractéristiques : urticaire, angio-œdème, hypotension, bronchospasme. Traitement : l'adrénaline (épinéphrine) intramusculaire est le traitement de première ligne.","tr":"Ciddi, yaşamı tehdit eden sistemik alerjik reaksiyon. Bulgular: ürtiker, anjiyoödem, hipotansiyon, bronkospazm. Tedavi: intramusküler epinefrin (adrenalin) birinci basamak tedavidir.","nl":"Een ernstige, levensbedreigende systemische allergische reactie. Kenmerken: urticaria, angio-oedeem, hypotensie, bronchospasme. Behandeling: intramusculaire adrenaline (epinefrine) is de eerstelijnsbehandeling.","ru":"Тяжёлая, угрожающая жизни системная аллергическая реакция. Признаки: крапивница, ангионевротический отёк, гипотензия, бронхоспазм. Лечение: внутримышечный адреналин (эпинефрин) — терапия первой линии.","zh":"一种严重的、危及生命的全身性过敏反应。特征：荨麻疹、血管性水肿、低血压、支气管痉挛。治疗：肌肉注射肾上腺素是一线治疗。","pt_BR":"Reação alérgica sistêmica grave e potencialmente fatal. Características: urticária, angioedema, hipotensão, broncoespasmo. Tratamento: epinefrina (adrenalina) intramuscular é a terapia de primeira linha.","pt_PT":"Reação alérgica sistémica grave e potencialmente fatal. Características: urticária, angioedema, hipotensão, broncospasmo. Tratamento: adrenalina (epinefrina) intramuscular é a terapia de primeira linha."}},
  { id: 'dc-medical-0132', deck_id: 'deck-medical', sort_order: 132, front: "BLS — Basic Life Support", back: "A level of emergency medical care for patients in cardiac or respiratory arrest. Includes CPR (30 compressions : 2 breaths) and AED use. The foundation of resuscitation; can be performed by lay responders." , front_translations: {"es":"SBV — Suporte Básico de Vida","de":"BLS — Lebensrettende Basismaßnahmen","fr":"BLS — Réanimation de base","tr":"TYD — Temel Yaşam Desteği","nl":"BLS — Basale reanimatie","ru":"BLS — Базовая сердечно-лёгочная реанимация","zh":"BLS — 基础生命支持","pt_BR":"SBV — Suporte Básico de Vida","pt_PT":"SBV — Suporte Básico de Vida"}, back_translations: {"es":"Nivel de atendimento médico de emergencia para pacientes en parada cardíaca o respiratória. Incluye RCP (30 compresiones : 2 ventilaciones), uso de DEA y reconhecimento de engasgo.","de":"Ein Niveau der Notfallversorgung für Patienten mit Herz- oder Atemstillstand. Umfasst Herz-Lungen-Wiederbelebung (30 Kompressionen : 2 Beatmungen), AED-Einsatz und Erkennung von Erstickung.","fr":"Niveau de soins d'urgence pour les patients en arrêt cardiaque ou respiratoire. Comprend la RCP (30 compressions : 2 insufflations), l'utilisation du DEA et la reconnaissance de l'étouffement.","tr":"Kardiyak veya solunumsal arrest hastalarına yönelik acil tıbbi bakım düzeyi. KPR (30 kompresyon : 2 solunum), OED kullanımı ve boğulmanın tanınmasını içerir.","nl":"Een niveau van spoedeisende medische zorg voor patiënten met een hart- of ademhalingsstilstand. Omvat reanimatie (30 compressies : 2 beademingen), AED-gebruik en herkenning van verstikking.","ru":"Уровень экстренной медицинской помощи при остановке сердца или дыхания. Включает СЛР (30 компрессий : 2 вдоха), применение АНД и распознавание обструкции дыхательных путей.","zh":"针对心脏骤停或呼吸骤停患者的急救医疗级别。包括心肺复苏（30次按压：2次通气）、AED使用和窒息识别。","pt_BR":"Nível de atendimento médico de emergência para pacientes em parada cardíaca ou respiratória. Inclui RCP (30 compressões : 2 ventilações), uso de DEA e reconhecimento de engasgo.","pt_PT":"Nível de cuidados médicos de emergência para doentes em paragem cardíaca ou respiratória. Inclui RCP (30 compressões : 2 ventilações), uso de DAE e reconhecimento de engasgamento."}},
  { id: 'dc-medical-0133', deck_id: 'deck-medical', sort_order: 133, front: "Intubation", back: "Insertion of an endotracheal tube through the mouth into the trachea to secure the airway and allow mechanical ventilation. Indicated in respiratory failure, unconsciousness, or when airway protection is needed." , front_translations: {"es":"Intubación","de":"Intubation","fr":"Intubation","tr":"Entübasyon","nl":"Intubatie","ru":"Интубация","zh":"气管插管","pt_BR":"Intubação","pt_PT":"Entubação"}, back_translations: {"es":"Inserción de un tubo endotraqueal por la boca hasta a traqueia para assegurar a via aérea y permitir ventilación mecánica. Indicada cuando el paciente no consegue proteger su propia via aérea.","de":"Einführung eines Endotrachealtubus durch den Mund in die Luftröhre zur Sicherung der Atemwege und Ermöglichung der maschinellen Beatmung. Indiziert, wenn der Patient seine Atemwege nicht selbst schützen kann.","fr":"Insertion d'un tube endotrachéal par la bouche dans la trachée pour sécuriser les voies aériennes et permettre la ventilation mécanique. Indiquée lorsque le patient ne peut pas protéger ses propres voies aériennes.","tr":"Havayolunu güvence altına almak ve mekanik ventilasyon sağlamak için ağızdan trakea içine endotrakeal tüp yerleştirilmesi. Hasta kendi havayolunu koruyamadığında endikedir.","nl":"Het inbrengen van een endotracheale tube door de mond in de luchtpijp om de luchtweg te beveiligen en mechanische ventilatie mogelijk te maken. Geïndiceerd wanneer een patiënt zijn eigen luchtweg niet kan beschermen.","ru":"Введение эндотрахеальной трубки через рот в трахею для обеспечения проходимости дыхательных путей и проведения искусственной вентиляции лёгких. Показана, когда пациент не может самостоятельно защитить дыхательные пути.","zh":"经口将气管导管插入气管以保护气道并进行机械通气。适用于患者无法自行保护气道时。","pt_BR":"Inserção de um tubo endotraqueal pela boca até a traqueia para assegurar a via aérea e permitir ventilação mecânica. Indicada quando o paciente não consegue proteger sua própria via aérea.","pt_PT":"Inserção de um tubo endotraqueal pela boca até à traqueia para assegurar a via aérea e permitir ventilação mecânica. Indicada quando o doente não consegue proteger a sua própria via aérea."}},
  { id: 'dc-medical-0134', deck_id: 'deck-medical', sort_order: 134, front: "Catheterization (Urinary)", back: "Insertion of a catheter into the bladder via the urethra to drain urine. Indications: urinary retention, monitoring output in ICU, obstruction. Risks: urinary tract infection (CAUTI). Foley catheter has a retention balloon." , front_translations: {"es":"Cateterismo vesical","de":"Katheterisierung (Harnblase)","fr":"Cathétérisme urinaire","tr":"Üriner Kateterizasyon","nl":"Katheterisatie (urinair)","ru":"Катетеризация мочевого пузыря","zh":"导尿术","pt_BR":"Cateterismo vesical","pt_PT":"Cateterismo vesical"}, back_translations: {"es":"Inserción de un cateter en la bexiga por la uretra para drenar urina. Indicaciones: retención urinária, monitoramento preciso del débito urinário, cirugía o pacientes imobilizados.","de":"Einführung eines Katheters in die Blase durch die Harnröhre zur Urinableitung. Indikationen: Harnverhalt, genaue Urinausscheidungsmessung, Operation oder immobile Patienten.","fr":"Insertion d'un cathéter dans la vessie par l'urètre pour drainer l'urine. Indications : rétention urinaire, surveillance précise du débit urinaire, chirurgie ou patients immobilisés.","tr":"İdrarı boşaltmak için üretra yoluyla mesaneye kateter yerleştirilmesi. Endikasyonlar: üriner retansiyon, doğru idrar çıkış takibi, cerrahi veya immobil hastalar.","nl":"Het inbrengen van een katheter in de blaas via de urethra om urine af te voeren. Indicaties: urineretentie, nauwkeurige urineproductiemeting, chirurgie of immobiele patiënten.","ru":"Введение катетера в мочевой пузырь через уретру для отведения мочи. Показания: задержка мочи, точный контроль диуреза, хирургия или обездвиженные пациенты.","zh":"经尿道将导管插入膀胱以引流尿液。适应证：尿潴留、精确尿量监测、手术或卧床患者。","pt_BR":"Inserção de um cateter na bexiga pela uretra para drenar urina. Indicações: retenção urinária, monitoramento preciso do débito urinário, cirurgia ou pacientes imobilizados.","pt_PT":"Inserção de um cateter na bexiga pela uretra para drenar urina. Indicações: retenção urinária, monitorização precisa do débito urinário, cirurgia ou doentes imobilizados."}},
  { id: 'dc-medical-0135', deck_id: 'deck-medical', sort_order: 135, front: "Lumbar Puncture (LP / Spinal Tap)", back: "Insertion of a needle into the subarachnoid space at L3–L4 or L4–L5 to collect CSF. Diagnoses meningitis, encephalitis, subarachnoid hemorrhage, MS. Contraindicated if raised intracranial pressure." , front_translations: {"es":"Punción lombar (PL)","de":"Lumbalpunktion (LP)","fr":"Ponction lombaire (PL)","tr":"Lomber Ponksiyon (LP)","nl":"Lumbaalpunctie (LP)","ru":"Люмбальная пункция (ЛП)","zh":"腰椎穿刺（LP）","pt_BR":"Punção lombar (PL)","pt_PT":"Punção lombar (PL)"}, back_translations: {"es":"Inserción de una agulha en el espacio subaracnóideo en L3–L4 o L4–L5 para coletar LCR. Diagnostica meningite, hemorragia subaracnóidea y enfermedades del SNC.","de":"Einführung einer Nadel in den Subarachnoidalraum bei L3–L4 oder L4–L5 zur Entnahme von Liquor (CSF). Diagnostiziert Meningitis, Subarachnoidalblutung und ZNS-Erkrankungen.","fr":"Insertion d'une aiguille dans l'espace sous-arachnoïdien au niveau L3–L4 ou L4–L5 pour prélever du LCR. Permet de diagnostiquer la méningite, l'hémorragie sous-arachnoïdienne et les maladies du SNC.","tr":"BOS toplamak için L3–L4 veya L4–L5 düzeyinde subaraknoid aralığa iğne yerleştirilmesi. Menenjit, subaraknoid kanama ve MSS hastalıklarını tanılar.","nl":"Het inbrengen van een naald in de subarachnoïdale ruimte ter hoogte van L3–L4 of L4–L5 om liquor (CSF) op te vangen. Diagnosticeert meningitis, subarachnoïdale bloeding en CZS-ziekten.","ru":"Введение иглы в субарахноидальное пространство на уровне L3–L4 или L4–L5 для забора спинномозговой жидкости (СМЖ). Диагностирует менингит, субарахноидальное кровоизлияние и заболевания ЦНС.","zh":"在L3–L4或L4–L5水平将针头插入蛛网膜下腔以收集脑脊液（CSF）。用于诊断脑膜炎、蛛网膜下腔出血和中枢神经系统疾病。","pt_BR":"Inserção de uma agulha no espaço subaracnóideo em L3–L4 ou L4–L5 para coletar LCR. Diagnostica meningite, hemorragia subaracnóidea e doenças do SNC.","pt_PT":"Inserção de uma agulha no espaço subaracnoideu em L3–L4 ou L4–L5 para recolher LCR. Diagnostica meningite, hemorragia subaracnoideia e doenças do SNC."}},
  { id: 'dc-medical-0136', deck_id: 'deck-medical', sort_order: 136, front: "Troponin", back: "A cardiac biomarker; elevated troponin T and I indicate myocardial injury. High-sensitivity troponin rises within 1–3 hours of MI. A key diagnostic criterion for NSTEMI and STEMI. Also rises in PE, myocarditis, and renal failure." , front_translations: {"es":"Troponina","de":"Troponin","fr":"Troponine","tr":"Troponin","nl":"Troponine","ru":"Тропонин","zh":"肌钙蛋白","pt_BR":"Troponina","pt_PT":"Troponina"}, back_translations: {"es":"Un biomarcador cardíaco; troponina T y I elevadas indican lesão miocárdica. Ensaios de troponina de alta sensibilidad pueden detectar IAM agudo en poucas horas.","de":"Ein kardialer Biomarker; erhöhtes Troponin T und I weisen auf eine Myokardschädigung hin. Hochsensitive Troponin-Assays können einen akuten Myokardinfarkt innerhalb von Stunden nachweisen.","fr":"Un biomarqueur cardiaque ; des taux élevés de troponine T et I indiquent une lésion myocardique. Les dosages de troponine haute sensibilité peuvent détecter un infarctus aigu en quelques heures.","tr":"Bir kardiyak biyobelirteç; yüksek troponin T ve I miyokard hasarını gösterir. Yüksek duyarlılıklı troponin testleri akut MI'ı saatler içinde tespit edebilir.","nl":"Een cardiale biomarker; verhoogd troponine T en I wijzen op myocardschade. Hoogsensitieve troponine-assays kunnen een acuut MI binnen uren detecteren.","ru":"Сердечный биомаркер; повышенный тропонин T и I указывают на повреждение миокарда. Высокочувствительные тесты на тропонин позволяют выявить острый инфаркт миокарда в течение нескольких часов.","zh":"心脏生物标志物；肌钙蛋白T和I升高提示心肌损伤。高敏肌钙蛋白检测可在数小时内检出急性心肌梗死。","pt_BR":"Um biomarcador cardíaco; troponina T e I elevadas indicam lesão miocárdica. Ensaios de troponina de alta sensibilidade podem detectar IAM agudo em poucas horas.","pt_PT":"Um biomarcador cardíaco; troponina T e I elevadas indicam lesão miocárdica. Ensaios de troponina de alta sensibilidade podem detetar EAM agudo em poucas horas."}},
  { id: 'dc-medical-0137', deck_id: 'deck-medical', sort_order: 137, front: "D-dimer", back: "A fibrin degradation product elevated when clotting and fibrinolysis are active. High sensitivity for DVT/PE; low specificity (elevated in many conditions). A negative D-dimer reliably excludes PE in low-probability patients." , front_translations: {"es":"D-dímero","de":"D-Dimer","fr":"D-dimères","tr":"D-dimer","nl":"D-dimeer","ru":"D-димер","zh":"D-二聚体","pt_BR":"D-dímero","pt_PT":"D-dímero"}, back_translations: {"es":"Producto de degradación de la fibrina, elevado cuando coagulación y fibrinólise están ativas. Alta sensibilidad para excluir TEP y TVP cuando negativo. Baja especificidad.","de":"Ein Fibrin-Abbauprodukt, das bei aktiver Gerinnung und Fibrinolyse erhöht ist. Hohe Sensitivität zum Ausschluss von Lungenembolie und tiefer Venenthrombose bei negativem Ergebnis. Niedrige Spezifität.","fr":"Un produit de dégradation de la fibrine, élevé lorsque la coagulation et la fibrinolyse sont actives. Haute sensibilité pour exclure l'EP et la TVP en cas de résultat négatif. Faible spécificité.","tr":"Pıhtılaşma ve fibrinoliz aktif olduğunda yükselen bir fibrin yıkım ürünü. Negatif olduğunda PE ve DVT'yi dışlamada yüksek duyarlılık. Düşük özgüllük.","nl":"Een fibrine-afbraakproduct dat verhoogd is bij actieve stolling en fibrinolyse. Hoge sensitiviteit voor het uitsluiten van longembolie en DVT bij een negatief resultaat. Lage specificiteit.","ru":"Продукт деградации фибрина, повышающийся при активном свёртывании и фибринолизе. Высокая чувствительность для исключения ТЭЛА и ТГВ при отрицательном результате. Низкая специфичность.","zh":"一种纤维蛋白降解产物，在凝血和纤溶活跃时升高。阴性结果对排除肺栓塞和深静脉血栓具有高敏感性。特异性低。","pt_BR":"Produto de degradação da fibrina, elevado quando coagulação e fibrinólise estão ativas. Alta sensibilidade para excluir TEP e TVP quando negativo. Baixa especificidade.","pt_PT":"Produto de degradação da fibrina, elevado quando coagulação e fibrinólise estão ativas. Alta sensibilidade para excluir TEP e TVP quando negativo. Baixa especificidade."}},
  { id: 'dc-medical-0138', deck_id: 'deck-medical', sort_order: 138, front: "Creatinine and eGFR", back: "Serum creatinine is a waste product filtered by the kidneys; elevated levels indicate reduced kidney function. eGFR (estimated GFR) is calculated from creatinine, age, and sex; normal >90 mL/min/1.73m²." , front_translations: {"es":"Creatinina y TFGe","de":"Kreatinin und eGFR","fr":"Créatinine et DFGe","tr":"Kreatinin ve eGFR","nl":"Creatinine en eGFR","ru":"Креатинин и рСКФ","zh":"肌酐与eGFR","pt_BR":"Creatinina e TFGe","pt_PT":"Creatinina e TFGe"}, back_translations: {"es":"La creatinina sérica es un producto residual filtrado por los riñones; niveles elevados indican función renal reduzida. La TFGe estima quão bem los riñones filtram el sangre.","de":"Serumkreatinin ist ein Abfallprodukt, das von den Nieren gefiltert wird; erhöhte Werte weisen auf eine eingeschränkte Nierenfunktion hin. Die eGFR schätzt, wie gut die Nieren das Blut filtern.","fr":"La créatinine sérique est un déchet filtré par les reins ; des taux élevés indiquent une fonction rénale diminuée. Le DFGe estime la capacité des reins à filtrer le sang.","tr":"Serum kreatinin böbrekler tarafından süzülen bir atık üründür; yüksek değerler azalmış böbrek fonksiyonunu gösterir. eGFR böbreklerin kanı ne kadar iyi süzdüğünü tahmin eder.","nl":"Serumcreatinine is een afvalproduct dat door de nieren wordt gefilterd; verhoogde waarden wijzen op verminderde nierfunctie. eGFR schat hoe goed de nieren het bloed filteren.","ru":"Креатинин сыворотки — продукт обмена, фильтруемый почками; повышенный уровень указывает на снижение функции почек. рСКФ оценивает, насколько эффективно почки фильтруют кровь.","zh":"血清肌酐是由肾脏过滤的代谢废物；水平升高提示肾功能下降。eGFR估算肾脏过滤血液的能力。","pt_BR":"A creatinina sérica é um produto residual filtrado pelos rins; níveis elevados indicam função renal reduzida. A TFGe estima quão bem os rins filtram o sangue.","pt_PT":"A creatinina sérica é um produto residual filtrado pelos rins; níveis elevados indicam função renal reduzida. A TFGe estima a capacidade dos rins de filtrar o sangue."}},
  { id: 'dc-medical-0139', deck_id: 'deck-medical', sort_order: 139, front: "Prothrombin Time (PT) / INR", back: "Measures the extrinsic coagulation pathway. INR = patient PT / mean normal PT. Used to monitor warfarin therapy (target INR 2–3 for most indications). Prolonged in liver disease, vitamin K deficiency, warfarin use." , front_translations: {"es":"Tiempo de Protrombina (TP) / INR","de":"Prothrombinzeit (PT) / INR","fr":"Temps de prothrombine (TP) / INR","tr":"Protrombin Zamanı (PT) / INR","nl":"Protrombinetijd (PT) / INR","ru":"Протромбиновое время (ПВ) / МНО","zh":"凝血酶原时间 (PT) / INR","pt_BR":"Tempo de Protrombina (TP) / INR","pt_PT":"Tempo de Protrombina (TP) / INR"}, back_translations: {"es":"Mide a via extrínseca de la coagulación. INR = TP del paciente / TP médio normal. Usado para monitorar a terapia con varfarina (INR alvo 2–3 para a maioria de las indicaciones).","de":"Misst den extrinsischen Gerinnungsweg. INR = Patienten-PT / mittlere Normal-PT. Wird zur Überwachung der Warfarin-Therapie verwendet (Ziel-INR 2–3 für die meisten Indikationen).","fr":"Mesure la voie extrinsèque de la coagulation. INR = TP du patient / TP moyen normal. Utilisé pour surveiller le traitement par warfarine (INR cible 2–3 pour la plupart des indications).","tr":"Ekstrensek pıhtılaşma yolunu ölçer. INR = hasta PT / ortalama normal PT. Varfarin tedavisini izlemek için kullanılır (çoğu endikasyonda hedef INR 2–3).","nl":"Meet de extrinsieke stollingscascade. INR = patiënt-PT / gemiddelde normale PT. Gebruikt om warfarinetherapie te monitoren (doel-INR 2–3 voor de meeste indicaties).","ru":"Измеряет внешний путь свёртывания. МНО = ПВ пациента / среднее нормальное ПВ. Используется для контроля терапии варфарином (целевое МНО 2–3 для большинства показаний).","zh":"检测外源性凝血途径。INR = 患者PT / 平均正常PT。用于监测华法林治疗（多数适应证目标INR 2–3）。","pt_BR":"Mede a via extrínseca da coagulação. INR = TP do paciente / TP médio normal. Usado para monitorar a terapia com varfarina (INR alvo 2–3 para a maioria das indicações).","pt_PT":"Mede a via extrínseca da coagulação. INR = TP do doente / TP médio normal. Usado para monitorizar a terapêutica com varfarina (INR alvo 2–3 para a maioria das indicações)."}},
  { id: 'dc-medical-0140', deck_id: 'deck-medical', sort_order: 140, front: "aPTT — Activated Partial Thromboplastin Time", back: "Measures the intrinsic coagulation pathway. Used to monitor unfractionated heparin therapy (target 60–100 seconds, or 1.5–2.5× normal). Prolonged in hemophilia A/B, lupus anticoagulant, and heparin use." , front_translations: {"es":"TTPa — Tiempo de Tromboplastina Parcial Ativada","de":"aPTT — Aktivierte partielle Thromboplastinzeit","fr":"TCA — Temps de céphaline activée","tr":"aPTT — Aktive Parsiyel Tromboplastin Zamanı","nl":"aPTT — Geactiveerde partiële tromboplastinetijd","ru":"АЧТВ — Активированное частичное тромбопластиновое время","zh":"aPTT — 活化部分凝血活酶时间","pt_BR":"TTPa — Tempo de Tromboplastina Parcial Ativada","pt_PT":"TTPa — Tempo de Tromboplastina Parcial Ativada"}, back_translations: {"es":"Mide a via intrínseca de la coagulación. Usado para monitorar terapia con heparina no fracionada (alvo 60–80 segundos). Prolongado en la hemofilia A y B.","de":"Misst den intrinsischen Gerinnungsweg. Wird zur Überwachung der unfraktionierten Heparintherapie verwendet (Zielwert 60–80 Sekunden). Verlängert bei Hämophilie A und B.","fr":"Mesure la voie intrinsèque de la coagulation. Utilisé pour surveiller l'héparinothérapie non fractionnée (cible 60–80 secondes). Prolongé dans l'hémophilie A et B.","tr":"İntrensek pıhtılaşma yolunu ölçer. Fraksiyone olmayan heparin tedavisini izlemek için kullanılır (hedef 60–80 saniye). Hemofili A ve B'de uzar.","nl":"Meet de intrinsieke stollingscascade. Gebruikt om ongefractioneerde heparinetherapie te monitoren (doel 60–80 seconden). Verlengd bij hemofilie A en B.","ru":"Измеряет внутренний путь свёртывания. Используется для контроля терапии нефракционированным гепарином (целевое значение 60–80 секунд). Удлинено при гемофилии A и B.","zh":"检测内源性凝血途径。用于监测普通肝素治疗（目标60–80秒）。血友病A和B时延长。","pt_BR":"Mede a via intrínseca da coagulação. Usado para monitorar terapia com heparina não fracionada (alvo 60–80 segundos). Prolongado na hemofilia A e B.","pt_PT":"Mede a via intrínseca da coagulação. Usado para monitorizar terapêutica com heparina não fracionada (alvo 60–80 segundos). Prolongado na hemofilia A e B."}},
  { id: 'dc-medical-0141', deck_id: 'deck-medical', sort_order: 141, front: "Palmar Erythema", back: "Reddening of the palms, particularly in the thenar and hypothenar eminences. Associated with liver disease (cirrhosis), pregnancy, rheumatoid arthritis, and thyrotoxicosis. A sign of elevated estrogen." , front_translations: {"es":"Eritema palmar","de":"Palmarerythem","fr":"Érythème palmaire","tr":"Palmar Eritem","nl":"Palmair erytheem","ru":"Пальмарная эритема","zh":"手掌红斑","pt_BR":"Eritema palmar","pt_PT":"Eritema palmar"}, back_translations: {"es":"Vermelhidão de las palmas de las manos, particularmente en las eminencias tenar y hipotenar. Associado a enfermedad hepática, gravidez, tireotoxicose y artrite reumatoide.","de":"Rötung der Handflächen, besonders im Bereich der Thenar- und Hypothenareminenz. Assoziiert mit Lebererkrankungen, Schwangerschaft, Thyreotoxikose und rheumatoider Arthritis.","fr":"Rougeur des paumes, particulièrement au niveau des éminences thénar et hypothénar. Associé aux maladies hépatiques, à la grossesse, à la thyrotoxicose et à la polyarthrite rhumatoïde.","tr":"Özellikle tenar ve hipotenar eminenslerde avuç içi kızarıklığı. Karaciğer hastalığı, gebelik, tirotoksikoz ve romatoid artrit ile ilişkilidir.","nl":"Roodheid van de handpalmen, met name ter hoogte van de thenar- en hypothenareminentie. Geassocieerd met leverziekte, zwangerschap, thyreotoxicose en reumatoïde artritis.","ru":"Покраснение ладоней, особенно в области тенара и гипотенара. Связано с заболеваниями печени, беременностью, тиреотоксикозом и ревматоидным артритом.","zh":"手掌发红，尤其是大鱼际和小鱼际处。与肝病、妊娠、甲状腺毒症和类风湿性关节炎相关。","pt_BR":"Vermelhidão das palmas das mãos, particularmente nas eminências tenar e hipotenar. Associado a doença hepática, gravidez, tireotoxicose e artrite reumatoide.","pt_PT":"Vermelhidão das palmas das mãos, particularmente nas eminências tenar e hipotenar. Associado a doença hepática, gravidez, tirotoxicose e artrite reumatoide."}},
  { id: 'dc-medical-0142', deck_id: 'deck-medical', sort_order: 142, front: "Clubbing", back: "Enlargement of the terminal phalanges with loss of the normal angle between the nail and nail bed. Associated with chronic hypoxia (COPD, cyanotic heart disease), lung cancer, cystic fibrosis, and inflammatory bowel disease." , front_translations: {"es":"Baqueteamento digital","de":"Trommelschlägelfinger (Clubbing)","fr":"Hippocratisme digital","tr":"Çomak Parmak","nl":"Trommelstokvingers","ru":"Барабанные пальцы","zh":"杵状指","pt_BR":"Baqueteamento digital","pt_PT":"Hipocratismo digital"}, back_translations: {"es":"Aumento de las falanges distais con perda del ángulo normal entre a unha y el leito ungueal. Associado a enfermedad pulmonar, cardiopatia cianótica y enfermedad inflamatória intestinal.","de":"Vergrößerung der Endphalangen mit Verlust des normalen Winkels zwischen Nagel und Nagelbett. Assoziiert mit Lungenerkrankungen, zyanotischen Herzerkrankungen und chronisch-entzündlichen Darmerkrankungen.","fr":"Élargissement des phalanges distales avec perte de l'angle normal entre l'ongle et le lit unguéal. Associé aux maladies pulmonaires, aux cardiopathies cyanogènes et aux maladies inflammatoires de l'intestin.","tr":"Tırnak ile tırnak yatağı arasındaki normal açının kaybolmasıyla terminal falanksların büyümesi. Akciğer hastalığı, siyanotik kalp hastalığı ve inflamatuar bağırsak hastalığı ile ilişkilidir.","nl":"Vergroting van de terminale falangen met verlies van de normale hoek tussen nagel en nagelbed. Geassocieerd met longziekte, cyanotische hartziekte en inflammatoire darmziekte.","ru":"Утолщение концевых фаланг с утратой нормального угла между ногтем и ногтевым ложем. Связано с заболеваниями лёгких, цианотическими пороками сердца и воспалительными заболеваниями кишечника.","zh":"末端指骨增大，甲与甲床之间正常角度消失。与肺部疾病、紫绀型心脏病和炎症性肠病相关。","pt_BR":"Aumento das falanges distais com perda do ângulo normal entre a unha e o leito ungueal. Associado a doença pulmonar, cardiopatia cianótica e doença inflamatória intestinal.","pt_PT":"Aumento das falanges distais com perda do ângulo normal entre a unha e o leito ungueal. Associado a doença pulmonar, cardiopatia cianótica e doença inflamatória intestinal."}},
  { id: 'dc-medical-0143', deck_id: 'deck-medical', sort_order: 143, front: "Spider Naevi", back: "Vascular lesions with a central arteriole and radiating capillaries resembling a spider. Found on the upper body. >5 is clinically significant; associated with liver disease (cirrhosis) and pregnancy." , front_translations: {"es":"Aranhas vasculares","de":"Spider-Nävi","fr":"Angiomes stellaires","tr":"Spider Nevi","nl":"Spider naevi","ru":"Сосудистые звёздочки","zh":"蜘蛛痣","pt_BR":"Aranhas vasculares","pt_PT":"Aranhas vasculares"}, back_translations: {"es":"Lesões vasculares con una arteríola central y capilares irradiados semelhantes a una aranha. Encontradas en la parte superior del cuerpo. Associadas a enfermedad hepática y gravidez.","de":"Gefäßläsionen mit einer zentralen Arteriole und strahlenförmig ausgehenden Kapillaren, die einer Spinne ähneln. Am Oberkörper zu finden. Assoziiert mit Lebererkrankungen und Schwangerschaft.","fr":"Lésions vasculaires avec une artériole centrale et des capillaires radiants ressemblant à une araignée. Situées sur le haut du corps. Associées aux maladies hépatiques et à la grossesse.","tr":"Merkezi bir arteriyol ve örümceğe benzeyen radyal kapillerlerden oluşan vasküler lezyonlar. Üst vücutta bulunur. Karaciğer hastalığı ve gebelik ile ilişkilidir.","nl":"Vasculaire laesies met een centraal arteriooltje en uitstralende capillairen die op een spin lijken. Komen voor op het bovenlichaam. Geassocieerd met leverziekte en zwangerschap.","ru":"Сосудистые образования с центральной артериолой и расходящимися капиллярами, напоминающие паука. Обнаруживаются на верхней части тела. Связаны с заболеваниями печени и беременностью.","zh":"以中央小动脉为核心、放射状毛细血管呈蜘蛛形的血管病变。好发于上半身。与肝病和妊娠相关。","pt_BR":"Lesões vasculares com uma arteríola central e capilares irradiados semelhantes a uma aranha. Encontradas na parte superior do corpo. Associadas a doença hepática e gravidez.","pt_PT":"Lesões vasculares com uma arteríola central e capilares irradiados semelhantes a uma aranha. Encontradas na parte superior do corpo. Associadas a doença hepática e gravidez."}},
  { id: 'dc-medical-0144', deck_id: 'deck-medical', sort_order: 144, front: "Consent: Capacity", back: "The ability of a patient to make an informed decision. Requires: understanding information, retaining it, weighing pros/cons, and communicating a choice. Capacity is decision-specific and can fluctuate." , front_translations: {"es":"Consentimento: Capacidad","de":"Einwilligung: Einwilligungsfähigkeit","fr":"Consentement : Capacité","tr":"Onam: Kapasite","nl":"Toestemming: Wilsbekwaamheid","ru":"Согласие: Дееспособность","zh":"知情同意：行为能力","pt_BR":"Consentimento: Capacidade","pt_PT":"Consentimento: Capacidade"}, back_translations: {"es":"La capacidad de un paciente de tomar una decisão informada. Requiere: compreender a información, rete-la, ponderar prós y contras y comunicar a decisão.","de":"Die Fähigkeit eines Patienten, eine informierte Entscheidung zu treffen. Erfordert: Verständnis der Information, Behalten der Information, Abwägen von Vor- und Nachteilen und Mitteilung der Entscheidung.","fr":"La capacité d'un patient à prendre une décision éclairée. Nécessite : comprendre l'information, la retenir, peser le pour et le contre, et communiquer la décision.","tr":"Bir hastanın bilgilendirilmiş karar verme yeteneği. Gereklilikler: bilgiyi anlama, bilgiyi akılda tutma, artıları ve eksileri tartma ve kararı iletme.","nl":"Het vermogen van een patiënt om een geïnformeerde beslissing te nemen. Vereist: de informatie begrijpen, onthouden, voor- en nadelen afwegen en de beslissing communiceren.","ru":"Способность пациента принять осознанное решение. Требует: понимания информации, удержания её в памяти, взвешивания за и против и сообщения о решении.","zh":"患者做出知情决定的能力。要求：理解信息、记住信息、权衡利弊以及表达决定。","pt_BR":"A capacidade de um paciente de tomar uma decisão informada. Requer: compreender a informação, retê-la, ponderar prós e contras e comunicar a decisão.","pt_PT":"A capacidade de um doente de tomar uma decisão informada. Requer: compreender a informação, retê-la, ponderar prós e contras e comunicar a decisão."}},
  { id: 'dc-medical-0145', deck_id: 'deck-medical', sort_order: 145, front: "Antibiotic Resistance", back: "The ability of bacteria to survive exposure to antibiotics, making infections harder to treat. Mechanisms: beta-lactamase production, efflux pumps, altered target sites. Reduced by appropriate prescribing and completing courses." , front_translations: {"es":"Resistencia a antibióticos","de":"Antibiotikaresistenz","fr":"Résistance aux antibiotiques","tr":"Antibiyotik Direnci","nl":"Antibioticaresistentie","ru":"Антибиотикорезистентность","zh":"抗生素耐药性","pt_BR":"Resistência a antibióticos","pt_PT":"Resistência a antibióticos"}, back_translations: {"es":"La capacidad de las bacterias de sobreviver a la exposición a antibióticos, tornando las infecciones más difíceis de tratar. Mecanismos: degradación enzimática, bombas de efluxo y modificación del alvo.","de":"Die Fähigkeit von Bakterien, eine Antibiotikaexposition zu überleben, wodurch Infektionen schwerer zu behandeln sind. Mechanismen: enzymatischer Abbau, Effluxpumpen und Zielmodifikation.","fr":"La capacité des bactéries à survivre à l'exposition aux antibiotiques, rendant les infections plus difficiles à traiter. Mécanismes : dégradation enzymatique, pompes d'efflux et modification de la cible.","tr":"Bakterilerin antibiyotik maruziyetinden sağ kalma yeteneği, enfeksiyonları tedavi etmeyi zorlaştırır. Mekanizmalar: enzimatik yıkım, efluks pompaları ve hedef modifikasyonu.","nl":"Het vermogen van bacteriën om blootstelling aan antibiotica te overleven, waardoor infecties moeilijker te behandelen zijn. Mechanismen: enzymatische afbraak, effluxpompen en doelwitmodificatie.","ru":"Способность бактерий выживать при воздействии антибиотиков, что затрудняет лечение инфекций. Механизмы: ферментативная деградация, эффлюксные помпы и модификация мишени.","zh":"细菌在抗生素暴露下存活的能力，使感染更难治疗。机制包括酶降解、外排泵和靶点修饰。","pt_BR":"A capacidade das bactérias de sobreviver à exposição a antibióticos, tornando as infecções mais difíceis de tratar. Mecanismos: degradação enzimática, bombas de efluxo e modificação do alvo.","pt_PT":"A capacidade das bactérias de sobreviver à exposição a antibióticos, tornando as infeções mais difíceis de tratar. Mecanismos: degradação enzimática, bombas de efluxo e modificação do alvo."}},
  { id: 'dc-medical-0146', deck_id: 'deck-medical', sort_order: 146, front: "Hospital-Acquired Infection (HAI)", back: "An infection acquired in a hospital or healthcare setting not present at admission. Examples: MRSA, Clostridioides difficile (C. diff), CAUTI, CLABSI. Prevention: hand hygiene, sterile technique, isolation protocols." , front_translations: {"es":"Infección hospitalar (IRAS)","de":"Nosokomiale Infektion (HAI)","fr":"Infection nosocomiale (IAS)","tr":"Hastane Enfeksiyonu (HE)","nl":"Ziekenhuisinfectie (HAI)","ru":"Внутрибольничная инфекция (ВБИ)","zh":"医院获得性感染 (HAI)","pt_BR":"Infecção hospitalar (IRAS)","pt_PT":"Infeção associada aos cuidados de saúde (IACS)"}, back_translations: {"es":"Infección adquirida en hospital o ambiente de salud, no presente en la admisión. Ejemplos: MRSA, C. difficile, infecciones urinárias associadas a cateter, pneumonia associada a la ventilación mecánica.","de":"Eine Infektion, die im Krankenhaus oder Gesundheitswesen erworben wird und bei Aufnahme nicht vorhanden war. Beispiele: MRSA, C. difficile, katheterassoziierte Harnwegsinfektionen, beatmungsassoziierte Pneumonie.","fr":"Infection acquise dans un hôpital ou un établissement de santé, non présente à l'admission. Exemples : SARM, C. difficile, infections urinaires liées aux cathéters, pneumonie associée à la ventilation.","tr":"Hastaneye yatışta mevcut olmayıp hastane veya sağlık ortamında edinilen enfeksiyon. Örnekler: MRSA, C. difficile, kateter ilişkili üriner sistem enfeksiyonları, ventilatör ilişkili pnömoni.","nl":"Een infectie opgelopen in een ziekenhuis of zorginstelling die niet aanwezig was bij opname. Voorbeelden: MRSA, C. difficile, katheter-gerelateerde urineweginfecties, beademingsgerelateerde pneumonie.","ru":"Инфекция, приобретённая в больнице или учреждении здравоохранения, отсутствовавшая при поступлении. Примеры: MRSA, C. difficile, катетер-ассоциированные ИМП, вентилятор-ассоциированная пневмония.","zh":"在医院或医疗机构获得的、入院时不存在的感染。例如：MRSA、艰难梭菌感染、导管相关尿路感染、呼吸机相关性肺炎。","pt_BR":"Infecção adquirida em hospital ou ambiente de saúde, não presente na admissão. Exemplos: MRSA, C. difficile, infecções urinárias associadas a cateter, pneumonia associada à ventilação mecânica.","pt_PT":"Infeção adquirida num hospital ou ambiente de saúde, não presente na admissão. Exemplos: MRSA, C. difficile, infeções urinárias associadas a cateter, pneumonia associada à ventilação mecânica."}},
  { id: 'dc-medical-0147', deck_id: 'deck-medical', sort_order: 147, front: "Benign vs. Malignant Tumor", back: "Benign: localized, well-differentiated, slow-growing, does not invade or metastasize, rarely life-threatening (unless compressing vital structures). Malignant: invasive, poorly differentiated, able to metastasize via blood or lymph." , front_translations: {"es":"Tumor benigno vs. maligno","de":"Gutartiger vs. bösartiger Tumor","fr":"Tumeur bénigne vs. maligne","tr":"Benign ve Malign Tümör","nl":"Benigne vs. maligne tumor","ru":"Доброкачественная и злокачественная опухоль","zh":"良性与恶性肿瘤","pt_BR":"Tumor benigno vs. maligno","pt_PT":"Tumor benigno vs. maligno"}, back_translations: {"es":"Benigno: localizado, bem diferenciado, crecimiento lento, no invade nem metastatiza, raramente ameaça a vida. Maligno: invasivo, pouco diferenciado, crecimiento rápido, puede metastatizar.","de":"Gutartig: lokalisiert, gut differenziert, langsam wachsend, infiltriert und metastasiert nicht, selten lebensbedrohlich. Bösartig: invasiv, schlecht differenziert, schnell wachsend, kann metastasieren.","fr":"Bénigne : localisée, bien différenciée, croissance lente, n'envahit ni ne métastase, rarement mortelle. Maligne : invasive, peu différenciée, croissance rapide, peut métastaser.","tr":"Benign: lokalize, iyi diferansiye, yavaş büyür, invaze etmez veya metastaz yapmaz, nadiren yaşamı tehdit eder. Malign: invaziv, kötü diferansiye, hızlı büyür, metastaz yapabilir.","nl":"Benigne: gelokaliseerd, goed gedifferentieerd, langzaam groeiend, invasie of metastasering ontbreekt, zelden levensbedreigend. Maligne: invasief, slecht gedifferentieerd, snelgroeiend, kan metastaseren.","ru":"Доброкачественная: локализованная, хорошо дифференцированная, медленно растущая, не инвазирует и не метастазирует, редко угрожает жизни. Злокачественная: инвазивная, низкодифференцированная, быстро растущая, может метастазировать.","zh":"良性：局限性，分化好，生长缓慢，不侵袭不转移，很少危及生命。恶性：侵袭性，分化差，生长迅速，可转移。","pt_BR":"Benigno: localizado, bem diferenciado, crescimento lento, não invade nem metastatiza, raramente ameaça a vida. Maligno: invasivo, pouco diferenciado, crescimento rápido, pode metastatizar.","pt_PT":"Benigno: localizado, bem diferenciado, crescimento lento, não invade nem metastiza, raramente ameaça a vida. Maligno: invasivo, pouco diferenciado, crescimento rápido, pode metastizar."}},
  { id: 'dc-medical-0148', deck_id: 'deck-medical', sort_order: 148, front: "Tumor Staging (TNM)", back: "T (tumor size/invasion), N (lymph node involvement), M (distant metastasis). Combined to give an overall stage (I–IV). Stage IV indicates distant metastases. Staging guides prognosis and treatment choice." , front_translations: {"es":"Estadiamento tumoral (TNM)","de":"Tumorstaging (TNM)","fr":"Stadification tumorale (TNM)","tr":"Tümör Evrelemesi (TNM)","nl":"Tumorstadiëring (TNM)","ru":"Стадирование опухоли (TNM)","zh":"肿瘤分期 (TNM)","pt_BR":"Estadiamento tumoral (TNM)","pt_PT":"Estadiamento tumoral (TNM)"}, back_translations: {"es":"T (tamaño/invasão tumoral), N (acometimento linfonodal), M (metástase a la distancia). Combinados para definir el etapa geral (I–IV). Etapa más alto = más avançado y peor prognóstico.","de":"T (Tumorgröße/-invasion), N (Lymphknotenbefall), M (Fernmetastasen). Kombiniert zu einem Gesamtstadium (I–IV). Höheres Stadium = fortgeschrittener und schlechtere Prognose.","fr":"T (taille/invasion tumorale), N (atteinte ganglionnaire), M (métastases à distance). Combinés pour donner un stade global (I–IV). Stade plus élevé = plus avancé et pronostic plus mauvais.","tr":"T (tümör boyutu/invazyonu), N (lenf nodu tutulumu), M (uzak metastaz). Genel evre oluşturmak için birleştirilir (I–IV). Yüksek evre = daha ileri ve daha kötü prognoz.","nl":"T (tumorgrootte/-invasie), N (lymfeklierbetrokkenheid), M (afstandsmetastasen). Gecombineerd tot een algeheel stadium (I–IV). Hoger stadium = meer gevorderd en slechtere prognose.","ru":"T (размер/инвазия опухоли), N (поражение лимфоузлов), M (отдалённые метастазы). Объединяются в общую стадию (I–IV). Более высокая стадия = более запущенный процесс и худший прогноз.","zh":"T（肿瘤大小/侵犯）、N（淋巴结受累）、M（远处转移）。综合得出总分期（I–IV）。分期越高 = 越晚期，预后越差。","pt_BR":"T (tamanho/invasão tumoral), N (acometimento linfonodal), M (metástase à distância). Combinados para definir o estágio geral (I–IV). Estágio mais alto = mais avançado e pior prognóstico.","pt_PT":"T (tamanho/invasão tumoral), N (envolvimento ganglionar), M (metástase à distância). Combinados para definir o estadio geral (I–IV). Estadio mais alto = mais avançado e pior prognóstico."}},
  { id: 'dc-medical-0149', deck_id: 'deck-medical', sort_order: 149, front: "Chemotherapy Side Effects", back: "Common effects from rapid division of cancer cells: bone marrow suppression (neutropenia, anemia, thrombocytopenia), alopecia, mucositis, nausea/vomiting, peripheral neuropathy, and increased infection risk." , front_translations: {"es":"Efectos colaterais de la quimioterapia","de":"Nebenwirkungen der Chemotherapie","fr":"Effets secondaires de la chimiothérapie","tr":"Kemoterapi Yan Etkileri","nl":"Bijwerkingen van chemotherapie","ru":"Побочные эффекты химиотерапии","zh":"化疗副作用","pt_BR":"Efeitos colaterais da quimioterapia","pt_PT":"Efeitos secundários da quimioterapia"}, back_translations: {"es":"Efectos comuns por la divisão rápida de las células cancerígenas: supresión medular (neutropenia, anemia, trombocitopenia), náusea, alopecia, mucosite, fadiga y imunossupresión.","de":"Häufige Effekte durch schnelle Teilung der Krebszellen: Knochenmarksuppression (Neutropenie, Anämie, Thrombozytopenie), Übelkeit, Alopezie, Mukositis, Fatigue und Immunsuppression.","fr":"Effets courants liés à la division rapide des cellules cancéreuses : suppression médullaire (neutropénie, anémie, thrombocytopénie), nausées, alopécie, mucite, fatigue et immunosuppression.","tr":"Kanser hücrelerinin hızlı bölünmesinden kaynaklanan yaygın etkiler: kemik iliği supresyonu (nötropeni, anemi, trombositopeni), bulantı, alopesi, mukozit, yorgunluk ve immünsupresyon.","nl":"Veelvoorkomende effecten door snelle deling van kankercellen: beenmergsuppressie (neutropenie, anemie, trombocytopenie), misselijkheid, alopecia, mucositis, vermoeidheid en immunosuppressie.","ru":"Частые эффекты, связанные с быстрым делением раковых клеток: угнетение костного мозга (нейтропения, анемия, тромбоцитопения), тошнота, алопеция, мукозит, утомляемость и иммуносупрессия.","zh":"因快速分裂的癌细胞所致的常见效应：骨髓抑制（中性粒细胞减少、贫血、血小板减少）、恶心、脱发、黏膜炎、疲劳和免疫抑制。","pt_BR":"Efeitos comuns pela divisão rápida das células cancerígenas: supressão medular (neutropenia, anemia, trombocitopenia), náusea, alopecia, mucosite, fadiga e imunossupressão.","pt_PT":"Efeitos comuns pela divisão rápida das células cancerígenas: supressão medular (neutropenia, anemia, trombocitopenia), náuseas, alopecia, mucosite, fadiga e imunossupressão."}},
  { id: 'dc-medical-0150', deck_id: 'deck-medical', sort_order: 150, front: "Placebo Effect", back: "A beneficial clinical response to an inactive treatment caused by a patient's belief in its effectiveness. Important in clinical trial design (double-blind, placebo-controlled). Not merely 'imagined'; involves measurable physiological changes." , front_translations: {"es":"Efecto placebo","de":"Placeboeffekt","fr":"Effet placebo","tr":"Plasebo Etkisi","nl":"Placebo-effect","ru":"Эффект плацебо","zh":"安慰剂效应","pt_BR":"Efeito placebo","pt_PT":"Efeito placebo"}, back_translations: {"es":"Una respuesta clínica benéfica a un tratamiento inativo, causada por la creencia del paciente en su eficácia. Controlado en investigaciones por medio de grupos placebo para isolar los verdaderos efectos del fármaco.","de":"Eine positive klinische Reaktion auf eine inaktive Behandlung, die durch den Glauben des Patienten an deren Wirksamkeit verursacht wird. In der Forschung durch Placebogruppen kontrolliert, um echte Arzneimittelwirkungen zu isolieren.","fr":"Une réponse clinique bénéfique à un traitement inactif, causée par la croyance du patient en son efficacité. Contrôlé en recherche par des groupes placebo pour isoler les véritables effets du médicament.","tr":"Hastanın etkinliğine olan inancından kaynaklanan, inaktif bir tedaviye karşı olumlu klinik yanıt. Araştırmada gerçek ilaç etkilerini ayırt etmek için plasebo grupları kullanılarak kontrol edilir.","nl":"Een gunstige klinische respons op een inactieve behandeling, veroorzaakt door het geloof van de patiënt in de effectiviteit ervan. In onderzoek gecontroleerd met placebogroepen om echte geneesmiddeleffecten te isoleren.","ru":"Положительный клинический ответ на неактивное лечение, вызванный верой пациента в его эффективность. В исследованиях контролируется с помощью плацебо-групп для выявления истинного эффекта препарата.","zh":"由于患者相信治疗有效而对非活性治疗产生的有益临床反应。在研究中通过安慰剂对照组来分离真正的药物效果。","pt_BR":"Uma resposta clínica benéfica a um tratamento inativo, causada pela crença do paciente em sua eficácia. Controlado em pesquisas por meio de grupos placebo para isolar os verdadeiros efeitos do fármaco.","pt_PT":"Uma resposta clínica benéfica a um tratamento inativo, causada pela crença do doente na sua eficácia. Controlado em investigação através de grupos placebo para isolar os verdadeiros efeitos do fármaco."}},
];
